import 'dotenv/config';
import { connectDB } from '../config/db.js';
import Location from '../models/Location.js';

// Auto-generated by exportLocations.js — do not edit manually
const descriptions = {
  "prague-castle": {
    en: `Brave explorer, you stand before the legendary Prague Castle — the largest ancient castle complex on Earth, sprawling across 70,000 square metres of sheer history. Unlock its hidden layers and discover that beneath these royal halls runs a network of forgotten tunnels used by medieval monks to smuggle wine. Ancient secrets whisper through every stone: this fortress has never fallen to a direct military assault in over a thousand years. Three presidents, countless kings, and one Holy Roman Emperor called it home. Seek the hidden Romanesque foundations buried beneath the Baroque exteriors — your questlog demands it. The castle is not merely a destination; it is the final boss zone of Prague itself.`,
    cz: `Odvážný průzkumníku, stojíš před legendárním Pražským hradem — největším starověkým hradním komplexem na Zemi, rozkládajícím se na 70 000 čtverečních metrech ryzí historie. Odemkni jeho skryté vrstvy a zjisti, že pod těmito královskými sály se vine síť zapomenutých tunelů, které středověcí mniši využívali k pašování vína. Starověká tajemství šeptají z každého kamene: tato pevnost nebyla nikdy dobyta přímým vojenským útokem po více než tisíc let. Hledej skryté románské základy pohřbené pod barokními fasádami — tvůj questlog to vyžaduje. Hrad není jen cíl; je to finální boss zóna samotné Prahy.`,
    zh: `勇敢的探险家，你站在传奇的布拉格城堡面前——这是地球上最大的古代城堡建筑群，占地七万平方米，充满历史的厚重感。解锁它的隐藏层次，你将发现在这些皇家大厅之下，蜿蜒着一条被遗忘的地下隧道网络，中世纪的僧侣曾用它来秘密运送葡萄酒。每一块石头都低语着古老的秘密：这座要塞在超过一千年的历史中从未被直接军事攻击所攻克。寻找埋藏于巴洛克外墙之下的罗马式地基——你的任务日志要求你这样做。城堡不仅仅是一个目的地，它是布拉格本身的最终Boss区域。`,
  },

  "charles-bridge": {
    en: `Brave explorer, Charles Bridge is not merely a crossing — it is a 516-metre gauntlet of stone saints, ancient curses, and legendary power. Unlock the bridge's true secret: the mortar binding its sandstone blocks was reportedly mixed with eggs and wine for extra strength, making this structure equal parts architecture and medieval recipe. Touch the bronze plaque beneath the statue of St. John of Nepomuk — worn smooth by millions of hands seeking good luck — and claim your blessing. Construction began on 9 July 1357 at 5:31 AM, a date chosen by Emperor Charles IV for its palindromic numerology: 1-3-5-7-9-7-5-3-1. The bridge rewards those who cross it at dawn.`,
    cz: `Odvážný průzkumníku, Karlův most není jen přechod — je to 516metrová gauntletová zkouška kamenných světců, starověkých kleteb a legendární moci. Odemkni pravé tajemství mostu: malta spojující pískovcové bloky prý byla zamíchána s vejci a vínem pro větší pevnost, což z této stavby činí dílo rovným dílem architektury i středověkého receptu. Dotkni se bronzové desky pod sochou sv. Jana Nepomuckého — vyleštěné miliony rukou hledajícími štěstí — a získej své požehnání. Stavba začala 9. července 1357 v 5:31, datum zvolené císařem Karlem IV. pro jeho palindromní numerologii: 1-3-5-7-9-7-5-3-1. Most odměňuje ty, kteří jej překročí za úsvitu.`,
    zh: `勇敢的探险家，查理大桥不仅仅是一座桥——它是一条516米长的石雕圣人、古老诅咒与传奇力量的考验之路。解锁大桥真正的秘密：据说砌合砂岩石块的砂浆是用鸡蛋和葡萄酒调制的，以增加强度，使这座建筑既是建筑学杰作，也是一道中世纪食谱。触摸圣约翰·内波穆克雕像下方被数百万双祈福之手磨光的铜牌，领取你的祝福。建造工程于1357年7月9日5时31分开始，这个日期由查理四世皇帝特意选定，因为它构成了回文数字：1-3-5-7-9-7-5-3-1。大桥将在黎明时分给予穿越者最丰厚的奖赏。`,
  },

  "old-town-square": {
    en: `Brave explorer, you have reached Old Town Square — the ancient arena where Prague's greatest dramas have unfolded for nine centuries. Unlock its hidden past: beneath the cobblestones lies an entire medieval city, one full storey lower than today's street level, swallowed by centuries of flooding and deliberate landfill. Twenty-seven Protestant leaders were executed here in 1621; look for the twenty-seven white crosses embedded in the pavement — most tourists walk right over them without ever knowing. The square is no mere plaza; it is the save point between Prague's darkest chapters and its brightest festivals. Stand at its centre and feel a thousand years of history pressing upward through your boots.`,
    cz: `Odvážný průzkumníku, dosáhl jsi Staroměstského náměstí — starověké arény, kde se po devět století odehrávala největší dramata Prahy. Odemkni jeho skrytou minulost: pod dlažebními kostkami leží celé středověké město, jedno celé podlaží níže než dnešní úroveň ulice, pohlcené staletími záplav a záměrného zavážení. V roce 1621 bylo zde popraveno dvacet sedm protestantských vůdců; hledej dvacet sedm bílých křížů zabudovaných do dlažby — většina turistů po nich přejde, aniž by to kdy věděla. Náměstí není jen prostranství; je to bod uložení hry mezi nejtemnějšími kapitolami Prahy a jejími nejjasnějšími slavnostmi. Postav se do jeho středu a pocit tisíc let historie se prodere přes tvé boty.`,
    zh: `勇敢的探险家，你已抵达老城广场——这个古老的竞技场，九百年来上演着布拉格最伟大的历史戏剧。解锁它隐藏的过去：在鹅卵石之下，埋藏着一整座中世纪城市，比今日的街道低整整一层，被数百年的洪水和刻意填埋所吞没。1621年，二十七位新教领袖在此被处决；寻找嵌入地面的二十七个白色十字架——大多数游客从它们上面走过，却浑然不知。广场不仅仅是一个广场；它是布拉格最黑暗篇章与最光辉节日之间的存档点。站在它的中心，感受千年历史透过你的靴底向上涌来。`,
  },

  "astronomical-clock": {
    en: `Brave explorer, the Orloj awaits you — a cosmic machine installed in 1410 that tracks solar time, lunar cycles, Babylonian time, and the zodiac simultaneously. Legend claims the city blinded its creator, Master Hanuš, so he could never replicate its secrets elsewhere; in revenge, he reached into the mechanism and sabotaged it, cursing anyone who repairs it carelessly. Unlock the Easter egg hidden in plain sight: the clock has a skeleton figure that rings the bell on the hour — but the fourth figure, a Turk shaking his head, was added as a medieval insult toward Ottoman invaders. Each hourly show reveals twelve apostles in the windows above. This is no mere timepiece; it is a quest timer for Prague itself.`,
    cz: `Odvážný průzkumníku, čeká na tebe Orloj — kosmický stroj nainstalovaný v roce 1410, který současně sleduje sluneční čas, lunární cykly, babylónský čas a zvěrokruh. Legenda tvrdí, že město oslepilo svého tvůrce, mistra Hanuše, aby nemohl svá tajemství nikde jinde zopakovat; v odplatě sáhl do mechanismu a záměrně ho poškodil, proklínaje každého, kdo ho neopatrně opraví. Odemkni easter egg skrytý na očích: hodiny mají kostlivce, který odbíjí zvon každou hodinu — ale čtvrtá figura, Turek třesoucí hlavou, byla přidána jako středověká urážka osmanských útočníků. Každá hodinová show odhaluje dvanáct apoštolů v oknech nahoře. Toto není jen časoměřič; je to quest timer pro samotnou Prahu.`,
    zh: `勇敢的探险家，奥尔洛伊在等待着你——这台安装于1410年的宇宙机器，同时追踪太阳时间、月亮周期、巴比伦时间和黄道十二宫。传说城市将其创造者汉努什大师弄瞎，以防止他在别处复制这些秘密；作为报复，他将手伸入机械装置中蓄意破坏，诅咒任何不谨慎修复它的人。解锁隐藏在明处的彩蛋：时钟有一个骷髅人物，每小时敲响一次钟——但第四个人物，一个摇着头的土耳其人，是作为对奥斯曼入侵者的中世纪侮辱而添加的。每小时的表演都会在上方窗口展示十二门徒。这不仅仅是一个计时器；它是布拉格本身的任务计时器。`,
  },

  "pinkas-synagogue": {
    en: `Brave explorer, Pinkas Synagogue is the most solemn quest zone in Prague — a 16th-century synagogue whose interior walls are covered floor to ceiling with 80,000 names, written by hand in red and black: every Jewish victim of the Holocaust from Bohemia and Moravia. Each name includes a birth date and a date of death or deportation. The communists whitewashed the walls in 1968 claiming damp damage, conveniently erasing the memorial. After 1989, volunteers spent years restoring every single name from archival records. Unlock the Easter egg in the upper gallery: children's drawings from the Terezín concentration camp are displayed here — artwork created by young prisoners who were taught in secret by the artist Friedl Dicker-Brandeis. 15,000 children passed through Terezín. Fewer than 100 survived.`,
    cz: `Odvážný průzkumníku, Pinkasova synagoga je nejslavnostnější quest zónou v Praze — synagoga ze 16. století, jejíž vnitřní stěny jsou od podlahy ke stropu pokryty 80 000 jmény napsanými ručně červenou a černou barvou: každá židovská oběť holocaustu z Čech a Moravy. Každé jméno obsahuje datum narození a datum úmrtí nebo deportace. Komunisté v roce 1968 stěny přebílili s odůvodněním vlhkostních škod, čímž vhodně vymazali pomník. Po roce 1989 dobrovolníci strávili roky obnovováním každého jména z archivních záznamů. Odemkni easter egg v horní galerii: zde jsou vystaveny dětské kresby z koncentračního tábora Terezín — umělecká díla vytvořená mladými vězni, kteří byli tajně vyučováni umělkyní Friedl Dicker-Brandeis. Terezínem prošlo 15 000 dětí. Přežilo méně než 100.`,
    zh: `勇敢的探险家，平卡斯会堂是布拉格最庄严的任务区——一座16世纪的会堂，其内部墙壁从地板到天花板写满了80000个用红色和黑色手写的名字：来自波西米亚和摩拉维亚的每一位大屠杀犹太受害者。每个名字都包含出生日期和死亡或驱逐日期。共产党人于1968年以受潮损坏为由将墙壁粉刷一新，借此抹去了这座纪念碑。1989年之后，志愿者们花费数年时间从档案记录中恢复了每一个名字。解锁上层画廊中的彩蛋：这里展示着来自特莱西恩斯塔特集中营的儿童画作——由年轻囚犯创作的艺术品，他们曾被艺术家弗里德尔·迪克尔-布兰代斯秘密教导。15000名儿童经过特莱西恩斯塔特。不足100人幸存。`,
  },

  "mucha-museum": {
    en: `Brave explorer, the Mucha Museum is a compact but legendary loot chest dedicated to Alphonse Mucha — the Czech artist who accidentally invented the Art Nouveau poster while rushing a commission for actress Sarah Bernhardt on New Year's Eve 1894. The resulting lithograph made him the most famous commercial artist in Paris overnight. Unlock the Easter egg hiding in his biography: Mucha spent his final years working in secret on his true masterpiece — the Slav Epic, twenty monumental canvases depicting Slavic history. He considered his Paris celebrity work embarrassing compared to this. The Epic is now in Moravský Krumlov and technically viewable, though Mucha himself called his famous decorative posters "mere bread-winning art." The man who defined beautiful Art Nouveau hated being famous for it.`,
    cz: `Odvážný průzkumníku, Muchovo muzeum je kompaktní, ale legendární truhla s looty věnovaná Alfonsovi Muchovi — českému umělci, který náhodně vynalezl secesní plakát při chvatném plnění zakázky pro herečku Sáru Bernhardtovou na Silvestra roku 1894. Výsledná litografie z něj přes noc udělala nejslavnějšího komerčního umělce v Paříži. Odemkni easter egg ukrytý v jeho biografii: Mucha strávil poslední léta tajnou prací na svém skutečném mistrovském díle — Slovanské epopeji, dvaceti monumentálních plátnech zobrazujících slovanské dějiny. V porovnání s tímto dílem považoval svou pařížskou celebritu za trapnou. Epos je nyní v Moravském Krumlově a technicky k vidění, přestože Mucha sám označoval své slavné dekorativní plakáty jako "pouhé výdělečné umění". Muž, který definoval krásnou secesi, nenáviděl být za ni slavný.`,
    zh: `勇敢的探险家，慕夏博物馆是一个紧凑却传奇的战利品宝箱，专门献给阿尔丰斯·慕夏——这位捷克艺术家在1894年除夕夜匆忙完成女演员莎拉·伯恩哈特的委托作品时，意外地发明了新艺术风格海报。由此诞生的石版画让他一夜之间成为巴黎最著名的商业艺术家。解锁隐藏在他传记中的彩蛋：慕夏晚年秘密创作他真正的杰作——斯拉夫史诗，二十幅描绘斯拉夫历史的巨型画布。与之相比，他认为自己在巴黎的名人商业作品令人尴尬。史诗现存于莫拉夫斯基·克鲁姆洛夫，理论上可以参观——尽管慕夏本人将他的知名装饰海报称为"仅仅是谋生之作"。这位定义了美丽新艺术风格的人，恨自己因此成名。`,
  },

  "st-james-apostle": {
    en: `Brave explorer, St. James the Apostle Church in Old Town is Prague's most acoustically legendary quest zone — a 14th-century Gothic church with a Baroque interior so richly decorated it takes twenty minutes just to identify every altarpiece. It hosts some of the finest organ concerts in the city, the instrument itself rumbling through a vault that makes every note feel ancient. Unlock the deeply unsettling Easter egg hanging above the door: near the church entrance hangs a desiccated human forearm, blackened with age. In 1400, a thief tried to steal a jewelled statue of the Virgin; she grabbed his arm and would not let go. The monks had to amputate it. The arm has hung there as a warning for over 600 years. The church has never needed a security system since. Enter, if you dare.`,
    cz: `Odvážný průzkumníku, Kostel sv. Jakuba Staršího ve Starém Městě je akusticky nejlegendárnější quest zónou Prahy — gotický kostel ze 14. století s barokním interiérem tak bohatě zdobeným, že identifikace každého oltářního obrazu trvá dvacet minut. Hostí jedny z nejlepších varhanních koncertů ve městě, samotný nástroj duní klenbou, která každou notu činí starobylou. Odemkni hluboce zneklidňující easter egg visící nad dveřmi: poblíž vchodu do kostela visí vysušená lidská předloktí, zčernalá věkem. V roce 1400 se zloděj pokusil ukrást klenotem ozdobenou sochu Panny Marie; ona ho chytila za ruku a nepustila. Mniši museli ruku amputovat. Paže visí jako varování přes 600 let. Kostel od té doby nikdy nepotřeboval bezpečnostní systém. Vstup, pokud se odvážíš.`,
    zh: `勇敢的探险家，老城区的圣雅各伯教堂是布拉格声学上最传奇的任务区——一座14世纪的哥特式教堂，其巴洛克式内部装饰如此华丽繁复，仅辨认每一幅祭坛画就需花费二十分钟。这里举办城市中最精彩的管风琴音乐会，乐器在穹顶中轰鸣，使每一个音符都显得古朴悠远。解锁悬挂在门上方那令人深感不安的彩蛋：教堂入口附近悬挂着一条因岁月而变黑的干枯人类前臂。1400年，一名盗贼试图偷走一尊镶嵌珠宝的圣母像；圣母抓住了他的手臂，紧握不放。僧侣们不得不将其截肢。这条手臂作为警示悬挂了超过600年。此后教堂再也不需要安全系统。进入吧，如果你敢的话。`,
  },

  "bethlehem-chapel": {
    en: `Brave explorer, Bethlehem Chapel is the most revolutionary quest zone in Prague — a deliberately simple preaching hall built in 1391 specifically to hold 3,000 people and deliver sermons in Czech, not Latin, at a time when that alone was an act of religious defiance. Jan Hus preached here from 1402 until his arrest, denouncing church corruption with such force that his ideas pre-dated the Protestant Reformation by a hundred years. Unlock the Easter egg scratched into history: Hus was burned at the Council of Constance in 1415, but his followers — the Hussites — developed the world's first military use of wagons as mobile fortresses, and used it to defeat five Crusades sent against them. The chapel was rebuilt from ruins in 1950. Every brick here is an act of stubbornness.`,
    cz: `Odvážný průzkumníku, Betlémská kaple je nejrevolučnější quest zónou v Praze — záměrně prostá kazatelna postavena v roce 1391 speciálně pro 3 000 lidí k poslouchání kázání v češtině, ne latině, v době, kdy to samo o sobě byl akt náboženského vzdoru. Jan Hus zde kázal od roku 1402 až do svého zatčení, odsuzující církevní korupci s takovou silou, že jeho myšlenky předešly protestantskou reformaci o sto let. Odemkni easter egg vyrytý do dějin: Hus byl upálen na Kostnickém koncilu v roce 1415, ale jeho stoupenci — husité — vyvinuli první vojenské využití vozů jako pojízdných pevností na světě a použili je k porážce pěti křížových výprav vyslaných proti nim. Kaple byla přestavěna ze sutin v roce 1950. Každá cihla zde je aktem zarytosti.`,
    zh: `勇敢的探险家，伯利恒礼拜堂是布拉格最具革命性的任务区——一座刻意简朴的布道堂，建于1391年，专门容纳3000人，用捷克语而非拉丁语布道，而在那个年代，仅此一点便是宗教抗命之举。扬·胡斯自1402年起在此布道，直至被捕，以巨大的力量谴责教会腐败，其思想比新教改革早了整整一百年。解锁刻入历史的彩蛋：胡斯于1415年在康斯坦茨会议上被烧死，但他的追随者——胡斯派——发明了世界上第一次将马车用作移动要塞的军事战术，并用它击败了五次派来对抗他们的十字军东征。礼拜堂于1950年从废墟中重建。这里的每一块砖都是一种执拗的宣言。`,
  },

  "national-museum": {
    en: `Brave explorer, the National Museum crowns Wenceslas Square like the final boss chamber of Czech civilization — a Neo-Renaissance fortress of knowledge housing millions of artefacts, fossils, and national treasures. Unlock its battle-scarred Easter egg: during the Soviet invasion of August 1968, Warsaw Pact tanks mistook this grand building for the parliament and opened fire. The bullet holes were patched with lighter stone — visible to this day if you know exactly where to look on the main facade. The museum closed for fourteen years of renovation and reopened in 2018, its restored interior more legendary than ever. The meteorite collection alone is worth the entry fee. This is no mere building; it is the save point of the Czech nation.`,
    cz: `Odvážný průzkumníku, Národní muzeum korunuje Václavské náměstí jako finální boss komora české civilizace — neorenezanční pevnost poznání ukrývající miliony artefaktů, fosilií a národních pokladů. Odemkni jeho bitvami zjizvený easter egg: během sovětské invaze v srpnu 1968 tanky Varšavské smlouvy zaměnily tuto velkolepou budovu za parlament a zahájily palbu. Kulometné díry byly opraveny světlejším kamenem — dodnes viditelným, pokud přesně víš, kde na hlavní fasádě hledat. Muzeum bylo kvůli rekonstrukci zavřeno čtrnáct let a znovu otevřeno v roce 2018, jeho zrestaurovaný interiér legendárnější než kdy dříve. Samotná sbírka meteoritů za vstupné stojí. Toto není jen budova; je to save point českého národa.`,
    zh: `勇敢的探险家，国家博物馆如同捷克文明的最终Boss房间般雄踞瓦茨拉夫广场顶端——这座新文艺复兴风格的知识堡垒收藏着数百万件文物、化石和国家珍宝。解锁其伤痕累累的彩蛋：1968年8月苏联入侵期间，华沙条约组织的坦克将这座宏伟建筑误认为议会大厦并开枪射击。弹孔被颜色较浅的石头修补——如果你知道确切位置，今天仍能在主立面上找到它们。博物馆因翻修关闭了十四年，于2018年重新开放，修复后的内部比以往更加传奇。仅陨石收藏就物超所值。这不仅仅是一座建筑；它是捷克民族的存档点。`,
  },

  "kafka-museum": {
    en: `Brave explorer, the Kafka Museum is the most deliberately disorienting quest zone in Prague — and that is entirely intentional. Located in Malá Strana, this dark labyrinth of sound installations, projected manuscripts, and existential dread celebrates Franz Kafka, a man who wrote in German, lived as a Czech Jew, and felt at home nowhere. Unlock the Easter egg guarding the entrance: the courtyard features a sculpture of two mechanical men urinating into a pool shaped like the Czech Republic, by artist David Černý — the figures move, and visitors can text a number to make them write messages in urine. Kafka himself dreamed of escaping Prague and never could. You, brave explorer, have the advantage: you chose to enter.`,
    cz: `Odvážný průzkumníku, Kafkovo muzeum je nejzáměrněji dezorientující quest zóna v Praze — a to je zcela záměrné. Umístěné v Malé Straně, tento temný labyrint zvukových instalací, promítaných rukopisů a existenciální hrůzy slaví Franze Kafku, muže, který psal německy, žil jako český Žid a necítil se doma nikde. Odemkni easter egg střežící vchod: nádvoří zdobí socha dvou mechanických mužů močících do bazénu ve tvaru České republiky, od umělce Davida Černého — figury se pohybují a návštěvníci mohou zaslat SMS s číslem, aby nechali figury psát zprávy močí. Kafka sám snil o útěku z Prahy a nikdy nemohl. Ty, odvážný průzkumníku, máš výhodu: vstoupil jsi dobrovolně.`,
    zh: `勇敢的探险家，卡夫卡博物馆是布拉格最故意让人迷失方向的任务区——这完全是有意为之。位于小城区，这个充满声音装置、投影手稿和存在主义恐惧的黑暗迷宫，颂扬着弗朗茨·卡夫卡——一个用德语写作、以捷克犹太人身份生活、在任何地方都感到无家可归的人。解锁守护入口的彩蛋：庭院里有一座艺术家大卫·切尔尼创作的雕塑，两个机械人向形如捷克共和国的水池里排尿——人物会移动，游客还可以发短信让他们用尿液写出信息。卡夫卡自己梦想着逃离布拉格，却始终未能如愿。你，勇敢的探险家，拥有一个优势：你是主动选择进入的。`,
  },

  "national-theatre": {
    en: `Brave explorer, the National Theatre is the most emotionally loaded building in Prague — a Neo-Renaissance opera house built entirely through public donations as an act of Czech national defiance against Austro-Hungarian rule. The fundraising began in 1851 and every Czech citizen contributed: schoolchildren gave pennies, farmers gave grain, miners gave coal. Unlock the devastating Easter egg: two months after opening in 1881, the nearly completed theatre burned down. Rather than despair, the Czech nation raised the funds again in just 47 days and rebuilt it even more beautifully. "The Nation to Itself" is inscribed above the stage — a motto earned twice over. Every performance here carries the weight of a people who refused to let fire erase their culture. This stage is sacred ground.`,
    cz: `Odvážný průzkumníku, Národní divadlo je emotivně nejzatíženější budovou v Praze — neorenezanční operní dům postavený výhradně z veřejných sbírek jako akt českého národního odporu proti rakousko-uherské nadvládě. Sbírka začala v roce 1851 a přispěl každý český občan: školáci dávali haléře, zemědělci obilí, horníci uhlí. Odemkni zdrcující easter egg: dva měsíce po otevření v roce 1881 takřka dokončené divadlo vyhořelo. Místo zoufalství národ sebral prostředky znovu za pouhých 47 dní a přestavěl ho ještě krásnějším. "Národ sobě" je napsáno nad scénou — motto dvakrát si zasloužené. Každé vystoupení zde nese tíhu národa, který odmítl dovolit ohni vymazat jeho kulturu. Tato scéna je posvátnou půdou.`,
    zh: `勇敢的探险家，国家剧院是布拉格情感最为厚重的建筑——一座新文艺复兴风格的歌剧院，完全通过公众捐款建造，是捷克民族对抗奥匈帝国统治的一次自我宣示。募捐始于1851年，每位捷克公民都有所贡献：学童捐出了硬币，农民捐出了粮食，矿工捐出了煤炭。解锁令人心碎的彩蛋：1881年开幕后仅两个月，几近完工的剧院便付之一炬。捷克民族没有陷入绝望，而是仅用47天便再次筹集了资金，并将其重建得更加美丽。舞台上方镌刻着"民族献给自我"——这是一句被赢得了两次的格言。这里的每一场演出都承载着一个民族拒绝让烈火抹去其文化的分量。这个舞台是神圣的土地。`,
  },

  "dox-centre": {
    en: `Brave explorer, DOX Centre for Contemporary Art is Prague's most provocative cultural quest zone — a former factory in Holešovice converted into the city's largest contemporary art gallery, a labyrinth of industrial spaces, steel walkways, and installations that challenge, disturb, and occasionally infuriate. Unlock the Easter egg parked permanently on the roof: DOX hosts a full-sized ZEPPELIN — a 42-metre airship gondola mounted on the roof as a permanent installation and reading room, accessible to visitors. It was airlifted into place by helicopter. Inside the gondola is a library dedicated to utopian and dystopian literature. The gallery itself shows work from artists the Prague establishment has not yet decided how to categorise. That is precisely the point. Holešovice was once a factory district. It is now where the future is being assembled.`,
    cz: `Odvážný průzkumníku, DOX Centrum pro současné umění je nejprovokativnější kulturní quest zónou Prahy — bývalá továrna v Holešovicích přeměněná v největší galerii současného umění ve městě, labyrint průmyslových prostor, ocelových chodníků a instalací, které vyzývají, zneklidňují a příležitostně rozzuřují. Odemkni easter egg trvale zaparkovaný na střeše: DOX hostí plnorozměrný ZEPPELIN — 42metrovou gondolu vzducholodi umístěnou na střeše jako trvalá instalace a čítárna, přístupná návštěvníkům. Byla přepravena na místo vrtulníkem. Uvnitř gondoly je knihovna věnovaná utopické a dystopické literatuře. Galerie sama vystavuje práce umělců, které pražský establishment zatím nerozhodl, jak kategorizovat. To je přesně ten bod. Holešovice byly kdysi tovární čtvrtí. Nyní je to místo, kde se sestavuje budoucnost.`,
    zh: `勇敢的探险家，DOX当代艺术中心是布拉格最具挑衅性的文化任务区——霍莱绍维采区一座前工厂被改造成城市最大的当代艺术画廊，一个由工业空间、钢制走道和装置艺术构成的迷宫，充满挑战、令人不安，偶尔还会激怒观者。解锁永久停放在屋顶上的彩蛋：DOX馆内有一艘完整尺寸的飞艇——一个42米长的飞艇吊舱被安装在屋顶上，作为永久装置和阅览室供游客使用。它是由直升机吊运就位的。吊舱内部是一个专门收藏乌托邦与反乌托邦文学的图书馆。画廊本身展示着布拉格当权派尚未决定如何分类的艺术家作品。这正是重点所在。霍莱绍维采曾是一个工厂区，如今它是未来正在被组装的地方。`,
  },

  "rudolfinum": {
    en: `Brave explorer, the Rudolfinum is Prague's grandest cultural fortress — a Neo-Renaissance concert hall and gallery completed in 1885, home to the Czech Philharmonic Orchestra and one of the finest concert venues in Central Europe. Its Dvořák Hall is considered acoustically perfect; recordings made here are used worldwide as reference benchmarks for classical sound. Unlock the Easter egg embedded in its wartime misuse: during the Nazi occupation, the building was requisitioned as the headquarters of the German occupying administration. The occupiers were so offended by a statue of the Jewish composer Felix Mendelssohn on the rooftop that they ordered it removed. The soldiers tasked with the job could not identify which statue was Mendelssohn among the row of composers — so they removed the one with the biggest nose. It was Wagner. The Mendelssohn stayed.`,
    cz: `Odvážný průzkumníku, Rudolfinum je nejvelkolepější kulturní pevností Prahy — neorenezanční koncertní sál a galerie dokončená v roce 1885, domov České filharmonie a jedno z nejkrásnějších koncertních míst ve střední Evropě. Dvořákova síň je považována za akusticky dokonalou; nahrávky pořízené zde jsou celosvětově používány jako referenční standardy pro klasický zvuk. Odemkni easter egg vtesaný do jeho válečného zneužití: během nacistické okupace byla budova zabrána jako sídlo německé okupační správy. Okupanti byli tak pobouřeni sochou židovského skladatele Felixe Mendelssohna na střeše, že nařídili její odstranění. Vojáci pověření úkolem nedokázali identifikovat, která socha je Mendelssohn mezi řadou skladatelů — a tak odstranili tu s největším nosem. Byl to Wagner. Mendelssohn zůstal.`,
    zh: `勇敢的探险家，鲁道夫音乐厅是布拉格最宏伟的文化要塞——一座完工于1885年的新文艺复兴风格音乐厅和画廊，是捷克爱乐乐团的驻地，也是中欧最优秀的音乐厅之一。德沃夏克音乐厅被认为声学完美；在此录制的唱片被全球用作古典音效的参考基准。解锁嵌入其战时被滥用历史中的彩蛋：纳粹占领期间，该建筑被征用为德国占领当局的总部。占领者对屋顶上犹太作曲家费利克斯·门德尔松的雕像深感不满，下令将其移除。被派去执行任务的士兵无法在一排作曲家雕像中辨认出哪一个是门德尔松——于是他们移除了鼻子最大的那一个。那是瓦格纳。门德尔松留了下来。`,
  },

  "czech-museum-of-music": {
    en: `Brave explorer, the Czech Museum of Music occupies one of the most beautiful Baroque churches in Prague — the former Church of St. Mary Magdalene in Malá Strana, deconsecrated and transformed into a treasure vault of musical history. Inside, over 3,000 instruments are catalogued across four floors, from medieval lutes to 20th-century synthesizers. Unlock the Easter egg humming in the permanent collection: the museum holds the oldest surviving guitar in the world, a six-string instrument dating from 1779 — predating the standardisation of the modern guitar and looking nothing like what you would expect. It is displayed in a climate-controlled case next to instruments played by Dvořák himself. This is not a dusty archive; interactive stations let you hear every instrument in the collection. The church that once echoed with prayer now echoes with music theory. The trade was fair.`,
    cz: `Odvážný průzkumníku, České muzeum hudby sídlí v jednom z nejkrásnějších barokních kostelů Prahy — bývalém Kostele sv. Máří Magdalény na Malé Straně, dekonsekrovaném a přeměněném v trezor hudební historie. Uvnitř je na čtyřech podlažích katalogizováno přes 3 000 nástrojů, od středověkých luten po syntezátory 20. století. Odemkni easter egg hučící ve stálé sbírce: muzeum uchovává nejstarší dochovanou kytaru na světě — šestistrunný nástroj z roku 1779, předcházející standardizaci moderní kytary a nevypadající vůbec tak, jak bys čekal. Je vystavena v klimatizované vitríně vedle nástrojů, na které hrál sám Dvořák. Toto není zaprášený archiv; interaktivní stanice ti umožní slyšet každý nástroj ze sbírky. Kostel, který kdysi zněl modlitbami, nyní zní hudební teorií. Výměna byla spravedlivá.`,
    zh: `勇敢的探险家，捷克音乐博物馆坐落于布拉格最美丽的巴洛克式教堂之一——小城区前圣玛利亚抹大拉教堂，经去圣化改造后成为音乐历史的宝库。馆内四层楼共收录了3000余件乐器，从中世纪琉特琴到20世纪合成器，一应俱全。解锁在永久馆藏中嗡嗡作响的彩蛋：博物馆收藏着世界上现存最古老的吉他——一把可追溯至1779年的六弦乐器，早于现代吉他的标准化，其外形与你想象中的完全不同。它被陈列在一个恒温展柜中，旁边摆放着德沃夏克本人演奏过的乐器。这里绝非一个布满灰尘的档案馆；互动展台让你得以聆听馆藏中每件乐器的声音。这座曾经回响着祷告声的教堂，如今回响着乐理之声。这笔交换是值得的。`,
  },

  "veletrzni-palace": {
    en: `Brave explorer, Veletržní Palace in Holešovice is the most underrated quest zone in Prague — a Functionalist trade fair palace built in 1928 that was so architecturally radical Le Corbusier visited and declared it had influenced his own work. It is now the National Gallery's modern and contemporary art collection, housing the largest collection of French Impressionist and Post-Impressionist art in Central Europe outside Paris. Unlock the Easter egg concealed in its tragic history: in 1974, a catastrophic fire destroyed much of the collection, including irreplaceable works. The rebuilding took decades. Hidden in the permanent collection is a painting by Van Gogh's that survived the fire only because it was on loan elsewhere that year. The collection you see today is partly defined by what was not there when the fire started. Absence shaped the art.`,
    cz: `Odvážný průzkumníku, Veletržní palác v Holešovicích je nejvíce podceňovanou quest zónou v Praze — funkcionalistický veletržní palác postavený v roce 1928, který byl architektonicky tak radikální, že ho navštívil Le Corbusier a prohlásil, že ovlivnil jeho vlastní práci. Nyní ukrývá sbírku moderního a současného umění Národní galerie, hostící největší sbírku francouzského impresionismu a postimpresionismu ve střední Evropě mimo Paříž. Odemkni easter egg ukrytý v jeho tragické historii: v roce 1974 katastrofický požár zničil velkou část sbírky, včetně nenahraditelných děl. Přestavba trvala desetiletí. Ve stálé sbírce je skrytý obraz Van Gogha, který přežil požár jen proto, že byl ten rok zapůjčen jinde. Sbírka, kterou dnes vidíš, je částečně definována tím, co tam nebylo, když požár vypukl. Absence formovala umění.`,
    zh: `勇敢的探险家，霍莱绍维采的贸易博览会宫是布拉格最被低估的任务区——一座建于1928年的功能主义贸易展览宫，其建筑风格如此激进，以至于勒·柯布西耶亲自来访，并声称它影响了自己的作品。它现在是国家美术馆的现代与当代艺术收藏地，收藏着巴黎以外中欧地区规模最大的法国印象派和后印象派艺术收藏。解锁隐藏在其悲剧历史中的彩蛋：1974年，一场灾难性的火灾摧毁了大部分藏品，包括无可替代的作品。重建工作历时数十年。永久收藏中有一幅梵高的画作幸免于难，仅仅是因为那一年它正在外地借展。你今天所见的收藏，部分是由那场火灾发生时恰好不在场的东西所定义的。缺席塑造了艺术。`,
  },

  "laterna-magika": {
    en: `Brave explorer, Laterna Magika is the most experimental performance quest zone in Prague — a multimedia theatre company founded in 1958 that combines live action, film projection, dance, and opera into a single simultaneous performance, a form so radical it had no name when it was invented. It debuted at the 1958 Brussels World Expo and caused an international sensation; critics invented the term "black light theatre" to describe it. Unlock the Easter egg sealed in its political history: during the Velvet Revolution of November 1989, Laterna Magika's theatre became the operational headquarters of the Civic Forum — Václav Havel's dissident movement that toppled communist rule. Dissidents held press conferences here, coordinated strikes, and planned the transition of power in the backstage dressing rooms. A revolution was stage-managed from a theatre. Prague could not have scripted it better.`,
    cz: `Odvážný průzkumníku, Laterna Magika je nejexperimentálnější performativní quest zónou Prahy — multimediální divadelní soubor založený v roce 1958, který kombinuje živé akce, filmové projekce, tanec a operu do jediného simultánního představení, formy tak radikální, že neměla název, když byla vynalezena. Debutovala na Světové výstavě v Bruselu v roce 1958 a způsobila mezinárodní senzaci; kritici vymysleli termín "black light theatre", aby ji popsali. Odemkni easter egg zapečetěný v její politické historii: během Sametové revoluce v listopadu 1989 se divadlo Laterny Magiky stalo operačním centrem Občanského fóra — disidentského hnutí Václava Havla, které svrhlo komunistickou nadvládu. Disidenti zde pořádali tiskové konference, koordinovali stávky a plánovali přechod moci v zákulisních šatnách. Revoluce byla scénicky řízena z divadla. Praha to nemohla napsat lépe.`,
    zh: `勇敢的探险家，魔幻灯笼剧院是布拉格最具实验性的演出任务区——一个成立于1958年的多媒体剧团，将现场表演、电影投影、舞蹈和歌剧融合为一场同步演出，这种形式在被发明时是如此激进，以至于还没有名字。它在1958年布鲁塞尔世界博览会上首次亮相，引发了国际轰动；批评家们发明了"黑光剧场"这个术语来描述它。解锁封存在其政治历史中的彩蛋：1989年11月天鹅绒革命期间，魔幻灯笼剧院的剧场成为公民论坛——瓦茨拉夫·哈维尔领导的异见运动的行动总部，该运动推翻了共产主义统治。异见人士在此举行新闻发布会、协调罢工，并在后台化妆室里规划权力交接。一场革命在剧院的舞台管理下完成。布拉格找不到比这更好的剧本了。`,
  },

  "museum-of-communism": {
    en: `Brave explorer, the Museum of Communism is the most darkly entertaining quest zone in Prague — a collection of propaganda posters, secret police interrogation recreations, and Cold War artefacts housed, with magnificent irony, above a McDonald's and next to a casino. Unlock its legendary Easter egg: the museum's location was chosen partly as a joke. Communism squeezed between capitalism's two most iconic symbols was considered the most appropriate commentary possible. Inside, a recreation of a factory production line shows a quota board that never reached its target — a perfect metaphor frozen in time. The gift shop sells genuine Communist-era milk bottles and party membership booklets. The most important Easter egg is the building itself. Prague's sense of humour survived everything.`,
    cz: `Odvážný průzkumníku, Muzeum komunismu je nejtemnější zábavnou quest zónou v Praze — sbírka propagandistických plakátů, rekonstrukcí výslechů tajné policie a artefaktů ze studené války umístěná, s velkolepou ironií, nad McDonald's a vedle kasina. Odemkni její legendární easter egg: umístění muzea bylo zvoleno částečně jako vtip. Komunismus zmáčknutý mezi dvěma nejsymboličtějšími symboly kapitalismu byl považován za nejpřípadnější možný komentář. Uvnitř rekonstrukce tovární výrobní linky zobrazuje tabulku kvót, která nikdy nedosáhla svého cíle — dokonalá metafora zmrazená v čase. Muzejní obchod prodává skutečné lahve od mléka z komunistické éry a stranické průkazy. Nejdůležitější easter egg je samotná budova. Pražský smysl pro humor přežil vše.`,
    zh: `勇敢的探险家，共产主义博物馆是布拉格最黑色幽默的任务区——一批宣传海报、秘密警察审讯场景重现以及冷战文物，极具讽刺意味地被安置在一家麦当劳楼上、紧邻一家赌场。解锁其传奇彩蛋：博物馆的选址部分出于一个玩笑。共产主义被夹在资本主义两个最具标志性的符号之间，被认为是最恰当不过的注脚。馆内一条工厂生产线的复原场景展示了一块从未达到目标的配额板——一个凝固在时间中的完美隐喻。礼品店出售真正的共产主义时代牛奶瓶和党员手册。最重要的彩蛋就是建筑本身。布拉格的幽默感经历了一切，依然存活。`,
  },

  "prague-city-gallery": {
    en: `Brave explorer, the Prague City Gallery is the most dispersed quest zone in the city — not a single building but a network of six exhibition spaces scattered across Prague, each occupying a historic structure repurposed for contemporary art. The main branch in the Stone Bell House on Old Town Square operates inside a Gothic palace dating to 1310, its medieval vaulted rooms hung with contemporary paintings in a juxtaposition so deliberately jarring it works as aesthetic argument. Unlock the Easter egg sealed in the Stone Bell House's rediscovery: the Gothic facade was hidden behind a Baroque plaster shell for centuries and only accidentally uncovered during renovations in 1975 when workers chipped through the plaster and found the original medieval stonework beneath. The Baroque exterior was simply peeled back. The city had been hiding its own Gothic palace inside a later building, the way Prague always hides one era inside another.`,
    cz: `Odvážný průzkumníku, Galerie hlavního města Prahy je nejrozptýlenější quest zónou ve městě — nikoli jediná budova, ale síť šesti výstavních prostor rozptýlených po Praze, každý obsazující historickou stavbu přeměněnou na současné umění. Hlavní pobočka v Domě U Kamenného zvonu na Staroměstském náměstí funguje uvnitř gotického paláce pocházejícího z roku 1310, jehož středověké klenuté prostory jsou osazeny současnými malbami v juxtapozici tak záměrně šokující, že funguje jako estetický argument. Odemkni easter egg zapečetěný v znovuobjevení Domu U Kamenného zvonu: gotická fasáda byla po staletí skryta za barokní omítkovou skořápkou a náhodně odkryta až při renovacích v roce 1975, kdy dělníci proklepali omítku a pod ní nalezli původní středověké kamenné zdivo. Barokní exteriér byl jednoduše odloupnut. Město skrývalo vlastní gotický palác uvnitř pozdější budovy, tak jako Praha vždy skrývá jednu éru uvnitř jiné.`,
    zh: `勇敢的探险家，布拉格市立美术馆是城市中最分散的任务区——不是单一的建筑，而是散布于布拉格各处的六个展览空间网络，每一个都占据着一座改作当代艺术用途的历史建筑。老城广场石钟楼屋的主馆在一座可追溯至1310年的哥特式宫殿内运营，其中世纪拱顶房间里悬挂着当代绘画，这种故意制造的强烈反差作为一种美学论点发挥着作用。解锁封存在石钟楼屋重新发现中的彩蛋：哥特式外墙被巴洛克灰泥外壳隐藏了数百年，直到1975年翻修期间，工人凿穿灰泥，意外地在其下发现了原始的中世纪石砌工艺，才得以重见天日。巴洛克外墙就这样被剥落下来。这座城市一直将自己的哥特式宫殿藏在一座后期建筑之内，正如布拉格总是将一个时代隐藏在另一个时代之内。`,
  },

  "state-opera": {
    en: `Brave explorer, the Prague State Opera is one of the most beautiful Neo-Rococo theatre interiors in the world — a gilded, velvet-draped, chandelier-hung quest zone that opened in 1888 as the New German Theatre, built by Prague's German-speaking minority as a direct rival to the Czech National Theatre that had opened seven years earlier. The two theatres staged competing premieres across the street from each other for decades. Unlock the Easter egg in its postwar transformation: after WWII, Prague's German community was expelled and the theatre was renamed, re-staffed with Czech artists, and absorbed into the state cultural apparatus. The building's entire identity changed overnight while the chandeliers stayed exactly where they were. It now stages Italian opera and ballet to international audiences. The architecture remembers a community that no longer exists here.`,
    cz: `Odvážný průzkumníku, Státní opera Praha je jedním z nejkrásnějších neorokokových divadelních interiérů na světě — pozlacená, sametem oděná, lustry osvětlená quest zóna, která byla otevřena v roce 1888 jako Nové německé divadlo, postavené pražskou německy mluvící menšinou jako přímý rival Národního divadla, které se otevřelo o sedm let dříve. Obě divadla po desetiletí soupeřila o premiéry naproti sobě přes ulici. Odemkni easter egg v jeho poválečné transformaci: po druhé světové válce bylo pražské německé společenství vyhnáno a divadlo bylo přejmenováno, znovu obsazeno českými umělci a absorbováno do státního kulturního aparátu. Celá identita budovy se přes noc změnila, zatímco lustry zůstaly přesně tam, kde byly. Nyní uvádí italskou operu a balet pro mezinárodní publikum. Architektura si pamatuje komunitu, která zde již neexistuje.`,
    zh: `勇敢的探险家，布拉格国家歌剧院是世界上最美丽的新洛可可风格剧院内部空间之一——一个金碧辉煌、丝绒帷幕、水晶吊灯的任务区，于1888年作为新德意志剧院开幕，由布拉格讲德语的少数族裔建造，直接与七年前开幕的捷克国家剧院抗衡。两座剧院数十年来在街道两侧相互争夺首演机会。解锁其战后转变中的彩蛋：二战后，布拉格的德裔社区遭到驱逐，剧院随即更名，重新由捷克艺术家接管，并被纳入国家文化机构体系。整座建筑的身份在一夜之间发生了彻底改变，而水晶吊灯依然悬挂在原处。如今它为国际观众上演意大利歌剧和芭蕾舞。这座建筑的砖石记忆着一个已不再存在于此的社群。`,
  },

  "estates-theatre": {
    en: `Brave explorer, the Estates Theatre is one of the most musically hallowed quest zones in Europe — a Neoclassical gem completed in 1783 that holds the title of the only surviving venue where Mozart himself conducted a world premiere. Don Giovanni debuted on this stage on October 29, 1787, with Mozart at the podium, having written the overture the night before in a single sleepless session. The audience gave him a standing ovation lasting so long the performance nearly did not start. Unlock the Easter egg hidden in the building's history: the theatre was featured in Miloš Forman's 1984 film Amadeus as the Vienna opera house — because Vienna's opera house had been modernised while Prague's remained perfectly preserved in its 18th-century form. Mozart's stage survived by never changing.`,
    cz: `Odvážný průzkumníku, Stavovské divadlo je jednou z hudebně nejposvátnějších quest zón v Evropě — neoklasický skvost dokončený v roce 1783, který drží titul jediného dochovaného místa, kde Mozart osobně dirigoval světovou premiéru. Don Giovanni měl premiéru na tomto jevišti 29. října 1787 s Mozartem u pultu, který předchozí noc napsal předehru v jediném spánku prostém sezení. Publikum mu dalo standing ovation tak dlouhé, že představení málem nezačalo. Odemkni easter egg ukrytý v historii budovy: divadlo bylo použito ve filmu Miloše Formana z roku 1984 Amadeus jako vídeňská opera — protože vídeňská opera prošla modernizací, zatímco pražská zůstala dokonale zachována ve své podobě z 18. století. Mozartova scéna přežila tím, že se nikdy nezměnila.`,
    zh: `勇敢的探险家，庄园剧院是欧洲音乐上最神圣的任务区之一——一座竣工于1783年的新古典主义瑰宝，是唯一幸存的莫扎特本人亲自执棒世界首演的场馆。唐·乔凡尼于1787年10月29日在这个舞台上首演，莫扎特亲执指挥棒，他在前一天晚上通宵一气呵成写完了序曲。观众给予他持续如此之久的起立鼓掌，以至于演出几乎没能开始。解锁隐藏在建筑历史中的彩蛋：这座剧院曾在米洛斯·福尔曼1984年的电影《莫扎特传》中作为维也纳歌剧院出现——因为维也纳的歌剧院已经现代化改造，而布拉格的剧院则完美保留了18世纪的原貌。莫扎特的舞台因为从未改变而得以留存。`,
  },

  "naprstek-museum": {
    en: `Brave explorer, the Náprstek Museum is Prague's most overlooked cultural dungeon — a museum of Asian, African, and American cultures founded in 1862 by Vojta Náprstek, a Czech entrepreneur and passionate moderniser who smuggled banned books into the country, supported the women's rights movement, and installed the first flush toilet and sewing machine in Bohemia, which he displayed alongside ethnographic artefacts from around the world. Unlock the Easter egg in the founding story: Náprstek had been exiled to America after the 1848 revolution, spent years in Milwaukee among Czech émigré communities, and returned to Prague convinced that Bohemia needed radical modernisation. He built his museum partly as a one-man campaign to drag Prague into the modern era. The totem poles and Japanese armour are extraordinary. So is the toilet installation.`,
    cz: `Odvážný průzkumníku, Náprstkovo muzeum je nejpřehlíženějším kulturním dungeonem Prahy — muzeum asijských, afrických a amerických kultur, které v roce 1862 založil Vojta Náprstek, český podnikatel a vášnivý modernizátor, který do země pašoval zakázané knihy, podporoval hnutí za práva žen a instaloval do Čech první splachovací záchod a šicí stroj, které vystavoval vedle etnografických artefaktů z celého světa. Odemkni easter egg v zakladatelském příběhu: Náprstek byl po revoluci roku 1848 vyhoštěn do Ameriky, strávil roky v Milwaukee mezi českými emigrantskými komunitami a vrátil se do Prahy přesvědčen, že Čechy potřebují radikální modernizaci. Své muzeum budoval částečně jako jednomužnou kampaň za vtažení Prahy do moderní éry. Totemové sloupy a japonský pancíř jsou mimořádné. Stejně tak instalace záchodu.`,
    zh: `勇敢的探险家，纳普尔斯泰克博物馆是布拉格最被忽视的文化地牢——一座亚洲、非洲和美洲文化博物馆，由捷克企业家兼热忱现代化倡导者沃伊塔·纳普尔斯泰克于1862年创立。他曾将禁书秘密带入国内，支持妇女权利运动，并在波西米亚安装了第一台抽水马桶和缝纫机，将其与来自世界各地的民族志文物一同展出。解锁嵌入创馆故事中的彩蛋：纳普尔斯泰克在1848年革命后被流放至美国，在密尔沃基的捷克侨民社区中度过了数年，归来后确信波西米亚需要彻底的现代化。他建立博物馆，部分是作为一场将布拉格拖入现代的单人运动。图腾柱和日本盔甲令人叹为观止。那台抽水马桶装置同样如此。`,
  },

  "technical-museum": {
    en: `Brave explorer, the National Technical Museum in Letná is the most satisfyingly dense quest zone in Prague — a vast hangar of machines, vehicles, and inventions where a full-sized biplane dangles from the ceiling above vintage motorcycles, steam locomotives, and a complete working mine shaft descending three floors underground. Unlock the Easter egg in its Cold War aviation hall: the museum holds a Czechoslovak jet fighter from the 1950s that was secretly photographed and reverse-engineered by Western intelligence agencies — its design had been based on a captured German prototype and represented an entire parallel aerospace development tradition the West did not know existed. The mine shaft tour runs every hour and deposits visitors in an authentic reconstruction of 1930s coal mining operations. You can descend into the earth beneath Letná Park. The apocalypse bunkers are not the only thing down there.`,
    cz: `Odvážný průzkumníku, Národní technické muzeum v Letné je nejuspokojeji hustou quest zónou Prahy — obrovský hangár strojů, vozidel a vynálezů, kde plnorozměrný dvouplošník visí ze stropu nad vintage motocykly, parními lokomotivami a kompletní funkční šachtou sestupující tři patra pod zem. Odemkni easter egg v jeho leteckém sále studené války: muzeum uchovává československý proudový letoun z 50. let 20. století, který byl tajně vyfotografován a zpětně inženýrován západními zpravodajskými agenturami — jeho design byl založen na ukořistěném německém prototypu a reprezentoval celou paralelní tradici leteckého vývoje, o které Západ nevěděl, že existuje. Prohlídka šachty jezdí každou hodinu a vyloží návštěvníky do autentické rekonstrukce těžby uhlí ve 30. letech 20. století. Můžeš sestoupit pod zem pod Letenskými sady. Apokalyptické bunkry nejsou jediná věc tam dole.`,
    zh: `勇敢的探险家，莱特纳国家技术博物馆是布拉格密度最令人满足的任务区——一个巨大的机器、车辆和发明物品库，全尺寸双翼飞机从天花板上悬垂，其下是复古摩托车、蒸汽机车，以及一个通向地下三层的完整运作矿井。解锁冷战航空大厅中的彩蛋：博物馆收藏着一架1950年代的捷克斯洛伐克喷气式战斗机，曾被西方情报机构秘密拍摄并进行逆向工程——其设计基于一架缴获的德国原型机，代表着西方不知道存在的整个平行航空航天发展传统。矿井参观每小时一班，将游客带入1930年代煤矿开采作业的真实重建现场。你可以在莱特纳公园地下向地球深处下降。末日掩体并不是那里唯一的东西。`,
  },

  "kafka-statue": {
    en: `Brave explorer, the Kafka Statue in Josefov is one of the strangest quest items in all of Prague — a revolving sculpture of a headless suited man carrying a smaller figure on his shoulders, both slowly rotating out of sync with each other. Created by sculptor Jaroslav Rona in 2003, it references Kafka's early short story "Description of a Struggle", in which the narrator rides a man through the night streets. The Easter egg is in the material: the statue is made from layered stacked horizontal sections like a glitching 3D model — a figure that looks solid from one angle and fragmented from another. Like every Kafka story, it makes perfect sense only if you stop trying to understand it. Stand here long enough and Prague itself starts to feel like a Kafka novel. It already was.`,
    cz: `Odvážný průzkumníku, Kafkova socha v Josefově je jedním z nejpodivnějších quest předmětů v celé Praze — otáčející se socha bezhlavého muže v obleku nesoucího na ramenou menší postavu, obě pomalu rotující nesynchronizovaně. Vytvořena sochařem Jaroslavem Ronou v roce 2003, odkazuje na Kafkovu ranou povídku "Popis jednoho zápasu", v níž vypravěč jezdí na muži nočními ulicemi. Easter egg je v materiálu: socha je vyrobena z vrstvených horizontálně naskládaných sekcí jako zaseknutý 3D model — postava, která vypadá pevně z jednoho úhlu a fragmentovaně z druhého. Jako každý Kafkův příběh dává dokonalý smysl jen tehdy, když přestaneš chápat. Postoj zde dost dlouho a Praha sama začne připadat jako Kafkův román. Vždy tak byla.`,
    zh: `勇敢的探险家，约瑟夫城的卡夫卡雕像是布拉格所有任务道具中最奇异的之一——一座旋转的无头西装男子雕塑，他的肩膀上扛着一个较小的人物，两者慢慢地以不同步的节奏旋转。由雕塑家雅罗斯拉夫·罗纳于2003年创作，它参考了卡夫卡的早期短篇小说《斗争的描述》，其中叙述者在夜晚的街道上骑着一个男人。彩蛋在于材质：雕像由分层堆叠的水平截面组成，如同一个故障的3D模型——从一个角度看是完整的，从另一个角度看则是碎片化的。就像卡夫卡的每一个故事，只有当你停止试图理解它时，它才完全说得通。在这里站得足够久，布拉格本身就开始感觉像一部卡夫卡小说。它本来就是。`,
  },

  "hasek-memorial": {
    en: `Brave explorer, the Hašek Memorial honours Jaroslav Hašek — the most gloriously disreputable writer in Czech history, author of The Good Soldier Švejk, the greatest anti-war novel ever written, and a man who lived his entire life as performance art. Hašek founded a fake political party as a joke, was arrested by both the Austro-Hungarian and Russian armies, joined the Bolsheviks for a while, ran a dog-selling scam, and published his novel in instalments from a pub. Unlock the Easter egg in the memorial's location: the small plaque and statue are in Žižkov — the working-class quarter Hašek himself lived in and loved, a neighbourhood still famous for having more pubs per capita than anywhere else in Prague. Hašek would have wanted to be remembered near a bar. He is. Pop in for a beer in his honour and keep moving.`,
    cz: `Odvážný průzkumníku, Haškovský pomník uctívá Jaroslava Haška — nejslavněji neseriózního spisovatele v české historii, autora Osudy dobrého vojáka Švejka, největšího protiválečného románu, který byl kdy napsán, a muže, který celý svůj život žil jako performance art. Hašek založil falešnou politickou stranu jako vtip, byl zatčen jak austro-uherskou, tak ruskou armádou, chvíli se přidal k bolševikům, provozoval podvod s prodejem psů a vydával svůj román na pokračování z hospody. Odemkni easter egg v umístění pomníku: malá plaketa a socha jsou na Žižkově — dělnické čtvrti, v níž Hašek sám žil a miloval ji, čtvrti stále proslulé nejvyšší hustotou hospod na obyvatele v celé Praze. Hašek by chtěl být vzpomínán u baru. Je. Dej si pivo na jeho počest a jdi dál.`,
    zh: `勇敢的探险家，哈谢克纪念碑是为捷克历史上最光荣的无赖作家雅罗斯拉夫·哈谢克而设——他是《好兵帅克》的作者，这是有史以来最伟大的反战小说，而他本人则将整个生命活成了一场行为艺术。哈谢克曾以玩笑方式创立了一个假政党，先后被奥匈帝国和俄罗斯军队逮捕，短暂加入了布尔什维克，经营过一个卖狗骗局，并在一家酒吧里以连载方式出版了他的小说。解锁隐藏在纪念碑位置中的彩蛋：这块小牌匾和雕像位于日什科夫——哈谢克本人居住且深爱的工人阶级街区，这个街区至今以布拉格人均酒吧密度最高而闻名。哈谢克会希望自己被铭记于一家酒吧旁边。他确实是。为了纪念他，进去喝一杯啤酒，然后继续前行。`,
  },

  "prague-planetarium": {
    en: `Brave explorer, Prague Planetarium in Stromovka Park is the largest planetarium in the Czech Republic and one of the most beloved quest zones for citizens who never appear on tourist maps. Built in 1960 during the space-race era, its main dome projects the night sky as it appears from Prague with scholarly precision — 5,000 stars, the Milky Way, the planets in their correct positions, the whole celestial dungeon laid out above your reclining head. Unlock the Easter egg in its Cold War heritage: the planetarium was built partly as a propaganda tool to demonstrate Soviet scientific achievement, but the astronomers who staffed it treated it as a genuine research institution and quietly published work that contradicted official cosmological doctrine. Science outlasted the ideology that funded it. The current star projector is a Zeiss model that has been in continuous use since 1960. It has shown the same stars to three generations of Prague children.`,
    cz: `Odvážný průzkumníku, Pražské planetárium ve Stromovce je největším planetáriem v České republice a jednou z nejoblíbenějších quest zón pro občany, kteří se nikdy neobjevují na turistických mapách. Postavené v roce 1960 v éře vesmírného závodu, jeho hlavní kupole promítá noční oblohu tak, jak se jeví z Prahy s vědeckou přesností — 5 000 hvězd, Mléčná dráha, planety ve správných polohách, celý nebeský dungeon rozložený nad tvou nakloněnou hlavou. Odemkni easter egg v jeho dědictví studené války: planetárium bylo postaveno částečně jako propagandistický nástroj k demonstraci sovětských vědeckých úspěchů, ale astronomové, kteří ho obsazovali, s ním zacházeli jako se skutečnou výzkumnou institucí a tiše publikovali práce, které odporovaly oficiální kosmologické doktríně. Věda přežila ideologii, která ji financovala. Současný hvězdný projektor je model Zeiss, který je v nepřetržitém provozu od roku 1960. Ukázal stejné hvězdy třem generacím pražských dětí.`,
    zh: `勇敢的探险家，斯特罗莫夫卡公园里的布拉格天文馆是捷克共和国最大的天文馆，也是从未出现在旅游地图上的市民们最钟爱的任务区之一。建于1960年太空竞赛时代，其主穹顶以学术精准度投影出从布拉格所见的夜空——5000颗星星、银河、处于正确位置的行星，整个天体地牢铺展在你仰卧的头顶之上。解锁其冷战遗产中的彩蛋：天文馆的建造部分是作为展示苏联科学成就的宣传工具，但驻守其中的天文学家将其视为真正的研究机构，悄悄发表了与官方宇宙学教条相矛盾的研究成果。科学比资助它的意识形态活得更久。当前的星空投影仪是一台自1960年起持续使用的蔡司型号。它已向三代布拉格儿童展示了同样的星空。`,
  },

  "old-royal-palace": {
    en: `Brave explorer, the Old Royal Palace inside Prague Castle is where Bohemian history was literally defenestrated — three times. The famous Vladislav Hall, completed in 1502, is so vast that knights once held jousting tournaments on horseback inside it. The hall's Late Gothic vaulting fans across the ceiling in impossible curves that architects still study in disbelief. Unlock the Easter egg: in 1618, Protestant noblemen threw three Catholic royal governors out of this building's windows — the Second Defenestration of Prague that triggered the Thirty Years War. The Catholics claimed the men survived because angels caught them. Protestants noted they landed in a pile of manure. The 30-metre fall produced two competing miracle stories that shaped European history. Politics have always been messy here.`,
    cz: `Odvážný průzkumníku, Starý královský palác uvnitř Pražského hradu je místem, kde byla česká historie doslova defenestrována — třikrát. Proslulý Vladislavský sál, dokončený v roce 1502, je tak rozlehlý, že uvnitř kdysi probíhaly rytířské turnaje na koních. Pozdně gotická klenba sálu se prostírá stropem v nemožných křivkách, které architekti stále studují s nedůvěrou. Odemkni easter egg: v roce 1618 protestanští šlechtici vyhodili tři katolické královské místodržitele z oken této budovy — Druhá pražská defenestrace, která spustila třicetiletou válku. Katolíci tvrdili, že muži přežili, protože je chytili andělé. Protestanti poznamenali, že dopadli na hromadu hnoje. Pád z 30 metrů vyvolal dva konkurenční příběhy o zázraku, které formovaly evropské dějiny. Politika zde byla vždy chaotická.`,
    zh: `勇敢的探险家，布拉格城堡内的旧皇宫是波西米亚历史被字面意义上"抛出窗外"的地方——这种事发生了三次。完工于1502年的弗拉迪斯拉夫大厅如此宽阔，骑士们曾在厅内骑马进行比武竞技。大厅的晚期哥特式拱顶以不可思议的曲线横跨天花板，至今仍令建筑师们叹为观止。解锁彩蛋：1618年，新教贵族将三位天主教皇家总督从这座建筑的窗户中扔出——这就是引发三十年战争的布拉格第二次掷出窗外事件。天主教徒声称这些人幸存是因为天使接住了他们；新教徒则指出他们落在了一堆粪肥上。从30米高处坠落产生了两个相互竞争的奇迹故事，这些故事塑造了欧洲历史。这里的政治历来如此混乱。`,
  },

  "st-vitus-cathedral": {
    en: `Brave explorer, St. Vitus Cathedral looms above Prague Castle like a final dungeon tower — and it took 600 years to build, completed only in 1929. Unlock its ancient secret: the cathedral holds the Crown Jewels of Bohemia in a chamber sealed by seven locks, each key held by a different official. No single person can open it alone. Hidden deeper still, the Gothic chapel of St. Wenceslas is lined with 1,345 semi-precious stones embedded directly into the plaster walls — an Easter egg most pilgrims miss entirely. The patron saint's skull resides within, still wearing the helmet of a warrior-king. Enter, brave soul, and let the stained glass burn its legends into your eyes.`,
    cz: `Odvážný průzkumníku, Katedrála sv. Víta se tyčí nad Pražským hradem jako věž finálního dungeonu — a její stavba trvala 600 let, dokončena byla až v roce 1929. Odemkni její starověké tajemství: katedrála ukrývá Českou korunu ve světnici uzavřené sedmi zámky, přičemž každý klíč drží jiný úředník. Nikdo ji nemůže otevřít sám. Ještě hlouběji skryta, gotická kaple sv. Václava je vyložena 1 345 polodrahokamy přímo vloženými do omítky stěn — easter egg, který většina poutníků zcela přehlédne. Lebka patrona světce zde sídlí, stále ozdobena přilbou válečného krále. Vstup, odvážná duše, a nech vitrážová okna vypálit jejich legendy do tvých očí.`,
    zh: `勇敢的探险家，圣维特大教堂如同最终副本的高塔般耸立于布拉格城堡之上——它花了600年才建成，直到1929年才竣工。解锁其古老的秘密：大教堂将波西米亚的皇冠珠宝存放在一个由七把锁封闭的房间里，每把钥匙由不同的官员持有。没有任何一个人能独自打开它。更深处隐藏着圣瓦茨拉夫哥特式礼拜堂，其墙壁上直接嵌入了1345块半宝石——这是大多数朝圣者完全错过的彩蛋。守护圣人的头骨就安放在此，仍戴着战士王的头盔。进入吧，勇敢的灵魂，让彩色玻璃将其传说烙印在你的眼中。`,
  },

  "vysehrad": {
    en: `Brave explorer, Vyšehrad rises above the Vltava as Prague's forgotten first capital — older than Prague Castle itself, draped in myth older than memory. According to legend, the Slavic prophetess Libuše stood on this very cliff and proclaimed: "I see a city whose glory will touch the stars." Unlock the Easter egg buried in the cemetery: Vyšehrad's graveyard holds the remains of Dvořák, Smetana, Mucha, and over 600 Czech legends — yet its most visited tomb belongs to a poet whose monument has been vandalized so many times the city gave up replacing the ornament. Ancient walls, a Romanesque rotunda, and underground casemates await the brave explorer who dares leave the tourist trail.`,
    cz: `Odvážný průzkumníku, Vyšehrad se zvedá nad Vltavou jako zapomenuté první hlavní město Prahy — starší než samotný Pražský hrad, halený mýty staršími než paměť. Podle legendy stála slovanská věštkyně Libuše na tomto útesu a prohlásila: "Vidím město, jehož sláva se dotkne hvězd." Odemkni easter egg pohřbený na hřbitově: Vyšehradský hřbitov ukrývá ostatky Dvořáka, Smetany, Muchy a přes 600 českých legend — přesto jeho nejnavštěvovanější hrobka patří básníkovi, jehož pomník byl vandalizován tolikrát, že město vzdalo výměnu ozdoby. Starověké hradby, románská rotunda a podzemní kasematy čekají na odvážného průzkumníka, který se odváží opustit turistickou trasu.`,
    zh: `勇敢的探险家，维谢赫拉德屹立于伏尔塔瓦河上方，是布拉格被遗忘的第一座首都——比布拉格城堡更古老，笼罩在比记忆更古老的神话之中。据传说，斯拉夫女先知利布谢就站在这悬崖上宣告："我看见一座城市，其荣耀将触及星辰。"解锁埋藏在墓地里的彩蛋：维谢赫拉德墓地安葬着德沃夏克、斯美塔那、慕夏及600多位捷克传奇人物——然而其访问量最高的墓碑属于一位诗人，他的纪念碑被破坏了太多次，城市已放弃更换装饰。古老的城墙、罗马式圆形教堂和地下炮台，等待着敢于离开旅游路线的勇敢探险家。`,
  },

  "josefov": {
    en: `Brave explorer, you have entered Josefov — Prague's ancient Jewish Quarter, a labyrinth of synagogues and sorrow compressed into six city blocks. For centuries, the community was confined here by royal decree, yet they transformed confinement into legend. Unlock the ultimate Easter egg: the Old-New Synagogue, built around 1270, holds in its attic the remains of the Golem — a clay giant animated by the mystic Rabbi Loew to protect his people. The city never dared demolish the attic to check. Six synagogues survived the Nazi occupation only because the Reich planned a museum of an extinct race here. Walk these cobblestones, brave soul, and feel the weight of defiant survival beneath every step.`,
    cz: `Odvážný průzkumníku, vstoupil jsi do Josefova — starověké židovské čtvrti Prahy, labyrintu synagog a smutku stlačeného do šesti městských bloků. Po staletí byla komunita zde uvězněna královským dekretem, přesto přeměnila uvěznění v legendu. Odemkni ultimate easter egg: Staronová synagoga, postavená kolem roku 1270, ukrývá na svém půdě ostatky Golema — hliněného obra oživlého mystickým rabínem Löwem na ochranu svého lidu. Město se nikdy neodvážilo půdu strhnout, aby to ověřilo. Šest synagog přežilo nacistickou okupaci pouze proto, že Říše zde plánovala muzeum vyhynulé rasy. Procházej tyto dlažební kostky, odvážná duše, a pocit tíhy vzdorného přežití pod každým krokem.`,
    zh: `勇敢的探险家，你已进入约瑟夫城——布拉格古老的犹太区，一个压缩在六个城市街区内的会堂与悲伤的迷宫。几个世纪以来，这个社区被皇家法令限制于此，但他们将禁锢转化为了传说。解锁终极彩蛋：建于约1270年的旧新会堂，其阁楼中保存着魔像的遗骸——一个由神秘的拉比洛维赋予生命以保护其人民的泥土巨人。城市从未敢拆除阁楼去核实。六座会堂在纳粹占领中幸存，仅因为帝国计划在此建立一个关于灭绝种族的博物馆。踏着这些鹅卵石，勇敢的灵魂，感受每一步下方顽强生存的重量。`,
  },

  "old-jewish-cemetery": {
    en: `Brave explorer, you stand at the Old Jewish Cemetery — one of the most haunting quest zones in all of Prague. Between 1439 and 1787, over 100,000 souls were buried here in layers twelve deep, because the community was forbidden from expanding beyond these walls. The gravestones, tilted and stacked like broken pixels, mark only the topmost layer of a vast underground archive of history. Unlock the hidden truth: the tombstone of Rabbi Loew, creator of the legendary Golem, is here — and Prague tradition holds that leaving a small stone or a wish on paper grants mysterious protection. Every stone is a save file. Every layer a deleted chapter. Tread carefully, brave explorer — the dead are stacked beneath you.`,
    cz: `Odvážný průzkumníku, stojíš na Starém židovském hřbitově — jedné z nejstrašidelnějších quest zón v celé Praze. Mezi lety 1439 a 1787 bylo zde pohřbeno přes 100 000 duší ve dvanácti vrstvách, protože komunita nesměla rozšiřovat prostor za tyto zdi. Náhrobky, nakloněné a naskládané jako rozbité pixely, označují jen nejvrchnější vrstvu obrovského podzemního archivu dějin. Odemkni skrytou pravdu: náhrobek rabína Löwa, tvůrce legendárního Golema, je zde — a pražská tradice praví, že položení malého kamene nebo papíru s přáním přináší záhadnou ochranu. Každý kámen je save file. Každá vrstva smazaná kapitola. Kráčej opatrně, odvážný průzkumníku — mrtví jsou naskládáni pod tebou.`,
    zh: `勇敢的探险家，你站在旧犹太墓地——布拉格所有任务区中最令人毛骨悚然的地方之一。1439年至1787年间，超过10万个灵魂被埋葬在这里，深达十二层，因为这个社区被禁止扩展到这些围墙之外。墓碑倾斜堆叠，如同破碎的像素，仅标记着这座庞大地下历史档案馆最顶层的一层。解锁隐藏的真相：传说中魔像创造者拉比洛维的墓碑就在这里——布拉格传统认为，在上面放置一块小石头或一张许愿纸，可以获得神秘的保护。每块石头都是一个存档点，每一层都是一个被删除的章节。小心踏步，勇敢的探险家——逝者就叠压在你脚下。`,
  },

  "st-nicholas-mala-strana": {
    en: `Brave explorer, St. Nicholas Church in Malá Strana is the Baroque final boss of Prague's skyline — its green copper dome and twin towers dominate the Lesser Town like a triumphant endgame cutscene. Built by the Jesuits between 1703 and 1761, it replaced a smaller Gothic church and consumed the surrounding neighbourhood in the process. Unlock the Easter egg concealed in its ceiling: the nave fresco by Johann Lukas Kracker is one of the largest ceiling paintings in Europe, covering 1,500 square metres. During the Cold War, the communist secret police used the church tower as a surveillance post to spy on the nearby embassies. The KGB literally watched the West from inside a Baroque masterpiece. Enter and look up, brave explorer.`,
    cz: `Odvážný průzkumníku, Chrám sv. Mikuláše na Malé Straně je barokní finální boss pražského panoramatu — jeho zelená měděná kupole a dvojčata věží dominují Malé Straně jako triumfální závěrečná scéna hry. Jezuité ho stavěli v letech 1703 až 1761 a nahradil menší gotický kostel, přičemž pohltil okolní čtvrť. Odemkni easter egg ukrytý v jeho stropě: freska lodě od Johanna Lukase Krackera je jednou z největších stropních maleb v Evropě a pokrývá 1 500 čtverečních metrů. Během studené války využívala komunistická tajná policie věž kostela jako pozorovací stanoviště ke sledování okolních velvyslanectví. KGB doslova sledovalo Západ zevnitř barokního mistrovského díla. Vstup a podívej se nahoru, odvážný průzkumníku.`,
    zh: `勇敢的探险家，小城区圣尼古拉斯教堂是布拉格天际线上的巴洛克式最终Boss——其绿色铜制穹顶和双塔如同游戏胜利的终场动画般主宰着小城区。耶稣会士于1703年至1761年间建造了它，取代了一座更小的哥特式教堂，并在此过程中吞并了周围的街区。解锁隐藏在天花板中的彩蛋：由约翰·卢卡斯·克拉克尔创作的中殿壁画是欧洲最大的天花板画作之一，覆盖面积达1500平方米。冷战期间，共产党秘密警察将教堂塔楼用作监视站，监视附近的各国大使馆。克格勃实际上是从一座巴洛克杰作内部监视西方的。进入并抬头仰望，勇敢的探险家。`,
  },

  "loreta-prague": {
    en: `Brave explorer, Loreta Prague is one of the most legendary pilgrimage quest zones in Central Europe — a Baroque sanctuary built around a replica of the Holy House of Nazareth, the supposed birthplace of the Virgin Mary. Twenty such replicas exist across Europe; Prague's version is the most decorated. Unlock the Easter egg locked in the treasury: the Diamond Monstrance, crafted in 1699, is studded with 6,222 diamonds arranged to look like sunbeams radiating from the host. It weighs twelve kilograms of pure legend. The carillon tower plays "We Greet Thee a Thousand Times" every hour on twenty-seven bells — a tune that has echoed over Prague's rooftops without interruption since 1694. This is an audio dungeon. Listen before you enter.`,
    cz: `Odvážný průzkumníku, Pražská Loreta je jednou z nejlegendárnějších poutních quest zón ve střední Evropě — barokní svatyně postavená kolem repliky Svaté chýše z Nazaretu, předpokládaného rodiště Panny Marie. Dvacet takových replik existuje po celé Evropě; pražská verze je nejzdobenější. Odemkni easter egg uzamčený v pokladnici: Diamantová monstrance, vytvořená v roce 1699, je posázena 6 222 diamanty uspořádanými tak, aby připomínaly sluneční paprsky vyzařující z hostie. Váží dvanáct kilogramů ryzí legendy. Zvonicová věž hraje "Tisíckrát pozdravujeme tebe" každou hodinu na dvaceti sedmi zvonech — melodie, která zní nad pražskými střechami bez přerušení od roku 1694. Toto je audio dungeon. Poslouchej, než vstoupíš.`,
    zh: `勇敢的探险家，布拉格洛雷塔是中欧最传奇的朝圣任务区之一——这座巴洛克圣地围绕着拿撒勒圣屋的复制品而建，据说那是圣母玛利亚的出生地。全欧洲存在二十处这样的复制品，布拉格的版本是装饰最精美的一处。解锁锁在宝库中的彩蛋：制作于1699年的钻石圣体光，镶嵌着6222颗钻石，排列成从圣体向外放射的阳光形状。它重达十二公斤，是纯粹的传奇。钟楼每小时用二十七口钟演奏"我们千次问候你"——这首曲调自1694年起便不间断地回荡在布拉格的屋顶之上。这是一个音频地牢。在你进入之前，先聆听。`,
  },

  "powder-tower": {
    en: `Brave explorer, the Powder Tower is Prague's most misnamed landmark — built in 1475 as a ceremonial gate for royal processions, it became a gunpowder magazine only because the city needed somewhere to store the stuff and the tower sat conveniently empty. Unlock its Easter egg chiselled into the stonework: the tower's Gothic decoration was left unfinished when King Vladislaus II abandoned Prague for Budějovice in 1483, and it was never resumed. For nearly 400 years the tower stood bare until a Neo-Gothic architect completed it in 1886 — blending medieval original with Victorian invention so seamlessly that experts still argue about which carvings are authentic. Stand at its base and try to spot the joins. This gateway marks the start of the Royal Route quest line.`,
    cz: `Odvážný průzkumníku, Prašná brána je nejšpatněji pojmenovanou památkou Prahy — postavena v roce 1475 jako ceremonielní brána pro královské průvody, stala se skladem střelného prachu jen proto, že město potřebovalo místo pro uskladnění a věž seděla vhodně prázdná. Odemkni její easter egg vytesaný do zdiva: gotická výzdoba věže zůstala nedokončena, když král Vladislav II. opustil Prahu pro Budějovice v roce 1483, a nebyla nikdy obnovena. Téměř 400 let věž stála holá, dokud ji neogotický architekt nedokončil v roce 1886 — prolínaje středověký originál s viktoriánskou invencí tak bezešvě, že experti stále diskutují o tom, které řezby jsou autentické. Postoj u její základny a zkus najít spoje. Tato brána označuje začátek quest linie Královské cesty.`,
    zh: `勇敢的探险家，火药塔是布拉格命名最不当的地标——建于1475年，原为皇家游行队伍的礼仪城门，后来之所以成为火药库，仅仅是因为城市需要地方存放火药，而这座塔恰好方便地空着。解锁凿刻在砖石中的彩蛋：当弗拉迪斯劳斯二世国王于1483年离开布拉格前往布杰约维采时，塔的哥特式装饰未能完成，此后再未续建。近400年来，这座塔一直矗立着，光秃秃的，直到1886年一位新哥特风格的建筑师将其完成——将中世纪原作与维多利亚时代的创意如此无缝地融合，以至于专家们至今仍在争论哪些雕刻是真品。站在其底部，试着找出接缝所在。这座城门标志着皇家之路任务线的起点。`,
  },

  "municipal-house": {
    en: `Brave explorer, the Municipal House is Prague's most opulent quest reward — an Art Nouveau palace completed in 1912 on the exact site of the Royal Court where Bohemian kings once lived. Every surface is a boss-level detail: mosaics, stained glass, wrought iron, and painted ceilings commissioned from the greatest Czech artists of the era, including Alfons Mucha. Unlock the Easter egg hidden in plain sight at the entrance: the mosaic above the main portal reads "Homage to Prague" and was designed by Karel Špillar — but the allegorical figures flanking it represent Humiliation and Revival, a coded political message the Austro-Hungarian censors somehow missed. The Smetana Hall inside hosted the premiere of an independent Czechoslovakia in 1918. Every banquet room is a different aesthetic dungeon. Explore all of them.`,
    cz: `Odvážný průzkumníku, Obecní dům je nejhonosnější quest odměnou Prahy — secesní palác dokončený v roce 1912 na přesném místě Královského dvora, kde kdysi žili čeští králové. Každý povrch je detail hodný finálního bosse: mozaiky, vitráže, kované železo a malované stropy zadané největším českým umělcům té doby, včetně Alfonse Muchy. Odemkni easter egg skrytý na očích u vchodu: mozaika nad hlavním portálem nese nápis "Hold Praze" a navrhoval ji Karel Špillar — ale alegorické figury po jejích stranách představují Pokoření a Obrodu, zakódované politické poselství, které austro-uherští cenzoři nějak přehlédli. Smetanova síň uvnitř hostila premiéru nezávislého Československa v roce 1918. Každý sál je jiný estetický dungeon. Prozkoumej je všechny.`,
    zh: `勇敢的探险家，市政厅是布拉格最华丽的任务奖励——这座新艺术风格的宫殿于1912年竣工，建于波西米亚国王曾经居住的皇家宫廷的确切遗址之上。每一个表面都是最终Boss级别的细节：马赛克、彩色玻璃、锻铁和彩绘天花板，均由那个时代最伟大的捷克艺术家创作，包括阿尔丰斯·慕夏。解锁入口处隐藏在明处的彩蛋：主门廊上方的马赛克写着"向布拉格致敬"，由卡雷尔·什皮拉尔设计——但两侧的寓言人物代表着屈辱与复兴，这是一条不知为何被奥匈帝国审查员遗漏的隐晦政治信息。内部的斯美塔那音乐厅于1918年举办了独立捷克斯洛伐克的首次演出。每个宴会厅都是一个不同的美学地牢。逐一探索它们。`,
  },

  "old-town-hall": {
    en: `Brave explorer, Old Town Hall is not one building but a cluster of five medieval houses fused together across five centuries, each absorbed by the growing civic administration like a slow bureaucratic dungeon expansion. The tower offers the best view of Old Town Square, but the real quest reward is underground: the hall sits atop a preserved Gothic cellar complex you can walk through, one full storey below street level — the swallowed remains of the pre-flood medieval city. Unlock the Easter egg visible from outside: the hall's eastern wing was blown up by the Nazis on May 8th, 1945, the last day of the war. Rather than rebuild it, Prague left the scar deliberately — the gap in the roofline is a permanent monument to the last act of occupation. History as architecture.`,
    cz: `Odvážný průzkumníku, Staroměstská radnice není jednou budovou, ale shlukemm pěti středověkých domů sloučených po pět staletí, každý pohlcen rostoucí městskou správou jako pomalá byrokratická dungeon expanze. Věž nabízí nejlepší výhled na Staroměstské náměstí, ale skutečná quest odměna je pod zemí: radnice stojí nad zachovaným gotickým sklep-komplexem, jímž můžeš procházet, celé patro pod úrovní ulice — pohlcené zbytky předpovodňového středověkého města. Odemkni easter egg viditelný zvenčí: východní křídlo radnice bylo nacisty vyhodeno do vzduchu 8. května 1945, poslední den války. Místo přestavby Praha záměrně nechala jizvu — mezera v linii střechy je trvalým pomníkem posledního aktu okupace. Historie jako architektura.`,
    zh: `勇敢的探险家，老城市政厅并非一座建筑，而是五栋中世纪房屋在五个世纪间融合而成的建筑群，每一栋都像缓慢的官僚地牢扩张一般被不断壮大的市政机构所吞并。塔楼提供了俯瞰老城广场的最佳视角，但真正的任务奖励在地下：市政厅坐落于一座保存完好的哥特式地窖建筑群之上，你可以在其中穿行，位于街道以下整整一层——被洪水吞没的中世纪城市的遗迹。解锁从外部可见的彩蛋：市政厅的东翼于1945年5月8日，也就是战争最后一天，被纳粹炸毁。布拉格没有重建，而是故意保留了这道伤疤——屋顶轮廓上的缺口，是占领最后一幕的永久纪念碑。历史即建筑。`,
  },

  "tyn-church": {
    en: `Brave explorer, the Church of Our Lady before Týn lurks behind Old Town Square's rooftops like a hidden level revealed only when you know exactly where to look — its twin Gothic towers, topped with golden spires, are perpetually photobombed by the buildings pressed against its facade. Unlock the Easter egg sealed inside: the famous astronomer Tycho Brahe is buried beneath the floor of this church. Brahe lost his nose in a duel and wore a gold-and-silver prosthetic for the rest of his life; his measurements of planetary motion later enabled Kepler to derive the laws of orbital mechanics. A man with a metal nose laid the groundwork for space travel, and he rests here in the dark, beneath the tourists. Look down, brave explorer.`,
    cz: `Odvážný průzkumníku, Chrám Panny Marie před Týnem se schovává za střechami Staroměstského náměstí jako skrytá úroveň odhalená jen tehdy, když přesně víš, kde hledat — jeho dvojčata gotických věží korunovaná zlatými věžičkami jsou trvale přefocena budovami přitisknutými k jeho fasádě. Odemkni easter egg zapečetěný uvnitř: slavný astronom Tycho Brahe je pohřben pod podlahou tohoto kostela. Brahe přišel o nos v souboji a po zbytek života nosil zlatostříbrnou protézu; jeho měření planetárního pohybu později umožnila Keplerovi odvodit zákony orbitální mechaniky. Muž s kovovým nosem položil základy kosmonautiky a odpočívá zde ve tmě, pod turisty. Podívej se dolů, odvážný průzkumníku.`,
    zh: `勇敢的探险家，泰恩圣母教堂藏匿在老城广场的屋顶之后，如同一个只有在你知道确切位置时才会显现的隐藏关卡——其哥特式双塔顶部镶嵌着金色尖顶，却总是被紧贴其正面的建筑遮挡在照片之外。解锁封存在内部的彩蛋：著名天文学家第谷·布拉赫就长眠于这座教堂的地板之下。布拉赫在一场决斗中失去了鼻子，此后余生佩戴着金银假鼻；他对行星运动的测量后来使开普勒得以推导出轨道力学定律。一个戴金属鼻子的人为太空旅行奠定了基础，而他就长眠在这里，在黑暗中，在游客的脚下。低头看，勇敢的探险家。`,
  },

  "mala-strana": {
    en: `Brave explorer, Malá Strana — the Lesser Town — is the most cinematically beautiful quarter in Prague, a Baroque neighbourhood of winding lanes, hidden gardens, and embassies crammed between the castle hill and the river. Film crews have used it as a substitute for every European city in history because its streets have changed so little since 1700. Unlock the Easter egg tucked in the garden network: Malá Strana conceals at least eight secret palace gardens behind its baroque facades, open to the public but completely invisible from the street. The Vrtbovský Garden is the finest — a terraced Baroque hillside with statues so dramatic they make you feel like you have unlocked a secret level that 90% of visitors walk past without ever knowing. Enter the hidden gates.`,
    cz: `Odvážný průzkumníku, Malá Strana je nejfilmovějším čtvrtí Prahy, barokní čtvrť s vinutými uličkami, skrytými zahradami a velvyslanectvími nacpanými mezi hradní kopec a řeku. Filmové štáby ji využívají jako náhradu za každé evropské město v historii, protože její ulice se od roku 1700 téměř nezměnily. Odemkni easter egg ukrytý v síti zahrad: Malá Strana skrývá za svými barokními fasádami nejméně osm tajných palácových zahrad, veřejnosti přístupných, ale z ulice zcela neviditelných. Vrtbovská zahrada je nejkrásnější — terasovitý barokní svah se sochami tak dramatickými, že máš pocit, jako bys odemkl tajnou úroveň, kolem které 90 % návštěvníků projde, aniž by ji kdy tušili. Vstup do skrytých bran.`,
    zh: `勇敢的探险家，小城区是布拉格最具电影感的街区——一个巴洛克风格的街区，蜿蜒的小巷、隐秘的花园，以及夹在城堡山与河流之间的各国大使馆。电影摄制组将其用作欧洲历史上各个城市的替代场景，因为自1700年以来，这里的街道几乎没有改变。解锁隐藏在花园网络中的彩蛋：小城区在其巴洛克式外墙后面隐藏着至少八座秘密宫殿花园，对公众开放，但从街道上完全看不见。弗尔特巴园是其中最精美的——一座阶梯式巴洛克山坡，雕塑戏剧性十足，让你感觉自己解锁了一个90%的游客从旁走过却浑然不知的秘密关卡。穿过那些隐藏的大门吧。`,
  },

  "schwarzenberg-palace": {
    en: `Brave explorer, Schwarzenberg Palace stands at the top of Hradčany Square like a Renaissance fever dream — its entire exterior coated in sgraffito, an elaborate scraping technique that covers every surface with geometric diamond patterns giving the flat stone walls an impossible three-dimensional illusion. Built between 1545 and 1567, it was considered the most fashionable building in Bohemia and launched a Prague-wide sgraffito trend that lasted a century. Unlock the Easter egg hidden in the decoration: the diamond rustication pattern was deliberately designed to make the walls look fortified from a distance while remaining decorative up close — military theatre as architecture. The building now houses the National Gallery's Baroque collection, including battle paintings so enormous they wrap around entire rooms. Enter and get lost in the illusion.`,
    cz: `Odvážný průzkumníku, Schwarzenberský palác stojí na vrcholu Hradčanského náměstí jako renesanční horečný sen — celý jeho exteriér pokryt sgrafitem, propracovanou technikou škrábání, která pokrývá každý povrch geometrickými diamantovými vzory, jež dávají plochým kamenným stěnám nemožnou trojrozměrnou iluzi. Postaven v letech 1545 až 1567, byl považován za nejmodernější budovu v Čechách a spustil celopražský sgraffitový trend trvající století. Odemkni easter egg ukrytý v dekoraci: vzor diamantového bosáže byl záměrně navržen tak, aby stěny vypadaly z dálky opevněné, přičemž zblízka zůstávaly dekorativní — vojenské divadlo jako architektura. Budova nyní ukrývá sbírku baroka Národní galerie, včetně bitevních maleb tak obrovských, že obalují celé místnosti. Vstup a ztrat se v iluzi.`,
    zh: `勇敢的探险家，施瓦岑贝格宫矗立于赫拉德恰尼广场顶部，如同一场文艺复兴式的狂热梦境——其整个外立面覆盖着灰泥刻画装饰，这种精细的刮除技术将每个表面都覆上几何菱形图案，赋予平坦石墙一种不可思议的三维错觉。建于1545年至1567年间，它被认为是波西米亚最时髦的建筑，并引发了持续一个世纪的全布拉格灰泥装饰风潮。解锁隐藏在装饰中的彩蛋：菱形粗面石工图案是刻意设计的，使墙壁从远处看起来像是要塞，而近看则保持装饰性——这是以建筑为媒介的军事戏剧。这座建筑现在收藏着国家美术馆的巴洛克藏品，包括大到将整个房间环绕起来的战争画作。进入，在幻觉中迷失吧。`,
  },

  "golden-lane": {
    en: `Brave explorer, Golden Lane is Prague Castle's most deceptively humble quest zone — a row of tiny, brightly coloured cottages built directly into the castle's defensive walls in the 16th century, originally housing castle guards and later taken over by goldsmiths, hence the name. Unlock the Easter egg hiding in plain sight at house number 22: Franz Kafka rented this tiny blue cottage from his sister between 1916 and 1917 and wrote some of his most important short stories here, hunched under a ceiling so low that a modern adult cannot stand straight. The cottage is now preserved exactly as it was. The entire street feels like a fairy-tale dungeon level — which is precisely why it remains the most-visited part of Prague Castle. Every door hides a different era.`,
    cz: `Odvážný průzkumníku, Zlatá ulička je nejklamně skromnou quest zónou Pražského hradu — řada malých, pestrobarevných domků zabudovaných přímo do obranných zdí hradu v 16. století, původně obývaných hradními strážemi a později zlatníky, odtud název. Odemkni easter egg ukrytý na očích v domě číslo 22: Franz Kafka si pronajal tento maličký modrý domek od své sestry v letech 1916 až 1917 a napsal zde některé ze svých nejdůležitějších povídek, přikrčen pod stropem tak nízkým, že dnešní dospělý člověk nemůže stát rovně. Domek je nyní zachován přesně tak, jak byl. Celá ulice působí jako pohádková dungeon úroveň — a právě proto zůstává nejnavštěvovanější částí Pražského hradu. Za každými dveřmi se skrývá jiná éra.`,
    zh: `勇敢的探险家，黄金巷是布拉格城堡中最具欺骗性的朴素任务区——一排色彩鲜艳的小屋，16世纪时直接建于城堡防御墙内，最初住着城堡卫兵，后来被金匠占据，由此得名。解锁隐藏在22号房子里显而易见的彩蛋：弗朗茨·卡夫卡于1916年至1917年间从他姐姐那里租用了这间小蓝屋，在这里佝偻着身子——天花板低到现代成年人无法直立——写下了一些最重要的短篇故事。这间小屋如今保持着原样。整条街道感觉像一个童话地牢关卡——这正是它至今仍是布拉格城堡访问量最高的区域的原因。每扇门后都隐藏着一个不同的时代。`,
  },

  "dalibor-tower": {
    en: `Brave explorer, Dalibor Tower is Prague Castle's grimly legendary dungeon — a round Gothic tower built in 1496 that served as the castle's prison for the next three centuries. Its most famous prisoner, the knight Dalibor of Kozojedy, was locked here in 1498 for sheltering rebellious serfs. According to legend, Dalibor taught himself to play the violin in his cell and his playing was so beautiful that citizens gathered outside the tower walls to listen and lowered food to him on ropes in gratitude. The authorities found this embarrassing and executed him promptly. Unlock the Easter egg in the building's legacy: Dalibor's story directly inspired Smetana's opera of the same name, making this tower the origin point of a Czech national opera. The dungeon produced art. Prague will always find a way.`,
    cz: `Odvážný průzkumníku, Daliborka je ponuře legendárním dungeonem Pražského hradu — gotická kulatá věž postavená v roce 1496, která sloužila jako hradní vězení po další tři staletí. Její nejslavnější vězeň, rytíř Dalibor z Kozojed, byl sem uvězněn v roce 1498 za ukrývání vzpurných nevolníků. Podle legendy se Dalibor naučil hrát na housle ve své cele a jeho hra byla tak krásná, že se obyvatelé shromažďovali u zdí věže, aby naslouchali, a vděčně mu spouštěli jídlo na lanech. Úřady to považovaly za trapné a rychle ho popravily. Odemkni easter egg v odkazu budovy: Daliborův příběh přímo inspiroval Smetanovu stejnojmennou operu, čímž z této věže učinil výchozí bod české národní opery. Dungeon produkoval umění. Praha vždy najde způsob.`,
    zh: `勇敢的探险家，达利博尔塔是布拉格城堡阴森传奇的地牢——一座建于1496年的圆形哥特式塔楼，此后三个世纪一直充当城堡的监狱。其最著名的囚犯，科佐耶德的骑士达利博尔，因庇护反叛农奴于1498年被关押于此。据传说，达利博尔在牢房中自学小提琴，其琴声如此美妙，以至于市民们聚集在塔墙外聆听，并用绳子为他放下食物以示感谢。当局对此感到难堪，随即将他处决。解锁埋藏在建筑历史中的彩蛋：达利博尔的故事直接启发了斯美塔那创作了同名歌剧，使这座塔楼成为捷克国家歌剧的发源地。地牢孕育了艺术。布拉格总能找到出路。`,
  },

  "st-georges-basilica": {
    en: `Brave explorer, St. George's Basilica inside Prague Castle is the oldest surviving church building in Prague — a Romanesque fortress-chapel consecrated in 920 AD, predating the Gothic cathedral next door by four centuries. Its stark white twin towers and austere interior are the deliberate opposite of Baroque excess: no gold, no frescoes, no drama — just stone, silence, and eleven hundred years of continuous use. Unlock the Easter egg sealed in a side chapel: the tomb of St. Ludmila, the first Czech Christian martyr, is here — grandmother of St. Wenceslas, strangled with her own veil by her daughter-in-law in 921 AD in a dynastic power struggle. The veil is gone. The tomb remains. Bohemian politics have always been personal. Stand in the oldest space in Prague and listen to what the stone remembers.`,
    cz: `Odvážný průzkumníku, Bazilika sv. Jiří uvnitř Pražského hradu je nejstarší dochovanou církevní stavbou v Praze — románská pevnostní kaple posvěcená v roce 920 n. l., předcházející gotické katedrále vedl o čtyři staletí. Její strohé bílé dvojité věže a asketický interiér jsou záměrným opakem barokního přebytku: žádné zlato, žádné fresky, žádné drama — jen kámen, ticho a jedenáct set let nepřetržitého užívání. Odemkni easter egg zapečetěný v boční kapli: zde je hrobka sv. Ludmily, první české křesťanské mučednice — babičky sv. Václava, uškrcené vlastním závojem snachou v roce 921 n. l. v dynastickém mocenském boji. Závoj je pryč. Hrobka zůstává. Česká politika byla vždy osobní. Postav se na nejstarším místě v Praze a naslouchej, co si kámen pamatuje.`,
    zh: `勇敢的探险家，布拉格城堡内的圣乔治圣殿是布拉格现存最古老的教堂建筑——一座于公元920年祝圣的罗马式要塞礼拜堂，比旁边的哥特式大教堂早了四个世纪。其朴素的白色双塔和简约的内部空间，是对巴洛克过度装饰的刻意对立：没有黄金，没有壁画，没有戏剧——只有石头、寂静和一千一百年的连续使用。解锁封存在侧礼拜堂中的彩蛋：这里安葬着圣鲁德米拉——捷克第一位基督教殉道者的墓，她是圣瓦茨拉夫的祖母，于公元921年在一场王朝权力斗争中被儿媳用自己的面纱勒死。面纱已不复存在，墓碑却留存至今。波西米亚的政治历来都是私人恩怨。站在布拉格最古老的空间里，聆听石头所铭记的一切。`,
  },

  "klementinum": {
    en: `Brave explorer, the Klementinum is Prague's most underestimated quest zone — a Jesuit complex so vast it is the second largest building in the city, after the castle. Built to reclaim Prague for Catholicism after the Reformation, it now houses the National Library with six million volumes. Unlock the legendary Easter egg in the Baroque Library Hall: the room's ceiling is painted with an elaborate trompe-l'oeil fresco — a flat ceiling made to look like a soaring dome through perspective illusion. Astronomical instruments and ancient globes line its gallery. The neighbouring Astronomical Tower held daily weather observations from 1775 onwards, making it the longest unbroken meteorological record in Central Europe. Every morning the librarian still climbs the tower to read the instruments. This is a living dungeon.`,
    cz: `Odvážný průzkumníku, Klementinum je nejpodceňovanější quest zónou Prahy — jezuitský komplex tak rozsáhlý, že je druhou největší budovou ve městě po hradě. Postaveno k znovuzískání Prahy pro katolicismus po reformaci, dnes ukrývá Národní knihovnu se šesti miliony svazků. Odemkni legendární easter egg v Barokní knihovní síni: strop místnosti je pokryt propracovanou trompe-l'oeil freskou — plochý strop, který perspektivní iluzí vypadá jako vznešená kupole. Astronomické přístroje a staré glóby lemují galerii. Sousední Astronomická věž uchovávala denní meteorologická pozorování od roku 1775, čímž se stala nejdelším nepřerušeným meteorologickým záznamem ve střední Evropě. Každé ráno knihovník stále stoupá na věž, aby četl přístroje. Toto je živý dungeon.`,
    zh: `勇敢的探险家，克莱门提努姆是布拉格最被低估的任务区——这座耶稣会建筑群规模之大，使其成为城市中仅次于城堡的第二大建筑。它的建造是为了在宗教改革后将布拉格重新归入天主教的怀抱，如今收藏着国家图书馆的六百万册藏书。解锁巴洛克图书馆大厅中的传奇彩蛋：房间天花板上绘有精心设计的错视画壁画——通过透视错觉，一个平坦的天花板被呈现为高耸的穹顶。天文仪器和古老地球仪陈列在回廊之中。毗邻的天文塔自1775年起记录每日气象观测数据，成为中欧持续时间最长的不间断气象记录。每天早晨，图书管理员仍然攀登上塔楼读取仪器数据。这是一个活着的地牢。`,
  },

  "vysehrad-cemetery": {
    en: `Brave explorer, Vyšehrad Cemetery is the most elite graveyard quest zone in Central Europe — an exclusive final resting place reserved by law for Czech citizens who have made an extraordinary contribution to the nation. Over 600 legends lie here: composers Dvořák and Smetana, painter Mucha, poet Neruda, sculptor Myslbek. Unlock the Easter egg embedded in the cemetery's design: at its centre stands the Slavín tomb — a collective mausoleum holding over 50 cultural figures under one roof, topped by a winged Victory figure so dramatic it makes individual tombstones look like tutorial content. Dvořák's tomb is covered in tiny offerings left by pilgrims — sheet music scraps, flowers, concert tickets. The dead here are not silent. They are the entire soundtrack of Czech identity.`,
    cz: `Odvážný průzkumníku, Vyšehradský hřbitov je nejelitnější hřbitovní quest zónou ve střední Evropě — exkluzivní poslední odpočiviště vyhrazené zákonem pro české občany, kteří přispěli národu mimořádným způsobem. Leží zde přes 600 legend: skladatelé Dvořák a Smetana, malíř Mucha, básník Neruda, sochař Myslbek. Odemkni easter egg zabudovaný do designu hřbitova: v jeho centru stojí hrobka Slavín — kolektivní mauzoleum ukrývající přes 50 kulturních osobností pod jednou střechou, korunované postavou okřídleného vítězství tak dramatickou, že individuální náhrobky vypadají jako tutoriální obsah. Dvořákův hrob je pokryt malými obětinami zanechanými poutníky — útržky notového záznamu, květinami, vstupenkami na koncerty. Mrtví zde nejsou tiší. Jsou celým soundtrackem české identity.`,
    zh: `勇敢的探险家，维谢赫拉德墓地是中欧最精英的墓地任务区——一处依法专为对国家做出卓越贡献的捷克公民保留的尊贵安息之地。这里长眠着600多位传奇人物：作曲家德沃夏克和斯美塔那、画家慕夏、诗人聂鲁达、雕塑家米斯勒贝克。解锁嵌入墓地设计中的彩蛋：其中心矗立着斯拉文墓——一座集体陵墓，在一个屋顶下安葬着50多位文化名人，顶部是一个有翼胜利女神像，其戏剧性之强，使个人墓碑看起来如同新手教程内容。德沃夏克的墓碑上覆盖着朝圣者留下的小小供品——乐谱碎片、鲜花、音乐会门票。这里的逝者并不沉默。他们是捷克民族认同的完整配乐。`,
  },

  "wenceslas-square": {
    en: `Brave explorer, Wenceslas Square is not a square at all — it is a 750-metre boulevard, the grand questboard where Czech history rewrites itself every generation. This legendary avenue witnessed the birth of Czechoslovakia in 1918, the Nazi occupation parade of 1939, the Soviet tanks of 1968, and the Velvet Revolution of 1989, all from the same cobblestones. Unlock the Easter egg hidden in the National Museum facade: the building was riddled with bullet holes from Soviet tanks in 1968 and the communists patched them with lighter stone — look closely and you can still count the scars. The equestrian statue of St. Wenceslas at the top marks the final rally point for every revolution. This is not tourism; it is a history dungeon.`,
    cz: `Odvážný průzkumníku, Václavské náměstí není vůbec náměstím — je to 750metrový bulvár, velký questboard, kde se česká historie přepisuje každou generaci. Tato legendární třída byla svědkem vzniku Československa v roce 1918, průvodu nacistické okupace v roce 1939, sovětských tanků v roce 1968 a Sametové revoluce v roce 1989 — vše ze stejných dlažebních kamenů. Odemkni easter egg skrytý na fasádě Národního muzea: budova byla v roce 1968 provrtána kulkami ze sovětských tanků a komunisté díry zaplnili světlejším kamenem — pohledem zblízka ještě stále spočítáš jizvy. Jezdecká socha sv. Václava nahoře označuje finální rallye bod každé revoluce. Toto není turistika; je to historický dungeon.`,
    zh: `勇敢的探险家，瓦茨拉夫广场根本不是广场——它是一条750米长的林荫大道，是捷克历史每隔一代就在此重写的宏大任务板。这条传奇大道见证了1918年捷克斯洛伐克的诞生、1939年纳粹占领的游行、1968年的苏联坦克，以及1989年的天鹅绒革命，全都发生在同一块鹅卵石上。解锁隐藏在国家博物馆外墙上的彩蛋：1968年苏联坦克的子弹在建筑上留下了密密麻麻的弹孔，共产党用颜色较浅的石头进行了修补——仔细看，你仍然可以数清那些伤痕。顶部圣瓦茨拉夫的骑马雕像是每次革命的最终集结点。这不是旅游；这是一个历史地牢。`,
  },

  "nove-mesto": {
    en: `Brave explorer, Nové Město — New Town — was founded by Emperor Charles IV in 1348 as a planned urban expansion so ambitious it remained the largest medieval city planning project in Central Europe for two centuries. "New" is a relative term: at 676 years old, its oldest stones predate most world capitals. Unlock the Easter egg hiding in plain sight: Wenceslas Square, Charles Square, and Cattle Market Square were all designed to specific dimensions by Charles IV himself, each sized to host different types of medieval market. The largest — Charles Square — is technically the biggest square in Prague and one of the biggest in Europe, yet most tourists never visit it because it looks like a park. It is a park. It was always a park. Charles planted it with trees in 1348. The dungeon has been a garden all along.`,
    cz: `Odvážný průzkumníku, Nové Město bylo založeno císařem Karlem IV. v roce 1348 jako plánovaná městská expanze tak ambiciózní, že po dvě staletí zůstávalo největším středověkým urbanistickým projektem ve střední Evropě. "Nové" je relativní pojem: s 676 lety jsou jeho nejstarší kameny starší než většina světových hlavních měst. Odemkni easter egg ukrytý na očích: Václavské náměstí, Karlovo náměstí a Dobytčí trh byly navrženy Karlem IV. osobně na konkrétní rozměry, každé uzpůsobené pro jiný typ středověkého trhu. Největší — Karlovo náměstí — je technicky největším náměstím v Praze a jedním z největších v Evropě, přesto ho většina turistů nikdy nenavštíví, protože vypadá jako park. Je to park. Vždy byl parkem. Karel ho osadil stromy v roce 1348. Dungeon byl celou dobu zahradou.`,
    zh: `勇敢的探险家，新城区由查理四世皇帝于1348年作为有计划的城市扩张项目而创建，其规模之宏大，使其在两个世纪内一直是中欧最大的中世纪城市规划项目。"新"是一个相对的概念：以676年的历史而言，其最古老的石头比大多数世界首都都要古老。解锁隐藏在明处的彩蛋：瓦茨拉夫广场、卡尔广场和牲畜市场广场均由查理四世亲自设计，各有具体尺寸，分别用于举办不同类型的中世纪集市。其中最大的——卡尔广场——在技术上是布拉格最大的广场，也是欧洲最大的广场之一，但大多数游客从未造访，因为它看起来像一座公园。它确实是一座公园，从来都是。查理于1348年在此种下了树木。这个地牢自始至终都是一座花园。`,
  },

  "strahov-monastery": {
    en: `Brave explorer, Strahov Monastery perches at the edge of Petřín Hill like an endgame secret area that most players never unlock. Founded in 1143 by the Premonstratensian Order, its two Baroque library halls are among the most beautiful rooms on Earth — gilded ceiling frescoes, ancient globes, and 200,000 volumes shelved in carved wooden cases that smell of centuries. Unlock the Easter egg hidden in the Curiosities Cabinet: between the libraries sits a small room filled with bizarre natural specimens — dried sharks, strange insects, a narwhal horn — collected by the monks as evidence of God's weird creativity. The monastery also runs its own microbrewery on the premises. Ancient secrets and cold lager occupy the same sacred grounds. This is peak Czech civilization. Enter.`,
    cz: `Odvážný průzkumníku, Strahovský klášter sedí na okraji Petřína jako endgame tajná oblast, kterou většina hráčů nikdy neodemkne. Premonstráti ho založili v roce 1143 a jeho dva barokní knihovní sály patří k nejkrásnějším místnostem na Zemi — zlacené stropní fresky, starověké glóby a 200 000 svazků uložených v řezaných dřevěných skříních vonících staletími. Odemkni easter egg ukrytý v Kabinetu kuriozit: mezi knihovnami se nachází malá místnost plná bizarních přírodních vzorků — sušení žraloci, podivný hmyz, narvalí roh — shromážděných mnichy jako důkaz Boží podivné tvořivosti. Klášter také provozuje vlastní minipivnici v areálu. Starověká tajemství a studené pivo obývají tytéž posvátné prostory. Toto je vrchol české civilizace. Vstup.`,
    zh: `勇敢的探险家，斯特拉霍夫修道院栖居于彼得任山边缘，如同一个大多数玩家从未解锁的游戏终局秘密区域。由普雷蒙特雷会于1143年创立，其两座巴洛克图书馆大厅是地球上最美丽的房间之列——镀金天花板壁画、古老地球仪，以及20万册图书陈列在散发着岁月芬芳的雕刻木质书架上。解锁隐藏在珍奇陈列室中的彩蛋：两座图书馆之间有一个小房间，里面陈满了奇异的自然标本——干制的鲨鱼、奇特的昆虫、独角鲸的角——这些都是僧侣们作为上帝奇异创造力证明而收集的。修道院还在院内自营一家微型啤酒厂。古老的秘密与冰凉的啤酒共处于同一片圣地。这是捷克文明的巅峰。进入吧。`,
  },

  "wallenstein-palace": {
    en: `Brave explorer, Wallenstein Palace is the largest Baroque palace in Prague — and it was built by one of history's most audacious power-hungry commanders. General Albrecht von Wallenstein demolished 23 houses, three gardens, a brick kiln, and a town gate between 1623 and 1630 to make room for a palace designed to outshine Prague Castle itself. He was assassinated before he could move in. Unlock the Easter egg hiding in the garden: the garden loggia features bronze statues that are actually 17th-century copies — the Swedish army stole the originals during the Thirty Years War and took them to Stockholm, where they remain today. The garden also contains a bizarre pond of giant Koi and a free-roaming peacock population that answers to no one. Albrecht would approve.`,
    cz: `Odvážný průzkumníku, Valdštejnský palác je největším barokním palácem v Praze — a postavil ho jeden z historicky nejodvážnějších velitelů lačných po moci. Generál Albrecht z Valdštejna v letech 1623 až 1630 zbořil 23 domů, tři zahrady, cihelnu a městskou bránu, aby udělal místo pro palác navržený k předstižení samotného Pražského hradu. Byl zavražděn dříve, než se mohl nastěhovat. Odemkni easter egg ukrytý v zahradě: zahradní lodžie obsahuje bronzové sochy, které jsou ve skutečnosti kopiemi ze 17. století — švédská armáda ukradla originály během třicetileté války a odvezla je do Stockholmu, kde jsou dodnes. Zahrada také obsahuje bizarní jezírko s obřím kaprem a volně se pohybující populaci pávů, která nikomu neodpovídá. Albrecht by schválil.`,
    zh: `勇敢的探险家，瓦伦斯坦宫是布拉格最大的巴洛克宫殿——由历史上最大胆、最渴望权力的指挥官之一建造。阿尔布雷希特·冯·瓦伦斯坦将军于1623年至1630年间拆除了23栋房屋、三座花园、一座砖窑和一座城门，为一座旨在超越布拉格城堡的宫殿腾出空间。他在搬入之前便遭到暗杀。解锁隐藏在花园中的彩蛋：花园凉廊展示的铜像实际上是17世纪的复制品——瑞典军队在三十年战争期间偷走了原件并带回斯德哥尔摩，至今仍在那里。花园里还有一个养着巨型锦鲤的奇异池塘，以及一群不受任何人管束的自由漫步的孔雀。阿尔布雷希特会赞许的。`,
  },

  "kavarna-slavia": {
    en: `Brave explorer, Kavárna Slavia is the most historically charged café quest zone in Prague — a grand Art Deco coffee house on the Vltava embankment operating since 1884, where every generation of Czech artists, writers, and dissidents has gathered to argue, plot, and create. Kafka drank here. Rainer Maria Rilke wrote here. Václav Havel used it as an informal headquarters during the dissident years. Unlock the Easter egg behind the bar: during the communist era, the café was nationalised and slowly allowed to decay. When it was privatised in 1991, new owners tried to convert it into a casino. Havel, then president, intervened personally. The café was saved. A reproduction of Viktor Oliva's painting "The Absinthe Drinker" still presides over the room — the original is here too. Order a coffee, sit by the window, watch the castle. You are in the right place.`,
    cz: `Odvážný průzkumníku, Kavárna Slavia je historicky nejnabitější café quest zónou Prahy — velkolepá art deco kavárna na vltavském nábřeží fungující od roku 1884, kde se každá generace českých umělců, spisovatelů a disidentů scházela k hádkám, plánování a tvorbě. Kafka tu pil. Rainer Maria Rilke tu psal. Václav Havel ji využíval jako neformální základnu v disidentských letech. Odemkni easter egg za barem: v komunistické éře byla kavárna znárodněna a pomalu nechána chátrat. Když byla v roce 1991 zprivatizována, noví majitelé se ji pokusili přeměnit na kasino. Havel, tehdy prezident, osobně zasáhl. Kavárna byla zachráněna. Reprodukce Olivova obrazu "Absinťák" stále vládne místnosti — originál je tu také. Objednej si kávu, sedni u okna, dívej se na hrad. Jsi na správném místě.`,
    zh: `勇敢的探险家，斯拉维亚咖啡馆是布拉格历史底蕴最为深厚的咖啡馆任务区——一家自1884年起在伏尔塔瓦河畔经营的宏伟装饰艺术咖啡馆，每一代捷克艺术家、作家和异见人士都曾在此聚会，争论、密谋和创作。卡夫卡在这里喝咖啡，莱纳·马利亚·里尔克在这里写作，瓦茨拉夫·哈维尔在异见岁月中将其作为非正式的据点。解锁隐藏在吧台后面的彩蛋：共产主义时代，咖啡馆被收归国有，随之慢慢凋败。1991年私有化后，新老板试图将其改造成赌场。时任总统的哈维尔亲自出面干预，咖啡馆得以保全。维克托·奥利瓦的画作《苦艾酒饮者》的复制品至今仍悬挂于室内主位——原作也在这里。点一杯咖啡，坐在窗边，凝视城堡。你来对地方了。`,
  },

  "petrin-tower": {
    en: `Brave explorer, Petřín Tower is Prague's greatest optical illusion — a 63-metre steel lookout tower that looks exactly like the Eiffel Tower but is built at one-fifth the scale, on a hill that makes it appear much taller than it is. Commissioned in 1891 for the Prague Jubilee Exhibition, it was constructed by the Czech Tourist Club in just four months, funded largely by public subscription. Unlock the Easter egg in the view: on a clear day the tower's observation deck reveals not just Prague but the Bohemian countryside for 100 kilometres in every direction — including Germany, Austria, and Slovakia. The tower has 299 steps. The lift was added in 1953. True brave explorers climb. Also: during WWII the tower was used as a radio transmitter for resistance broadcasts. The Nazis never found it.`,
    cz: `Odvážný průzkumníku, Petřínská rozhledna je největší optickou iluzí Prahy — 63metrová ocelová vyhlídková věž, která vypadá přesně jako Eiffelova věž, ale je postavena v pětinové velikosti, na kopci, který ji činí mnohem vyšší, než ve skutečnosti je. Objednána v roce 1891 pro Jubilejní výstavu v Praze, byla postavena Klubem českých turistů za pouhé čtyři měsíce, financována z velké části veřejnou sbírkou. Odemkni easter egg ve výhledu: za jasného dne vyhlídková plošina věže odhaluje nejen Prahu, ale i českou krajinu na 100 kilometrů na všechny strany — včetně Německa, Rakouska a Slovenska. Věž má 299 schodů. Výtah byl přidán v roce 1953. Skuteční odvážní průzkumníci lezou pěšky. Také: během druhé světové války sloužila věž jako rozhlasový vysílač pro odbojová vysílání. Nacisté ji nikdy nenašli.`,
    zh: `勇敢的探险家，彼得任瞭望塔是布拉格最伟大的视觉错觉——一座63米高的钢制瞭望塔，外形与埃菲尔铁塔一模一样，但仅有五分之一的比例，建于一座山丘之上，使其看起来比实际高得多。受托于1891年布拉格周年纪念博览会，由捷克旅游俱乐部在短短四个月内建成，资金主要来自公众认购。解锁视野中的彩蛋：天气晴朗时，塔的观景台不仅能看到布拉格，还能看到四面八方100公里范围内的波西米亚乡村——包括德国、奥地利和斯洛伐克。塔有299级台阶。电梯于1953年增设。真正的勇敢探险家选择徒步攀登。此外：二战期间，该塔曾被用作抵抗运动广播的无线电发射器。纳粹从未找到它。`,
  },

  "zizkov-tv-tower": {
    en: `Brave explorer, the Žižkov Television Tower is Prague's most gloriously weird landmark — a 216-metre brutalist rocket ship that the communists built between 1985 and 1992, partly over a demolished Jewish cemetery. Today it is unmistakable on the skyline and deeply loved despite its troubled origins. Unlock the Easter egg crawling across its surface: artist David Černý mounted ten giant black crawling babies on the tower's exterior in 2000 as a temporary installation — they proved so unsettling and beloved that they became permanent. Each baby has no face, replaced by a barcode. One floor of the tower is a luxury hotel room bookable by any brave explorer who dares sleep inside a Communist rocket with faceless infant guardians. Legendary.`,
    cz: `Odvážný průzkumníku, Žižkovský televizní vysílač je nejslavněji podivnou památkou Prahy — 216metrová brutalistická raketa, kterou komunisté stavěli mezi lety 1985 a 1992, částečně přes zbořený židovský hřbitov. Dnes je na obzoru nezaměnitelný a hluboce milovaný navzdory svým problematickým počátkům. Odemkni easter egg plazící se po jeho povrchu: umělec David Černý v roce 2000 připevnil na exteriér věže deset obrovských černých lezoucích miminek jako dočasnou instalaci — ukázala se tak znepokojivá a oblíbená, že se stala trvalou. Každé miminko nemá tvář, nahrazenou čárovým kódem. Jedno patro věže je luxusní hotelový pokoj rezervovatelný každým odvážným průzkumníkem, který se odváží přespat uvnitř komunistické rakety se strážci-miminy bez tváří. Legendární.`,
    zh: `勇敢的探险家，日什科夫电视塔是布拉格最辉煌奇异的地标——一座216米高的野兽派火箭飞船，由共产党人于1985年至1992年间建造，部分地基建于一座被拆除的犹太墓地之上。如今它在天际线上无可比拟，尽管起源颇具争议，却深受人们喜爱。解锁爬行在其表面的彩蛋：艺术家大卫·切尔尼于2000年将十个巨大的黑色爬行婴儿安装在塔的外墙上，原本是临时装置——它们被证明如此令人不安又广受喜爱，最终成为永久装置。每个婴儿都没有脸，取而代之的是条形码。塔的一层是一间可供预订的豪华酒店客房，供任何敢于在共产主义火箭内、由无脸婴儿守护中入睡的勇敢探险家享用。传奇之地。`,
  },

  "nusle-steps-murals": {
    en: `Brave explorer, the Nusle Steps Murals are Prague's most rewarding hidden-gem quest zone for the observant explorer — a network of outdoor staircases connecting Vinohrady to the Nusle valley below, whose stair walls have been turned over to local artists and now form a kilometre-long open-air gallery of murals, mosaics, and painted tiles that changes year by year. The staircases themselves are a 19th-century civic engineering project built to allow workers to descend from the bourgeois plateau of Vinohrady to the factories below. Unlock the Easter egg in the most-photographed panel: one staircase contains a mosaic portrait of Nikola Tesla, installed by a local resident who discovered that Tesla had briefly lived in a building on the street above in 1889 while visiting Prague and attending a lecture by Ernst Mach. Tesla in Prague. Few people know. Now you do.`,
    cz: `Odvážný průzkumníku, Nuselské schody s malbami jsou nejodměňující hidden-gem quest zónou Prahy pro pozorného průzkumníka — síť venkovních schodišť spojujících Vinohrady s Nuselským údolím níže, jejichž schodišťové stěny byly předány místním umělcům a nyní tvoří kilometrovou galerii nástěnných maleb, mozaik a malovaných kachlíků na otevřeném vzduchu, která se mění rok od roku. Schodiště sama jsou projektem občanského inženýrství z 19. století, postaveným tak, aby umožnila dělníkům sestoupit z měšťanské plošiny Vinohrad do továren níže. Odemkni easter egg v nejfotografovanějším panelu: jedno schodiště obsahuje mozaikový portrét Nikoly Tesly, nainstalovaný místním obyvatelem, který zjistil, že Tesla krátce žil v budově na ulici výše v roce 1889 při návštěvě Prahy a účasti na přednášce Ernsta Macha. Tesla v Praze. Málokdo to ví. Teď to víš.`,
    zh: `勇敢的探险家，努斯尔阶梯壁画是布拉格对善于观察的探险者最具回报的隐藏宝石任务区——一组连接维诺赫拉迪与下方努斯尔谷地的户外阶梯，其阶梯墙壁已交由本地艺术家使用，如今形成一条每年都在变化的长达一公里的壁画、马赛克和彩绘瓷砖露天画廊。阶梯本身是19世纪的市政工程项目，为使工人能从维诺赫拉迪的资产阶级高台下降至下方工厂而建。解锁最常被拍摄的画板中的彩蛋：一处阶梯含有尼古拉·特斯拉的马赛克肖像，由一位发现特斯拉于1889年短暂居住在上方街道某建筑中的本地居民安装——当时特斯拉正在造访布拉格，并出席恩斯特·马赫的一场讲座。特斯拉在布拉格。鲜有人知晓此事，现在你知道了。`,
  },

  "anthony": {
    en: `Brave explorer, Holešovice Street Art is the most densely layered outdoor quest zone in Prague — an entire neighbourhood whose industrial walls, railway underpasses, and derelict facades have been systematically claimed by artists over two decades, creating a rotating outdoor gallery that no curator controls and no ticket can access. Some pieces are gone within weeks. Others survive years of weather and further layers. Unlock the Easter egg in the legal framework: Prague has designated certain walls in Holešovice as official street art zones, negotiated between the city, building owners, and artist communities — meaning the murals here exist in a rare legal grey zone where they are simultaneously unofficial and tolerated. The best pieces are not on the designated walls. They never are. Follow the railway tracks east of Nádraží Holešovice and look up. The walls tell a different history of Prague than any guidebook. They tell it faster too.`,
    cz: `Odvážný průzkumníku, Holešovické street art je nejhustěji vrstvená venkovní quest zóna v Praze — celá čtvrť, jejíž průmyslové stěny, železniční podchody a zpustlé fasády byly systematicky zabrány umělci po dvě desetiletí, čímž vznikla rotující venkovní galerie, kterou žádný kurátor nekontroluje a žádná vstupenka ji neumožňuje. Některé kousky zmizí během týdnů. Jiné přežijí roky počasí a další vrstvy. Odemkni easter egg v právním rámci: Praha označila určité stěny v Holešovicích jako oficiální street art zóny, sjednaně mezi městem, vlastníky budov a uměleckými komunitami — což znamená, že nástěnné malby zde existují ve vzácné právní šedé zóně, kde jsou zároveň neoficiální a tolerované. Nejlepší kousky nejsou na označených stěnách. Nikdy nejsou. Sleduj železniční koleje na východ od Nádraží Holešovice a dívej se nahoru. Stěny vyprávějí jinou historii Prahy než jakýkoli průvodce. Také ji vyprávějí rychleji.`,
    zh: `勇敢的探险家，霍莱绍维采街头艺术是布拉格层次最为丰富的户外任务区——整个街区的工业墙壁、铁路地下通道和废弃外墙二十年来被艺术家们系统性地占领，形成一个没有策展人掌控、没有门票可以进入的轮换户外画廊。有些作品几周内便消失，另一些则经受数年风雨和更多层次的叠加而幸存。解锁法律框架中的彩蛋：布拉格将霍莱绍维采的某些墙壁指定为官方街头艺术区，由城市、建筑业主和艺术家社群协商确定——这意味着这里的壁画存在于一个罕见的法律灰色地带，既是非官方的，又是被默许的。最出色的作品不在指定墙壁上，从来都不是。沿着霍莱绍维采火车站以东的铁路轨道走，抬头看。这些墙壁讲述着一段与任何旅游指南都不同的布拉格历史。而且讲得更快。`,
  },

  "certovka": {
    en: `Brave explorer, Čertovka is the most romantic hidden-gem quest zone in Prague — a narrow mill stream running behind Kampa Island that creates an artificial waterway so slender you can almost touch both banks at once. The name means "Devil's Stream," supposedly named after a famously ill-tempered woman who once lived beside it. The stream powered mills for centuries; the last one, the Grand Priory Mill, still has its waterwheel turning. Unlock the Easter egg built into the waterway: Čertovka's current is so gentle and the banks so close that a paddleboat can navigate it completely — and several rental companies offer exactly this. The narrowest point is just wide enough for one boat, meaning oncoming traffic requires reverse paddling. It is gloriously impractical. This tiny stream creates the most photogenic corner of Prague and almost nobody knows its name. Now you do.`,
    cz: `Odvážný průzkumníku, Čertovka je nejromantičtější hidden-gem quest zónou Prahy — úzký mlýnský potok tekoucí za Kampa ostrovem, vytvářející umělý vodní tok tak úzký, že se téměř dotkneš obou břehů najednou. Název znamená "ďábelský potok" a je prý pojmenován po pověstně nevrlé ženě, která kdysi žila u jeho břehů. Potok po staletí poháněl mlýny; poslední z nich, Velkopřevorský mlýn, má stále otáčející se mlýnské kolo. Odemkni easter egg zabudovaný do vodní cesty: proud Čertovky je tak mírný a břehy tak blízko, že po ní může proplout šlapací člun — a několik půjčoven to přesně nabízí. Nejužší místo je jen dost široké pro jeden člun, takže protijedoucí provoz vyžaduje couvání. Je to nádherně nepraktické. Tento malý potok vytváří nejfotogeničtější kout Prahy a téměř nikdo nezná jeho název. Teď ho znáš.`,
    zh: `勇敢的探险家，切尔托夫卡是布拉格最浪漫的隐藏宝石任务区——一条流经坎帕岛后方的狭窄磨坊水流，形成一条水道，其狭窄程度几乎让你同时触及两岸。这个名字意为"魔鬼溪"，据说得名于一位曾住在其旁的以脾气暴躁著称的女人。这条溪流几个世纪以来为磨坊提供动力；最后一座，大修道院磨坊，至今仍有水车转动。解锁内置于水道中的彩蛋：切尔托夫卡的水流如此平缓，两岸如此接近，以至于脚踏船可以完全穿越其中——几家租赁公司就提供了这项服务。最窄处恰好只能容纳一艘船通过，这意味着对向来船时需要倒桨。这实在是一种令人愉快的不实用。这条小溪创造了布拉格最上镜的角落，但几乎没有人知道它的名字。现在你知道了。`,
  },

  "vojanovy-sady": {
    en: `Brave explorer, Vojanovy Sady is the most secret garden quest zone in Prague — a walled Baroque garden in Malá Strana hidden behind an unmarked door in a residential street, visible on no tourist map and missed by virtually every first-time visitor. Founded by Carmelite monks in the 17th century, the garden contains two Baroque chapels, ancient apple trees, peacocks that roam freely between the rose beds, and the particular silence of enclosed sacred space. Unlock the Easter egg in its hidden entrance: the door to the garden is set into a blank wall on Letenská Street with no visible signage beyond a small plaque that most people dismiss as a building address. Behind it is half a hectare of medieval garden that feels like a cheat code for escaping the city without leaving it. Prague contains rooms the city forgot to lock. This is one of them. Say nothing to anyone.`,
    cz: `Odvážný průzkumníku, Vojanovy sady jsou nejtajnější zahradní quest zónou v Praze — zahradní barokní zahrada v Malé Straně ukrytá za neoznačenými dveřmi v rezidenční ulici, neviditelná na žádné turistické mapě a přehlédnutá prakticky každým prvním návštěvníkem. Zahrada, kterou karmelitáni založili v 17. století, obsahuje dvě barokní kaple, staré jabloně, pávy volně se procházející mezi záhony růží a zvláštní ticho uzavřeného posvátného prostoru. Odemkni easter egg v jejím skrytém vchodu: dveře do zahrady jsou zasazeny do holé stěny na Letenské ulici bez viditelného označení kromě malé plakety, kterou většina lidí odbyde jako adresu budovy. Za nimi je půl hektaru středověké zahrady, která se cítí jako cheat kód pro útěk z města bez jeho opuštění. Praha obsahuje místnosti, které město zapomnělo zamknout. Toto je jedna z nich. Nikomu nic neříkej.`,
    zh: `勇敢的探险家，沃亚诺维萨迪是布拉格最秘密的花园任务区——小城区一处被围墙环绕的巴洛克花园，隐藏在住宅街道上一扇毫无标识的门后，不出现在任何旅游地图上，几乎每一位初次游客都会错过它。由加尔默罗修士于17世纪创建，花园内有两座巴洛克礼拜堂、古老的苹果树、在玫瑰花坛间自由漫步的孔雀，以及封闭神圣空间特有的静谧。解锁其隐藏入口中的彩蛋：花园的大门嵌入莱特纳街的一面白墙之中，没有任何可见的标识，只有一块大多数人会当作楼牌号而忽视的小牌匾。门后是半公顷的中世纪花园，感觉像是在不离开城市的情况下逃离城市的秘籍。布拉格有些房间是城市忘记锁上的，这就是其中之一。什么都别告诉任何人。`,
  },

  "st-michael-mystery-church": {
    en: `Brave explorer, St. Michael's Mystery Church — Kostel sv. Michaela — is the most genuinely mysterious quest zone in Prague, a deconsecrated Baroque church in Kinský Garden on Petřín Hill that was dismantled log by log from a village in the Carpathian Ukraine in 1929 and rebuilt in Prague as a museum of folk architecture. The building is a Greek Catholic wooden church transported 1,200 kilometres and erected on a Prague hillside, creating a structure that looks as though it teleported from a completely different culture. Unlock the Easter egg in its ongoing strangeness: the church was used briefly in the 1990s as a rehearsal space by experimental theatre companies and reportedly still contains traces of stage sets from those years behind the iconostasis. It opens only on summer weekends and its interior remains extraordinarily atmospheric — dark wood, faded icons, and the smell of old timber from a completely different mountain range. Step inside and recalibrate your location data.`,
    cz: `Odvážný průzkumníku, Záhadný kostel sv. Michaela je nejopravdověji záhadnou quest zónou Prahy, dekonsekrovaný barokní kostel v Kinského zahradě na Petříně, který byl demontován kláda po kládě z vesnice v Podkarpatské Rusi v roce 1929 a přestaven v Praze jako muzeum lidové architektury. Budova je řeckokatolický dřevěný kostel přepravený 1 200 kilometrů a postavený na pražském svahu, čímž vznikla stavba, která vypadá, jako by se teleportovala z úplně jiné kultury. Odemkni easter egg v jeho pokračující podivnosti: kostel byl v 90. letech krátce využíván jako zkušební prostor experimentálními divadelními soubory a prý stále ukrývá stopy jevištních dekorací z těch let za ikonostasem. Otevírá se pouze o letních víkendech a jeho interiér zůstává mimořádně atmosférický — tmavé dřevo, vyblédlé ikony a vůně starého dřeva z úplně jiného pohoří. Vstup a překalibruj si data o poloze.`,
    zh: `勇敢的探险家，圣米迦勒神秘教堂是布拉格最真正神秘的任务区——彼得任山金斯基花园中一座被去圣化的巴洛克教堂，于1929年从喀尔巴阡乌克兰的一个村庄一根圆木一根圆木地拆卸运来，在布拉格重建为民间建筑博物馆。这是一座旅行了1200公里并被竖立在布拉格山坡上的希腊天主教木制教堂，造就了一座看起来像是从完全不同的文化中传送而来的建筑。解锁其持续奇特性中的彩蛋：教堂在90年代曾短暂被实验剧团用作排练场地，据说在圣像壁后面至今仍保留着那些年份舞台布景的痕迹。它只在夏季周末开放，内部保持着非同寻常的氛围——黑色木材、褪色圣像，以及来自完全不同山脉的旧木材气息。踏入其中，重新校准你的位置数据。`,
  },

  "kafka-rotating-head": {
    en: `Brave explorer, the Kafka Rotating Head at the Quadrio shopping centre is the most hypnotic public artwork in Prague — a 10.9-metre-tall stainless steel sculpture of Franz Kafka's head composed of 42 independently rotating horizontal layers that continuously rearrange themselves, the face assembling and dissolving in slow motion like a thought that cannot hold its own shape. Created by sculptor David Černý in 2014, it is the most technically complex public sculpture in the Czech Republic and runs on a custom computer system that has never been fully documented publicly. Unlock the Easter egg in the timing: the layers periodically align into a perfect portrait — but only for a few seconds before the rotation pulls the face apart again. Visitors who wait long enough see Kafka's face emerge and vanish. It is the most Kafka thing in Prague. Even his face cannot hold still.`,
    cz: `Odvážný průzkumníku, Kafkova rotující hlava u obchodního centra Quadrio je nejhypnotičtějším veřejným uměleckým dílem Prahy — 10,9metrová nerezová socha Kafkovy hlavy složená z 42 nezávisle rotujících horizontálních vrstev, které se neustále přeskupují, tvář se sestavuje a rozpouští v pomalém pohybu jako myšlenka, která nemůže udržet svůj vlastní tvar. Vytvořená sochařem Davidem Černým v roce 2014, je to technicky nejsložitější veřejná socha v České republice, fungující na vlastním počítačovém systému, který nebyl nikdy veřejně plně zdokumentován. Odemkni easter egg v načasování: vrstvy se periodicky zarovnají do dokonalého portrétu — ale jen na pár sekund, než rotace znovu roztáhne tvář. Návštěvníci, kteří čekají dost dlouho, spatří Kafkovu tvář se vynořit a zase zmizet. Je to nejvíce Kafkovská věc v Praze. Ani jeho tvář nemůže stát klidně.`,
    zh: `勇敢的探险家，Quadrio购物中心的卡夫卡旋转头像是布拉格最令人着迷的公共艺术作品——一座10.9米高的不锈钢卡夫卡头部雕塑，由42个独立旋转的水平层面组成，不断地重新排列，面孔在慢动作中组合又消散，宛如一个无法保持自身形态的念头。由雕塑家大卫·切尔尼于2014年创作，它是捷克共和国技术上最复杂的公共雕塑，运行于一套从未被完整公开记录的定制计算机系统之上。解锁隐藏在时机中的彩蛋：各层面会周期性地对齐成一幅完美的肖像——但仅持续几秒钟，旋转便会再次将面孔拉开。等待足够长时间的游客会看到卡夫卡的脸浮现又消失。这是布拉格最具卡夫卡风格的事物。连他的脸也无法保持静止。`,
  },

  "john-lennon-wall": {
    en: `Brave explorer, the John Lennon Wall is the most repainted surface in Prague — a 30-metre stretch of Malá Strana wall that has been covered and recovered in peace graffiti, Beatles lyrics, and portraits since Lennon's assassination in 1980. It began as an act of illegal Czech youth protest against the communist regime and the secret police painted over it every night. Every morning new messages appeared. The regime eventually gave up. Unlock the Easter egg in its maintenance history: the wall is technically owned by the Knights of Malta, who have occasionally tried to have it painted white and consistently failed due to public outrage. The wall gets repainted completely by visitors every few weeks, meaning the current surface is entirely different from any photograph you have seen. It never looks the same twice.`,
    cz: `Odvážný průzkumníku, Lennonova zeď je nejčastěji přemalovávaným povrchem v Praze — 30metrový úsek malostranské zdi, pokrývaný a znovu pokrývaný mírových graffiti, texty Beatles a portréty od Lennonovy vraždy v roce 1980. Začalo to jako ilegální akt protestu českých mladých lidí proti komunistickému režimu a tajná policie ji každou noc přemalovávala. Každé ráno se objevovaly nové zprávy. Režim nakonec vzdal. Odemkni easter egg v její historii údržby: zeď je technicky ve vlastnictví Maltézských rytířů, kteří se ji příležitostně pokoušeli nechat nabílit a konzistentně selhávali kvůli veřejnému pobouření. Zeď je návštěvníky úplně přemalována každých několik týdnů, což znamená, že aktuální povrch je zcela jiný než na jakékoli fotografii, kterou jsi viděl. Nikdy nevypadá dvakrát stejně.`,
    zh: `勇敢的探险家，列侬墙是布拉格被重新涂绘次数最多的表面——自列侬1980年遇刺以来，这段30米长的小城区墙壁不断被和平涂鸦、披头士歌词和肖像所覆盖。它起初是捷克青年反抗共产主义政权的非法抗议行为，秘密警察每晚将其粉刷干净。每天早晨，新的信息又会出现。政权最终放弃了。解锁其维护历史中的彩蛋：这面墙在技术上属于马耳他骑士团所有，他们偶尔试图将其涂成白色，但由于公众的强烈反对，每次都以失败告终。墙壁每隔几周就会被游客完全重新涂绘，这意味着当前的表面与你所见过的任何照片都完全不同。它从不会两次看起来相同。`,
  },

  "novy-svet": {
    en: `Brave explorer, Nový Svět — New World — is the most enchanted hidden quest zone in Prague, a cluster of tiny cobblestoned streets below Prague Castle that looks like a fairy-tale village materialised inside a capital city. The lane names are gloriously odd: Golden Pear Street, Cannon Street, Owl Lane. The houses are doll-sized, painted in faded pastels, with wooden shutters and window boxes of geraniums. Unlock the Easter egg hidden in its most famous resident: the Danish astronomer Tycho Brahe lived here before relocating to larger quarters at Prague Castle. He was not the only genius to occupy these lanes — the Baroque sculptor Matthias Braun was born in a house you can still identify today. The street is residential, lived-in, and almost entirely free of tourist infrastructure. It is the Prague that exists between the quest markers. Walk slowly.`,
    cz: `Odvážný průzkumníku, Nový Svět je nejokouzlenější skrytou quest zónou Prahy, shluk malých dlážděných uliček pod Pražským hradem, který vypadá jako pohádková vesnice zhmotnělá uvnitř hlavního města. Názvy uliček jsou nádherně bizarní: Ulice zlaté hrušky, Dělostřelecká ulice, Sova Lane. Domy jsou v miniaturní velikosti, natřené ve vybledlých pastelu, s dřevěnými okenicemi a truhlíky pelargónií. Odemkni easter egg ukrytý v jeho nejslavnějším obyvateli: dánský astronom Tycho Brahe zde žil, než se přestěhoval do větších prostor na Pražském hradě. Nebyl jediným géniem, který obýval tyto ulice — barokní sochař Matyáš Braun se narodil v domě, který dodnes můžeš identifikovat. Ulice je rezidenční, obydlená a téměř zcela bez turistické infrastruktury. Je to Praha, která existuje mezi quest markery. Jdi pomalu.`,
    zh: `勇敢的探险家，新世界——Nový Svět——是布拉格最迷人的隐藏任务区，一簇布拉格城堡下方的小鹅卵石街道，看起来像是一个在首都城市内实体化的童话村庄。街道名称奇妙无比：金梨街、炮兵街、猫头鹰巷。房屋小巧如玩偶，涂着褪色的柔和色彩，有木质百叶窗和天竺葵花箱。解锁隐藏在其最著名居民身上的彩蛋：丹麦天文学家第谷·布拉赫在迁往布拉格城堡更大的住所之前，曾住在这里。他并非唯一住过这些小巷的天才——巴洛克雕塑家马蒂亚斯·布劳恩就出生在一栋你今天仍能辨认出的房子里。这条街住着居民，有人居住，几乎完全没有旅游基础设施。这是存在于任务标记之间的布拉格。慢慢走。`,
  },

  "kotva-department-store": {
    en: `Brave explorer, Kotva Department Store is Prague's most brutally fascinating architectural quest zone — a 1975 Brutalist shopping centre whose honeycomb concrete facade, hexagonal floor plan, and deliberately fortress-like massing made it one of the most controversial and celebrated buildings of Communist-era Czechoslovakia, awarded the national prize for architecture the year it opened. Unlock the Easter egg sealed in the design competition: Kotva was the result of an open architectural competition that a young Czech husband-and-wife team won against dozens of established firms — their concept was radical enough that Party officials nearly rejected it for looking too Western. It was approved. The department store is still trading, still occupies the original building, and still divides architectural opinion fifty years later. Half of Prague considers it an eyesore. The other half considers it a masterpiece. Both camps are correct. It is the most honest building in the city.`,
    cz: `Odvážný průzkumníku, Obchodní dům Kotva je architektonicky nejdramatičtěji fascinující quest zónou Prahy — brutalistické obchodní centrum z roku 1975, jehož medové betonová fasáda, šestiúhelníkový půdorys a záměrně pevnostní hmotnost z ní udělaly jednu z nejkontroverzněji a nejslavnějších staveb komunistického Československa, oceněnou národní cenou za architekturu v roce otevření. Odemkni easter egg zapečetěný v soutěži o návrh: Kotva byla výsledkem otevřené architektonické soutěže, kterou vyhrálo mladé česky manželé nad desítkami zavedených firem — jejich koncept byl natolik radikální, že ho stranické kádry málem zamítly pro příliš occidentální vzhled. Byl schválen. Obchodní dům stále obchoduje, stále sídlí v původní budově a stále rozděluje architektonické mínění padesát let poté. Polovina Prahy ho považuje za ošklivce. Druhá polovina za mistrovské dílo. Oba tábory mají pravdu. Je to nejupřímnější budova ve městě.`,
    zh: `勇敢的探险家，科特瓦百货商场是布拉格建筑上最令人着迷的任务区——一座1975年的粗野主义购物中心，其蜂巢状混凝土外墙、六边形平面布局和刻意营造的堡垒感，使其成为共产主义时代捷克斯洛伐克最具争议性和最受称赞的建筑之一，在开业当年荣获国家建筑奖。解锁封存在设计竞赛中的彩蛋：科特瓦是一场开放建筑设计竞赛的结果，一对年轻的捷克夫妻档在击败数十家知名公司后获胜——他们的方案极为激进，以至于党的官员几乎以"看起来太西化"为由予以拒绝。最终获批。这家百货商场至今仍在营业，仍占据原始建筑，五十年后仍然在建筑界引发争议。布拉格一半人认为它碍眼，另一半认为它是杰作。两个阵营都是对的。它是城市中最诚实的建筑。`,
  },

  "prague-zoo": {
    en: `Brave explorer, Prague Zoo is consistently ranked among the best zoos in the world — a 58-hectare hillside sanctuary above the Vltava in Troja whose terrain of gorges, valleys, and natural slopes allows animals to inhabit environments that actually resemble their native habitats. The Komodo dragon enclosure has its own thermal regulation system. The Indonesian jungle pavilion maintains actual tropical humidity. Unlock the Easter egg written into the zoo's catastrophic 2002 chapter: the floods of that year submerged the entire lower zoo area, killing several animals including a hippopotamus, elephant, and bear. The gorilla Moja survived by being moved to a fire truck cabin. Her story was broadcast live across Europe. The zoo was rebuilt within a year and attendance doubled afterward — Praguers adopted the zoo's recovery as their own. The 2002 flood memorial near the entrance records every animal lost. Read it before you enter.`,
    cz: `Odvážný průzkumníku, Pražská zoologická zahrada je konzistentně hodnocena mezi nejlepšími zoo na světě — 58hektarové svažité útočiště nad Vltavou v Troji, jehož terén roklí, údolí a přirozených svahů umožňuje zvířatům obývat prostředí, která skutečně připomínají jejich původní biotopy. Výběh komodo draků má vlastní systém regulace teploty. Indonéský džunglový pavilon udržuje skutečnou tropickou vlhkost. Odemkni easter egg vepsaný do katastrofální kapitoly zoo roku 2002: záplavy toho roku pohřbily celou spodní část zoo, přičemž zahynulo několik zvířat, včetně hrocha, slona a medvěda. Gorila Moja přežila přesunem do kabiny hasičského vozidla. Její příběh byl živě vysílán po celé Evropě. Zoo bylo přestavěno během roku a návštěvnost se poté zdvojnásobila — Pražané přijali obnovu zoo jako svou vlastní. Pamětní deska záplav roku 2002 u vchodu zaznamenává každé ztracené zvíře. Přečti ji, než vstoupíš.`,
    zh: `勇敢的探险家，布拉格动物园在世界最佳动物园排名中始终名列前茅——特罗亚伏尔塔瓦河上方一处58公顷的山坡庇护所，其峡谷、山谷和天然坡地地形使动物得以栖居于真正近似原生栖息地的环境中。科莫多巨蜥围栏拥有自己的温度调节系统，印度尼西亚丛林展馆维持着真实的热带湿度。解锁写入动物园2002年灾难章节的彩蛋：当年的洪水淹没了动物园整个下区，造成多头动物死亡，包括一头河马、一头大象和一头熊。大猩猩莫佳通过被转移到一辆消防车驾驶舱内而幸免于难，她的故事被欧洲各地直播报道。动物园在一年内完成重建，此后参观人数翻番——布拉格人将动物园的复兴视为自己的复兴。入口处的2002年洪水纪念碑记录了每一头失去的动物。进入之前，请先读一读它。`,
  },

  "mirror-maze-petrin": {
    en: `Brave explorer, the Mirror Maze on Petřín Hill is the most joyfully absurd quest zone in Prague — a small wooden building from the 1891 Jubilee Exhibition containing a maze of angled mirrors that disorients visitors within seconds and a panoramic diorama depicting the 1648 Battle of Charles Bridge, in which Prague's students and Jews defended the bridge against Swedish troops during the Thirty Years War. The two attractions exist in the same building for no coherent reason. Unlock the Easter egg in the diorama's detail: the battle scene includes over a hundred handcrafted figures, and among them — if you look carefully — are several figures clearly positioned doing things that have nothing to do with the battle. A man eating. A dog sleeping. A woman hanging laundry. The craftsman who made the diorama in 1891 quietly included his own commentary on the chaos of war. Nobody removed them. They are still there.`,
    cz: `Odvážný průzkumníku, Bludiště zrcadel na Petříně je nejradostněji absurdní quest zónou Prahy — malá dřevěná budova z Jubilejní výstavy roku 1891 obsahující labyrint zkosených zrcadel, která dezorientují návštěvníky během sekund, a panoramatické dioráma zobrazující Bitvu u Karlova mostu roku 1648, v níž pražští studenti a Židé bránili most proti švédským vojskům během třicetileté války. Tyto dvě atrakce existují ve stejné budově z žádného koherentního důvodu. Odemkni easter egg v detailu dioráma: bitevní scéna obsahuje přes sto ručně vyrobených figurek a mezi nimi — pokud se pozorně podíváš — je několik figurek jasně postavených, jak dělají věci, které nemají s bitvou nic společného. Muž jí. Pes spí. Žena věší prádlo. Řemeslník, který dioráma vytvořil v roce 1891, tiše zahrnul vlastní komentář k chaosu války. Nikdo je neodstranil. Stále tam jsou.`,
    zh: `勇敢的探险家，彼得任山镜子迷宫是布拉格最令人愉快的荒诞任务区——一座来自1891年周年纪念博览会的小木屋，内有一个几秒内就能让游客迷失方向的斜角镜子迷宫，以及一个描绘1648年查理大桥战役的全景立体模型，在三十年战争中，布拉格的学生和犹太人在此抵御瑞典军队。这两处景点毫无逻辑地共存于同一栋建筑内。解锁立体模型细节中的彩蛋：战场场景包含一百多个手工制作的人物，其中——如果你仔细看——有几个人物明显处于与战斗毫无关系的姿态：一个正在吃东西的男人，一只正在睡觉的狗，一个正在晾衣服的女人。1891年制作这个立体模型的工匠悄悄地加入了自己对战争混乱的注脚。没有人将其移除，它们至今仍在。`,
  },

  "aquapalace": {
    en: `Brave explorer, Aquapalace Praha is the largest water park in Central Europe — a quest zone of a completely different register from everything else in this guide, a vast indoor-outdoor complex of slides, wave pools, thermal baths, and children's areas in Čestlice on the southern edge of Prague that Praguers treat as their domestic holiday destination when the weather defeats them. Unlock the Easter egg in its scale: the park covers 21,000 square metres under a single roof, and on winter weekends its visitor population temporarily exceeds that of several surrounding Czech towns. The thermal section maintains pools at temperatures ranging from 32 to 38 degrees; the outdoor slides operate until October. It was built in 2003 and was immediately the most visited leisure attraction in Bohemia. Sometimes the greatest quest reward is simply being warm and wet in a Central European November. No shame in this. The knights of Prague needed rest days too.`,
    cz: `Odvážný průzkumníku, Aquapalace Praha je největším aquaparkem ve střední Evropě — quest zóna zcela jiného rázu než vše ostatní v tomto průvodci, obrovský vnitřní-venkovní komplex skluzavek, bazénů s vlnami, termálních lázní a dětských zón v Čestlicích na jižním okraji Prahy, který Pražané považují za svůj domácí dovolenkový cíl, když je počasí přemůže. Odemkni easter egg v jeho rozsahu: park pokrývá 21 000 čtverečních metrů pod jednou střechou a o zimních víkendech jeho návštěvnická populace dočasně převyšuje populaci několika okolních českých měst. Termální sekce udržuje bazény při teplotách od 32 do 38 stupňů; venkovní skluzavky fungují do října. Byl postaven v roce 2003 a okamžitě se stal nejnavštěvovanější volnočasovou atrakcí v Čechách. Někdy je největší quest odměnou jednoduše být teplý a mokrý ve středoevropském listopadu. V tom není hanba. I pražští rytíři potřebovali dny odpočinku.`,
    zh: `勇敢的探险家，布拉格水上宫殿是中欧最大的水上乐园——在本指南中与其他所有内容截然不同的一类任务区，布拉格南缘切斯特利采的一座巨大室内外综合体，滑梯、波浪池、温泉浴和儿童区一应俱全，布拉格人将其视为天气不好时的本地度假目的地。解锁其规模中的彩蛋：公园在单一屋顶下覆盖了21000平方米，冬季周末其游客人口暂时超过捷克周边几座城镇的居民数量。温泉区维持着从32度到38度不等的泳池温度；室外滑梯运营至十月。它建于2003年，立即成为波西米亚访问量最高的休闲景点。有时，最大的任务奖励就是在中欧的十一月里既温暖又湿漉漉地泡着。这没什么好惭愧的，布拉格的骑士们也需要休息日。`,
  },

  "strelecky-ostrov": {
    en: `Brave explorer, Střelecký Ostrov — Marksman's Island — is the most calmly perfect quest zone in central Prague, a slender river island in the Vltava between the National Theatre and the Legion Bridge whose poplar trees, wooden benches, and complete absence of commercial infrastructure create an urban sanctuary used almost exclusively by locals who know how to find it. The island is accessible only by a footbridge from the embankment on the New Town side. Unlock the Easter egg in its name: the island was used from the 16th century onwards as an archery and musketry practice ground by Prague's civic guards — the sharpshooters, střelci, who gave it its name. Today its only residents are the swans, ducks, and cormorants that nest in the poplars above the waterline. Bring a book. Bring lunch. Bring nothing else. The island does not need improving and neither do you when you are on it.`,
    cz: `Odvážný průzkumníku, Střelecký ostrov je nejklidněji dokonalou quest zónou v centru Prahy, úzký říční ostrov ve Vltavě mezi Národním divadlem a Legiovým mostem, jehož topolové stromy, dřevěné lavice a naprostá absence komerční infrastruktury vytvářejí městský útulek využívaný téměř výhradně místními, kteří vědí, jak ho najít. Ostrov je přístupný pouze lávkou z nábřeží na novostranské straně. Odemkni easter egg v jeho názvu: ostrov byl od 16. století využíván jako střelecká a mušketerská cvičná plocha pražskými občanskými strážemi — ostrostřelci, střelci, kteří mu dali jméno. Dnes jsou jeho jedinými obyvateli labutě, kachny a kormoráni hnízdicí v topolech nad hladinou vody. Přines si knihu. Přines si oběd. Přines nic jiného. Ostrov nepotřebuje vylepšovat a ani ty, když jsi na něm.`,
    zh: `勇敢的探险家，射手岛是布拉格市中心最平静完美的任务区，伏尔塔瓦河中国家剧院与军团桥之间的一座细长河中小岛，其白杨树、木质长椅和完全没有商业基础设施，创造了一处几乎只被知道如何找到它的本地人使用的城市庇护所。小岛只能通过新城一侧河岸的一座步行桥到达。解锁其名称中的彩蛋：自16世纪起，这座岛被布拉格市民卫队用作弓箭和火枪射击训练场——正是这些神枪手，střelci，给了它这个名字。如今，其唯一的居民是在水线上方白杨树中筑巢的天鹅、鸭子和鸬鹚。带一本书来，带午餐来，除此之外什么都不要带。小岛不需要任何改善，当你身在其上时，你也不需要。`,
  },

  "cafe-imperial": {
    en: `Brave explorer, Café Imperial is the most visually overwhelming food quest zone in Prague — an Art Deco café opened in 1914 whose interior is tiled from floor to ceiling in hand-painted ceramic panels, majolica reliefs, and mosaic columns so intricate that the renovation alone cost millions and took years to complete. Every surface tells a different story; every tile was fired at a different kiln. Unlock the Easter egg in its wartime history: during the Nazi occupation, Café Imperial served as a canteen for Wehrmacht officers — the same tables, the same ceramic walls, the same ceiling. After liberation, Praguers reclaimed it without a word. The schnitzel was simply kept on the menu. Sit at a window table, order the house goulash, and marvel that this room survived the 20th century intact. It barely did.`,
    cz: `Odvážný průzkumníku, Café Imperial je nejvizuálně ohromující food quest zónou v Praze — secesní kavárna otevřená v roce 1914, jejíž interiér je od podlahy ke stropu obložen ručně malovanými keramickými panely, majolikovými reliéfy a mozaikovými sloupy tak složitými, že samotná renovace stála miliony a trvala roky. Každý povrch vypráví jiný příběh; každý obklad byl vypálen v jiné peci. Odemkni easter egg v její válečné historii: během nacistické okupace sloužila Café Imperial jako kantýna pro důstojníky Wehrmachtu — stejné stoly, stejné keramické stěny, stejný strop. Po osvobození si ji Pražané znovu přivlastnili bez jediného slova. Vídeňský řízek byl jednoduše ponechán v menu. Sednout u okna, objednat si domácí guláš a žasnout, že tento pokoj přežil 20. století nedotčen. Sotva.`,
    zh: `勇敢的探险家，帝国咖啡馆是布拉格视觉上最令人震撼的美食任务区——一家开业于1914年的装饰艺术咖啡馆，其内部从地板到天花板铺满了手绘陶瓷板、彩陶浮雕和马赛克柱，精细程度使得仅修复工程就耗资数百万、历时数年方才完成。每个表面讲述着不同的故事；每块瓷砖都出自不同的窑炉。解锁其战时历史中的彩蛋：在纳粹占领期间，帝国咖啡馆曾作为国防军军官的餐厅——同样的桌椅，同样的陶瓷墙壁，同样的天花板。解放后，布拉格人不发一言地将其重新占据。炸排骨就这样继续留在了菜单上。坐在窗边的桌子旁，点一份招牌炖肉，惊叹于这个房间完好地熬过了20世纪。它几乎没能做到。`,
  },

  "u-fleku-brewery": {
    en: `Brave explorer, U Fleků is not merely a restaurant — it is Prague's oldest continuously operating brewery, founded in 1499, making it one of the oldest in the world. The dark lager brewed on the premises has been produced to the same recipe for over 500 years and is available nowhere else on Earth. Unlock the Easter egg concealed in the seating ritual: the waiters famously arrive unbidden at your table with shots of Becherovka herbal liqueur and add them to your bill automatically unless you firmly refuse. It has been this way for generations. The brewery's great hall seats 1,200 people simultaneously and has hosted emperors, presidents, and writers including Franz Kafka. It is the most legendary tavern dungeon in Bohemia. You are required by quest law to drink the dark beer.`,
    cz: `Odvážný průzkumníku, U Fleků není jen restaurace — je to nejstarší nepřetržitě fungující pivovar v Praze, založený v roce 1499, což z něj činí jeden z nejstarších na světě. Tmavé pivo vařené v areálu se vyrábí podle stejného receptu přes 500 let a není k dispozici nikde jinde na Zemi. Odemkni easter egg skrytý v rituálu sezení: číšníci proslule přicházejí neozváni ke stolu se skleničkami bylinného likéru Becherovka a přidávají je k účtu automaticky, pokud důrazně odmítneš. Tak to bylo po generace. Skvělý sál pivovaru pojme najednou 1 200 lidí a hostil císaře, prezidenty a spisovatele včetně Franze Kafky. Je to nejlegendárnější krčmový dungeon v Čechách. Zákon questu tě zavazuje vypít tmavé pivo.`,
    zh: `勇敢的探险家，弗列库酒馆不仅仅是一家餐厅——它是布拉格持续经营时间最长的酒厂，创立于1499年，是世界上最古老的酒厂之一。在此酿制的黑啤按照同一配方已生产了500多年，世界上其他地方无处可寻。解锁隐藏在就座仪式中的彩蛋：侍者以不请自来著称，他们会来到你的桌前送上贝赫洛夫卡草本利口酒，并自动计入账单，除非你坚决拒绝。几代人以来皆是如此。酒厂的大厅可同时容纳1200人，曾接待过皇帝、总统和包括弗朗茨·卡夫卡在内的作家。这是波西米亚最传奇的酒馆地牢。根据任务法则，你必须喝这杯黑啤。`,
  },

  "city-of-prague-museum": {
    en: `Brave explorer, the Museum of the City of Prague is the most intimate quest zone for understanding how Prague actually works — a Neo-Renaissance building in Nové Město housing the greatest cartographic treasure in Bohemia: the Langweil Model, a papier-mâché scale model of Prague as it appeared in 1826–1837, constructed by lithographer Antonín Langweil over eleven years with such obsessive precision that individual roof tiles, window frames, and garden plants are visible. Unlock the Easter egg built into the model itself: Langweil worked at a scale of 1:480 and included over 2,000 buildings, many of which no longer exist — the model is the only surviving record of entire neighbourhoods demolished in the late 19th century Jewish Quarter clearances. You can walk around a lost city preserved in paper. The model is updated to reflect demolitions that occurred after Langweil died. Someone has been maintaining this paper city for 200 years.`,
    cz: `Odvážný průzkumníku, Muzeum hlavního města Prahy je nejintimnější quest zónou pro pochopení toho, jak Praha skutečně funguje — neorenezanční budova v Novém Městě ukrývající největší kartografický poklad v Čechách: Langweilův model, papírmaché maketa Prahy tak, jak vypadala v letech 1826–1837, vytvořená litografem Antonínem Langweilem za jedenáct let s takovou obsedantní přesností, že jsou viditelné jednotlivé střešní tašky, okenní rámy a zahradní rostliny. Odemkni easter egg zabudovaný v samotném modelu: Langweil pracoval v měřítku 1:480 a zahrnul přes 2 000 budov, mnohé z nichž již neexistují — model je jediným dochovaným záznamem celých čtvrtí zbořených při pozdně 19. století asanaci Josefova. Můžeš procházet kolem ztraceného města zachovaného v papíru. Model je aktualizován, aby odrážel demolice, které nastaly po Langweilově smrti. Někdo udržuje toto papírové město 200 let.`,
    zh: `勇敢的探险家，布拉格市立博物馆是理解布拉格真实运作方式最亲切的任务区——新城区一座新文艺复兴风格建筑，收藏着波西米亚最重要的地图学珍品：朗威尔模型，一座用纸浆制作的1826至1837年间布拉格城市比例模型，由石印师安东宁·朗威尔历经十一年以近乎强迫症的精准度构建，单个屋顶瓦片、窗框和花园植物均清晰可见。解锁内置于模型本身的彩蛋：朗威尔以1:480的比例工作，纳入了2000余座建筑，其中许多已不复存在——该模型是19世纪末犹太区清拆中整批街区被夷平的唯一现存记录。你可以漫步于一座保存在纸张中的失落之城。模型持续更新，以反映朗威尔去世后发生的拆除事件。有人已经维护这座纸质城市长达200年。`,
  },

  "smetana-museum": {
    en: `Brave explorer, the Smetana Museum occupies a former waterworks building on the Vltava riverbank — a small but fiercely dedicated quest zone honouring Bedřich Smetana, the composer who essentially invented Czech national music. His symphonic cycle Má vlast — "My Homeland" — is performed every year to open the Prague Spring Music Festival, a tradition unbroken since 1946. Unlock the heartbreaking Easter egg: Smetana went completely deaf in 1874, at the height of his powers. He composed his most celebrated works, including the entire second half of Má vlast, in total silence — much like Beethoven before him. He could hear none of it. A letter survives in which he describes the constant high-pitched ringing in his ears. The museum holds his piano, his manuscripts, and the silence he composed through. Stand here and consider what that cost.`,
    cz: `Odvážný průzkumníku, Muzeum Bedřicha Smetany sídlí v bývalé budově vodárny na nábřeží Vltavy — malá, ale vášnivě oddaná quest zóna uctívající Bedřicha Smetanu, skladatele, který v podstatě vynalezl českou národní hudbu. Jeho symfonický cyklus Má vlast je každoročně prováděn k zahájení Pražského jara, tradice nepřerušená od roku 1946. Odemkni srdcervoucí easter egg: Smetana zcela ohluchl v roce 1874, na vrcholu svých tvůrčích sil. Svá nejslavnější díla, včetně celé druhé poloviny Mé vlasti, složil v naprostém tichu — podobně jako před ním Beethoven. Nic z toho neslyšel. Dochoval se dopis, v němž popisuje neustálé vysoké pískání v uších. Muzeum uchovává jeho klavír, jeho rukopisy a ticho, skrze které tvořil. Postav se zde a zamysli se, co ho to stálo.`,
    zh: `勇敢的探险家，斯美塔那博物馆坐落于伏尔塔瓦河畔的一座旧水务建筑内——一个规模不大却充满热忱的任务区，以纪念贝德里赫·斯美塔那，这位实际上发明了捷克民族音乐的作曲家。他的交响诗套曲《我的祖国》每年都会在布拉格之春音乐节开幕时演奏，这一传统自1946年起从未中断。解锁令人心碎的彩蛋：斯美塔那于1874年在其创作巅峰期完全失聪。他在完全的寂静中创作了最著名的作品，包括《我的祖国》的整个下半部分——就像在他之前的贝多芬一样。他什么都听不见。有一封信留存至今，其中描述了他耳中持续的高音嗡鸣。博物馆收藏着他的钢琴、他的手稿，以及他在其中作曲的那片寂静。站在这里，想想那意味着什么。`,
  },

  "stromovka-park": {
    en: `Brave explorer, Stromovka is Prague's oldest and most regal parkland quest zone — a former royal hunting ground established by King Přemysl Otakar II in the 13th century, converted into a public park in 1804, making it one of the first public parks in Central Europe. Its ancient oaks predate the city's modern districts entirely; some were saplings when Charles IV was emperor. Unlock the Easter egg buried underground: Rudolf II, obsessed with his gardens, had an underground canal tunnel built in 1593 to divert water from the Vltava River directly into the park's ponds — a feat of Renaissance hydraulic engineering that still functions today. The tunnel is nearly 1,100 metres long and was hand-dug entirely by workers using 16th-century tools. Prague's most peaceful park hides an imperial water pipe beneath every footstep.`,
    cz: `Odvážný průzkumníku, Stromovka je nejstarší a nejkrálovštější parková quest zóna Prahy — bývalá královská obora zřízená králem Přemyslem Otakarem II. ve 13. století, přeměněná na veřejný park v roce 1804, čímž se stala jedním z prvních veřejných parků ve střední Evropě. Její staré duby předcházejí moderním čtvrtím města zcela; některé byly semenáče, když byl Karel IV. císařem. Odemkni easter egg pohřbený pod zemí: Rudolf II., posedlý svými zahradami, nechal v roce 1593 postavit podzemní kanálový tunel, který odváděl vodu z Vltavy přímo do parkovních rybníků — mistrovský kousek renesančního hydraulického inženýrství, který funguje dodnes. Tunel je téměř 1 100 metrů dlouhý a byl celý ručně vykopán dělníky pomocí nástrojů 16. století. Nejklidnější park Prahy ukrývá pod každým krokem císařský vodovod.`,
    zh: `勇敢的探险家，斯特罗莫夫卡是布拉格最古老、最具王室气息的公园任务区——由国王普热米斯尔·奥托卡尔二世于13世纪建立的前皇家狩猎场，于1804年改建为公共公园，使其成为中欧最早的公共公园之一。其古老的橡树完全早于城市的现代街区；当查理四世还是皇帝时，其中一些还只是幼苗。解锁埋藏于地下的彩蛋：痴迷于自己花园的鲁道夫二世于1593年下令修建了一条地下运河隧道，将伏尔塔瓦河的水直接引入公园的池塘——这是一项至今仍在运作的文艺复兴时期水利工程壮举。隧道全长近1100米，完全由工人用16世纪的工具手工挖掘而成。布拉格最宁静的公园，在每一个脚步之下都隐藏着一条帝国水管。`,
  },

  "divoka-sarka": {
    en: `Brave explorer, Divoká Šárka is Prague's wildest natural quest zone — a nature reserve within the city limits that looks and feels like a Bohemian wilderness, complete with rock formations, a river gorge, a lake for summer swimming, and woodland trails that stretch for kilometres with no buildings in sight. The name comes from the legend of Šárka, a warrior woman from Czech mythology who lured an enemy chieftain to his death with a combination of wine, beauty, and ambush — a story so dramatically local it gave Smetana material for one of his Má vlast movements. Unlock the Easter egg in the summer season: the natural reservoir known as Džbán, carved into the valley, becomes an outdoor swimming lake used by thousands of Praguers who treat it as their private beach. No tourist infrastructure, no entry fee. Just water, trees, and the city pretending it is not there.`,
    cz: `Odvážný průzkumníku, Divoká Šárka je nejdivočejší přírodní quest zónou Prahy — přírodní rezervace v hranicích města, která vypadá a působí jako bohemské divočina, s skalními útvary, říčním kaňonem, jezerem pro letní koupání a lesními stezkami táhnoucími se kilometry bez jediné budovy v dohledu. Název pochází z legendy o Šárce, válečné ženě z české mytologie, která lákala nepřátelského náčelníka do záhuby kombinací vína, krásy a zálohy — příběh tak dramaticky lokální, že poskytl Smetanovi materiál pro jeden z pohybů jeho Má vlasti. Odemkni easter egg v letní sezóně: přírodní nádrž zvaná Džbán, vytesaná do údolí, se stává přírodním koupacím jezerem využívaným tisíci Pražanů, kteří ji považují za svou soukromou pláž. Žádná turistická infrastruktura, žádné vstupné. Jen voda, stromy a město, které předstírá, že tam není.`,
    zh: `勇敢的探险家，迪沃卡·沙尔卡是布拉格最狂野的自然任务区——城市范围内的一处自然保护区，其外貌和感觉都像是波西米亚的原始荒野，有岩石地貌、河流峡谷、夏季游泳湖泊，以及绵延数公里、视野内不见任何建筑物的林间小径。这个名字来源于捷克神话中战士女性沙尔卡的传说，她用葡萄酒、美貌和伏击诱使一位敌方首领走向死亡——这个故事极具地方色彩，以至于斯美塔那将其作为《我的祖国》某一乐章的素材。解锁夏季的彩蛋：被称为"水壶"的天然水库，凿入山谷之中，成为一个被数以千计的布拉格市民当作私人海滩使用的露天游泳湖。没有旅游设施，没有入场费。只有水、树木，以及一座假装自己不存在的城市。`,
  },

  "botanical-garden": {
    en: `Brave explorer, Prague's Botanical Garden in Troja is the city's most peacefully underexplored quest zone — a terraced hillside garden tumbling down toward the Vltava, home to over 3,500 plant species across outdoor gardens and a vast tropical greenhouse that creates a sudden ambush of equatorial heat the moment you step inside. Unlock the Easter egg growing in the vineyard: the garden maintains a small traditional Czech vineyard on its terraced slopes, producing actual wine sold only at the garden's own shop in quantities so limited they sell out before most visitors learn of them. The vineyard dates to an era when Troja's hillsides were entirely covered in grape cultivation, long before Prague expanded to swallow the neighbourhood. The giant water lilies in the greenhouse can support the weight of a small child standing on a single leaf. This is documented. Children have tested it.`,
    cz: `Odvážný průzkumníku, Botanická zahrada v Troji je nejklidněji neprobádanou quest zónou Prahy — terasovitá zahrada svažující se k Vltavě, domov přes 3 500 druhů rostlin v venkovních zahradách a rozsáhlém tropickém skleníku, který vytváří náhlý záchvat rovníkového tepla, jakmile vejdeš dovnitř. Odemkni easter egg rostoucí ve vinici: zahrada udržuje malou tradiční českou vinici na svých terasovitých svazích, produkující skutečné víno prodávané pouze v zahradním vlastním obchodě v takových omezeném množství, že se vyprodá, než se o nich většina návštěvníků dozví. Vinice pochází z éry, kdy trojské svahy byly zcela pokryty pěstováním hroznů, dávno předtím, než Praha expandovala a pohltila čtvrť. Obří lekníny ve skleníku unesou váhu malého dítěte stojícího na jediném listu. Je to zdokumentováno. Děti to otestovaly.`,
    zh: `勇敢的探险家，特罗亚的布拉格植物园是城市中最宁静却鲜有探索的任务区——一座阶梯式山坡花园，沿坡而下通向伏尔塔瓦河，收藏着户外花园和一座宽阔热带温室中超过3500种植物，踏入温室的瞬间便会遭遇一场赤道热带气候的突然伏击。解锁生长在葡萄园中的彩蛋：植物园在其阶梯式山坡上维护着一小片传统捷克葡萄园，生产出的葡萄酒仅在园内自营商店出售，数量如此有限，以至于大多数游客在得知消息之前便已售罄。这片葡萄园的历史可追溯至特罗亚山坡完全被葡萄种植覆盖的年代，那时布拉格尚未扩张并吞并这一街区。温室中的巨型睡莲能够承受一个站在单片叶子上的小孩子的重量。这已有记录。孩子们已经测试过了。`,
  },

  "letna-park": {
    en: `Brave explorer, Letná Park crowns the bluff above the Vltava like a secret level unlocked only by those willing to climb. Few tourists make it here — which means its legendary panoramic view of Prague's red rooftops is practically yours alone. Unlock the greatest Easter egg in all of Prague: the giant metronome ticking on the park's terrace replaced the world's largest Stalin statue, a 14,000-tonne colossus demolished in 1962. The Soviets built tunnels beneath it to store nuclear supplies. Today the metronome ticks over an abandoned skatepark carved into its foundations — a monument to absurdity that only this city could produce. Grab a beer from the legendary beer garden and survey your conquered kingdom.`,
    cz: `Odvážný průzkumníku, Letenský park korunuje sráz nad Vltavou jako tajná úroveň odemčená jen těm, kdo jsou ochotni vylézt. Málo turistů se sem dostane — což znamená, že jeho legendární panoramatický výhled na červené střechy Prahy je prakticky jen tvůj. Odemkni největší easter egg celé Prahy: obrovský metronom tikající na terase parku nahradil největší Stalinovu sochu na světě, kolos o hmotnosti 14 000 tun zbořený v roce 1962. Sověti pod ním vybudovali tunely pro uskladnění jaderných zásob. Dnes metronom tiká nad opuštěným skateparkem vysekaným do jeho základů — monument absurdity, který by mohl vyprodukovat jen toto město. Vezmi si pivo z legendární pivní zahrady a prohlédni si své dobyté království.`,
    zh: `勇敢的探险家，莱特纳公园如同一个只有愿意攀登者才能解锁的秘密关卡，雄踞于伏尔塔瓦河上方的峭壁之上。鲜有游客到达这里——这意味着其俯瞰布拉格红色屋顶的传奇全景几乎只属于你一人。解锁布拉格最伟大的彩蛋：公园露台上滴答作响的巨大节拍器，取代了世界上最大的斯大林雕像，那是一座重达14000吨的庞然大物，于1962年被拆除。苏联人在其下方修建了隧道，用于储存核物资。如今，节拍器在嵌入其地基的废弃滑板公园上方滴答作响——这是一座只有这座城市才能产生的荒诞纪念碑。从传奇啤酒花园取一杯啤酒，俯瞰你征服的王国。`,
  },

  "prokopske-valley": {
    en: `Brave explorer, Prokopské Valley is Prague's most geologically dramatic quest zone — a protected nature reserve within the city limits where limestone cliffs, rare steppe vegetation, and a former quarry have created a landscape that belongs to the Bohemian countryside rather than a European capital. The valley floor follows a stream through gorges flanked by white rock faces streaked with rust and ochre. Unlock the Easter egg written into the geology: the limestone formations here are over 400 million years old — Silurian and Devonian period rock that contains fossilised marine creatures from a time when this entire region was a shallow tropical sea. You can find trilobite fossils embedded in the cliff faces with no equipment beyond your eyes. The quarry carved into the southern end of the valley operated until the mid-20th century; its blasted terraces now host rare orchids. Prague sits on top of a fossilised ocean. Most Praguers have never considered this.`,
    cz: `Odvážný průzkumníku, Prokopské údolí je geologicky nejdramatičtější quest zónou Prahy — chráněná přírodní rezervace v hranicích města, kde vápencové útesy, vzácná stepní vegetace a bývalý lom vytvořily krajinu, která patří spíše do české venkoviny než do evropského hlavního města. Dno údolí sleduje potok skalními roklinami lemovanými bílými skalními stěnami posetými rzí a okrem. Odemkni easter egg vepsaný do geologie: vápencové útvary zde jsou starší než 400 milionů let — silurské a devonské horniny obsahující zkameněliny mořských tvorů z doby, kdy byl celý tento region mělkým tropickým mořem. Zkameněliny trilobitů můžeš najít zasazené do skalních stěn bez jakéhokoli vybavení kromě svých očí. Lom vytesaný do jižního konce údolí fungoval až do poloviny 20. století; jeho vytrhaná terasy nyní hostí vzácné orchideje. Praha sedí na zkameněném oceánu. Většina Pražanů to nikdy neuvažovala.`,
    zh: `勇敢的探险家，普罗科普斯卡峡谷是布拉格地质上最壮观的任务区——城市范围内的一处自然保护区，石灰岩悬崖、珍稀草原植被和一处旧采石场共同造就了一片更属于波西米亚乡野而非欧洲首都的景观。峡谷底部沿着一条小溪穿越两侧白色岩壁的峡谷延伸，岩壁上布满铁锈色和赭色条纹。解锁镌刻在地质中的彩蛋：这里的石灰岩地层已有超过4亿年的历史——志留纪和泥盆纪的岩石中包含着来自该地区曾是浅热带海洋时代的海洋生物化石。你无需任何工具，仅凭双眼便能在崖壁上找到三叶虫化石。凿入峡谷南端的采石场运营至20世纪中叶；其爆炸后形成的台地如今生长着稀有兰花。布拉格坐落于一片化石化的海洋之上，而大多数布拉格人从未想过这一点。`,
  },

  "petrin-hill": {
    en: `Brave explorer, Petřín Hill is Prague's greatest cheat code — a forested sanctuary rising 318 metres above the city, hiding more secrets per square metre than any dungeon in the questlog. Unlock the hidden truth: the Hunger Wall snaking across its slopes was built by Emperor Charles IV in 1360 not for defence, but as a public works project to feed the city's poor during a famine — medieval universal basic income carved in stone. Ride the funicular like a true veteran explorer, then conquer the Eiffel Tower lookalike at the summit (one-fifth the height, built the same year). The rose gardens below bloom with a hundred varieties that never appear on any map. This is your hidden sanctuary zone.`,
    cz: `Odvážný průzkumníku, Petřín je největší cheat code Prahy — zalesněná svatyně tyčící se 318 metrů nad městem, ukrývající více tajemství na čtvereční metr než jakýkoliv dungeon v questlogu. Odemkni skrytou pravdu: Hladová zeď vinoucí se po svazích byla postavena císařem Karlem IV. v roce 1360 ne pro obranu, ale jako veřejně prospěšný projekt k nakrmení chudých měšťanů během hladomoru — středověký základní příjem vytesaný v kameni. Jeď lanovkou jako skutečný veterán-průzkumník, pak dobuď napodobeninu Eiffelovy věže na vrcholu (pětina výšky, postavena ve stejném roce). Růžové zahrady pod ní kvetou se stovkou odrůd, které se neobjevují na žádné mapě. Toto je tvá skrytá svatyně.`,
    zh: `勇敢的探险家，彼得任山是布拉格最伟大的秘籍——一片海拔318米的林木圣地，每平方米隐藏的秘密比任务日志中的任何地牢都要多。解锁隐藏的真相：蜿蜒于山坡上的饥饿之墙建于1360年，由查理四世皇帝下令修建，目的并非防御，而是作为公共工程项目在饥荒期间养活城市穷人——刻在石头上的中世纪全民基本收入。乘坐缆车如真正的老牌探险家一般，然后征服山顶上的埃菲尔铁塔仿制品（高度为五分之一，建于同年）。山下的玫瑰园中盛开着百余个品种，从未出现在任何地图上。这是你的隐藏圣地。`,
  },

  "hvezda-game-reserve": {
    en: `Brave explorer, Hvězda Game Reserve is Prague's most mathematically improbable quest zone — a Renaissance star-shaped hunting lodge built in 1556 at the geometric centre of a vast woodland that Habsburg Archduke Ferdinand II designed in the shape of a six-pointed star when viewed from above. He had the entire forest cleared and replanted in the star pattern, creating a landscape you can only fully appreciate from a map. Unlock the Easter egg buried under the building: the star-shaped château contains an underground tunnel system built for emergency escape, and the basement houses a permanent exhibition on the White Mountain Battle of 1620 — the decisive confrontation fought in the meadows directly outside this building that ended Czech Protestant independence for 300 years. The battle's archaeological finds are displayed in rooms beneath the rooms where nobles once hunted. History runs beneath everything in Prague.`,
    cz: `Odvážný průzkumníku, Letohrádek Hvězda je matematicky nejpravděpodobnější quest zónou Prahy — renesanční šesticípý lovecký zámeček postavený v roce 1556 v geometrickém středu rozsáhlého lesa, který habsburský arcivévoda Ferdinand II. navrhl ve tvaru šestipaprsčité hvězdy při pohledu shora. Nechal celý les vymýtit a znovu vysadit ve hvězdném vzoru, čímž vytvořil krajinu, kterou lze plně ocenit pouze z mapy. Odemkni easter egg pohřbený pod budovou: hvězdicový zámeček obsahuje podzemní tunelový systém postavený pro nouzový únik a suterén ukrývá stálou expozici o Bitvě na Bílé hoře roku 1620 — rozhodující střetnutí svedené na loukách přímo před touto budovou, které ukončilo českou protestantskou nezávislost na 300 let. Archeologické nálezy z bitvy jsou vystaveny v místnostech pod místnostmi, kde kdysi šlechtici lovili. Historie probíhá pod vším v Praze.`,
    zh: `勇敢的探险家，赫韦兹达猎苑是布拉格数学上最不可思议的任务区——一座建于1556年的文艺复兴时期星形狩猎行宫，位于哈布斯堡大公费迪南德二世从俯视角度设计成六角星形的广阔林地的几何中心。他命人将整片森林清除，再按星形图案重新种植，创造出一片只有从地图上才能完全欣赏的景观。解锁埋藏在建筑地下的彩蛋：星形城堡内建有用于紧急逃脱的地下隧道系统，地下室设有关于1620年白山之战的永久展览——这场决定性的对抗就发生在这座建筑正前方的草地上，终结了捷克新教独立长达300年。战役的考古发现陈列在昔日贵族狩猎房间的下方房间里。历史流淌于布拉格的一切之下。`,
  },

  "vinohrady-rose-garden": {
    en: `Brave explorer, the Vinohrady Rose Garden — Havlíčkovy sady — is Prague's most civilised hidden quest zone, a hillside park in the Vinohrady neighbourhood that most tourists never reach, containing a historic vineyard, a functioning winery pavilion open to the public, and a rose garden of startling beauty that peaks in June when the entire hillside turns red, pink, and white. Unlock the Easter egg fermenting on the premises: the park maintains a traditional vineyard descended from the same grape-growing tradition that once covered all of Vinohrady — the name literally means "vineyards" — and the winery pavilion holds tastings of wine produced from grapes still harvested here annually. The park was named after journalist Karel Havlíček Borovský, who was exiled by the Habsburgs for his political writing. His newspaper, Národní noviny, was the first truly independent Czech press. He is buried at Vyšehrad. The roses were planted later but they are still angry.`,
    cz: `Odvážný průzkumníku, Vinohrady Růžová zahrada — Havlíčkovy sady — je nejcivilizovanější skrytou quest zónou Prahy, svažitý park ve čtvrti Vinohrady, kam většina turistů nikdy nedorazí, obsahující historickou vinici, fungující vinařský pavilon otevřený veřejnosti a růžovou zahradu překvapivé krásy, která dosáhne vrcholu v červnu, kdy se celý svah obarví červenou, růžovou a bílou. Odemkni easter egg kvasící v areálu: park udržuje tradiční vinici pocházející ze stejné tradice pěstování hroznů, která kdysi pokrývala celé Vinohrady — název doslova znamená "vinice" — a vinařský pavilon pořádá degustace vína vyrobeného z hroznů stále sklízených zde každoročně. Park byl pojmenován po novináři Karlu Havlíčkovi Borovském, kterého Habsburkové vyhnali za jeho politické psaní. Jeho noviny, Národní noviny, byly prvním skutečně nezávislým českým tiskem. Je pohřben na Vyšehradě. Růže byly vysazeny později, ale stále jsou naštvaně.`,
    zh: `勇敢的探险家，维诺赫拉迪玫瑰园——哈夫利切科维萨迪——是布拉格最优雅的隐藏任务区，维诺赫拉迪街区的一处山坡公园，大多数游客从未到达，园内有一座历史悠久的葡萄园、一个对公众开放的运营中的葡萄酒亭，以及一座令人惊艳的玫瑰园，六月份整个山坡变成红、粉和白色时达到顶峰。解锁在场地内发酵的彩蛋：公园维护着一片传统葡萄园，承袭着曾经覆盖整个维诺赫拉迪的种葡萄传统——这个名字字面意思就是"葡萄园"——葡萄酒亭提供用每年仍在此采摘的葡萄酿制的葡萄酒品鉴。公园以记者卡雷尔·哈夫利切克·博罗夫斯基命名，他因政治写作被哈布斯堡王朝流放。他的报纸《国家报》是首份真正独立的捷克报刊。他长眠于维谢赫拉德。玫瑰是后来种植的，但仍然充满愤怒。`,
  },

  "kunraticky-forest": {
    en: `Brave explorer, Kunratický les is Prague's most ancient woodland quest zone — a forest reserve in the southern city that has been continuously forested since the medieval period and contains the ruins of Nový Hrad castle, a Gothic fortress built by King Wenceslas IV around 1411 that has been slowly returning to the earth for 600 years. The castle ruins sit in a forest clearing accessible only on foot, reached by trails that feel genuinely remote despite being fifteen minutes from the city centre by tram. Unlock the Easter egg in the forest's ecology: Kunratický les contains a stream-fed valley system with documented populations of otters — an animal that had disappeared from Prague entirely during the industrial period and returned naturally in the 1990s as water quality improved. The otters were not reintroduced. They came back because the city got cleaner. Environmental recovery as a quest reward. It took fifty years.`,
    cz: `Odvážný průzkumníku, Kunratický les je nejstarší lesní quest zónou Prahy — lesní rezervace v jižním městě, která je nepřetržitě zalesněna od středověku a obsahuje ruiny Nového Hradu, gotické pevnosti postavené králem Václavem IV. kolem roku 1411, která se pomalu vrací do země 600 let. Hradní ruiny sedí v lesní mýtině přístupné pouze pěšky, dosažitelné stezkami, které se cítí opravdu vzdálené, přestože jsou patnáct minut od centra města tramvají. Odemkni easter egg v ekologii lesa: Kunratický les obsahuje systém potokem zásobeného údolí s dokumentovanými populacemi vyder — zvíře, které v průmyslovém období z Prahy zcela zmizelo a přirozeně se vrátilo v 90. letech, jak se zlepšila kvalita vody. Vydry nebyly reintrodukovány. Vrátily se, protože město se stalo čistším. Ekologická obnova jako quest odměna. Trvalo to padesát let.`,
    zh: `勇敢的探险家，库纳尔提茨基森林是布拉格最古老的林地任务区——城市南部的一片森林保护区，自中世纪起便持续被森林覆盖，内有新赫拉德城堡的废墟，这座哥特式要塞由国王瓦茨拉夫四世于约1411年建造，已经缓慢地归还于大地600年。城堡废墟坐落在只能徒步到达的林中空地，通往那里的小径尽管距市中心乘电车只需十五分钟，却给人一种真正远离尘嚣的感觉。解锁森林生态中的彩蛋：库纳尔提茨基森林中有一个溪流滋养的山谷系统，记录在案的水獭种群在此栖居——这种动物在工业时期已完全从布拉格消失，随着水质改善，于20世纪90年代自然回归。水獭并未被重新引入，它们回来是因为这座城市变得更干净了。环境恢复作为任务奖励，历时五十年。`,
  },

  "troja-chateau-garden": {
    en: `Brave explorer, Troja Château Garden is the most Versailles-adjacent quest zone in Prague — a French Baroque formal garden laid out in the late 17th century in front of a summer palace that the Sternberg family built to impress Holy Roman Emperor Leopold I when he visited from Vienna. The château's grand staircase is decorated with life-sized mythological figures in combat, carved with such violent energy they appear to be falling off the building. Unlock the Easter egg in the estate's vineyard: Troja Château operates one of the most prestigious traditional vineyards in Bohemia, producing Riesling and Saint Laurent wines whose annual harvest is celebrated with a festival each September. The château building now belongs to the City of Prague and houses a permanent collection of 19th-century Czech painting. The garden is free. The wine is not. Both are necessary.`,
    cz: `Odvážný průzkumníku, Trojský zámecký zahrada je quest zónou Prahy nejblíže Versailles — francouzská barokní zahrada pravidelného stylu, rozložená na konci 17. století před letním palácem, který rodina Šternberků postavila k okouzlení císaře Svaté říše římské Leopolda I., když navštívil z Vídně. Velkolepé schodiště zámku je zdobeno živými mytologickými figurami v boji, vytesanými s takovou násilnou energií, že se zdá, jako by padaly z budovy. Odemkni easter egg ve vinici statku: Trojský zámek provozuje jednu z nejprestižnějších tradičních vinic v Čechách, produkující ryzlink a vína svatovavřinecké, jejichž každoroční sklizeň je slavena festivalem každý září. Budova zámku nyní patří Hlavnímu městu Praze a ukrývá stálou sbírku českého malířství 19. století. Zahrada je zdarma. Víno není. Obojí je nezbytné.`,
    zh: `勇敢的探险家，特罗亚城堡花园是布拉格最接近凡尔赛的任务区——一座17世纪末在一座夏宫前铺设的法式巴洛克规则式花园，斯滕伯格家族建造这座夏宫，是为了在神圣罗马帝国皇帝利奥波德一世从维也纳前来造访时给他留下深刻印象。城堡的宏伟楼梯装饰着真人大小的神话人物交战场景，雕刻时充满如此猛烈的能量，以至于它们看起来像是正从建筑上跌落下来。解锁庄园葡萄园中的彩蛋：特罗亚城堡经营着波西米亚最负盛名的传统葡萄园之一，生产雷司令和圣洛朗葡萄酒，每年九月都会举行节庆活动庆祝丰收。城堡建筑现属布拉格市所有，收藏着19世纪捷克绘画的永久藏品。花园免费入场，葡萄酒则不然。两者都是必要的。`,
  },

  "cisarsky-ostrov": {
    en: `Brave explorer, Císařský Ostrov — Emperor's Island — is Prague's most genuinely wild quest zone, an uninhabited river island in the Vltava north of the city that has been a protected nature reserve since 1988 and is largely inaccessible to casual visitors. The island's floodplain forest is one of the last surviving examples of natural Vltava riverine habitat, home to kingfishers, herons, beavers, and over 300 plant species in a space that feels nothing like a capital city. Unlock the Easter egg in its royal past: the island was a private hunting ground for the Habsburg emperors, used by Rudolf II for falconry and maintained as an imperial game reserve for centuries. After 1918, it passed to the Czechoslovak state, was briefly used for agriculture, and eventually abandoned to nature. The beavers arrived on their own in the 1990s. Nobody invited them. They are the best thing that happened to the island.`,
    cz: `Odvážný průzkumníku, Císařský ostrov je nejopravdověji divokou quest zónou Prahy, neobydlený říční ostrov ve Vltavě severně od města, který je od roku 1988 chráněnou přírodní rezervací a je z velké části nepřístupný běžným návštěvníkům. Lužní les ostrova je jedním z posledních dochovaných příkladů přirozeného říčního biotopu Vltavy, domov ledňáčků, volavek, bobrů a více než 300 druhů rostlin v prostoru, který se nijak nepodobá hlavnímu městu. Odemkni easter egg v jeho královské minulosti: ostrov byl soukromým lovištěm habsburských císařů, Rudolf II. ho využíval pro sokolnictví a po staletí byl udržován jako císařská obora. Po roce 1918 přešel na československý stát, byl krátce využíván pro zemědělství a nakonec ponechán přírodě. Bobři přišli sami v 90. letech. Nikdo je nepozval. Jsou nejlepší věcí, která se ostrovu přihodila.`,
    zh: `勇敢的探险家，皇帝岛是布拉格最真正意义上的野性任务区，伏尔塔瓦河城北一座无人居住的河中岛屿，自1988年起被划为自然保护区，大体上不对普通游客开放。岛上的洪泛平原森林是伏尔塔瓦河天然河岸栖息地最后幸存的样本之一，翠鸟、苍鹭、海狸和300多种植物物种栖居于此，这个空间让你感觉完全不像身处一个首都城市。解锁其皇室过往中的彩蛋：这座岛屿曾是哈布斯堡皇帝的私人狩猎场，鲁道夫二世在此进行猎鹰活动，数百年来一直作为皇家猎苑维护。1918年后归属捷克斯洛伐克国家，短暂用于农业，最终被遗弃给自然。海狸于90年代自行到来，没有人邀请它们。它们是岛上发生的最好的事情。`,
  },

  "riegrovy-sady": {
    en: `Brave explorer, Riegrovy Sady is Prague's most beloved secret beer garden quest zone — a hillside park in Vinohrady neighbourhood that most tourists never discover, yet contains the greatest open-air beer garden in the city, with a panoramic view of Prague Castle across the valley that renders every tourist viewpoint redundant. Unlock the Easter egg in its Cold War history: beneath the park runs a network of civil defence tunnels built in the 1950s to shelter citizens during a nuclear attack, stretching under Vinohrady for kilometres. They have never been opened to the public. The hill above is blissfully unaware of what lies beneath — old men play chess, students drink Kozel, and dogs chase each other through the rose garden. The apocalypse bunker below is simply waiting. Enjoy the beer.`,
    cz: `Odvážný průzkumníku, Riegrovy sady jsou nejmilejší tajnou beer garden quest zónou Prahy — svažitý park ve čtvrti Vinohrady, který většina turistů nikdy neobjeví, přesto obsahuje největší letní zahradu ve městě s panoramatickým výhledem na Pražský hrad přes údolí, který činí každý turistický vyhlídkový bod nadbytečným. Odemkni easter egg v jeho historii studené války: pod parkem se vine síť civilní obrany tunelů postavených v 50. letech 20. století, aby ukryly občany během jaderného útoku, táhnoucí se pod Vinohrady na kilometry. Nikdy nebyly otevřeny veřejnosti. Kopec nahoře o tom, co leží pod ním, blažně neví — starci hrají šachy, studenti pijí Kozel a psi se honí navzájem přes růžovou zahradu. Apokalyptický kryt dole jen čeká. Užij si pivo.`,
    zh: `勇敢的探险家，里格罗维萨迪是布拉格最受喜爱的秘密啤酒花园任务区——维诺赫拉迪街区的一处山坡公园，大多数游客从未发现，却拥有城市中最棒的露天啤酒花园，俯瞰山谷对岸布拉格城堡的全景，使所有游客观景点都显得多余。解锁其冷战历史中的彩蛋：公园下方蜿蜒着一条20世纪50年代建造的民防隧道网络，旨在核攻击时为市民提供庇护，在维诺赫拉迪地下延伸数公里。这些隧道从未向公众开放。上方的山丘对其下方的一切浑然不觉——老人们下象棋，学生们喝着科泽尔啤酒，狗狗们在玫瑰园中你追我赶。下面的末日掩体只是在静静等待。享受你的啤酒吧。`,
  },

  "dancing-house": {
    en: `Brave explorer, the Dancing House — Tančící dům — is Prague's most controversial architectural quest unlock, a deconstructivist office building completed in 1996 by architects Vlado Milunić and Frank Gehry that locals immediately nicknamed "Fred and Ginger" after the two towers that appear to dance together along the Vltava embankment. It replaced a bombed-out gap site left by a stray American bomb in 1945 — the only building on the entire embankment to have been destroyed in WWII. Unlock the Easter egg at the top: the rooftop bar and restaurant called Ginger offers a 360-degree panoramic view of Prague that rivals any lookout tower in the city, yet almost no tourists know it exists. The building was fiercely opposed by President Václav Havel — whose apartment was in the adjacent building — until he changed his mind and became its biggest champion. The man who killed communism also saved a dancing office block.`,
    cz: `Odvážný průzkumníku, Tančící dům je nejkontroverznějším architektonickým quest odemčením Prahy, dekonstruktivistická kancelářská budova dokončená v roce 1996 architekty Vladem Milunićem a Frankem Gehrym, které místní okamžitě přezdívali "Fred a Ginger" po dvou věžích, jež se zdají tančit spolu podél vltavského nábřeží. Nahradila bombardováním vzniklou mezeru ponechanou zbloudilou americkou bombou v roce 1945 — jedinou budovu na celém nábřeží zničenou za druhé světové války. Odemkni easter egg nahoře: střešní bar a restaurace Ginger nabízí 360stupňový panoramatický výhled na Prahu soupeřící s jakoukoliv vyhlídkovou věží ve městě, přesto o jeho existenci téměř žádní turisté neví. Stavba se setkala s tvrdým odporem prezidenta Václava Havla — jehož byt byl v sousední budově — dokud si nepřehodnotil svůj postoj a nestal se jejím největším zastáncem. Muž, který zabil komunismus, také zachránil tančící kancelářský blok.`,
    zh: `勇敢的探险家，跳舞的房子是布拉格最具争议性的建筑任务解锁——一座由建筑师弗拉多·米卢尼奇和弗兰克·盖里于1996年完成的解构主义办公楼，当地人立即将其昵称为"弗雷德和金格尔"，因为两座塔楼看起来像是在沿伏尔塔瓦河岸共舞。它取代了一枚1945年迷失的美国炸弹留下的废墟空地——整条河岸上唯一一栋在二战中被摧毁的建筑。解锁顶部的彩蛋：名为金格尔的屋顶酒吧和餐厅提供可与城市任何瞭望塔媲美的360度全景，但几乎没有游客知道它的存在。这座建筑曾遭到总统瓦茨拉夫·哈维尔的强烈反对——他的公寓就在隔壁建筑里——直到他改变主意，成为其最大的支持者。那个终结共产主义的人，也拯救了一栋跳舞的办公楼。`,
  },

  "nusle-bridge": {
    en: `Brave explorer, Nusle Bridge is Prague's most structurally imposing and psychologically loaded quest zone — a 485-metre Communist-era motorway viaduct completed in 1973 that strides across the Nusle Valley on five enormous pillars, carrying both road traffic and the metro line C inside its hollow concrete deck. At 42 metres above the valley floor, it became notorious as a site of tragedy and was eventually fitted with safety barriers and an emergency phone line — both visible from below. Unlock the Easter egg built into the construction: the bridge's hollow box girder deck is so vast that the metro runs through it entirely enclosed, meaning Prague's commuters travel through the interior of a bridge without realising it. The metro stations at each end — Vyšehrad and Pankrác — are themselves built into the bridge approaches. The engineering is extraordinary. The viaduct does not care about your feelings. It simply holds the city together.`,
    cz: `Odvážný průzkumníku, Nuselský most je nejvíce konstrukčně impozantní a psychologicky zatíženou quest zónou Prahy — 485metrový dálniční viadukt z komunistické éry dokončený v roce 1973, který překračuje Nuselské údolí na pěti obrovských pilířích a nese silniční provoz i linku metra C uvnitř svého dutého betonového mostu. Ve výšce 42 metrů nad dnem údolí se proslavil jako místo tragédií a byl nakonec vybaven ochrannými zábradlími a tísňovou telefonní linkou — obojí viditelné zdola. Odemkni easter egg zabudovaný do konstrukce: dutý skříňový most mostu je tak rozlehlý, že metro jím jede zcela uzavřeno, což znamená, že pražští pendleři cestují uvnitř mostu, aniž by si to uvědomili. Stanice metra na obou koncích — Vyšehrad a Pankrác — jsou samy zabudovány do přístupových tras mostu. Inženýrství je mimořádné. Viadukt se nestará o tvé pocity. Jednoduše drží město pohromadě.`,
    zh: `勇敢的探险家，努斯尔大桥是布拉格结构上最令人叹为观止、心理上最沉重的任务区——一座于1973年竣工的共产主义时代高速公路高架桥，以五根巨大的桥墩横跨努斯尔山谷，其中空混凝土桥面同时承载着公路交通和地铁C线。桥面距谷底42米，这里曾以悲剧事件著称，最终被安装了安全护栏和紧急电话线——两者从桥下均清晰可见。解锁内置于建筑中的彩蛋：大桥的中空箱梁桥面如此宽阔，地铁在其中完全封闭地行驶，这意味着布拉格的通勤者是在大桥内部穿行而不自知。两端的地铁站——维谢赫拉德站和潘克拉茨站——本身就建在大桥引道之内。这项工程非同凡响。高架桥不关心你的感受，它只是简单地将这座城市凝聚在一起。`,
  },

  "lobkowicz-palace": {
    en: `Brave explorer, Lobkowicz Palace inside Prague Castle is the only building in the entire castle complex that remains in private ownership — and that private owner happens to hold one of the most extraordinary personal art collections in Europe. The Lobkowicz family reclaimed their palace after 1989 following Communist confiscation, and immediately opened it to the public with their ancestral collection intact: original manuscripts by Beethoven and Mozart, armour, paintings by Bruegel and Canaletto, and instruments from across four centuries. Unlock the Easter egg in the music archive: the palace holds Beethoven's personal handwritten score of his Fourth and Fifth Symphonies, with his own corrections visible in a different ink — you can see the composer changing his mind mid-composition. The family audio guide is narrated by the current Prince Lobkowicz himself. Nowhere else in Prague does a living aristocrat explain his own ancestors' belongings in your earphones. Enter as a guest of the oldest surviving dynasty in Bohemia.`,
    cz: `Odvážný průzkumníku, Lobkovický palác uvnitř Pražského hradu je jedinou budovou v celém hradním komplexu, která zůstává v soukromém vlastnictví — a ten soukromý vlastník náhodou drží jednu z nejpozoruhodnějších osobních uměleckých sbírek v Evropě. Rodina Lobkowiczů si po roce 1989 svůj palác znovu získala po komunistickém zabavení a okamžitě ho otevřela veřejnosti s rodovou sbírkou nedotčenou: originální rukopisy Beethovena a Mozarta, zbroje, obrazy Bruegela a Canaletta a nástroje ze čtyř století. Odemkni easter egg v hudebním archivu: palác uchovává Beethovenovu osobní ručně psanou partituru jeho Čtvrté a Páté symfonie s jeho vlastními opravami viditelnými v jiném inkoustu — vidíš, jak skladatel mění názor uprostřed kompozice. Rodinný audioprůvodce vypráví sám současný kníže Lobkowicz. Nikde jinde v Praze živý aristokrat nevysvětluje majetek svých předků ve tvých sluchátkách. Vstup jako host nejstarší přeživší dynastie v Čechách.`,
    zh: `勇敢的探险家，布拉格城堡内的洛布科维茨宫是整个城堡建筑群中唯一仍为私人所有的建筑——而这位私人业主恰好拥有欧洲最非凡的私人艺术收藏之一。洛布科维茨家族在共产主义没收后于1989年之后收回了他们的宫殿，并立即向公众开放，家族藏品完好如初：贝多芬和莫扎特的亲笔手稿、盔甲、勃鲁盖尔和卡纳莱托的画作，以及跨越四个世纪的乐器。解锁音乐档案中的彩蛋：宫殿收藏着贝多芬亲手书写的第四和第五交响曲总谱，他本人用不同颜色的墨水所作的修改清晰可见——你可以看到作曲家在创作过程中改变主意的痕迹。家族语音导览由现任洛布科维茨亲王本人亲自讲述。在布拉格没有任何其他地方，一位在世的贵族会在你的耳机中为你解说他自己祖先的财产。以波西米亚最古老的幸存王朝宾客的身份进入吧。`,
  },

  "kampa-island": {
    en: `Brave explorer, Kampa Island is the most enchanted natural quest zone in central Prague — a sliver of land separated from Malá Strana by the Čertovka mill stream, accessible by small bridges and covered with weeping willows, grassy riverside banks, and the legendary Kampa Museum of modern art perched on its northern tip. The island feels physically disconnected from the city despite being metres from it. Unlock the Easter egg left behind by the 2002 flood: the Kampa Museum was entirely submerged — floodwater reached the second floor — and the art collection survived only because staff worked through the night moving pieces to higher ground. High-water marks are still painted on the museum's exterior wall. More mysterious: scattered across the island's park are dozens of yellow rubber ducks and small ceramic figures left by unknown visitors over years, creating an unofficial, ever-changing folk art installation that the city has never explained or removed. Nobody knows who started it.`,
    cz: `Odvážný průzkumníku, Kampa je nejokouzlenější přírodní quest zónou v centru Prahy — proužek země oddělený od Malé Strany mlýnským potokem Čertovkou, přístupný malými mosty a porostlý vrbami, travnatými říčními břehy a legendárním Muzeem Kampa moderního umění tyčícím se na jeho severním cípu. Ostrov se cítí fyzicky odpojen od města i přes to, že je od něj vzdálen jen pár metrů. Odemkni easter egg zanechaný povodní roku 2002: Muzeum Kampa bylo zcela zaplaveno — voda dosáhla druhého patra — a sbírka umění přežila jen proto, že zaměstnanci pracovali celou noc a přemísťovali exponáty na vyšší místa. Výšky vody jsou stále vymalované na vnější zdi muzea. Záhadnější: po celém parku ostrova jsou roztroušeny desítky žlutých gumových kachniček a malé keramické figurky zanechané neznámými návštěvníky v průběhu let, čímž vznikla neoficiální, neustále se měnící instalace lidového umění, kterou město nikdy nevysvětlilo ani neodstranilo. Nikdo neví, kdo ji začal.`,
    zh: `勇敢的探险家，坎帕岛是布拉格市中心最迷人的自然任务区——一条被切尔托夫卡磨坊溪流与小城区隔开的细长陆地，通过小桥可达，覆盖着垂柳、青草河岸，以及矗立在其北端的传奇坎帕现代艺术博物馆。尽管距离城市只有几米，小岛却让人感觉与城市完全隔绝。解锁2002年洪水留下的彩蛋：坎帕博物馆被完全淹没——洪水达到二楼——艺术收藏之所以幸存，仅因为员工们彻夜工作将展品转移至更高处。洪水水位线至今仍标注在博物馆外墙上。更神秘的是：散布在岛上公园各处的是数十只黄色橡皮鸭和小型陶瓷人偶，由多年来身份不明的访客留下，形成了一个城市从未解释或移除的非官方、不断变化的民间艺术装置。没有人知道是谁开始了这一切。`,
  },

  "zizkov-horse-statue": {
    en: `Brave explorer, the Žižkov Horse Statue — the equestrian monument to Jan Žižka atop Vítkov Hill — is the most quietly overwhelming hidden-gem quest zone in Prague, because most visitors who find the Žižkov viewpoint focus entirely on the panorama and never notice the statue itself is the third-largest bronze equestrian sculpture in the world. Jan Žižka of Trocnov was the Hussite general who won every battle he ever fought, including the crucial Battle of Vítkov Hill in 1420 directly on this spot, defeating a Crusade sent by the Pope and Holy Roman Emperor with a force one-tenth the size. He did this while already blind in one eye from an earlier battle. Unlock the Easter egg inside the statue: the bronze is hollow, and for a period during the Communist era, the interior was used as a storage space for classified documents. The interior is no longer accessible. The horse stands 9 metres tall. Žižka himself was reportedly a very small man.`,
    cz: `Odvážný průzkumníku, Žižkova jezdecká socha — jezdecký pomník Jana Žižky na vrcholu Vítkova — je nejtišeji ohromující hidden-gem quest zónou v Praze, protože většina návštěvníků, kteří najdou žižkovský vyhlídkový bod, se soustředí výhradně na panorama a nikdy si nevšimnou, že samotná socha je třetí největší bronzovou jezdeckou sochou na světě. Jan Žižka z Trocnova byl husitský generál, který vyhrál každou bitvu, v níž kdy bojoval, včetně klíčové Bitvy na Vítkově v roce 1420 přímo na tomto místě, kde porazil křížovou výpravu vyslanou papežem a císařem Svaté říše římské se silou desetkrát menší. Udělal to, když byl z předchozí bitvy už slepý na jedno oko. Odemkni easter egg uvnitř sochy: bronz je dutý a po určitou dobu v komunistické éře byl interiér využíván jako úložiště utajovaných dokumentů. Interiér již není přístupný. Kůň stojí 9 metrů. Sám Žižka byl prý velmi malý muž.`,
    zh: `勇敢的探险家，日什科夫骑马雕像——维特科夫山顶扬·日什卡的骑马纪念碑——是布拉格最静默震撼的隐藏宝石任务区，因为大多数找到日什科夫观景台的游客都会完全专注于全景，而从未注意到这座雕像本身是世界第三大青铜骑马雕塑。特罗茨诺夫的扬·日什卡是胡斯派将领，他赢得了自己参与的每一场战役，包括1420年在这个确切地点进行的关键性维特科夫山战役，以十分之一的兵力击败了教皇和神圣罗马帝国皇帝派遣的十字军。他在此之前的战役中已经一只眼睛失明，却仍做到了这一切。解锁雕像内部的彩蛋：青铜是空心的，共产主义时代的某个时期，内部曾被用作存放机密文件的储存空间。内部现已不再开放。马的高度达9米。据说日什卡本人是个身材很小的人。`,
  },

  "o2-arena": {
    en: `Brave explorer, the O2 Arena is Prague's mightiest entertainment fortress — a 20,000-capacity indoor colosseum that opened in 2004 for the Ice Hockey World Championship and instantly became the largest arena in Central Europe. Unlock the Easter egg in its naming history: the arena cycled through three different corporate sponsors before stabilising as "O2" — one of the first major naming-rights deals ever struck in Czech sport. Below the main floor lies a dedicated ice rink used year-round. The Rolling Stones, international hockey legends, and sold-out boxing cards have all shaken its walls. Its iconic dome has earned a permanent place on Prague's eastern skyline. The crowd noise from 20,000 fans shakes the floor from three levels up. Add this fortress to your questlog.`,
    cz: `Odvážný průzkumníku, O2 Arena je nejmocnější zábavní pevností Prahy — vnitřní koloseum s kapacitou 20 000 míst, otevřené v roce 2004 pro Mistrovství světa v hokeji a okamžitě se stalo největší arénou ve střední Evropě. Odemkni easter egg v historii jejího pojmenování: aréna prošla třemi různými firemními sponzory, než se stabilizovala jako "O2" — jeden z prvních velkých obchodů se jmennými právy v českém sportu. Pod hlavním parketem se nachází hokejová plocha využívaná celoročně. Rolling Stones, hokejové legendy i vyprodaná boxerská gala — vše otřáslo jejími zdmi. Ikonická kopule si vydobyla trvalé místo na východním obzoru Prahy. Hluk 20 000 fanoušků třese podlahou ze tří pater výše. Přidej tuto pevnost do svého questlogu.`,
    zh: `勇敢的探险家，O2竞技场是布拉格最强大的娱乐堡垒——一座容纳2万人的室内圆形剧场，2004年为冰球世锦赛开幕，立即成为中欧最大的竞技场。解锁其命名历史中的彩蛋：竞技场先后以三个不同的企业赞助商命名，最终稳定为"O2"——这是捷克体育史上最早的大型冠名权交易之一。主地板下方设有一座全年运营的冰场。滚石乐队、冰球传奇和满座拳击赛全都在此震动过这座建筑的墙壁。标志性圆顶在布拉格东部天际线上占据了永久席位。2万名球迷的喧嚣从三层楼高处传来，震动着地板。将这座堡垒加入你的任务日志。`,
  },

  "new-royal-palace": {
    en: `Brave explorer, the New Royal Palace inside Prague Castle is the site of the most consequential act of aerial diplomacy in European history: on 23 May 1618, three Catholic royal governors were hurled from its windows by Protestant Bohemian nobles — an act that triggered the Thirty Years War and killed a third of Central Europe's population. Unlock the absurd Easter egg: all three men survived the 17-metre fall into the castle moat. Catholics credited divine intervention; Protestants pointed out they had landed in a rubbish heap. Both were right about what mattered: the war that followed reshaped the map of Europe. History's most consequential defenestration launched from this very room. You are standing at the window. Look down.`,
    cz: `Odvážný průzkumníku, Nový královský palác uvnitř Pražského hradu je místem nejdůsažnějšího aktu letecké diplomacie v evropské historii: 23. května 1618 byli tři katoličtí královští místodržitelé vyhozeni z jeho oken protestantskými českými šlechtici — čin, který spustil třicetiletou válku a zabil třetinu obyvatelstva střední Evropy. Odemkni absurdní easter egg: všichni tři muži přežili pád ze 17 metrů do hradního příkopu. Katolíci přičítali přežití božímu zásahu; protestanti poukazovali na to, že dopadli na hromadu odpadků. Oba měli pravdu v tom, na čem záleželo: válka, která následovala, překreslila mapu Evropy. Nejvýznamnější defenestrace v historii byla provedena právě z této místnosti. Stojíš u okna. Pohleď dolů.`,
    zh: `勇敢的探险家，布拉格城堡内的新皇宫是欧洲历史上最具影响力的"窗外外交"事件发生地：1618年5月23日，三位天主教皇室总督被新教波西米亚贵族从这里的窗户抛出——这一举动引发了三十年战争，杀死了中欧三分之一的人口。解锁那个荒诞的彩蛋：三人均从17米高处坠入城堡护城河后存活。天主教徒将其归因于神圣干预，新教徒则指出他们落入了一堆垃圾之中。双方在最重要的一点上都没有错：随之而来的战争重塑了欧洲版图。历史上最具影响力的掷窗事件，就是从这个房间发起的。你就站在那扇窗边。向下看。`,
  },

  "vitkov-national-memorial": {
    en: `Brave explorer, the National Memorial on Vítkov Hill is one of Prague's most surreal quest zones — a monumental 1938 Functionalist mausoleum surmounted by the world's largest equestrian bronze statue: a 16.5-tonne Jan Žižka on horseback, visible from kilometres away. Unlock the Easter egg buried beneath it: the mausoleum was built to honour Czechoslovakia's greatest heroes but became a communist pantheon, most infamously housing the embalmed body of Klement Gottwald, the first communist president. After 1989, his corpse was quietly cremated and removed. The catacombs now hold a permanent exhibition on 20th-century Czech history. The giant warrior above has outlasted every ideology that sought to claim him. The boss is the building itself.`,
    cz: `Odvážný průzkumníku, Národní památník na Vítkově je jednou z nejsurreálnějších quest zón Prahy — monumentální funkcionalistické mauzoleum z roku 1938, korunované největší jezdeckou bronzovou sochou na světě: 16,5tunový Jan Žižka na koni, viditelný z kilometrů daleko. Odemkni easter egg pohřbený pod ním: mauzoleum bylo postaveno ke cti největších hrdinů Československa, ale stalo se komunistickým panteonem, nejhůře ukrývající nabalzamované tělo Klementa Gottwalda, prvního komunistického prezidenta. Po roce 1989 bylo jeho tělo potichu zpopelněno a odvezeno. Katakomby nyní ukrývají stálou výstavu o českých dějinách 20. století. Obrovský válečník výše přežil každou ideologii, která se ho pokusila přivlastnit. Boss je samotná budova.`,
    zh: `勇敢的探险家，维特科夫山上的国家纪念碑是布拉格最超现实的任务区之一——一座建于1938年的宏伟功能主义陵墓，其上矗立着世界上最大的骑马青铜雕像：重达16.5吨的扬·日什卡骑马像，从数公里外便清晰可见。解锁埋藏在其下方的彩蛋：这座陵墓原为供奉捷克斯洛伐克最伟大英雄而建，却演变为共产主义先贤祠，最臭名昭著的是曾存放第一位共产主义总统克莱门特·哥特瓦尔德的防腐遗体。1989年后，他的遗体被悄悄火化并移走。地下墓穴现设有关于20世纪捷克历史的常设展览。顶上那位巨大的战士，见证并超越了每一种试图将他据为己有的意识形态。Boss就是这座建筑本身。`,
  },

  "lake-dzban": {
    en: `Brave explorer, Lake Džbán is Prague's most guarded natural secret — an artificial reservoir carved from a forested valley in the city's northwest that Praguers treat as their private swimming hole, almost never appearing on tourist maps. The surrounding nature reserve protects rare orchids, protected insects, and one of the last stretches of natural floodplain meadow within city limits. Unlock the Easter egg in the water itself: Džbán was created in the 1970s by damming a small valley purely for recreation — it has no natural river source, sustained entirely by rainfall and groundwater. Water quality is monitored weekly and rated swimworthy every summer. You will share it with locals and a suspicious number of ducks. No tourist infrastructure awaits you here.`,
    cz: `Odvážný průzkumníku, Džbán je nejstřeženějším přírodním tajemstvím Prahy — umělá nádrž vytesaná z lesnatého údolí v severozápadní části města, kterou Pražané považují za své soukromé koupalištní ráje a která se téměř nikdy neobjevuje na turistických mapách. Okolní přírodní rezervace chrání vzácné orchideje, chráněný hmyz a jeden z posledních úseků přírodní nivní louky v hranicích města. Odemkni easter egg ve vodě samotné: Džbán byl vytvořen v 70. letech zahrazením malého údolí čistě pro rekreaci — nemá žádný přirozený říční pramen, udržuje ho výhradně déšť a podzemní voda. Kvalita vody je monitorována každý týden a každé léto hodnocena jako vhodná ke koupání. Budeš ji sdílet s místními a podezřelým počtem kachen. Žádná turistická infrastruktura tě tu nečeká.`,
    zh: `勇敢的探险家，德日班湖是布拉格守护得最严的自然秘密——一座从城市西北部林地山谷中开凿出的人工水库，布拉格市民将其视为私人游泳胜地，几乎从不出现在旅游地图上。周围的自然保护区保护着珍稀兰花、受保护昆虫，以及城市边界内最后一片天然泛滥平原草地。解锁隐藏在水中的彩蛋：德日班建于20世纪70年代，通过筑坝拦截一处小山谷纯粹用于休闲——它没有任何天然河流水源，完全依靠雨水和地下水维持。城市每周监测水质，每个夏天都被评定为适合游泳。你将与当地居民和数量惊人的鸭子共享这片水域。这里没有任何旅游设施等待你。`,
  },

  "modranska-rokle": {
    en: `Brave explorer, Modřanská rokle is Prague's deepest geological time machine — a protected gorge at the city's southern edge where exposed rock faces reveal 380-million-year-old Devonian limestone packed with fossilised coral reefs and ancient sea creatures. This entire zone was once the floor of a tropical ocean. Unlock the Easter egg in the rock: the gorge is one of the most significant geological sites in Bohemia, studied since the 19th century, with fossils so well-preserved that some specimens helped define the global Devonian geological period. Trails follow the narrow valley bottom between steep walls of ancient stone. You are walking on a seabed, brave explorer. The city does not know you are here. Press on.`,
    cz: `Odvážný průzkumníku, Modřanská rokle je nejhlubším geologickým strojem času Prahy — chráněná rokle na jižním okraji města, kde obnažené skalní stěny odhalují 380 milionů let staré devonské vápence plné zkamenělých korálových útesů a starověkých mořských tvorů. Celá tato zóna byla kdysi dnem tropického oceánu. Odemkni easter egg v hornině: rokle je jedním z nejvýznamnějších geologických nalezišť v Čechách, studovaných od 19. století, s tak dobře zachovanými fosiliemi, že některé exempláře pomohly definovat globální devonské geologické období. Stezky sledují úzké dno údolí mezi strmými stěnami prastarého kamene. Kráčíš po mořském dně, odvážný průzkumníku. Město neví, že jsi zde. Pokračuj.`,
    zh: `勇敢的探险家，莫德扬斯卡裂谷是布拉格最深邃的地质时间机器——位于城市南部边缘的一处受保护峡谷，裸露的岩壁揭示了3.8亿年前泥盆纪石灰岩，其中密布着石化珊瑚礁和古代海洋生物。整个区域曾经是热带海洋的海底。解锁隐藏在岩石中的彩蛋：这条峡谷是波西米亚最重要的地质遗址之一，自19世纪起便有科学家研究，其中一些标本保存如此完好，被用于帮助定义全球泥盆纪地质时期。小径沿着古老巨石陡壁间的狭窄谷底蜿蜒。你正行走在一片古老的海底上，勇敢的探险家。这座城市不知道你在这里。继续前行。`,
  },

  "charles-university": {
    en: `Brave explorer, Charles University is the oldest university in Central Europe — founded by Emperor Charles IV in 1348, the first university north of the Alps and east of Paris, making Prague briefly the intellectual capital of the Holy Roman Empire. The original Carolinum hall is still in use today, its Gothic bay window one of the oldest surviving secular Gothic structures in Bohemia. Unlock the Easter egg embedded in its revolutionary history: Jan Hus, burned at the stake in 1415, was rector of this university before becoming the most influential religious reformer of his era. His condemnation triggered the Hussite Wars. The university debated, voted, and helped launch a century of religious conflict from these very halls. Education, as it turns out, has consequences.`,
    cz: `Odvážný průzkumníku, Karlova univerzita je nejstarší univerzitou ve střední Evropě — založena císařem Karlem IV. v roce 1348, první univerzita severně od Alp a východně od Paříže, čímž se Praha na čas stala intelektuálním hlavním městem Svaté říše římské. Původní síň Karolinum je dosud v provozu, její gotický arkýř je jednou z nejstarších dochovaných světských gotických staveb v Čechách. Odemkni easter egg vrostlý do její revoluční historie: Jan Hus, upálený v roce 1415, byl rektorem této univerzity, než se stal nejvlivnějším náboženským reformátorem své doby. Jeho odsouzení spustilo husitské války. Univerzita debatovala, hlasovala a pomohla zahájit století náboženského konfliktu přímo z těchto sálů. Vzdělání má, jak se ukázalo, důsledky.`,
    zh: `勇敢的探险家，查理大学是中欧最古老的大学——由查理四世皇帝于1348年创立，是阿尔卑斯山以北、巴黎以东的第一所大学，使布拉格一度成为神圣罗马帝国的知识之都。卡罗林努姆礼堂至今仍在使用，其哥特式凸窗是波西米亚现存最古老的世俗哥特式建筑之一。解锁嵌入其革命历史中的彩蛋：1415年被烧死在火刑柱上的扬·胡斯，在成为那个时代最具影响力的宗教改革者之前，曾是这所大学的校长。他的定罪引发了胡斯战争。大学在这些大厅里进行辩论、投票，并帮助开启了一个世纪的宗教冲突。事实证明，教育是有后果的。`,
  },

  "heydrich-assassination-site": {
    en: `Brave explorer, this bend in Libeň is where history pivoted on 27 May 1942 — the site of Operation Anthropoid, the only successful assassination of a senior Nazi official during World War II. Czech and Slovak paratroopers trained in Britain ambushed Heydrich's open-top car as it slowed around this hairpin curve. Unlock the tragic Easter egg: the operation nearly failed — the Sten gun jammed at point-blank range. The bomb thrown at the car also missed its target. But fragments from the car's own bodywork penetrated Heydrich's spleen, and he died of sepsis eight days later. The Nazis massacred the entire village of Lidice in reprisal. Seven heroes, a misfired gun, and one explosion changed the war's course. Mark this location, brave explorer. Do not forget.`,
    cz: `Odvážný průzkumníku, tato zatáčka v Libni je místem, kde se 27. května 1942 obrátily dějiny — místo operace Anthropoid, jediného úspěšného atentátu na vysokého nacistického představitele za druhé světové války. Čeští a slovenští výsadkáři vycvičení v Británii přepadli Heydrichův otevřený vůz, když zpomaloval v této ostrém zatáčce. Odemkni tragický easter egg: operace málem selhala — samopal Sten se zasekl z bezprostřední vzdálenosti. Bomba hozená na auto také minula. Ale fragmenty karoserie vozu pronikly do Heydrichovy sleziny a on zemřel na sepsi o osm dní později. Nacisté v odplatě zmasakrovali celou vesnici Lidice. Sedm hrdinů, selhavší zbraň a jeden výbuch změnily průběh války. Označ toto místo, odvážný průzkumníku. Nezapomeň.`,
    zh: `勇敢的探险家，利布尼的这段路弯是历史在1942年5月27日转折的地方——人类行动的现场，二战中唯一一次成功刺杀高级纳粹官员的行动。在英国受训的捷克和斯洛伐克伞兵在海德里希的敞篷车在这个急弯处减速时发动了伏击。解锁那个令人痛心的彩蛋：行动险些失败——斯滕冲锋枪在近距离卡壳，投向汽车的炸弹也偏离了目标。但车身碎片刺入了海德里希的脾脏，他在八天后死于败血症。纳粹作为报复屠杀了利迪采整个村庄。七位英雄、一把卡壳的枪和一次爆炸，改变了战争的进程。标记这个地点，勇敢的探险家。不要忘记。`,
  },

  "cathedral-cyril-methodius": {
    en: `Brave explorer, the Cathedral of Saints Cyril and Methodius on Resslova Street is the most battle-scarred sacred quest zone in Prague — an Orthodox church whose crypt became the final fortress of seven Czech paratroopers after Operation Anthropoid. For three weeks they hid here; then the Nazis came. The siege on 18 June 1942 lasted six hours. The Germans tried tear gas, flooding the crypt with fire hoses, and direct assault down the ventilation shaft. Not one paratrooper surrendered. None survived. Unlock the Easter egg written in stone: bullet holes from the final battle are preserved in the crypt walls and exterior stonework — untouched since 1942. A museum inside documents every hour of that day. Touch the walls. Feel eighty years of resistance.`,
    cz: `Odvážný průzkumníku, Katedrála sv. Cyrila a Metoděje v Resslově ulici je nejzjizvěnější posvátnou quest zónou Prahy — pravoslavný chrám, jehož krypta se stala poslední pevností sedmi českých výsadkářů po operaci Anthropoid. Tři týdny se zde ukrývali; pak přišli nacisté. Obléhání 18. června 1942 trvalo šest hodin. Němci použili slzný plyn, zaplavili kryptu hadicemi a zaútočili přímo ventilační šachtou. Žádný z výsadkářů se nevzdal. Žádný nepřežil. Odemkni easter egg zapsaný v kameni: otvory po kulkách z poslední bitvy jsou zachovány ve zdech krypty a vnějším zdiva — nedotčené od roku 1942. Muzeum uvnitř dokumentuje každou hodinu toho dne. Dotkni se zdí. Pocit osmdesáti let odporu.`,
    zh: `勇敢的探险家，雷斯洛瓦街上的圣西里尔与美多德大教堂是布拉格伤痕最深的神圣任务区——一座东正教教堂，其地下墓穴成为人类行动后七位捷克伞兵的最后堡垒。他们在此躲藏了三周，然后纳粹到来。1942年6月18日的围攻持续了六个小时。德军尝试了催泪弹，用消防水管淹没地窖，并从通风管直接强攻。没有一位伞兵投降，没有一人存活。解锁仍刻写在石头上的彩蛋：最后一战留下的弹孔被保留在地下墓穴的墙壁和外部石砌上——自1942年起从未被触动。内部博物馆记录了那一天的每一个小时。触摸这些墙壁，感受八十年的抵抗。`,
  },

  "smichovske-nadrazi": {
    en: `Brave explorer, Smíchovské nádraží is Prague's newest urban quest zone — a completely rebuilt railway station that opened in 2024 as the most ambitious regeneration project in the city in decades. The 19th-century railway viaduct arches were preserved and woven into a sprawling underground shopping arcade that sits directly beneath active train platforms. Unlock the Easter egg in its dual identity: what looks like a station is actually a city-within-a-city — apartments, offices, a park, and public squares across multiple blocks, all connected underground. The old station façade still stands on the original street, now the main entrance atrium. Prague's past and future converge on a single platform above the buried bones of the old Smíchov. Board your quest here.`,
    cz: `Odvážný průzkumníku, Smíchovské nádraží je nejnovější urbanistickou quest zónou Prahy — kompletně přestavěné železniční nádraží, otevřené v roce 2024 jako nejambicióznější regenerační projekt ve městě za desetiletí. Klenutí 19. století železničního viaduktu bylo zachováno a vetkáno do rozsáhlého podzemního nákupního arkádu ležícího přímo pod aktivními nástupišti. Odemkni easter egg v jeho dvojí identitě: to, co vypadá jako nádraží, je ve skutečnosti město ve městě — byty, kanceláře, park a veřejná prostranství na více blocích, vše propojeno pod zemí. Stará fasáda nádraží stojí na původní ulici, nyní jako hlavní vstupní atrium. Minulost a budoucnost Prahy se sbíhají na jediném nástupišti nad pohřbenými kostmi starého Smíchova. Nastup na svůj quest zde.`,
    zh: `勇敢的探险家，斯米霍夫车站是布拉格最新的城市任务区——一座于2024年开放的全面重建火车站，是数十年来最宏大的城市更新项目。19世纪铁路高架桥拱券得以保留，并编织进一个直接位于运营站台下方的宽阔地下购物廊。解锁其双重身份中的彩蛋：看似一座车站的地方，实际上是一座城中城——公寓、办公室、公园和公共广场跨越多个街区，全部在地下相连。原站房外立面仍矗立在原有街道上，现已成为主入口中庭。布拉格的过去与未来在旧斯米霍夫骸骨之上的一个站台处交汇。在此踏上你的旅程。`,
  },

  "masarykovo-nadrazi": {
    en: `Brave explorer, Masarykovo nádraží is Prague's oldest railway station, opened in 1845 as the terminus of the Emperor Ferdinand Northern Railway. The first steam locomotive to reach Prague pulled in here at midnight on 20 August 1845, watched by thousands of astonished citizens who had never seen a self-moving machine. The station was renamed after Tomáš Masaryk, the first Czechoslovak president, in 1919. Unlock the dark Easter egg sealed in its platforms: during the Nazi occupation, deportation trains carrying Jewish families to concentration camps departed from these same tracks. The station's cheerful Art Nouveau interiors witnessed the start of journeys from which thousands never returned. One building contains a century of beginnings and endings. History does not distinguish between them.`,
    cz: `Odvážný průzkumníku, Masarykovo nádraží je nejstarším pražským vlakovým nádražím, otevřeným v roce 1845 jako terminus Císařské ferdinandovy severní dráhy. První parní lokomotiva, která dosáhla Prahy, přijela sem o půlnoci 20. srpna 1845 za přihlížení tisíců ohromených občanů, kteří nikdy neviděli stroj pohybující se sám od sebe. Nádraží bylo přejmenováno po Tomáši Masarykovi, prvním prezidentu Československa, v roce 1919. Odemkni temný easter egg zapečetěný v jeho nástupištích: během nacistické okupace odjížděly z těchto stejných kolejí deportační vlaky přepravující židovské rodiny do koncentračních táborů. Veselé secesní interiéry nádraží byly svědky začátku cest, z nichž se tisíce nikdy nevrátily. Jedna budova obsahuje století začátků i konců. Historie mezi nimi nerozlišuje.`,
    zh: `勇敢的探险家，马萨里克车站是布拉格最古老的火车站，1845年作为皇帝费迪南德北方铁路的终点站开放。第一列抵达布拉格的蒸汽机车于1845年8月20日午夜驶入此处，数千名从未见过自动移动机械的惊讶市民在旁观看。1919年，车站以第一任捷克斯洛伐克总统托马什·马萨里克的名字命名。解锁封存在站台中的黑暗彩蛋：纳粹占领期间，将犹太家庭运往集中营的驱逐列车就从这些轨道出发。车站欢快的新艺术风格内饰见证了数千人再也没有返回的旅程的起点。一座建筑包含了一个世纪的起点与终点。历史并不区分二者。`,
  },

  "centralni-park-praha": {
    en: `Brave explorer, Centrální park Praha in Stodůlky is Prague's most underrated green quest zone — a sprawling urban woodland built on the edge of the city's largest communist-era housing estates, designed as breathing space for the concrete panel-block jungle nearby. Unlock the Easter egg scattered through its woodland paths: several socialist-realist public sculptures from the communist era remain hidden in the park's forested areas, slowly being reclaimed by moss and ivy. No signs point to them; locals know where they are. The monumental workers and heroic pioneers they once represented now stand quietly in sun-dappled clearings, watching joggers pass, forgotten by everyone except the trees. History is not always demolished. Sometimes it is simply overgrown.`,
    cz: `Odvážný průzkumníku, Centrální park Praha ve Stodůlkách je nejvíce podceňovanou zelenou quest zónou Prahy — rozsáhlý městský les vybudovaný na okraji největšího komunistického sídliště, navržený jako dýchací prostor pro betonovou panelákovou džungli v sousedství. Odemkni easter egg roztroušený po jeho lesních cestách: několik sociálně-realistických veřejných soch z komunistické éry zůstává skrytých v zalesněných oblastech parku, pomalu pohlcovaných mechem a břečťanem. Žádné cedule na ně neukazují; místní vědí, kde jsou. Monumentální dělníci a hrdinští pionýři nyní stojí v tichých mýtinách, sledují procházející jogery a jsou zapomenuti každým kromě stromů. Historie není vždy zbořena. Někdy je jen zarostlá.`,
    zh: `勇敢的探险家，斯托杜尔基区的布拉格中央公园是城市中最被低估的绿色任务区——一片宽阔的城市林地，建在城市最大的共产主义时代住宅区边缘，被设计为附近板楼丛林的呼吸空间。解锁散落在林间小径中的彩蛋：共产主义时代的数件社会主义现实主义公共雕塑仍隐藏在公园的林地区域，慢慢被苔藓和常春藤所覆盖。没有任何标识指向它们；当地居民知道它们在哪里。那些曾代表着宏大工人和英雄先驱的雕像，如今静静地矗立在阳光斑驳的空地里，注视着慢跑者走过，被除了树木以外的所有人遗忘。历史并不总是被拆除的，有时它只是被植物覆盖了。`,
  },

  "vaclav-havel-airport": {
    en: `Brave explorer, Václav Havel Airport Prague is the gateway boss zone of Bohemia — renamed in 2012 to honour the playwright, dissident, and first post-communist president who steered Czechoslovakia's peaceful transition to democracy. Few airports name themselves after people who spent years in prison for opposing the very system the airport was built under. Unlock the Easter egg in Terminal 1: the original 1937 Art Nouveau departure hall is a protected cultural monument still embedded within the functioning airport. A building from the propeller-plane era stands surrounded by jet bridges, still processing passengers, its stucco ceilings watching travellers with the calm of something that has survived an entire century of Czech history. The airport that outlasted communism was named for the man who ended it.`,
    cz: `Odvážný průzkumníku, Letiště Václava Havla Praha je vstupní boss zónou Čech — přejmenované v roce 2012 na počest dramatika, disidenta a prvního postkomunistického prezidenta, který řídil mírový přechod Československa k demokracii. Málo letišť pojmenovává sebe po lidech, kteří strávili roky ve vězení za odpor vůči systému, pod nímž bylo letiště postaveno. Odemkni easter egg v Terminálu 1: původní secesní odbavovací hala z roku 1937 je chráněnou kulturní památkou stále zabudovanou ve fungujícím letišti. Budova z éry vrtulových letadel stojí obklopena leteckými mosty, stále odbavuje cestující, její štukové stropy sledují cestovatele klidem něčeho, co přežilo celé století české historie. Letiště, které přežilo komunismus, bylo pojmenováno po muži, který mu učinil konec.`,
    zh: `勇敢的探险家，瓦茨拉夫·哈维尔布拉格机场是波西米亚的入场Boss区域——2012年以剧作家、异见人士及第一位后共产主义总统的名字命名，此人引领捷克斯洛伐克完成了向民主的和平过渡。很少有机场以曾因反对建造该机场的体制而身陷囹圄多年的人来命名自身。解锁1号航站楼中的彩蛋：1937年原建的新艺术风格候机大厅是一处受保护的文化古迹，至今仍嵌入这座正常运转的机场之中。一栋属于螺旋桨飞机时代的建筑被登机廊桥所环绕，仍在为旅客办理登机手续，其灰泥天花板以跨越整个世纪捷克历史的平静注视着行旅者。这座熬过共产主义的机场，以终结它的那个人的名字命名。`,
  },

  "praha-hlavni-nadrazi": {
    en: `Brave explorer, Praha hlavní nádraží is the grandest portal in the city — an Art Nouveau masterpiece completed in 1909 by architect Josef Fanta, its soaring domed entrance hall decorated with ceramic garlands, stained glass, and a golden ceiling that most commuters hurry past without ever looking up. The station was originally named "Franz Josef Station" after the Habsburg emperor. Unlock the Easter egg hidden in its wartime past: in March 1939, as Nazi troops occupied Prague, the station's platforms were the departure point for Kindertransport trains that evacuated nearly 700 Jewish children to Britain. The man who organised it, Sir Nicholas Winton, kept it secret for 50 years. The golden ceiling watched all of it. Look up when you enter.`,
    cz: `Odvážný průzkumníku, Praha hlavní nádraží je nejvelkolepější branou ve městě — mistrovské dílo secese dokončené v roce 1909 architektem Josefem Fantou, jehož impozantní vstupní hala s kopulí je ozdobena keramickými girlandami, vitrážemi a zlatým stropem, kolem kterého většina cestujících spěchá, aniž by kdy vzhlédla. Nádraží bylo původně pojmenováno "Nádraží Františka Josefa" po habsburském císaři. Odemkni easter egg ukrytý v jeho válečné minulosti: v březnu 1939, kdy nacistická vojska obsadila Prahu, sloužila nástupiště nádraží jako odletový bod Kindertransportu, který evakuoval téměř 700 židovských dětí do Británie. Muž, který to zorganizoval, Sir Nicholas Winton, to tajil 50 let. Zlatý strop to vše sledoval. Vzhlédni, když vejdeš.`,
    zh: `勇敢的探险家，布拉格主火车站是城市中最宏伟的门户——由建筑师约瑟夫·范塔于1909年完成的新艺术风格杰作，其高耸的圆顶入口大厅饰以陶瓷花环、彩色玻璃和一顶金色天花板，大多数通勤者匆匆而过，从未抬头仰望。车站最初以哈布斯堡皇帝的名字命名为"弗朗茨·约瑟夫站"。解锁隐藏在其战时过去中的彩蛋：1939年3月纳粹军队占领布拉格时，车站的站台成为"儿童运输"列车的出发点，这些列车将近700名犹太儿童疏散到英国。组织这一切的尼古拉斯·温顿爵士将此秘密保守了50年。那顶金色天花板目睹了这一切。进入时，请抬起头来。`,
  },

  "sapa-praha": {
    en: `Brave explorer, Sapa Praha is Prague's most unexpected quest zone — a vast self-contained Vietnamese commercial district in the city's south, spanning several city blocks and operating entirely on its own terms. Dubbed "Little Hanoi," it is the largest Vietnamese community hub in Central Europe, home to over 10,000 Vietnamese residents and a wholesale market supplying Vietnamese restaurants across the entire Czech Republic. Unlock the Easter egg in its Cold War origins: the community here did not arrive as refugees but as contracted industrial workers sent to Czechoslovakia in the 1970s and 80s under a socialist brotherhood agreement between the two communist states. They stayed when the system changed. Prague gained an entire district it did not know it was getting. Explore every corridor.`,
    cz: `Odvážný průzkumníku, Sapa Praha je nejneočekávanější quest zónou Prahy — rozsáhlá soběstačná vietnamská obchodní čtvrť na jihu města, rozprostírající se přes několik bloků a fungující zcela po svém. Přezdívaná "Malé Hanoi", je největším vietnamským komunitním centrem ve střední Evropě, domovem přes 10 000 vietnamských obyvatel a velkoobchodního trhu zásobujícího vietnamské restaurace po celé České republice. Odemkni easter egg v jeho původu studené války: komunita zde nepřišla jako uprchlíci, ale jako smluvní průmysloví dělníci poslaní do Československa v 70. a 80. letech 20. století v rámci dohody o socialistickém bratrství mezi dvěma komunistickými státy. Zůstali, když se systém změnil. Praha získala celou čtvrť, o které nevěděla, že ji dostává. Prozkoumej každou chodbu.`,
    zh: `勇敢的探险家，萨帕布拉格是城市中最出人意料的任务区——布拉格南部一个广阔的、自给自足的越南商业区，横跨数个城市街区，完全按自己的规则运行。被称为"小河内"，这里是中欧最大的越南社区中心，居住着逾万名越南居民，其批发市场向整个捷克共和国的越南餐厅供货。解锁其冷战起源中的彩蛋：这里的越南社区并非作为难民抵达，而是依据两个共产主义国家之间的社会主义兄弟协议，于20世纪70至80年代作为合同工业工人被派遣至捷克斯洛伐克。当制度改变之时，他们选择留下。布拉格获得了一个它不知道自己正在得到的完整城区。探索每一条走廊。`,
  },

  "haje": {
    en: `Brave explorer, Háje is the southernmost terminus of Prague Metro Line C — the end of the line, the final save point before the city gives way to outer suburbs. Few tourists ever come this far south, which means you will find something rare: genuine, unperformed, everyday Prague. The station's 1970s design features decorative ceramic wall panels — art embedded in communist infrastructure, noticed by almost no one. Unlock the Easter egg in the district's scale: Háje sits at the heart of one of Prague's largest communist-era housing estates, home to tens of thousands of residents who have built a fully functional city-within-a-city from identical concrete towers. Every Prague story begins here for someone. Ride the metro to the end and witness it.`,
    cz: `Odvážný průzkumníku, Háje jsou nejjižnější konečnou stanicí metra linky C — konec trasy, poslední save point před tím, než město ustupuje okrajovým předměstím. Turisté sem jezdí jen zřídka, což znamená, že tady najdeš něco vzácného: skutečnou, nehrající, každodenní Prahu. Design stanice ze 70. let je vybaven dekorativními keramickými nástěnnými panely — umění vložené do komunistické infrastruktury, povšimnuté téměř nikým. Odemkni easter egg v rozměrech čtvrti: Háje leží v srdci jednoho z největších komunistických sídlišť Prahy, domovem desítek tisíc obyvatel, kteří si z identických betonových věží vybudovali plně funkční město ve městě. Každý pražský příběh pro někoho začíná zde. Projet metrem na konec a buď tomu svědkem.`,
    zh: `勇敢的探险家，哈耶是布拉格地铁C线最南端的终点站——线路的尽头，城市让位于外郊区之前的最后一个存档点。几乎没有游客会来到这么南边，这意味着你将在这里找到罕见的东西：真实的、未经表演的、日常的布拉格。车站的1970年代设计以装饰性陶瓷墙面板为特色——嵌入共产主义基础设施中的艺术，几乎没有人注意到。解锁该街区规模中的彩蛋：哈耶位于布拉格最大的共产主义时代住宅区中心，居住着数万名居民，他们从一模一样的混凝土塔楼中建立了一个功能完整的城中城。对某些人来说，每个布拉格故事都从这里开始。坐地铁到终点，亲眼见证它。`,
  },

  "pankrac-skyline": {
    en: `Brave explorer, the Pankrác plateau is Prague's most schizophrenic quest zone — a hilltop of gleaming glass towers visible from across the city, rising above the historic skyline in a statement of architectural defiance. UNESCO has threatened to strip Prague's World Heritage status if further towers are built here. Unlock the dark Easter egg carved beneath the foundations: below the office towers sits a still-operational prison complex where Nazi interrogators executed Czech resistance fighters in a dedicated guillotine chamber during the occupation. A memorial marks the execution site. The glass towers of finance rise directly above the ground where hundreds were beheaded. Prague does not shy away from its contradictions. You should not either.`,
    cz: `Odvážný průzkumníku, pankrácká plošina je nejvíce schizofrenní quest zónou Prahy — kopec třpytivých skleněných věží viditelných z celého města, tyčících se nad historickým panoramatem v prohlášení architektonické vzdoru. UNESCO pohrozilo Praze odnětím statusu světového dědictví, pokud budou postaveny další věže. Odemkni temný easter egg vytesaný pod základy: pod kancelářskými věžemi se nachází stále funkční vězeňský komplex, kde nacistickými vyšetřovateli byli popraveni čeští odbojáři v specializované gilotinové komoře během okupace. Pamětní místo označuje místo popravy. Skleněné věže financí se tyčí přímo nad zemí, kde byli sťati stovky lidí. Praha se nevyhýbá svým rozporům. Ty bys také neměl.`,
    zh: `勇敢的探险家，潘克拉茨高地是布拉格最精神分裂的任务区——一座被闪耀的现代玻璃高楼所冠顶的山丘，以建筑反叛的姿态矗立于历史天际线之上。联合国教科文组织曾威胁，如果再建高楼，将剥夺布拉格的世界遗产地位。解锁刻写在地基之下的黑暗彩蛋：办公楼下方是一座仍在运营的监狱综合设施，纳粹占领期间曾在专用断头台室中处决捷克抵抗战士。一处纪念碑标志着行刑地点。金融业的玻璃塔楼直接矗立在数百人曾被斩首的土地之上。布拉格并不回避其内在矛盾，你也不应该。`,
  },

  "andel": {
    en: `Brave explorer, Anděl is the beating commercial heart of Smíchov — a roaring crossroads of metro, trams, shopping, and street life serving as the hub for Prague's left bank. The name means "Angel," taken from a historic inn that once stood at this junction. Unlock the Easter egg buried in its Soviet-era identity: the metro station here was renamed "Moskevská" — Moscow Station — in 1984 as a tribute to the Soviet sister city. After the Velvet Revolution, Praguers voted almost immediately to restore the name Anděl. The Angel had waited patiently under the Moscow label for five years. One more hidden fact: the shopping mall on the square was designed by Jean Nouvel, one of the most celebrated architectural commissions in 1990s Prague. The Angel inherited quite a wardrobe.`,
    cz: `Odvážný průzkumníku, Anděl je tlukotem obchodního srdce Smíchova — hučící křižovatka metra, tramvají, obchodů a pouličního života sloužící jako centrum levého břehu Prahy. Název znamená "anděl" a pochází z historického hostince, který kdysi stál na tomto rozcestí. Odemkni easter egg pohřbený v jeho sovětské identitě: stanice metra zde byla v roce 1984 přejmenována na "Moskevská" — jako hold sovětskému sesterském městu. Po Sametové revoluci Pražané hlasovali téměř okamžitě pro obnovení názvu Anděl. Anděl čekal trpělivě pod názvem Moskva pět let. Ještě jedna skrytá skutečnost: obchodní centrum na náměstí bylo navrženo Jeanem Nouvelem, jedna z nejslavnějších architektonických zakázek Prahy 90. let. Anděl zdědil poměrně bohatý šatník.`,
    zh: `勇敢的探险家，天使广场是斯米霍夫跳动的商业心脏——地铁、有轨电车、购物与街头生活交汇的喧嚣十字路口，是布拉格左岸的枢纽。其名字意为"天使"，来源于曾经矗立于这个路口的一家历史悠久的旅馆。解锁埋藏在其苏联时代身份中的彩蛋：这里的地铁站于1984年被改名为"莫斯科站"，以向苏联姐妹城市致敬。天鹅绒革命后，布拉格市民几乎立即投票将其改回天使。天使在莫斯科的标签下耐心等待了五年。还有一处隐藏彩蛋：广场上的购物中心由让·努维尔设计，是布拉格90年代最著名的建筑委托项目之一。天使继承了相当丰富的遗产。`,
  },

  "trojska-lavka": {
    en: `Brave explorer, Trojská lávka is Prague's most dramatic infrastructure resurrection — a pedestrian footbridge connecting Holešovice to Troja that collapsed spectacularly into the Vltava in December 2017, killing one person and shocking a city that had watched it sway for years. The collapse was filmed from multiple angles and went viral. Unlock the Easter egg in the rebuild: the replacement bridge opened in 2024 with a bold asymmetric cable-stayed design deliberately unlike anything else on the river — a conscious rejection of the original's failure, engineered to flex with the Vltava rather than resist it. Stand on it, look east toward the zoo, look west for one of the cleanest Vltava views in the city. A fallen bridge became a better one. That is the most Prague thing imaginable.`,
    cz: `Odvážný průzkumníku, Trojská lávka je nejdramatičtější infrastrukturní resurrekcí Prahy — lávka pro pěší spojující Holešovice s Trojou, která se spektakulárně zřítila do Vltavy v prosinci 2017, přičemž jeden člověk přišel o život a město, které sledovalo její houpání léta, bylo otřeseno. Zřícení bylo natočeno z více úhlů a stalo se virálním. Odemkni easter egg v přestavbě: náhradní most byl otevřen v roce 2024 s odvážným asymetrickým mimoosovým kabelovým návrhem záměrně nepodobným ničemu jinému na řece — vědomé odmítnutí selhání originálu, navržené tak, aby pružně reagoval na Vltavu, spíše než jí odolával. Postav se na něj, podívej se na východ směrem k zoo, na západ pro jeden z nejčistějších výhledů na Vltavu ve městě. Padlý most se stal lepším. To je ta nejpražštější věc, jaká existuje.`,
    zh: `勇敢的探险家，特罗亚人行桥是布拉格最戏剧性的基础设施复活——一座连接霍莱绍维采与特罗亚的行人桥，于2017年12月壮观地倒塌入伏尔塔瓦河，造成一人死亡，令这座目睹它摇晃多年的城市深感震惊。倒塌过程被多角度拍摄并在网络上疯传。解锁重建中的彩蛋：替代桥梁于2024年以大胆的不对称斜拉设计开放，刻意与河上的其他任何桥梁都不相同——这是对原桥失败的有意识拒绝，设计为与伏尔塔瓦河共同弯曲而非抗拒。站在上面，向东望向动物园，向西望去是城里最干净的伏尔塔瓦景观之一。一座倒塌的桥，变成了一座更好的桥。这是最布拉格的事情了。`,
  },

  "podbaba": {
    en: `Brave explorer, Podbaba is Prague's best-kept secret village — a tiny riverside enclave in Prague 6 so far from the tourist trail it might as well exist in a parallel city. The neighbourhood clings to the Vltava bank in a cluster of villas and quiet lanes that have changed little since the early 20th century. Unlock the Easter egg rooted in ancient soil: archaeological excavations in Podbaba have uncovered traces of one of the oldest known Slavic settlements in the Prague area, dating to the 6th-7th century CE — predating Prague Castle itself. One of Prague's origin stories began quietly here, in a riverside enclave most Praguers have never visited. Find the old wine cellars carved into the riverbank cliff. This location is yours alone.`,
    cz: `Odvážný průzkumníku, Podbaba je nejstřeženější tajnou vesnicí Prahy — malinká říční enkláva v Praze 6, tak daleko od turistické trasy, že by klidně mohla existovat v paralelním městě. Čtvrť se přimyká k vltavskému břehu v hloučku vil a tichých uliček, které se od počátku 20. století téměř nezměnily. Odemkni easter egg zakořeněný v prastaré půdě: archeologické výzkumy v Podbabě odhalily stopy jednoho z nejstarších známých slovanských osídlení v pražské oblasti, datovaných do 6.-7. století n. l. — předcházejícím samotné Pražskému hradu. Jeden z příběhů o původu Prahy začal tiše zde, v říčním sídle, které většina Pražanů nikdy nenavštívila. Najdi staré vinné sklepy vytesané do říčního svahu. Toto místo je jen tvé.`,
    zh: `勇敢的探险家，波德巴巴是布拉格守护得最严的秘密村庄——布拉格6区的一个小小河边飞地，远离旅游路线，仿佛存在于另一座平行城市中。这个街区依偎在伏尔塔瓦河岸边，由一簇别墅和幽静小巷组成，自20世纪初以来几乎没有什么变化。解锁植根于古老土壤中的彩蛋：波德巴巴的考古发掘发现了布拉格地区已知最古老的斯拉夫聚落遗迹之一，可追溯至公元6至7世纪——早于布拉格城堡本身。布拉格的一个起源故事，静静地开始于这里，这个大多数布拉格市民从未造访过的河边飞地。寻找刻入河岸峭壁中的古老酒窖。这个地点只属于你。`,
  },

  "olsanske-hrbitovy": {
    en: `Brave explorer, Olšany Cemeteries is Prague's largest and most historically layered quest zone — a network of burial grounds established in 1680 during a plague epidemic, now covering over 50 hectares with more than two million graves spanning three and a half centuries. This is not a tourist site; it is where Prague buries its own. Unlock the Easter egg hidden in its most visited tomb: Jan Palach, the student who immolated himself on Wenceslas Square on 19 January 1969 in protest of the Soviet invasion, is buried here. The Communists originally reburied him in a remote village to prevent the grave becoming a protest shrine — after 1989, his remains returned to Olšany. Some defiances outlast the governments that tried to suppress them.`,
    cz: `Odvážný průzkumníku, Olšanské hřbitovy jsou největší a historicky nejvrstvovitější quest zónou Prahy — soustava pohřebišť zřízených v roce 1680 během epidemie moru, nyní rozkládajících se na více než 50 hektarech s více než dvěma miliony hrobů pokrývajících tři a půl století. Toto není turistické místo; je to místo, kde Praha pohřbívá své vlastní. Odemkni easter egg ukrytý v jeho nejnavštěvovanějším hrobě: Jan Palach, student, který se upálil na Václavském náměstí 19. ledna 1969 na protest sovětské invaze, je pohřben zde. Komunisté ho původně přepohřbili ve vzdálené vesnici, aby zabránili hrobu stát se protestním místem — po roce 1989 byly jeho ostatky vráceny na Olšany. Některé vzdory přežijí vlády, které se je snažily potlačit.`,
    zh: `勇敢的探险家，奥尔萨内公墓是布拉格规模最大、历史层次最为丰富的任务区——一片在1680年瘟疫流行期间建立的墓地网络，如今覆盖超过50公顷，有着超过两百万座横跨三个半世纪的坟墓。这不是旅游景点；这是布拉格安葬自己人的地方。解锁隐藏在其访问量最高墓碑中的彩蛋：扬·帕拉赫，1969年1月19日在瓦茨拉夫广场自焚以抗议苏联入侵的学生，就长眠于此。共产党人最初将他重新安葬在偏远村庄以防墓碑成为抗议圣地——1989年后，他的遗骨被迁回奥尔萨内。有些抗争，比试图压制它们的政府活得更长久。`,
  },

  "pruhonice-park": {
    en: `Brave explorer, Průhonice Park is the most spectacular quest zone beyond Prague's city limits — a UNESCO World Heritage Site most visitors never find: an English landscape park of 243 hectares surrounding a romantic Neo-Gothic castle, home to the most diverse ornamental tree collection in Central Europe. Unlock the Easter egg in its scientific identity: the park houses the Botanical Institute of the Czech Academy of Sciences and maintains the National Phytocenological Database — a complete record of Czech plant communities used to measure environmental change across the entire country. The park was created between 1885 and 1927 by Count Silva-Tarouca, who reportedly replanted the landscape three times before he was satisfied. Rare trees from five continents line paths almost no tourist walks. This is the final dungeon. Go.`,
    cz: `Odvážný průzkumníku, Průhonický park je nejokázalejší quest zónou za hranicemi Prahy — místo světového dědictví UNESCO, které většina návštěvníků nikdy nenajde: anglický krajinný park o rozloze 243 hektarů obklopující romantický neogotický zámek, domov nejrozmanitější sbírky okrasných stromů ve střední Evropě. Odemkni easter egg v jeho vědecké identitě: park ukrývá Botanický ústav Akademie věd ČR a spravuje Národní fytocenologickou databázi — úplný záznam českých rostlinných společenstev sloužící k měření environmentálních změn v celé zemi. Park byl vytvořen v letech 1885 až 1927 hrabětem Silvou-Taroucou, který prý krajinu třikrát přesadil, než byl spokojen. Vzácné stromy z pěti kontinentů lemují cesty, po nichž téměř žádný turista nechodí. Toto je finální dungeon. Jdi.`,
    zh: `勇敢的探险家，普鲁霍尼采公园是布拉格市界之外最壮观的任务区——一处大多数游客从未找到的联合国教科文组织世界遗产地：一座占地243公顷的英式风景公园，环绕着一座浪漫的新哥特式城堡，拥有中欧最多样化的观赏树木收藏。解锁其科学身份中的彩蛋：公园内设有捷克科学院植物研究所，并维护着国家植物社会学数据库——捷克植物群落的完整记录，用于衡量全国的环境变化。公园由席尔瓦-塔罗卡伯爵于1885年至1927年间创建，据说他在满意之前曾三次重新规划景观。来自五大洲的珍稀树木排列在几乎没有游客行走的小径两旁。这是最终地牢。出发吧。`,
  },

  "zlute-lazne": {
    en: `Brave explorer, Žluté lázně is Prague's most beloved seasonal quest zone — an urban riverside beach complex on the Vltava's east bank that functions as the city's unofficial summer headquarters. The name means "Yellow Baths," after the original yellow-painted bathing pavilions built here in the 1920s so Prague's working class could access the river. Today it hosts beach volleyball, river swimming, a climbing wall, tennis, and one of the finest beer gardens in the city. Unlock the Easter egg in the water itself: this stretch of the Vltava is consistently measured as the cleanest and safest swimming section within Prague city limits — a remarkable fact for a major European capital. The workers who bathed here in the 1920s would recognise everything except the prices.`,
    cz: `Odvážný průzkumníku, Žluté lázně jsou nejoblíbenější sezónní quest zónou Prahy — městský říční plážový komplex na východním břehu Vltavy, který funguje jako neoficiální letní hlavní stan města. Název znamená "Žluté lázně", pojmenovaný po původních žlutě natřených lázeňských pavilonech postavených zde ve 20. letech, aby pražská dělnická třída měla přístup k řece. Dnes hostí plážový volejbal, plavání ve Vltavě, lezeckou stěnu, tenis a jednu z nejkrásnějších pivních zahrad ve městě. Odemkni easter egg ve vodě samotné: tento úsek Vltavy je konzistentně měřen jako nejčistší a nejbezpečnější plavecká sekce v hranicích Prahy — pozoruhodný fakt pro řeku procházející hlavním městem Evropy. Dělníci, kteří se zde koupali ve 20. letech, by poznali vše kromě cen.`,
    zh: `勇敢的探险家，黄色浴场是布拉格最受喜爱的季节性任务区——伏尔塔瓦河东岸的一处城市河边沙滩综合设施，是这座城市非官方的夏季总部。其名字意为"黄色浴场"，来源于1920年代为布拉格工人阶级修建的原始黄色粉刷浴场凉亭。如今这里设有沙滩排球、河中游泳、攀岩墙、网球，以及城里最好的啤酒花园之一。解锁隐藏在水域中的彩蛋：这段伏尔塔瓦河被持续测定为布拉格城市范围内最干净、最安全的游泳区域——对于一条穿越欧洲主要首都的河流而言，这是一个非凡的事实。1920年代在此沐浴的工人们会认出这里的一切，除了价格。`,
  },

  "karlin": {
    en: `Brave explorer, Karlín is Prague's greatest urban resurrection — a 19th-century working district completely submerged under metres of Vltava floodwater in August 2002, the worst flooding Prague had seen in 200 years. The neighbourhood was effectively abandoned for years during remediation. Unlock the Easter egg in the disaster's silver lining: instead of rebuilding as before, the catastrophe triggered a complete cultural transformation. Landlords unable to find commercial tenants willing to risk another flood rented at low rates to artists, musicians, and young businesses. Bars opened. Studios appeared. Cafés followed. By 2010, Karlín had been rebranded as Prague's hippest neighbourhood. The flood that destroyed it became the most effective urban renewal tool the district ever had. Disaster as design.`,
    cz: `Odvážný průzkumníku, Karlín je největší městskou resurrekcí Prahy — 19. dělnická čtvrť zcela ponořená pod metry vltavské povodňové vody v srpnu 2002, nejhorší povodeň, jakou Praha zažila za 200 let. Čtvrť byla fakticky opuštěna na roky během sanace. Odemkni easter egg ve stříbrné podšívce katastrofy: namísto přestavby jako dříve, katastrofa spustila úplnou kulturní transformaci. Pronajímatelé neschopni najít komerční nájemníky ochotné riskovat další povodeň pronajímali za nízké nájemné umělcům, hudebníkům a mladým podnikům. Otevřely se bary. Ateliéry se objevily. Kavárny následovaly. Do roku 2010 byl Karlín rebrandován jako nejhipsterštější čtvrť Prahy. Povodeň, která ho zničila, se stala nejúčinnějším nástrojem obnovy, jaký čtvrť kdy měla. Katastrofa jako design.`,
    zh: `勇敢的探险家，卡尔林是布拉格最伟大的城市复活——一个19世纪的工人区，2002年8月被伏尔塔瓦河洪水淹没数米深，这是布拉格200年来最严重的洪灾。该街区在修复期间实际上被废弃了数年。解锁这场灾难阴云中的彩蛋：没有按原样重建，这场灾难触发了一场完整的文化转型。无法找到愿意冒险再次遭受洪水的商业租户，房东们以低廉租金将空间租给了艺术家、音乐家和年轻企业。酒吧开张了，工作室出现了，咖啡馆随之而来。到2010年，卡尔林已被重新定位为布拉格最时髦的街区。摧毁它的洪水，成为了这个街区有史以来最有效的城市更新工具。灾难即设计。`,
  },

  "namesti-miru": {
    en: `Brave explorer, Náměstí Míru — Peace Square — is the elegant heart of Vinohrady, Prague's most genteel residential district. The square is dominated by the Church of St. Ludmila, a twin-towered Neo-Gothic cathedral completed in 1893 with an 850-seat interior that dwarfs most of central Prague's churches. The adjacent Vinohrady Theatre, built in Art Nouveau style in 1907, stages Czech drama to packed audiences year-round. Unlock the Easter egg in the square's hidden winter life: every December, Náměstí Míru hosts Prague's only major free outdoor ice rink — a neighbourhood institution packed with local families who treat it as their village green. No tour guide mentions it. No ticket required. You found it. This is where the city lives rather than performs.`,
    cz: `Odvážný průzkumníku, Náměstí Míru je elegantním srdcem Vinohrad, nejelegantnější rezidenční čtvrti Prahy. Náměstí dominuje Kostel sv. Ludmily, dvětvěžová neogotická katedrála dokončená v roce 1893 s 850místným interiérem, který trpaslíkuje většinu kostelů centrální Prahy. Sousední Divadlo na Vinohradech, postavené v secesním stylu v roce 1907, uvádí české divadlo po celý rok plným hledišti. Odemkni easter egg ve skrytém zimním životě náměstí: každý prosinec hostí Náměstí Míru jediné velké bezplatné venkovní kluziště Prahy — místní instituce plná místních rodin, které ho používají jako své vesnické prostranství. Žádný průvodce o tom nemluví. Vstupenka není potřeba. Nalezl jsi to. Toto je místo, kde město žije, spíše než hraje.`,
    zh: `勇敢的探险家，和平广场是布拉格最高雅的住宅区维诺赫拉迪的优雅心脏。广场由圣卢德米拉教堂所主导，这是一座双塔新哥特式大教堂，完工于1893年，850座的内部空间使布拉格市中心的大多数教堂相形见绌。毗邻的维诺赫拉迪剧院以新艺术风格建于1907年，全年向满座观众上演捷克戏剧。解锁广场隐藏的冬季生活中的彩蛋：每年12月，和平广场都会举办布拉格唯一一个大型免费户外溜冰场——一个挤满了将其当作村庄广场使用的本地家庭的社区机构。没有任何导游提及此事，无需购票。你发现了它。这是城市真实生活的地方，而不是表演的场所。`,
  },

  "suchdol": {
    en: `Brave explorer, Suchdol is Prague's northernmost riverside village — a quiet enclave in Prague 6 where the city's noise fades and the Vltava bends through a landscape that has barely changed in a century. Forested slopes tumble down to the river, rowing clubs dot the bank, and the whole district has the atmosphere of a Bohemian village that was quietly absorbed by a capital city and never quite noticed. Unlock the Easter egg concealed on the hillside: Suchdol is home to the Czech University of Life Sciences, whose campus contains one of the largest university arboreta in the country — over 600 tree and shrub species from across the world, growing in a park most Praguers have never entered. The arboretum is open to the public. The village keeps this secret well.`,
    cz: `Odvážný průzkumníku, Suchdol je nejsevernější říční vesnicí Prahy — tichá enkláva v Praze 6, kde městský hluk zcela umlkne a Vltava se vine krajinou, která se za posledních sto let téměř nezměnila. Zalesněné svahy se svažují k řece, na břehu jsou veslařské kluby a celá čtvrť má atmosféru bohemské vesnice, kterou tiše pohltilo hlavní město, aniž si to kdy uvědomila. Odemkni easter egg ukrytý na svahu: Suchdol je domovem České zemědělské univerzity, jejíž kampus ukrývá jeden z největších univerzitních arboret v zemi — přes 600 druhů stromů a keřů z celého světa, rostoucích v parku, který většina Pražanů nikdy nenavštívila. Arboretum je přístupné veřejnosti. Vesnice toto tajemství dobře střeží.`,
    zh: `勇敢的探险家，苏赫多尔是布拉格最北端的河边村庄——布拉格6区的一处幽静飞地，城市的喧嚣在此完全消散，伏尔塔瓦河蜿蜒穿过一个百年来几乎未曾改变的景观。林木覆盖的山坡一路延伸至河岸，赛艇俱乐部点缀其间，整个街区都散发着波西米亚村庄的气息，仿佛它只是悄悄被一座首都吸纳，从未意识到这一点。解锁隐藏在山坡上的彩蛋：苏赫多尔是捷克生命科学大学的所在地，其校园内设有全国最大的大学植物园之一——来自世界各地的600余种乔木和灌木，生长在一座大多数布拉格人从未踏足的公园里。植物园对公众开放。这个村庄把这个秘密守护得很好。`,
  },

  "lihovar": {
    en: `Brave explorer, Lihovar — "The Distillery" — is Prague's most intoxicating hidden-gem quest zone: a repurposed industrial complex in Smíchov that once produced spirits for the entire region, now transformed into one of the city's most atmospheric cultural venues. Exposed brick, iron beams, and vaulted ceilings from the 19th-century factory frame live stages, markets, and bars. Unlock the Easter egg in the building's industrial legacy: Czech lihovar culture dates to the 18th century, when noble estates were legally required to process surplus grain into spirits as a fiscal regulation — alcohol production as tax law. The original distillation vats and copper piping were preserved as sculptural objects during conversion. This building is where a bureaucratic obligation became art. The alcohol is now metaphorical. But it is still very much on the menu.`,
    cz: `Odvážný průzkumníku, Lihovar je nejopojnější hidden-gem quest zónou Prahy — přestavěný průmyslový komplex na Smíchově, který kdysi vyráběl lihoviny pro celý region, nyní přeměněný v jedno z nejatmosféričtějších kulturních míst ve městě. Obnažené cihly, železné trámy a klenuté stropy z továrny 19. století rámují živá pódia, trhy a bary. Odemkni easter egg v průmyslovém dědictví budovy: česká lihovarská kultura sahá do 18. století, kdy bylo šlechtickým panstvím zákonem nařízeno zpracovávat přebytečné obilí na lihoviny jako fiskální regulaci — výroba alkoholu jako daňové právo. Původní destilační nádrže a měděné potrubí byly při přestavbě zachovány jako sochařské objekty. Tato budova je místem, kde se byrokratická povinnost stala uměním. Alkohol je nyní metaforický. Ale stále je na jídelním lístku.`,
    zh: `勇敢的探险家，Lihovar——"蒸馏厂"——是布拉格最令人沉醉的隐藏宝石任务区：斯米霍夫的一处改建工业综合体，曾为整个地区生产烈酒，现已转型为城市中氛围最浓郁的文化场所之一。19世纪工厂遗留的裸露砖墙、铁制横梁和穹顶天花板将现场舞台、集市和酒吧框在其中。解锁建筑工业遗产中的彩蛋：捷克蒸馏文化可追溯至18世纪，当时法律要求贵族庄园将多余的谷物加工成烈酒作为财政管制——酒精生产即税法。改建过程中，原有的蒸馏罐和铜制管道被保留下来作为雕塑装置。这座建筑是官僚义务化身为艺术的地方。如今的酒精是隐喻性的，但菜单上依然有酒。`,
  },

  "hraz-preharady-hostivar": {
    en: `Brave explorer, the Hostivař Reservoir Dam is Prague's eastern swimming fortress — a concrete dam completed in 1959 by blocking the Botič stream, creating a recreational lake that serves as the unofficial outdoor pool for Prague's entire southeastern quarter. On summer weekends, thousands descend to swim, windsurf, and picnic on the grassy banks. Unlock the Easter egg submerged beneath the surface: the reservoir sits atop what was once a network of medieval fishponds — Czech nobility maintained elaborate artificial pond systems across Bohemia for centuries, and this valley was part of that network. When the dam was built, archaeologists documented traces of the medieval pond infrastructure before the valley flooded. This lake was built on the bones of its predecessor. The fish, at least, never noticed the transition.`,
    cz: `Odvážný průzkumníku, Hráz přehrady Hostivař je východní plaveckou pevností Prahy — betonová přehrada dokončená v roce 1959 přehrazením Botiče, vytvářející rekreační jezero sloužící jako neoficiální koupaliště pro celou jihovýchodní čtvrť Prahy. O letních víkendech sem přicházejí tisíce lidí plavat, windsurfovat a piknikovat na travnatých březích. Odemkni easter egg ponořený pod hladinou: přehrada leží na místě, kde kdysi existovala síť středověkých rybníků — česká šlechta udržovala po staletí po celých Čechách propracované soustavy umělých rybníků a toto údolí bylo součástí té sítě. Při stavbě přehrady archeologové zdokumentovali stopy středověké rybniční infrastruktury, než bylo údolí zatopeno. Toto jezero bylo postaveno na kostech svého předchůdce. Ryby si přechodu, alespoň, nevšimly.`,
    zh: `勇敢的探险家，霍斯提瓦日水库大坝是布拉格的东部游泳堡垒——一座1959年通过拦截博季奇溪流而完成的混凝土大坝，形成了一个作为布拉格整个东南区非官方户外游泳池的休闲湖泊。夏季周末，数以千计的市民来此游泳、帆板和在草坡上野餐。解锁沉没于水面之下的彩蛋：水库坐落于昔日中世纪鱼塘网络的遗址之上——捷克贵族数百年来在波西米亚各地维护着精心设计的人工鱼塘系统，这片山谷也是其中的一部分。建造水库时，考古学家在山谷被淹没之前记录了中世纪鱼塘基础设施的遗迹。这座湖泊建立在其前身的骸骨之上。至少，鱼儿从未察觉到这次转变。`,
  },

  "soutok-berounky-vltavy": {
    en: `Brave explorer, the confluence of the Berounka and Vltava rivers at Lahovice is one of the most dramatically peaceful quest zones in all of Prague — and almost no one comes here. Standing at the precise point where two of Bohemia's great rivers merge, you can watch two distinct bodies of water flow together, their colour and current slightly different even as they become one. Unlock the Easter egg hidden in the current: the Berounka drains a vast agricultural watershed and rises dangerously fast in heavy rain — it has contributed to flooding downstream Prague repeatedly throughout history, most catastrophically in 2002. A historic ferry crossing operated at this confluence for centuries. This is the southwestern tip of Prague's city limits. Stand here and you are standing at the exact edge of the city.`,
    cz: `Odvážný průzkumníku, soutok Berounky a Vltavy v Lahovicích je jednou z nejdramatičtěji klidných quest zón celé Prahy — a téměř nikdo sem nepřijede. Stojíš na přesném místě, kde se spojují dvě velké bohemské řeky, a můžeš sledovat, jak dva odlišné vodní toky splývají, jejich barva a proud jsou mírně odlišné i v momentě, kdy se spojují. Odemkni easter egg ukrytý v proudu: Berounka odvádí vodu z rozsáhlého zemědělského povodí a v silném dešti stoupá nebezpečně rychle — opakovaně přispěla k povodním v Praze, nejkatastrofičtěji v roce 2002. Na tomto soutoku po staletí fungoval historický přívoz. Toto je jihozápadní cíp pražské hranice. Stojíš na samém okraji města.`,
    zh: `勇敢的探险家，拉霍维采的贝罗温卡河与伏尔塔瓦河的交汇处是布拉格所有任务区中最戏剧性的宁静地带——而几乎没有人来到这里。站在波西米亚两条大河汇合的精确位置，你可以目睹两股水流合二为一，即便在合并之际，其颜色和流速仍略有不同。解锁隐藏在水流中的彩蛋：贝罗温卡排泄着广阔农业流域的水流，大雨时水位上涨迅猛——它多次导致下游布拉格的洪水，最具灾难性的是2002年。这个汇流处曾有一条历史悠久的摆渡运营了数百年。这里是布拉格城市边界的西南端。站在这里，你就站在这座城市的最边缘。`,
  },

  "bohnice": {
    en: `Brave explorer, Bohnice is a northern Prague 8 quest zone that layers three thousand years of history beneath a modern housing estate. The Zámka hillfort holds settlements dating from the Eneolithic through the Bronze Age and the Hallstatt period. A Romanesque church dedicated to Saints Peter and Paul was founded here in 1158, later rebuilt in Baroque. The district's defining landmark is its Psychiatric Hospital, built between 1906 and 1911, which contains its own Church of St. Václav, a cemetery, and an experimental theatre — Divadlo Za plotem, Theatre Behind the Fence — where patients perform alongside professional actors. Unlock the Easter egg hiding in plain sight on every street sign: every single street in the Bohnice housing estate is named after a city or region of Poland — Lodžská, Zhořelecká, Hnězdenská — built deliberately as a monument to Czech-Polish friendship. Walk the streets here and you are walking through an atlas of Poland.`,
    cz: `Odvážný průzkumníku, Bohnice jsou severní quest zónou Prahy 8, která vrství tři tisíce let historie pod moderní panelové sídliště. Hradiště Zámka uchovává osídlení od eneolitu přes dobu bronzovou až po dobu halštatskou. Románský kostel sv. Petra a Pavla byl zde založen v roce 1158, později přestavěn v barokním slohu. Nejvýznamnější dominantou čtvrti je Psychiatrická nemocnice postavená v letech 1906–1911, která má vlastní kostel sv. Václava, hřbitov a experimentální divadlo — Divadlo Za plotem — kde pacienti hrají po boku profesionálních herců. Odemkni easter egg skrytý na každé ceduli s názvem ulice: každá ulice v bohnickém sídlišti nese jméno polského města nebo regionu — Lodžská, Zhořelecká, Hnězdenská — záměrně pojmenované jako pomník česko-polského přátelství. Projít zdejšími ulicemi znamená procházet atlasem Polska.`,
    zh: `勇敢的探险家，波赫尼采是布拉格8区北部的任务区，在现代板式住宅楼群之下层叠着三千年的历史。扎姆卡山堡保存着从铜石并用时代经青铜时代延续至哈尔施塔特时期的定居遗址。这里的圣彼得与保罗罗曼式教堂始建于1158年，后经巴洛克风格重建。该区最具代表性的地标是建于1906至1911年间的精神病医院，院内设有圣瓦茨拉夫教堂、一处墓地，以及名为"围栏后面的剧院"（Divadlo Za plotem）的实验剧场——患者在这里与专业演员同台演出。解锁隐藏在每一块路牌上的彩蛋：波赫尼采住宅区的每一条街道都以波兰的城市或地区命名——洛兹街、格尔利茨街、格涅兹诺街——这是作为捷波友谊纪念碑而特意如此命名的。走在这里的街道上，就是在穿越一部波兰地图册。`,
  },

  "letňany": {
    en: `Brave explorer, Letňany is Prague's northeastern outer-district quest zone — a sprawling neighbourhood defined by its airfield history, exhibition grounds, and shopping megastructure. The Letňany Airfield, now partly converted to trade fair grounds, hosted Czechoslovak aviation championships and international expos for decades. Unlock the dark Easter egg embedded in its runway history: on the night of 20–21 August 1968, this airfield was the first point of contact in Prague during the Warsaw Pact invasion of Czechoslovakia. Soviet military transport aircraft landed here in darkness, disgorging the first troops to occupy the city. The airfield that had hosted peaceful air shows became, in one night, the entry point of an army. The exhibition halls built later on the same grounds now host boat shows and trade fairs. History is thorough about its ironies.`,
    cz: `Odvážný průzkumníku, Letňany jsou severovýchodní vnější quest zónou Prahy — rozsáhlá čtvrť definovaná historií svého letiště, výstavními plochami a nákupní megastrukturou. Letiště Letňany, nyní z části přeměněné na výstaviště, hostilo po desetiletí československé letecké šampionáty a mezinárodní veletrhy. Odemkni temný easter egg zabudovaný v historii jeho dráhy: v noci ze 20. na 21. srpna 1968 bylo toto letiště prvním kontaktním místem v Praze při invazi vojsk Varšavské smlouvy do Československa. Sovětská vojenská transportní letadla zde přistála ve tmě a vyvrhla první vojáky k obsazení města. Letiště, které hostilo mírumilovné letecké přehlídky, se za jednu noc stalo vstupním bodem armády. Výstavní haly postavené na stejných pozemcích nyní hostí lodní výstavy a veletrhy. Historie je důkladná ve svých ironiích.`,
    zh: `勇敢的探险家，列特尼亚内是布拉格东北方向的外围任务区——一个由机场历史、展览场地和购物巨构所定义的广阔街区。列特尼亚内机场，如今部分已改建为贸易博览会场地，数十年间曾举办捷克斯洛伐克航空锦标赛和国际博览会。解锁嵌入其跑道历史中的黑暗彩蛋：1968年8月20日至21日夜间，这个机场成为华沙条约组织入侵捷克斯洛伐克期间布拉格的第一个接触点。苏联军事运输机在黑暗中降落于此，卸下了占领这座城市的第一批士兵。这个曾举办和平航空表演的机场，在一夜之间成为了一支军队的入口。之后在同一片土地上建起的展览大厅，如今举办着船展和贸易博览会。历史对其讽刺之处总是如此彻底。`,
  },

  "grand-hotel-prague-towers": {
    en: `Brave explorer, behold Grand Hotel Prague Towers — twin towers of unashamed opulence rising above the city like an architectural statement that dares you to question whether the lobby needs its own postcode. Luxury hotels in Prague have a distinguished tradition of hosting diplomats, rock stars, and visiting dignitaries who required seventeen pillows and a concierge capable of sourcing Moravian truffles at 2 AM with a straight face. Unlock the hidden truth: Cold War Prague's grand hotels were as much intelligence-gathering operations as hospitality establishments — their bars packed with foreign businessmen, Western journalists, and gentlemen reading newspapers far too intently. The chandeliers have seen things. The marble floors have absorbed more hushed conversations than any archive. Achievement unlocked: Ordering coffee here and pretending the price is completely normal.`,
    cz: `Odvážný průzkumníku, hleď na Grand Hotel Praha Towers — dvě věže nestydaté okázalosti tyčící se nad městem jako architektonická výzva, která zpochybňuje, zda lobby potřebuje vlastní PSČ. Luxusní hotely v Praze mají vznešenou tradici hostování diplomatů, rockových hvězd a návštěvníků, kteří potřebovali sedmnáct polštářů a recepčního schopného sehnat moravské lanýže ve 2 ráno s kamennou tváří. Odemkni skrytou pravdu: velkolepé hotely pražské studené války byly stejně tak zpravodajskými operacemi jako hotely — jejich bary plné zahraničních podnikatelů, západních novinářů a pánů čtoucích noviny příliš soustředěně. Lustry viděly věci. Mramorové podlahy vstřebaly více ztichlých rozhovorů než jakýkoli archiv. Odemčen achievement: Objednání kávy zde a předstírání, že cena je zcela normální.`,
    zh: `勇敢的探险家，仰望布拉格大酒店双塔——两座不知羞耻的奢华塔楼高耸于城市之上，如同一个建筑学宣言，暗示大堂或许需要自己的邮政编码。布拉格的豪华酒店有着接待外交官、摇滚明星和访客的光荣传统，这些访客需要十七个枕头，以及一位能够在凌晨两点面不改色地找来摩拉维亚松露的礼宾人员。解锁隐藏真相：冷战时期布拉格的大酒店既是情报收集机构，也是接待场所——酒吧里挤满了外国商人、西方记者，以及读报纸读得过于专注的绅士们。吊灯见过许多事。大理石地板吸收的低声交谈比任何档案馆都要多。成就解锁：在这里点一杯咖啡，并假装价格完全正常。`,
  },

  "muzeum-policie-cr": {
    en: `Brave explorer, tucked inside a former Augustinian monastery that made a dramatic career change, the Museum of the Czech Police is Prague's most underrated quest zone — where forensic science, communist history, and traffic-law dioramas collide with unexpectedly compelling results. Founded in 1982 when Czechoslovakia needed its police to be heroes in a museum if not always in practice, it has aged into something genuinely fascinating: decommissioned surveillance equipment, cold-case reconstructions, and interactive detective challenges that will immediately convince you that you are better at this than you actually are. Unlock the Easter egg in the crypt: the monastery's medieval cellars beneath the exhibition halls have never been fully excavated — officially. The interrogation rooms from the communist era have been left largely intact. Their austere practicality speaks louder than any placard ever could.`,
    cz: `Odvážný průzkumníku, schované uvnitř bývalého augustiniánského kláštera, který prošel dramatickou změnou kariéry, leží Muzeum Policie České republiky — nejpodceňovanější quest zóna Prahy. Místo, kde se kriminalistika, komunistická historie a dioramy dopravních předpisů střetávají s nečekaně poutavými výsledky. Založené v roce 1982, kdy Československo potřebovalo, aby jeho policie byla hrdiny alespoň v muzeu, dozrálo v něco skutečně fascinujícího: vyřazené sledovací vybavení, rekonstrukce studených případů a interaktivní detektivní výzvy, které tě okamžitě přesvědčí, že jsi v tom lepší, než ve skutečnosti jsi. Odemkni easter egg v kryptě: středověké sklepy kláštera pod výstavními sály nebyly nikdy zcela prozkoumány — oficiálně. Výslechové místnosti z komunistické éry byly z velké části ponechány nedotčeny. Jejich strohá funkčnost hovoří hlasitěji než jakákoli cedule.`,
    zh: `勇敢的探险家，藏身于一座经历了戏剧性职业转变的前奥古斯丁修道院内，捷克警察博物馆是布拉格最被低估的任务区——法医科学、共产主义历史和交通法规模型在这里以出人意料的引人入胜的方式碰撞在一起。1982年创建之初，捷克斯洛伐克需要其警察至少在博物馆里成为英雄。如今它已发展成真正令人着迷的场所：退役的监控设备、悬案重建，以及互动侦探挑战，后者会立刻让你相信自己比实际上更擅长这些。解锁地窟里的彩蛋：修道院中世纪地窖从未被完全发掘——官方如此声称。共产主义时代的审讯室基本保持原貌。那种简朴的实用性比任何说明牌都更有力地说明了一切。`,
  },

  "vysehrad-railway-bridge": {
    en: `Brave explorer, the Vyšehrad Railway Bridge is Prague's most stoic monument — a riveted iron arch that has carried trains across the Vltava since 1872 without once demanding recognition, a souvenir shop, or even a decent Wikipedia photograph. While Charles Bridge queues around the block, this engineering veteran quietly moves actual passengers across actual water at respectable intervals, entirely unbothered by the admiration it will never receive. Unlock the hidden truth: the original bridge was built with the bold Victorian confidence that everything would be fine right up until the trains got heavier — it was replaced in the early 20th century with a sturdier structure that has never been seriously questioned since. Arrive at dusk when a train crosses. Feel the rumble travel through the riverbank. Some experiences do not require a crowd, a caption, or a filter.`,
    cz: `Odvážný průzkumníku, Vyšehradský železniční most je nejstoičtějším monumentem Prahy — nýtovaný ocelový oblouk přepravující vlaky přes Vltavu od roku 1872 bez jediného požadavku na uznání, suvenýrový obchůdek nebo slušnou fotografii na Wikipedii. Zatímco se Karlův most frontuje kolem bloku, tento inženýrský veterán tiše přepravuje skutečné cestující přes skutečnou vodu v slušných intervalech, neobtěžován obdivem, který nikdy neobdrží. Odemkni skrytou pravdu: původní most byl postaven s tou odvážnou viktoriánskou jistotou, že všechno bude v pořádku až do chvíle, kdy vlaky zněžněly — byl nahrazen na počátku 20. století pevnější konstrukcí, která nikdy nebyla vážně zpochybněna. Přijď za soumraku, když přejíždí vlak. Pocit hukotu šířícího se nábřežím. Některé zážitky nevyžadují dav, popis ani filtr.`,
    zh: `勇敢的探险家，维谢赫拉德铁路桥是布拉格最沉默坚忍的纪念碑——自1872年起以铆接铁拱将火车运送过伏尔塔瓦河，从未要求任何认可、纪念品商店，甚至连一张像样的维基百科照片都没有。当查理大桥的队伍绕着街区排起长龙时，这位工程老兵在合理的间隔里悄然将真实的乘客送过真实的河水，对自己永远不会收到的赞美毫不在意。解锁隐藏真相：原来的桥以维多利亚时代的大胆自信建造，相信一切都会好起来——直到火车变得越来越重为止。它在20世纪初被更坚固的结构取代，此后从未受到过认真质疑。黄昏时分列车驶过时到达。感受震动沿着河岸传来。有些体验不需要人群、说明文字或滤镜。`,
  },

  "strahov-stadium": {
    en: `Brave explorer, the Great Strahov Stadium holds a record so enormous it sounds invented: the world's largest stadium by total area, covering 63,000 square metres on the hill above Malá Strana, capable of holding 220,000 spectators for the socialist Spartakiad gymnastics events. Every five years from 1955 to 1990, up to 180,000 participants performed synchronised routines here in human formations visible only from aircraft — part genuine athletic spectacle, part large-scale exercise in collective psychology, entirely unlike anything built before or since. Unlock the Easter egg visible only from above: aerial photographs of Spartakiad events show human beings arranged like living pixels in state-approved images — flags, symbols, historical tableaux composed entirely from bodies. Today the stadium rests quietly under grass and football nets, occasionally rousing itself for concerts. The grandstands remember everything. You were not here for any of it. Come anyway.`,
    cz: `Odvážný průzkumníku, Velký strahovský stadion drží rekord tak obrovský, že zní vymyšleně: největší stadion světa rozlohou, zabírající 63 000 čtverečních metrů na kopci nad Malou Stranou, schopný pojmout 220 000 diváků pro socialistické spartakiádní gymnastické akce. Každých pět let od roku 1955 do roku 1990 zde provádělo synchronizované sestavy až 180 000 účastníků v lidských formacích viditelných pouze z letadla — část opravdové atletické podívané, část rozsáhlého cvičení v kolektivní psychologii, zcela nepodobná ničemu vybudovanému předtím nebo poté. Odemkni easter egg viditelný pouze shora: letecké fotografie spartakiádních akcí ukazují lidi uspořádané jako živé pixely ve státem schválených obrazcích — vlajky, symboly, historické scény složené výhradně z lidských těl. Dnes stadion tiše odpočívá pod trávou a fotbalovými sítěmi, příležitostně se probouzí pro koncerty. Tribůny si pamatují vše. Nebyl jsi u ničeho z toho. Přijď stejně.`,
    zh: `勇敢的探险家，斯特拉霍夫大球场保持着一项大到让人觉得像是编造的纪录：世界上总面积最大的体育场，占地63000平方米，坐落于小城区上方的山丘上，能够容纳220000名观众观看社会主义斯巴达体育节的体操表演。从1955年到1990年，每五年多达18万名参与者在这里表演同步动作，形成只有从飞机上才能看清的人体阵列——既是真正的体育壮观景象，也是大规模集体心理活动，与此前或此后建造的任何事物都截然不同。解锁只有从高空才能看见的彩蛋：斯巴达体育节的航拍照片显示，人们被排列成国家批准图案中的活体像素——旗帜、符号、完全由身体组成的历史画面。如今体育场在草坪和足球网下静静休憩，偶尔为音乐会而苏醒。看台记得一切。你不曾在场见证其中任何一幕。无论如何，来这里看看。`,
  },

  "staromestska-vodarenska-vez": {
    en: `Brave explorer, the Old Town Water Tower has stood at the Staré Město end of the Vltava bridges since 1489 — a gothic water pump disguised as a decorative tower, which is a more honest account of its function than most buildings manage. Built to house the mechanical works supplying Prague's fountains with river water, it performed reliable hydraulic service for centuries while its neighbour, the grander Old Town Bridge Tower, collected all the architectural admiration. Unlock the Easter egg compressed into its walls: the tower was badly damaged when Swedish forces bombarded Prague in 1648, rebuilt from the rubble, struck by ice floods in 1784, rebuilt again, repurposed for gunpowder storage, and is still standing. It received a decorative baroque lantern in the 18th century as if to say: after 250 years of all this, it had earned something nice. This is the most resilient building in Prague.`,
    cz: `Odvážný průzkumníku, Staroměstská vodárenská věž stojí na staroměstském konci vltavských mostů od roku 1489 — gotická vodní pumpa zamaskovaná jako dekorativní věž, což je čestnější popis její funkce, než většina budov zvládne. Postavená k umístění mechanických pohonů zásobujících pražské fontány říční vodou, prováděla spolehlivé hydraulické služby po staletí, zatímco sousední, velkolepější Staroměstská mostecká věž sbírala veškeré architektonické obdivování. Odemkni easter egg zabudovaný do jejích zdí: věž byla těžce poškozena, když švédské síly bombardovaly Prahu v roce 1648, přestavěna z ruin, zasažena ledovými povodněmi v roce 1784, přestavěna znovu, přeměněna pro skladování střelného prachu, a stále stojí. V 18. století obdržela dekorativní barokní lucernu, jako by se říkalo: po 250 letech tohohle všeho si zasloužila něco pěkného. To je nejodolnější budova v Praze.`,
    zh: `勇敢的探险家，旧城水塔自1489年起屹立于伏尔塔瓦河桥旧城一端——一座以装饰塔形式伪装的哥特式水泵，这比大多数建筑对自身功能的描述都要诚实。它的建造是为了容纳向布拉格喷泉供应河水的机械装置，几个世纪以来默默提供可靠的水利服务，而它气派的邻居旧城桥塔则收获了所有的建筑赞誉。解锁嵌入其墙壁的彩蛋：1648年瑞典军队炮击布拉格时，水塔遭受严重损毁，从废墟中重建；1784年被冰洪水击中，再次重建；之后被改用于储存火药，至今仍然屹立。18世纪它还获得了一盏装饰性的巴洛克风格灯笼，仿佛在说：经历了250年的这一切，它值得拥有一些美好的东西。这是布拉格最坚韧的建筑。`,
  },

  "narodni-technicka-knihovna": {
    en: `Brave explorer, the National Technical Library is the kind of building that makes you feel marginally more intelligent simply by entering — the highest compliment architecture can pay. Opened in 2009 on the Dejvice campus of the Czech Technical University, this glass-and-concrete cube stacks six floors of scientific and technical literature inside a cathedral of ordered knowledge. The central atrium soars high enough that students have reportedly lost entire semesters inside it, its natural light angled by architects who clearly had strong opinions about photons. Unlock the Easter egg hidden in the basement: a tunnel network beneath the library connects to the broader ČVUT campus, allowing the truly committed student to move between faculties entirely underground — an achievement so perfectly on-brand for an engineering school that it could only have been approved with great enthusiasm. Visit during exam season for peak atmospheric density. You are surrounded by people building the future. Try not to distract them.`,
    cz: `Odvážný průzkumníku, Národní technická knihovna je ten typ budovy, který tě díky pouhému vstupu přiměje cítit se o něco inteligentnějším — nejvyšší poklona, jakou může architektura udělit. Otevřená v roce 2009 na dejvickém kampusu Českého vysokého učení technického, tato skleněno-betonová kostka vrství šest podlaží vědecké a technické literatury uvnitř katedrály uspořádaného vědění. Centrální atrium je tak vysoké, že studenti v něm prý ztratili celé semestry, přirozené světlo nastavené architekty, kteří evidentně měli silné názory na fotony. Odemkni easter egg v suterénu: tunelovací síť pod knihovnou spojuje se širším kampusem ČVUT, což umožňuje skutečně odhodlanému studentovi pohybovat se mezi fakultami zcela pod zemí — achievement tak dokonale typický pro inženýrskou školu, že mohl být schválen jen s velkým nadšením. Navštiv v době zkouškového pro maximální atmosferickou hustotu. Jsi obklopen lidmi budujícími budoucnost. Snaž se je nerušit.`,
    zh: `勇敢的探险家，国家技术图书馆是那种仅凭走进去就能让你感觉稍微聪明一点的建筑——这是建筑所能给予的最高赞美。2009年在捷克技术大学德亚维采校区开放，这座玻璃与混凝土构成的方块在有序知识的殿堂内叠放着六层科技文献。中央中庭高耸入云，据说有学生在其中迷失了整个学期，自然光线由对光子显然有强烈想法的建筑师精心设计。解锁地下室里的彩蛋：图书馆下方的隧道网络与捷克技术大学更广泛的校区相连，使真正专注的学生能够完全在地下穿梭于各学院之间——这一成就如此完美地符合工科学校的气质，以至于只可能以极大的热情获得批准。在考试季节到访，体验最高密度的学术氛围。你被正在构建未来的人们所包围。尽量不要打扰他们。`,
  },

  "nemocnice-motol": {
    en: `Brave explorer, Motol University Hospital is the largest hospital complex in the Czech Republic — a city-within-a-city sprawling across Praha 5 that has been patching up the nation since it opened in 1978. With over 2,300 beds and a staff count that rivals a small municipality, Motol handles everything from routine fractures to the kinds of medical emergencies that make other hospitals nervously recommend a second opinion. The campus itself is architecturally ambitious in the way that late-socialist Czechoslovakia did ambitious: enormous, purposeful, and completely indifferent to whether you find it pretty. Hidden-gem status comes not from glamour but from the fact that most people only visit under circumstances they would rather not discuss. Achievement unlocked: you came here voluntarily. That is statistically unusual and deserves +20 XP.`,
    cz: `Odvážný průzkumníku, Fakultní nemocnice Motol je největším nemocničním komplexem v České republice — město ve městě rozprostírající se po Praze 5, které záplatuje národ od svého otevření v roce 1978. S více než 2 300 lůžky a počtem zaměstnanců soupeřícím s malou obcí se Motol věnuje všemu od běžných zlomenin po ty druhy medicínských emergencí, které způsobují, že jiné nemocnice nervózně doporučují druhý názor. Kampus je architektonicky ambiciózní způsobem, jakým dělalo ambiciózní pozdně socialistické Československo: obrovský, účelný a naprosto lhostejný k tomu, zda ho považuješ za pěkný. Status hidden gem nepramení z okázalosti, ale ze skutečnosti, že většina lidí sem přichází za okolností, o nichž by raději nemluvila. Achievement odemčen: přišel jsi sem dobrovolně. To je statisticky neobvyklé a zaslouží si +20 XP.`,
    zh: `勇敢的探险家，莫托尔大学医院是捷克共和国最大的医院综合体——布拉格五区一座城中城，自1978年开业以来一直为这个国家缝缝补补。拥有2300余张病床和媲美小型城市的员工数量，莫托尔处理从日常骨折到那些让其他医院紧张地建议再次会诊的紧急医疗状况。院区本身以晚期社会主义捷克斯洛伐克的雄心方式展示着雄心：庞大、实用，且对你是否觉得它好看漠然置之。隐秘宝藏的身份并非来自魅力，而是来自大多数人只在他们宁愿不谈的情况下才会来访这一事实。成就解锁：你是自愿来这里的。这在统计上是不寻常的，值得+20 XP。`,
  },

  "oc-flora": {
    en: `Brave explorer, Atrium Flora sits at the crossroads of two great Prague truths: that Vinohrady has excellent metro connections, and that Olšany Cemetery next door is full of people who have run out of errands to run. Opened above the Flora metro station on Line A, this glass-roofed shopping mall offers the full taxonomy of modern retail therapy — fashion, electronics, a multiplex cinema, and a food court where the smell of fast food mingles with mild existential reflection. What makes Flora quietly remarkable is its location: to the north, one of Prague's largest cemeteries spreads across several hectares, lending the mall a contemplative edge that its architects almost certainly did not intend. Recommended approach: buy something frivolous, then take a respectful detour next door to recalibrate your priorities. Achievement unlocked: the circle of consumerism and mortality, all within walking distance.`,
    cz: `Odvážný průzkumníku, Atrium Flora stojí na křižovatce dvou velkých pražských pravd: že Vinohrady má vynikající metrospojení a že Olšanské hřbitovy hned vedle jsou plné lidí, kteří již nemají žádné pochůzky. Otevřené nad stanicí metra Flora na lince A, toto nákupní centrum s prosklenou střechou nabízí plnou taxonomii moderní obchodní terapie — módu, elektroniku, multikino a food court, kde se vůně fast foodu mísí s mírnou existenciální reflexí. Co Floru tiše pozoruhodnou činí, je její poloha: na severu se rozkládá jeden z největších pražských hřbitovů na několika hektarech, propůjčující obchodnímu centru kontemplatívní nádech, který jeho architekti téměř jistě nezamýšleli. Doporučený přístup: kup si něco zbytečného, pak si udělej uctivou odbočku vedle a přenastavte priority. Achievement odemčen: kruh konzumerismu a smrtelnosti, vše v docházkové vzdálenosti.`,
    zh: `勇敢的探险家，阿特里乌姆·弗洛拉购物中心位于布拉格两大真理的交汇点：维诺赫拉迪拥有出色的地铁连接，而紧邻的奥尔扎尼公墓则住满了已经没有差事可跑的人。这座建在A线弗洛拉地铁站上方的玻璃顶购物中心提供了现代零售疗法的完整分类——时装、电子产品、多厅影院，以及快餐气味与轻度存在主义沉思交融的美食广场。让弗洛拉悄然不凡的是它的位置：北面，布拉格最大的墓地之一延伸开数公顷，给购物中心带来了其建筑师几乎肯定没有预料到的沉思气质。建议做法：买点无关紧要的东西，然后绕道隔壁进行一次庄重的参观，重新校准你的优先事项。成就解锁：消费主义与死亡轮回，尽在步行距离之内。`,
  },

  "cafe-louvre": {
    en: `Brave explorer, Café Louvre has been hosting the great minds and mediocre lunches of Prague since 1902, making it one of the city's most durable cultural institutions — which is saying something in a city that has survived Habsburgs, Nazis, communists, and tourist season. Franz Kafka held court here. Albert Einstein played billiards in the back room (the table survives; his genius, alas, is not on offer). The café was so threatening to the communist regime that it was shut down in 1948 and stayed dark for forty years, which is perhaps the strongest possible endorsement a coffee shop can receive. Re-opened in 1992, it has since returned to its natural state: marble tables, high ceilings, strong coffee, and the comfortable illusion that you are about to have an important idea. Located on Národní třída at number 22, it demands at minimum a schwarzwälder and an hour of your finest unproductive thinking.`,
    cz: `Odvážný průzkumníku, Café Louvre hostí velké mysli a průměrné obědy Prahy od roku 1902, čímž se řadí mezi nejodolnější kulturní instituce města — což o něčem vypovídá v městě, které přežilo Habsburky, nacisty, komunisty a turistickou sezónu. Franz Kafka zde trůnil. Albert Einstein hrával kulečník v zadním pokoji (stůl přežil; jeho génius bohužel není k dispozici). Kavárna byla pro komunistický režim tak nebezpečná, že byla uzavřena v roce 1948 a zůstala temná čtyřicet let — to je pravděpodobně nejsilnější možná reklama, jaké se kavárně může dostat. Znovuotevřená v roce 1992, od té doby se vrátila do svého přirozeného stavu: mramorové stoly, vysoké stropy, silná káva a pohodlná iluze, že se chystáš mít důležitou myšlenku. Sídlí na Národní třídě číslo 22 a vyžaduje alespoň schwarzwälder a hodinu tvého nejkvalitnějšího neproduktivního přemýšlení.`,
    zh: `勇敢的探险家，卢浮宫咖啡馆自1902年起便招待着布拉格的伟大思想和平庸午餐，使其成为这座城市最经久不衰的文化机构之一——在一座历经哈布斯堡、纳粹、共产党和旅游旺季的城市里，这说法自有其分量。弗兰茨·卡夫卡曾在此驻守。阿尔伯特·爱因斯坦在后室打台球（那张台球桌流传至今；他的天才，遗憾地说，并不附赠）。这家咖啡馆对共产主义政权如此具有威胁性，以至于1948年被迫关闭，在黑暗中沉寂了四十年——这或许是一家咖啡店所能获得的最有力的背书。1992年重新开业，此后它回归了本来面目：大理石桌，高挑天花板，浓烈咖啡，以及你即将迸发出某个重要想法的舒适幻觉。坐落于国家大街22号，最起码需要一块黑森林蛋糕和一个小时的高质量无用思考。`,
  },

  "czech-national-bank": {
    en: `Brave explorer, the Czech National Bank occupies a neoclassical palace on Na Příkopě 28 that radiates the specific authority of an institution that controls how much your morning coffee is worth. Founded in 1919 alongside the First Czechoslovak Republic, the CNB has since managed the koruna through interwar prosperity, Nazi occupation, communist command economy, hyperinflationary chaos, and post-revolution capitalism — a monetary track record that is either impressive or harrowing depending on which decade you lived through. The Easter egg the bank would least expect you to find: the Monetary Museum in the basement is free, open to the public, and contains a surprisingly engaging history of Czech currency from medieval silver coins to present day. Most people walk past the building assuming it contains nothing but spreadsheets. Those people are missing out. Achievement unlocked: you know where the money is.`,
    cz: `Odvážný průzkumníku, Česká národní banka sídlí v neoklasicistním paláci na Na Příkopě 28, který vyzařuje specifickou autoritu instituce, jež kontroluje, kolik stojí tvoje ranní káva. Založená v roce 1919 spolu s První československou republikou, ČNB od té doby spravovala korunu meziválečnou prosperitou, nacistickou okupací, komunistickou centrálně plánovanou ekonomikou, hyperinflačním chaosem a porevoluční kapitalismus — měnové curriculum vitae, které je buď impozantní nebo děsivé, podle toho, které desetiletí jsi zažil. Easter egg, který by banka nejméně čekala, že najdeš: Monetární muzeum v suterénu je zdarma, otevřené veřejnosti a obsahuje překvapivě poutavou historii české měny od středověkých stříbrných mincí po současnost. Většina lidí prochází kolem budovy v přesvědčení, že neobsahuje nic než tabulky. Tito lidé o něco přicházejí. Achievement odemčen: víš, kde jsou peníze.`,
    zh: `勇敢的探险家，捷克国家银行占据着那普日科贝28号一座新古典主义宫殿，散发着一个掌控你早晨咖啡价格机构特有的权威感。1919年随第一捷克斯洛伐克共和国一同建立，捷克国家银行此后引导着克朗经历了两次世界大战之间的繁荣、纳粹占领、共产主义计划经济、恶性通货膨胀的混乱和后革命时代的资本主义——一段货币履历，视你经历的是哪个十年，要么令人印象深刻，要么令人不寒而栗。银行最不指望你发现的彩蛋：地下室里的货币博物馆免费向公众开放，收藏着从中世纪银币到今日的捷克货币令人惊讶地引人入胜的历史。大多数人经过这栋建筑时以为里面除了电子表格什么都没有。这些人错过了宝藏。成就解锁：你知道钱在哪里。`,
  },

  "palladium-prague": {
    en: `Brave explorer, Palladium Prague opened in 2007 on Náměstí Republiky and promptly became the kind of shopping centre that locals pretend not to enjoy but visit with suspicious regularity. Five floors of retail therapy sit inside what was once the Josefov Barracks — a 19th-century military complex whose soldiers could not have predicted that their parade ground would one day be occupied by a Zara and a food court. The real Easter egg is underfoot: during construction, workers uncovered medieval archaeological remains that the developers were legally obligated to preserve. A glass panel in the floor of the shopping centre now looks down onto actual medieval stonework, meaning you can stand in the middle of a modern mall and peer directly into the 13th century. Achievement unlocked: you found history beneath the H&M. That is not a sentence that gets written often.`,
    cz: `Odvážný průzkumníku, Palladium Praha otevřelo v roce 2007 na Náměstí Republiky a okamžitě se stalo tím druhem nákupního centra, který místní předstírají, že si neužívají, ale navštěvují ho s podezřelou pravidelností. Pět podlaží obchodní terapie sídlí uvnitř toho, co bylo kdysi Josefovskými kasárnami — vojenský komplex z 19. století, jehož vojáci nemohli předvídat, že jejich cvičiště bude jednoho dne obsazeno Zarou a food courtem. Skutečný Easter egg je pod nohama: při výstavbě dělníci odhalili středověké archeologické pozůstatky, které byli developeři právně povinni zachovat. Skleněný panel v podlaze nákupního centra nyní hledí dolů na skutečné středověké zdivo, což znamená, že můžeš stát uprostřed moderního obchodního centra a hledět přímo do 13. století. Achievement odemčen: našel jsi historii pod H&M. To není věta, která se píše příliš často.`,
    zh: `勇敢的探险家，布拉格帕拉迪乌姆购物中心2007年在共和国广场开业，随即成为那种本地人假装不享受但以令人怀疑的频率造访的购物中心。五层的零售疗法坐落在曾经的约瑟夫兵营内——一座19世纪军事综合体，其士兵们无论如何也预测不到他们的操场有朝一日会被一家Zara和美食广场占领。真正的彩蛋在脚下：施工期间，工人们挖掘出了中世纪考古遗迹，开发商依法有义务予以保存。购物中心地板上的一块玻璃面板现在俯视着真实的中世纪石砌建筑，意味着你可以站在现代商场中央，直接凝视13世纪。成就解锁：你在H&M下方发现了历史。这样的句子并不常被写下来。`,
  },

  "faculty-of-arts-uk": {
    en: `Brave explorer, the Faculty of Arts of Charles University stands on Náměstí Jana Palacha — a square named for the student who set himself on fire here in 1969 to protest the Soviet occupation, which gives you some indication of the weight this place carries. Founded as part of Charles University in 1348, making it one of the oldest humanities faculties in Central Europe, it has educated writers, philosophers, linguists, and dissidents across seven centuries with the quiet conviction that ideas are worth defending. On 21 December 2023, a student named David Kozák opened fire in the building, killing 14 people and injuring 25 in the deadliest mass shooting in Czech history since 1993. Eight of the victims were students from the Deaf Studies programme. The faculty did not close. It is still teaching. The courage required to return to a place like this is not a small thing. Check in with respect. Achievement unlocked: you stood where history was made and where people refused to let it end there.`,
    cz: `Odvážný průzkumníku, Filozofická fakulta Univerzity Karlovy stojí na Náměstí Jana Palacha — náměstí pojmenovaném po studentovi, který se zde v roce 1969 upálil na protest proti sovětské okupaci, což naznačuje, jakou tíhu toto místo nese. Založená jako součást Karlovy univerzity v roce 1348, čímž se řadí mezi nejstarší humanitní fakulty ve střední Evropě, vzdělávala spisovatele, filozofy, lingvisty a disidenty napříč sedmi staletími s tichým přesvědčením, že myšlenky stojí za obranu. 21. prosince 2023 student jménem David Kozák zahájil střelbu v budově, zabil 14 lidí a zranil 25 v nejsmrtelnější masové střelbě v české historii od roku 1993. Osm obětí byli studenti oboru Čeština v komunikaci neslyšících. Fakulta se nezavřela. Stále učí. Odvaha potřebná k návratu na takové místo není malá věc. Přijď s úctou. Achievement odemčen: stál jsi tam, kde se psaly dějiny, a kde lidé odmítli nechat je tam skončit.`,
    zh: `勇敢的探险家，查理大学哲学系坐落于扬·帕拉赫广场——这个广场以1969年在此自焚抗议苏联占领的学生命名，这让你明白这个地方承载着怎样的分量。作为查理大学的一部分创建于1348年，是中欧最古老的人文学院之一，七个世纪以来以对思想值得捍卫的静默信念培养了作家、哲学家、语言学家和异见人士。2023年12月21日，一名叫大卫·科扎克的学生在楼内开枪，杀死14人，伤及25人，成为捷克1993年以来最惨烈的大规模枪击事件。其中八名遇难者是聋人研究专业的学生。学院没有关闭。它仍在教学。回到这样的地方所需的勇气绝非小事。带着尊重来签到。成就解锁：你站在了历史书写之处，也站在了人们拒绝让历史就此终结之处。`,
  },

  "lehka-nejistota": {
    en: `Brave explorer, Lehká nejistota — Czech for "Slight Uncertainty" — is not a place you enter so much as a place you look up at and reconsider your life choices. Created by Czech sculptor Michal Trpák in 2015, this bronze figure of a suited businessman clutching an open umbrella hangs suspended above the street at Na Zbořenci in Praha 2, near the Mosaic House building. The umbrella does not appear to be providing meaningful structural support, yet the man looks remarkably composed about the whole situation. Trpák installed the piece as a meditation on the precariousness of modern life — the sensation that we are all suspended in mid-air, held up by things we do not fully understand, wearing business attire just in case anyone is watching. Neighbouring sculpture at Odborů features a female counterpart in an equally improbable aeronautical position. Achievement unlocked: you looked up while everyone else looked at their phones. That is the whole point of public art.`,
    cz: `Odvážný průzkumníku, Lehká nejistota — dílo českého sochaře Michala Trpáka z roku 2015 — není místo, do kterého vstoupíš, ale místo, na které se podíváš vzhůru a přehodnotíš svá životní rozhodnutí. Tato bronzová postava muže v obleku svírající otevřený deštník visí nad ulicí Na Zbořenci v Praze 2, nedaleko Mosaic House. Deštník zjevně neposkytuje přesvědčivou strukturální podporu, přesto muž působí pozoruhodně klidně ohledně celé situace. Trpák dílo vytvořil jako meditaci o nestabilitě moderního života — pocit, že všichni visíme ve vzduchu, drženi věcmi, kterým úplně nerozumíme, v obchodním oděvu pro případ, že se někdo dívá. Sousední socha na Odborů ukazuje ženský protějšek v obdobně nepravděpodobné aeronautické pozici. Achievement odemčen: podíval ses nahoru, zatímco všichni ostatní koukali do telefonů. To je celý smysl veřejného umění.`,
    zh: `勇敢的探险家，"Lehká nejistota"——捷克语意为"轻微的不确定性"——与其说是一个你走进去的地方，不如说是一个让你抬头仰望、重新思考人生选择的地方。2015年由捷克雕塑家米哈尔·特尔帕克创作，这尊身着西装、手握打开的雨伞的铜质商人雕像悬挂在布拉格二区娜兹博尔斯尼街上空（摩赛克之家建筑附近）。那把雨伞看起来并没有提供什么有意义的结构支撑，然而那个男人对整件事显得出奇地淡定。特尔帕克创作此作品是对现代生活不稳定性的沉思——那种我们都悬浮在半空中、被我们并不完全理解的东西支撑着、穿着正装以防有人在看的感觉。邻近奥德博鲁街上的另一尊雕塑展示了女性对应角色，同样处于令人难以置信的飞行姿态。成就解锁：当所有人都盯着手机时，你抬起了头。这就是公共艺术的全部意义。`,
  },

  "most-legii": {
    en: `Brave explorer, you stand on Most Legií — the Legion Bridge — a neo-Baroque stone triumph arching over the Vltava since 14 June 1901. Named after the 100,000-strong Czechoslovak Legions who fought across three continents in World War I, this bridge carries the weight of a republic that willed itself into existence. Unlock its hidden geometry: the bridge was designed to align with the axis of the National Theatre on the east bank, so that from the centre of the span you receive a perfectly framed view of that golden-roofed temple of Czech culture. Ornate lampposts line both sides — yet most visitors never notice that each one bears the lion of Bohemia in its ironwork. Cross it at twilight when the castle and the theatre frame both ends simultaneously. This is not merely a crossing; it is a monument to a nation that built itself a bridge before it built itself a state.`,
    cz: `Odvážný průzkumníku, stojíš na Mostě Legií — neobarokním kamennném triumfu klenutě překlenuujícím Vltavu od 14. června 1901. Pojmenovaný po 100 000 československých legionářích bojujících na třech kontinentech za první světové války, nese tento most tíhu republiky, která se svou vůlí zrodila. Odemkni jeho skrytou geometrii: most byl navržen tak, aby byl zarovnán s osou Národního divadla na východním břehu — ze středu klenby tak dostaneš dokonale zarámovaný výhled na tento zlatostřechý chrám české kultury. Zdobené lampy lemují oba břehy — přesto si většina návštěvníků nikdy nevšimne, že každá nese v kování českého lva. Překroč ho za soumraku, kdy hrad i divadlo zároveň zarámují oba konce. Toto není jen přechod; je to pomník národa, který si postavil most dříve, než si postavil stát.`,
    zh: `勇敢的探险家，你站在军团桥（Most Legií）上——这座新巴洛克式石桥自1901年6月14日起便拱跨伏尔塔瓦河。以十万名一战中征战三大洲的捷克斯洛伐克军团命名，这座桥承载着一个凭借意志力诞生的共和国的重量。解锁它隐藏的几何秘密：这座桥的设计轴线与东岸国家剧院的轴线完美对齐，使你从桥的中央能获得那座金顶捷克文化殿堂的完美框景。华美的路灯沿两侧排列——然而大多数游客从未注意到每盏灯的铁艺中都刻有波西米亚雄狮。在黄昏时分穿越，届时城堡与剧院同时框住两端。这不仅仅是一座桥；它是一个民族在建立国家之前先为自己建造桥梁的纪念碑。`,
  },

  "libensky-most": {
    en: `Brave explorer, the Libeňský most is one of Prague's greatest architectural achievements that almost no tourist ever visits — and that is your legendary advantage. At 780 metres, it is the longest bridge in Prague: a Cubist-inflected Functionalist masterpiece designed by architect Pavel Janák and engineer František Mencl, opened on 29 April 1928, precisely on the tenth anniversary of Czechoslovakia's independence. Unlock its hidden significance: that date was no accident — the bridge was built as a monument to the young republic's engineering ambition, its graceful arches embodying both national pride and Modernist confidence. Cross it on foot or tram and watch the full panorama of the northern Vltava bend below you, with Holešovice's industrial quarter on one side and the quieter streets of Libeň on the other. Tourists fight each other on Charles Bridge for a fragment of this view. Here, you will have 780 metres of it entirely to yourself.`,
    cz: `Odvážný průzkumníku, Libeňský most je jedním z největších architektonických výkonů Prahy, který téměř žádný turista nenavštíví — a to je tvá legendární výhoda. S délkou 780 metrů je nejdelším mostem Prahy — kubisticky laděné funkcionalistické mistrovské dílo architekta Pavla Janáka a inženýra Františka Mencla, otevřené 29. dubna 1928, přesně k desátému výročí vzniku Československa. Odemkni jeho skrytý význam: datum nebylo náhodné — most byl postaven jako pomník inženýrské ctižádosti mladé republiky, jeho graciézní oblouky ztělesňují jak národní hrdost, tak modernistické sebevědomí. Přejdi ho pěšky nebo tramvají a pozoruj panoráma severní vltavské zátoky pod sebou — průmyslová čtvrť Holešovic na jedné straně a tišší ulice Libně na druhé. Turisté se na Karlově mostě perou o zlomek tohoto výhledu. Tady budeš mít 780 metrů jen pro sebe.`,
    zh: `勇敢的探险家，利贝尼桥（Libeňský most）是布拉格最伟大的建筑成就之一，却几乎没有游客到访——这正是你传奇般的优势所在。以780米的长度，它是布拉格最长的桥梁，是建筑师帕维尔·雅纳克与工程师弗朗蒂塞克·门茨尔设计的立体主义风格功能主义杰作，于1928年4月29日开通，恰好在捷克斯洛伐克独立十周年纪念日。解锁它隐藏的意义：这个日期并非巧合——这座桥是作为年轻共和国工程雄心的纪念碑而建造的，其优雅的拱门既体现了民族自豪感，也象征着现代主义的自信。步行或乘坐有轨电车穿越此桥，俯瞰脚下北部伏尔塔瓦河的全景——一侧是霍莱绍维采的工业区，另一侧是利贝尼较为宁静的街道。游客们在查理大桥上争夺一片这样的景色，而在这里，780米的风光将完全属于你一人。`,
  },

  "namesti-hrdinu": {
    en: `Brave explorer, Náměstí Hrdinů — Heroes' Square — is the most sombre checkpoint in Prague: a square in the Nusle district named not for military victories but for civilian sacrifice. On 6 September 1945, this square hosted the last public execution in Prague, when Nazi collaborator Josef Pfitzner, former Deputy Mayor of the occupied city, was hanged before a crowd. In 1947 the square was formally renamed Náměstí Hrdinů in honour of all those executed, tortured, and persecuted in nearby Pankrác Prison during the Nazi occupation. Unlock its hidden weight: the Prague High Court building looming over the square's eastern edge was built in 1933, and during the Occupation its cellars served as execution chambers for hundreds of Czech resisters. The Pankrác tram depot on the south side has operated since 1927, carrying workers past this memorial square every single day for nearly a century. This is not a tourist attraction. It is a witness.`,
    cz: `Odvážný průzkumníku, Náměstí Hrdinů je nejtišší kontrolní bod Prahy — náměstí v nuselské čtvrti pojmenované ne pro vojenská vítězství, ale pro civilní oběti. Dne 6. září 1945 se na tomto náměstí konala poslední veřejná poprava v Praze, kdy byl před davem oběšen nacistický kolaborant Josef Pfitzner, bývalý náměstek primátora okupovaného města. V roce 1947 bylo náměstí formálně přejmenováno na Náměstí Hrdinů na počest všech popravených, mučených a pronásledovaných v nedalekém Pankráckém vězení za nacistické okupace. Odemkni jeho skrytou tíhu: budova Vrchního soudu Praha tyčící se nad východním okrajem náměstí byla postavena v roce 1933 a za Protektorátu sloužily její sklepy jako popraviště pro stovky českých odbojářů. Tramvajové depo Pankrác na jižní straně funguje od roku 1927, odvážejíc dělníky kolem tohoto pietního náměstí každý den skoro celé století. Toto není turistická atrakce. Je to svědek.`,
    zh: `勇敢的探险家，英雄广场（Náměstí Hrdinů）是布拉格最沉重的检查站——努斯莱区的一个广场，以平民的牺牲而非军事胜利命名。1945年9月6日，布拉格最后一次公开处决在此进行，纳粹合作者约瑟夫·普菲茨纳——被占领城市的前副市长——在人群面前被绞死。1947年，广场正式更名为英雄广场，以纪念纳粹占领期间在附近潘克拉茨监狱中被处决、受酷刑和迫害的所有人。解锁它隐藏的重量：耸立在广场东边的布拉格高等法院大楼建于1933年，占领期间其地窖被用作数百名捷克抵抗者的刑场。南侧的潘克拉茨有轨电车车库自1927年起运营，近一个世纪以来每天载着工人驶过这片纪念广场。这不是旅游景点，它是一位见证者。`,
  },

  "namesti-ip-pavlova": {
    en: `Brave explorer, Náměstí I. P. Pavlova is the most underrated intersection in Prague — a sprawling urban node named after Russian physiologist Ivan Petrovich Pavlov, whose research into conditioned reflexes changed science forever. Unlock its hidden irony: the square was renamed in his honour during the Communist era to celebrate Soviet scientific achievement — yet the name outlived the ideology by decades, and Praguers have since shortened it to the affectionate street names Ípák, Pavlák, or Ípáč. Below your feet runs the busiest metro station in the entire Prague network: I. P. Pavlova station serves over 118,000 passengers daily on Line C, the red spine of the city. During metro construction, workers unearthed the remains of a medieval city gate here, including relief tiles bearing the Bohemian lion — now displayed inside the station itself. The square marks the precise threshold between Nové Město and Vinohrady: step across it and the architecture, atmosphere, and attitude of the city transforms entirely. A level transition hiding in plain sight.`,
    cz: `Odvážný průzkumníku, Náměstí I. P. Pavlova je nejvíce podceňovaná křižovatka Prahy — rozsáhlý městský uzel pojmenovaný po ruském fyziologovi Ivanu Petroviči Pavlovovi, jehož výzkum podmíněných reflexů navždy změnil vědu. Odemkni jeho skrytou ironii: náměstí bylo v komunistické éře přejmenováno na jeho počest k oslavě sovětských vědeckých úspěchů — přesto jeho jméno přežilo ideologii o desetiletí a Pražané ho od té doby zkracují na přezdívky Ípák, Pavlák nebo Ípáč. Pod tvýma nohama se táhne nejrušnější stanice metra v celé síti Prahy: stanice I. P. Pavlova obsluhuje denně přes 118 000 cestujících na lince C, červené páteři města. Při stavbě metra dělníci odkryli pozůstatky středověké městské brány, včetně reliéfních dlaždic s českým lvem — dnes vystavených přímo uvnitř stanice. Náměstí označuje přesný práh mezi Novým Městem a Vinohrady: překroč ho a architektura, atmosféra i charakter města se zcela promění. Přechodová zóna ukrytá na očích.`,
    zh: `勇敢的探险家，I·P·帕夫洛夫广场是布拉格最被低估的交叉口——一个以俄罗斯生理学家伊万·彼得罗维奇·巴甫洛夫命名的宏大城市节点，他对条件反射的研究永远改变了科学。解锁它隐藏的讽刺：广场在共产党时代被更名为纪念苏联科学成就——然而这个名字比意识形态多存活了数十年，布拉格人此后将其缩短为亲切的街头称呼——Ípák、Pavlák或Ípáč。你脚下奔流着整个布拉格地铁网络中最繁忙的车站：I·P·帕夫洛夫站每天为超过11.8万名乘客服务，位于C线（红线）这条城市主干线上。地铁施工期间，工人们在此发现了中世纪城门的遗迹，包括刻有波西米亚雄狮的浮雕瓷砖——现陈列于车站内部。广场精确标记着新城区与葡萄园区之间的门槛：跨越它，城市的建筑、氛围和气质将彻底改变。一个隐藏在明处的关卡切换点。`,
  },

  "hotel-international-prague": {
    en: `Brave explorer, Hotel International Prague is the most unambiguous monument to collapsed ambition in the Czech Republic — an 88-metre Stalinist tower looming over the Dejvice district like a steel-and-stone dispatch from a vanished empire. Built between 1952 and 1956 with the personal backing of Alexej Čepička, Czechoslovak Minister of Defence and son-in-law of President Gottwald, it was modelled directly on Moscow's Seven Sisters skyscrapers and designed originally as a military hotel: a palace of ideology before it became a palace of hospitality. Unlock the extraordinary Easter egg it keeps on permanent display: the entire interior remains intact — socialist-realist murals, hammer-and-sickle reliefs, heroic worker friezes, and a red star crowning the tower, all protected as Czech cultural heritage since July 2000. Today it operates as a luxury hotel. You can drink cocktails under a fresco of triumphant socialism, sleep surrounded by Cold War propaganda art, and wake up to a view of a city that outlived the system that built the building. The absurdity is the whole point.`,
    cz: `Odvážný průzkumníku, Hotel International Praha je nejjednoznačnějším pomníkem zhrouceného ambice v České republice — 88metrový stalinský věžák tyčící se nad dejvickou čtvrtí jako ocelový a kamenný vzkaz ze zaniklého impéria. Postavený v letech 1952–1956 s osobní podporou Alexeje Čepičky, ministra národní obrany Československa a zetě prezidenta Gottwalda, byl modelovaný přímo podle moskevských Sedmi sester a původně navržen jako vojenský hotel: palác ideologie dříve, než se stal palácem pohostinnosti. Odemkni neobyčejný easter egg, který má trvale na odiv: celý jeho interiér zůstává nedotčený — socialistickorealistické nástěnné malby, reliéfy srpů a kladiv, hrdinské dělnické vlysy a červená hvězda korunující věž, vše chráněno jako české kulturní dědictví od července 2000. Dnes funguje jako luxusní hotel. Můžeš si dát koktejl pod freskou triumfálního socialismu, spát obklopený propagandistickým uměním studené války a probudit se s výhledem na město, které přežilo systém, jenž budovu vystavěl. Absurdita je celý smysl.`,
    zh: `勇敢的探险家，布拉格国际酒店是捷克共和国中对崩溃野心最壮观的纪念碑——一座88米高的斯大林主义塔楼，如同来自消逝帝国的钢铁与石头讯息，俯瞰着德意维采区。建于1952至1956年间，由捷克斯洛伐克国防部长、总统哥特瓦尔德女婿阿列克谢·切皮奇卡亲自支持，直接以莫斯科七姐妹摩天大楼为原型，最初设计为军事酒店：先是意识形态的殿堂，后才成为款待的殿堂。解锁它永久陈列的非凡彩蛋：其整个内部保持完好无损——社会主义现实主义壁画、镰刀锤子浮雕、英雄工人饰带，以及塔楼顶端的红星，自2000年7月起均受捷克文化遗产保护。如今它以豪华酒店的身份运营。你可以在胜利社会主义的壁画下喝鸡尾酒，在冷战宣传艺术的环绕中入眠，醒来欣赏那座历经建造它的体制崩塌而永存的城市的景色。荒诞本身就是重点所在。`,
  },

  "mustek": {
    en: `Brave explorer, you stand at Můstek — Prague's most deceptive landmark, hiding a medieval ghost beneath the busiest metro interchange in the city. The name means "little bridge," and that is precisely what once stood here: a small drawbridge spanning the moat of the Old Town fortifications, long since swallowed by centuries of urban layering. Unlock the Easter egg buried beneath your feet: when Metro Line A was excavated in the 1970s, workers uncovered the actual stone foundations of the original Gothic bridge, dating to the fourteenth century. Rather than destroy it, the Communists preserved and displayed the remains inside the station — descend the escalators and the Middle Ages are literally visible through the glass. Můstek marks the precise hinge between Old Town and Nové Město, between the medieval city and its grand nineteenth-century expansion. Every Praguer passes through it daily without pausing. You, brave explorer, now know what lies beneath.`,
    cz: `Odvážný průzkumníku, stojíš na Můstku — nejklamavější památce Prahy, skrývající středověký přízrak pod nejrušnějším metrem ve městě. Název znamená "malý most" a přesně to zde kdysi stálo: malý padací most přes příkop staroměstského opevnění, dávno pohltený staletími městského vrstveníí. Odemkni easter egg pohřbený pod tvýma nohama: při výkopu trasy metra A v 70. letech 20. století dělníci odkryli skutečné kamenné základy původního gotického mostu ze čtrnáctého století. Místo jeho zničení komunisté zachovali a zpřístupnili pozůstatky uvnitř stanice — sestup po eskalátorech a středověk je doslova viditelný skrz sklo. Můstek tvoří přesný závěs mezi Starým Městem a Novým Městem, mezi středověkým městem a jeho velkolepou expanzí v devatenáctém století. Každý Pražan tudy každodenně prochází bez zastavení. Ty, odvážný průzkumníku, nyní víš, co leží pod ním.`,
    zh: `勇敢的探险家，你站在穆斯泰克——布拉格最具欺骗性的地标，在这座城市最繁忙的地铁换乘站之下隐藏着一个中世纪的幽灵。这个名字意为"小桥"，这正是这里曾经存在的东西：一座横跨老城防御壕沟的小吊桥，早已被数百年的城市积淀所吞没。解锁埋藏在你脚下的彩蛋：20世纪70年代挖掘地铁A线时，工人们发现了可追溯至14世纪的原始哥特式桥梁的实际石质基础。共产党人没有将其摧毁，而是在车站内保存并展示了这些遗迹——乘扶梯下行，中世纪的遗址就透过玻璃清晰可见。穆斯泰克精确地标志着老城区与新城区之间、中世纪城市与其19世纪宏大扩张之间的转折点。每一个布拉格人每天都从这里经过，却从不停留。你，勇敢的探险家，现在知道了它脚下埋藏着什么。`,
  },

  "novomlysnska-water-tower": {
    en: `Brave explorer, the Novomlýnská Water Tower stands sentinel on the Vltava embankment as one of Prague's oldest surviving hydraulic monuments — a Renaissance tower that once powered the city's water supply through a system of wheels, pumps, and wooden pipes long before any modern plumbing existed. Built in the sixteenth century beside the New Mills weir complex that gave it its name, the tower drew water from the river and forced it uphill to fountains and cisterns across the city. Unlock its hidden chapter: when the New Town weir system was modernised in the nineteenth century, the tower lost its original function but gained a new life as a landmark. Its thick stone walls and distinctive cylindrical profile have survived floods, wars, and urban redevelopment that erased every other mill in its neighbourhood. The Vltava embankment stretching before you is one of Prague's grandest architectural corridors — and this tower, quiet and unhurried, predates almost every building in sight. A living relic of the city that kept Prague alive.`,
    cz: `Odvážný průzkumníku, Novomlýnská vodárenská věž stojí jako strážce na nábřeží Vltavy jako jedna z nejstarších dochovaných hydraulických památek Prahy — renesanční věž, která kdysi zásobovala město vodou prostřednictvím systému kol, čerpadel a dřevěných potrubí dlouho předtím, než existovalo jakékoliv moderní vodovody. Postavena v šestnáctém století vedle komplexu novomlýnského jezu, jenž jí dal název, čerpala věž vodu z řeky a přesouvala ji do kopce k fontánám a cisternám po celém městě. Odemkni její skrytou kapitolu: když byl systém novoměstského jezu modernizován v devatenáctém století, věž ztratila svou původní funkci, avšak získala nový život jako dominanta. Její silné kamenné zdi a charakteristický válcový profil přežily povodně, války a urbanistický rozvoj, který vymazal každý jiný mlýn v okolí. Vltavské nábřeží prostírající se před tebou je jedním z největkolepějších architektonických koridorů Prahy — a tato věž, tichá a bezstarostná, předchází téměř každou budovu v dohledu. Živá relikvie města, která udržovala Prahu naživu.`,
    zh: `勇敢的探险家，新磨坊水塔矗立在伏尔塔瓦河堤岸边，是布拉格最古老的水利建筑遗迹之一——这座文艺复兴时期的塔楼曾通过一套水车、泵和木制管道系统为城市供水，远早于任何现代管道设施的诞生。建于16世纪，毗邻给予它名称的新磨坊堰坝群，水塔从河中汲水，将其泵送至城市各处的喷泉和蓄水池。解锁它隐藏的章节：当新城堰坝系统在19世纪现代化改造后，水塔失去了原有功能，却作为地标焕发了新生。其厚实的石墙和独特的圆柱形轮廓经历了洪水、战争和城市改造，而这些变迁早已抹去了周边地区的每一座磨坊。眼前绵延的伏尔塔瓦河堤是布拉格最宏伟的建筑走廊之一——而这座塔楼，宁静从容，比视野中几乎所有建筑都更为古老。一件维系布拉格生命的城市活遗产。`,
  },

  "sitkova-water-tower": {
    en: `Brave explorer, the Šítkovská Water Tower is the elegant twin sentinel of the Novomlýnská Tower upstream — and the older of the two, its origins reaching back to the fifteenth century when the Šítek weir powered an entire mill district that fed medieval Prague. While the Novomlýnská tower served the New Town, this tower supplied water to the southern reaches of the same neighbourhood, working in tandem with the weir whose rushing water provided both power and a source. Unlock the Easter egg hiding in its recent history: the tower was dramatically damaged by a catastrophic flood in 1890 and its upper structure rebuilt — meaning the Renaissance base and the later Neo-Gothic crown are from entirely different centuries, layered on one another like sediment. In the twentieth century the tower was converted to house the Šítkovská water café, a cultural venue inside a medieval water tower on the Vltava embankment — one of the stranger reinventions in a city famous for its architectural afterlives. Stand here and watch the river that once powered everything flow silently past.`,
    cz: `Odvážný průzkumníku, Šítkovská vodárenská věž je elegantní dvojče Novomlýnské věže výše po proudu — a starší z obou, s počátky sahajícími do patnáctého století, kdy šítecký jez poháněl celou mlýnskou čtvrť, která živila středověkou Prahu. Zatímco Novomlýnská věž zásobovala Nové Město, tato věž přiváděla vodu do jižní části stejné čtvrti, pracujíc společně s jezem, jehož zurčící voda poskytovala jak energii, tak zdroj. Odemkni easter egg skrývající se v její nedávné historii: věž byla dramaticky poškozena při katastrofální povodni v roce 1890 a její horní část přestavěna — to znamená, že renesanční základna a pozdější novogotická korunka pocházejí z zcela odlišných století, vrstveny na sebe jako sediment. Ve dvacátém století byla věž přeměněna na Šítkovskou vodní kavárnu, kulturní prostory uvnitř středověké vodárenské věže na vltavském nábřeží — jedno z podivnějších znovuoživení v městě proslulém svými architektonickými posmrtnými životy. Postav se zde a sleduj řeku, která kdysi poháněla vše, jak tiše plyne kolem.`,
    zh: `勇敢的探险家，希特科夫水塔是上游新磨坊水塔优雅的孪生哨兵——也是两者中更古老的那个，其历史可追溯至15世纪，那时希特克堰为整个磨坊区提供动力，养活了中世纪的布拉格。新磨坊水塔为新城区供水，而这座水塔则为同一街区的南部地区供水，与堰坝协同工作，堰坝汹涌的水流既提供动力，又是水源。解锁隐藏在其近代历史中的彩蛋：1890年一场灾难性的洪水严重破坏了水塔，其上部结构被重建——这意味着文艺复兴风格的底座和后来的新哥特式塔顶来自完全不同的两个世纪，如同沉积物一样叠加在一起。20世纪，水塔被改造为希特科夫水咖啡馆，成为伏尔塔瓦河畔一座中世纪水塔内的文化场所——在这座以建筑"来世"著称的城市中，这是最奇特的再生改造之一。站在这里，静静注视那条曾经驱动一切的河流默默流淌而过。`,
  },

  "national-library-czech-republic": {
    en: `Brave explorer, the National Library of the Czech Republic is a quest destination hiding in plain sight — its most legendary treasure is not locked away behind glass but accessible to any soul brave enough to ask. The library's main home is the Klementinum, a colossal Baroque complex that rivals Prague Castle in sheer scale, second only to the Vatican Library in the number of manuscripts it holds. Unlock the ultimate hidden room: the Baroque Library Hall inside the Klementinum is one of the most beautiful rooms on Earth — a vaulted, gold-and-fresco chamber lined floor to ceiling with ancient tomes, crowned by a ceiling fresco of the Temple of Wisdom, and guarded by a seventeenth-century astronomical globe so precise it still shows the correct positions of the stars. For centuries this hall was kept entirely secret from the public. Today it opens for guided tours, yet most visitors to Prague never find it. The library holds 6.5 million documents, including medieval illuminated manuscripts, maps that show Bohemia as explorers once imagined it, and the oldest Czech book in existence. This is no mere archive; it is the final dungeon of Czech civilisation.`,
    cz: `Odvážný průzkumníku, Národní knihovna České republiky je cílová destinace skrývající se na očích — její nejlegendárnější poklad není uzamčen za sklem, ale přístupný každé duši dost odvážné, aby si o to říkala. Hlavní sídlo knihovny je Klementinum, kolosální barokní komplex soupeřící s Pražským hradem svou rozlehlostí, co do počtu rukopisů druhý pouze za vatikánskou knihovnou. Odemkni ultimate hidden room: Barokní knihovní sál uvnitř Klementina je jedním z nejkrásnějších prostor na Zemi — klenutý, zlato-fresková komnata lemovaná od podlahy ke stropu starými svazky, korunovaná stropní freskou Chrámu moudrosti a hlídaná sedmnáctým věkem astronomickým glóbem tak přesným, že stále ukazuje správné polohy hvězd. Po staletí byl tento sál veřejnosti zcela utajován. Dnes se otvírá pro prohlídky s průvodcem, přesto ho většina návštěvníků Prahy nikdy nenajde. Knihovna uchovává 6,5 milionu dokumentů, včetně středověkých iluminovaných rukopisů, map zobrazujících Čechy tak, jak si je průzkumníci kdysi představovali, a nejstarší českou knihu, která existuje. Toto není jen archiv; je to finální dungeon české civilizace.`,
    zh: `勇敢的探险家，捷克国家图书馆是一个隐藏在众目睽睽之下的任务目的地——其最传奇的珍宝并未锁在玻璃柜后，而是向每一个勇于探寻的灵魂开放。图书馆的主要驻地是克莱门廷，一座规模堪与布拉格城堡媲美的巴洛克宫殿建筑群，藏书量仅次于梵蒂冈图书馆。解锁终极隐藏房间：克莱门廷内的巴洛克图书馆大厅是地球上最美丽的房间之一——一个拱形的金色壁画大厅，从地板到天花板排满了古老的书卷，顶部是"智慧神殿"的天花板壁画，并由一个精准至今仍能显示星辰正确位置的17世纪天文地球仪守护。数百年来，这个大厅对公众完全保密。如今它对导览参观开放，然而布拉格的大多数访客从未找到它。图书馆收藏了650万件文献，包括中世纪彩绘手稿、描绘探险家昔日想象中波西米亚的地图，以及现存最古老的捷克文书。这不仅仅是一个档案馆；它是捷克文明的最终地牢。`,
  },

  "czech-post-jindrisska": {
    en: `Brave explorer, the Czech Post building on Jindřišská Street is a monument hiding an empire of logistics behind its grand Neo-Baroque facade — and directly beside it stands Jindřišská Tower, a free-standing Gothic bell tower that predates the post office by five centuries. The postal headquarters was built at the turn of the twentieth century to serve the Austro-Hungarian Empire's most modern communications network, when a letter posted in Prague in the morning could reach Vienna the same afternoon. Unlock the Easter egg above your head: the tower's bell has rung the hours over this street since the fifteenth century, witnessing the fall of three empires, two world wars, and the peaceful end of one. The post office building itself conceals one of the finest Art Nouveau interiors in Nové Město — its main sorting hall features vaulted ceilings and ironwork that no catalogue ever photographs. Today thousands of Praguers pass this corner daily to mail packages and pay bills without glancing at the Gothic spire that has watched over the same square for six hundred years. You, brave explorer, looked up.`,
    cz: `Odvážný průzkumníku, budova České pošty na Jindřišské ulici je monumentem skrývajícím říši logistiky za svou velkolepou neobarokní fasádou — a přímo vedle ní stojí Jindřišská věž, volně stojící gotická zvonice, která předchází poštu o pět století. Ústředí pošty bylo postaveno na přelomu dvacátého století, aby obsluhovalo nejmodernější komunikační síť Rakousko-Uherska, kdy dopis podaný v Praze ráno mohl ještě odpoledne dorazit do Vídně. Odemkni easter egg nad svou hlavou: věžní zvon bije hodiny nad touto ulicí od patnáctého století, svědek pádu tří říší, dvou světových válek a mírového konce jedné. Budova pošty sama skrývá jeden z nejkrásnějších secesních interiérů Nového Města — její hlavní třídicí hala se pyšní klenbami a železnými prvky, které žádný katalog nikdy nefotografuje. Dnes tisíce Pražanů denně míjí tento roh, aby poslali balíky a zaplatili účty, aniž by vzhlédli ke gotické věži, která celých šest set let hlídala stejné náměstí. Ty, odvážný průzkumníku, jsi vzhlédl.`,
    zh: `勇敢的探险家，金德日希斯卡街上的捷克邮政大楼是一座用宏伟的新巴洛克外墙掩盖着物流帝国的纪念碑——就在它旁边，屹立着金德日希斯卡塔，一座独立的哥特式钟楼，比邮政大楼早五个世纪。这座邮政总部建于20世纪之交，旨在服务奥匈帝国最现代化的通信网络，那时早上在布拉格投寄的信件，当天下午便能抵达维也纳。解锁你头顶上方的彩蛋：这座塔楼的钟声自15世纪起就在这条街道上报时，见证了三个帝国的覆灭、两次世界大战以及其中一次的和平终结。邮政大楼本身隐藏着新城区最精美的新艺术风格内部之一——其主要分拣大厅拥有任何目录都不曾拍摄的拱顶和铁艺构件。如今，成千上万的布拉格人每天经过这个路口寄包裹、缴账单，却从未抬头看一眼那座守望着同一广场长达六百年的哥特式尖塔。你，勇敢的探险家，抬起了头。`,
  },

  "chodovska-tvrz": {
    en: `Brave explorer, Chodovská Fortress is the most improbable survival story in Prague's outer districts — a medieval fortified manor that has stood in the middle of what became a Communist-era housing estate, quietly defying five centuries of development, demolition threats, and ideological indifference. The tvrz — a distinctly Czech category of fortified farm-manor, smaller than a castle but more defensible than a village — was first recorded in the fourteenth century as the seat of local nobility whose name has since been forgotten. Unlock the hidden irony of its survival: the surrounding Chodov housing estate, built from the 1970s onward with the brutal efficiency of socialist prefabrication, brought tens of thousands of new residents to the area — and it was their pressure and civic activism that ultimately saved the tvrz from demolition plans that circulated well into the 1980s. Restored and reopened as a cultural and community centre, the fortress now hosts concerts, exhibitions, and local history displays inside walls that predate every apartment block surrounding them by half a millennium. A level the map said should not exist.`,
    cz: `Odvážný průzkumníku, Chodovská tvrz je nejpravděpodobnější příběh přežití ve vnějších čtvrtích Prahy — středověký opevněný dvorec, který stojí uprostřed komunistického panelového sídliště a tiše vzdoruje pěti staletím rozvoje, hrozeb demolice a ideologické lhostejnosti. Tvrz — specificky česká kategorie opevněného zemského statku, menší než hrad, ale odolnější než vesnice — je poprvé doložena ve čtrnáctém století jako sídlo místní šlechty, jejíž jméno bylo od té doby zapomenuto. Odemkni skrytou ironii jejího přežití: okolní sídliště Chodov, budované od 70. let 20. století s brutální efektivitou socialistické panelové výstavby, přivedlo do oblasti desítky tisíc nových obyvatel — a byl to jejich tlak a občanský aktivismus, který nakonec zachránil tvrz před demoličními plány, které kolují ještě hluboko do 80. let. Obnovená a znovu otevřená jako kulturní a komunitní centrum, pevnost nyní hostí koncerty, výstavy a výstavy místní historie uvnitř zdí, které předcházejí každý okolní panelák o půl tisíciletí. Level, který mapa říkala, by neměl existovat.`,
    zh: `勇敢的探险家，霍多夫要塞是布拉格外围区域最不可思议的生存故事——一座中世纪防御庄园矗立在共产党时代住宅区的中央，悄然抵御着五个世纪的城市开发、拆迁威胁和意识形态冷漠。"tvrz"是一种独特的捷克防御农庄形态，比城堡小，但比普通村庄更易于防守——它首次出现于14世纪的文献记载，是当地贵族的领地，而那个贵族的名字早已被遗忘。解锁其生存背后隐藏的讽刺：周边的霍多夫住宅区从20世纪70年代起以社会主义预制板的残酷效率建造，为该地区带来了数万新居民——正是他们的压力和公民行动主义，最终拯救了这座要塞，免遭那些延续至80年代末期的拆迁计划的厄运。修复后作为文化和社区中心重新开放，这座要塞如今在比周围每一栋公寓楼早半个千年的石墙之内举办音乐会、展览和地方历史陈列。一个地图说本不该存在的关卡。`,
  },

  "narodni-trida": {
    en: `Brave explorer, Národní třída is the single most charged street in the Czech Republic — an elegant boulevard where the story of modern Czech freedom was written in real time on the night of 17 November 1989. On that evening, a peaceful student march was surrounded by riot police at the lower end of the street and beaten in an act of state brutality that proved to be the final miscalculation of the Communist regime. Unlock the memorial embedded in the wall: a bronze relief of outstretched hands marks the precise spot on the arcade at number 20 where the cordon closed — you can find it, touch it, and feel the weight of what happened here when tens of thousands returned the next day and the regime began to fall. The Velvet Revolution was born on this pavement. Within ten days, the Communists had resigned. Within six weeks, Václav Havel was president. The street today is lined with theatres, cafés, and bookshops — including the legendary Kavárna Slavia directly opposite. History was not made in this city's castles alone, brave explorer. Sometimes it happens on the pavement, at night, with bare hands against shields.`,
    cz: `Odvážný průzkumníku, Národní třída je nejnabitější ulicí v České republice — elegantní bulvár, kde byl příběh moderní české svobody psán v reálném čase v noci 17. listopadu 1989. Toho večera byl pokojný studentský pochod obklíčen pohotovostní policií na dolním konci ulice a zbičován v aktu státní brutality, který se ukázal jako poslední chybný výpočet komunistického režimu. Odemkni pamětní místo zasazené do zdi: bronzový reliéf natažených rukou označuje přesné místo v arkádě u čísla 20, kde se uzavřel kordon — najdeš ho, dotkneš se ho a pocítíš tíhu toho, co se zde stalo, když se druhý den vrátily desítky tisíc lidí a režim začal padat. Sametová revoluce se zrodila na tomto chodníku. Do deseti dnů komunisté rezignovali. Do šesti týdnů byl Václav Havel prezidentem. Ulice je dnes lemována divadly, kavárnami a knihkupectvím — včetně legendární Kavárny Slavia přímo naproti. Historie nebyla v tomto městě psána jen v hradech, odvážný průzkumníku. Někdy se to stane na chodníku, v noci, s holýma rukama proti štítům.`,
    zh: `勇敢的探险家，国家大道是捷克共和国最具历史分量的街道——一条优雅的林荫大道，1989年11月17日夜晚，现代捷克自由的故事在这里实时书写。那个夜晚，一场和平的学生游行在街道下端被防暴警察包围并遭到殴打，这一国家暴力行为成为共产党政权最后的致命误判。解锁嵌在墙上的纪念碑：一块铜制浮雕，雕刻着伸展的双手，精确标记着20号骑楼封锁线关闭的那个位置——你可以找到它，触摸它，感受当成千上万人第二天回到这里、政权开始崩溃时，这里所承载的历史重量。天鹅绒革命就在这块人行道上诞生。十天之内，共产党人辞职了。六周之内，瓦茨拉夫·哈维尔成为总统。这条街今天两侧林立着剧院、咖啡馆和书店——包括正对面传奇的斯拉维亚咖啡馆。历史并非只在这座城市的城堡中书写，勇敢的探险家。有时候，它发生在深夜的人行道上，赤手空拳对抗盾牌之间。`,
  },

  "karlovo-namesti": {
    en: `Brave explorer, Charles Square is the largest square in Prague — and almost no one outside the city knows it exists. While tourists crowd Old Town Square a kilometre to the north, this vast open park covering 80,000 square metres has been the civic heart of the New Town since Emperor Charles IV laid it out in 1348 as the centrepiece of his grand urban expansion. Unlock the Easter egg hidden in its centre: Charles IV originally used the square as a showground where holy relics — the Crown of Thorns, pieces of the True Cross, fragments of saints — were displayed to the public once a year, drawing pilgrims from across Central Europe. The relics are long gone, but the square still holds its medieval scale, unchanged in footprint since the fourteenth century. At its northern edge stands the New Town Hall, where Prague's first defenestration occurred in 1419 — forty-five years before the more famous one at the Castle — when Hussite rebels threw Catholic councillors from the windows. At its southern end stands Faust House, where legend holds that the alchemist Doctor Faustus struck his deal with the devil. Every corner of this square is a chapter in the questlog. Most explorers never open the book.`,
    cz: `Odvážný průzkumníku, Karlovo náměstí je největším náměstím v Praze — a téměř nikdo mimo město neví, že existuje. Zatímco turisté se mačkají na Staroměstském náměstí o kilometr severněji, tento rozlehlý otevřený park pokrývající 80 000 čtverečních metrů je od roku 1348, kdy ho císař Karel IV. naplánoval jako centrepiece své velkolepé urbanistické expanze, ciudadanským srdcem Nového Města. Odemkni easter egg skrytý v jeho středu: Karel IV. původně využíval náměstí jako výstaviště, kde byly jednou ročně vystavovány veřejnosti ostatky světců — Trnová koruna, úlomky Pravého kříže, fragmenty světců — přitahujíce poutníky z celé střední Evropy. Ostatky jsou dávno pryč, ale náměstí si stále zachovává svůj středověký rozměr, nezměněný v půdorysu od čtrnáctého století. Na jeho severním okraji stojí Novoměstská radnice, kde proběhla první pražská defenestrace v roce 1419 — o čtyřicet pět let dříve než ta slavnější na hradě — kdy husitští rebelové vyhodili katolické radní z oken. Na jeho jižním konci stojí Faustův dům, kde podle legendy alchymista Doktor Faust uzavřel smlouvu s ďáblem. Každý roh tohoto náměstí je kapitolou v questlogu. Většina průzkumníků knihu nikdy neotevře.`,
    zh: `勇敢的探险家，卡洛夫广场是布拉格最大的广场——而城外几乎没有人知道它的存在。当游客们拥挤在一公里之外的老城广场时，这片覆盖八万平方米的广阔开放公园，自1348年查理四世将其作为他宏大城市扩张计划的核心奠基以来，一直是新城区的市民中心。解锁隐藏在其中心的彩蛋：查理四世最初将这座广场用作圣物展场，每年一次向公众展示圣物——荆棘冠、真十字架碎片、圣徒遗骸——吸引来自整个中欧的朝圣者。圣物早已消失，但广场至今保持着中世纪的规模，自14世纪以来占地范围从未改变。广场北端矗立着新城市政厅，布拉格第一次抛窗事件就发生于此，时间是1419年——比那次更著名的城堡抛窗事件早了整整四十五年——当时胡斯派叛军将天主教议员从窗口扔了出去。广场南端矗立着浮士德宫，传说炼金术士浮士德博士就在这里与魔鬼签下了契约。这座广场的每一个角落都是任务日志中的一个章节。大多数探险家从未翻开这本书。`,
  },

  "karlstejn-castle": {
    en: `Brave explorer, Karlštejn Castle is the greatest day-quest available from Prague — a Gothic fortress rising from a wooded valley thirty kilometres southwest of the city, built by Emperor Charles IV in 1348 for a single, extraordinary purpose: to guard the Holy Roman Imperial regalia, the Bohemian Crown Jewels, and a staggering collection of holy relics including a fragment of the Crown of Thorns and pieces of the True Cross. Unlock the Easter egg sealed behind the most exclusive door in medieval Bohemia: the Chapel of the Holy Cross, located in the Great Tower, was so sacred that women were banned from entering the castle entirely for centuries — not just the chapel, but the entire grounds. Its walls are embedded with over 2,200 semi-precious stones and gold, and 129 portraits of saints painted by Master Theodoric, the greatest Bohemian painter of the fourteenth century. The chapel ceiling is set with glass to simulate a starfield. Charles IV so loved this place that he retreated here to meditate, wrote personal letters from its towers, and held Easter and Christmas services in its chapels. The castle was never conquered. The trail from the village is one of the finest short hikes in Bohemia. This is not a day trip; it is a legendary bonus stage.`,
    cz: `Odvážný průzkumníku, hrad Karlštejn je nejlepší jednodenní quest dostupný z Prahy — gotická pevnost vyrůstající ze zalesněného údolí třicet kilometrů jihozápadně od města, postavená císařem Karlem IV. v roce 1348 za jediným, mimořádným účelem: střežit říšské korunovační klenoty, české korunovační klenoty a ohromující sbírku svatých relikvií, včetně fragmentu Trnové koruny a úlomků Pravého kříže. Odemkni easter egg zapečetěný za nejexkluzivnějšími dveřmi středověkých Čech: Kaple sv. Kříže umístěná ve Velké věži byla natolik posvátná, že ženy byly po staletí ze vstupu na hrad zcela zakázány — nejen do kaple, ale na celé hradní pozemky. Její zdi jsou vsazeny s přes 2 200 polodrahokamy a zlatem a 129 portréty světců namalovanými Mistrem Theodorickem, největším českým malířem čtrnáctého století. Strop kaple je osazen sklem imitujícím hvězdnou oblohu. Karel IV. toto místo natolik miloval, že se sem uchyloval k meditaci, psal osobní dopisy z jeho věží a slavil zde velikonoční a vánoční bohoslužby. Hrad nebyl nikdy dobyt. Stezka z vesnice je jednou z nejkrásnějších krátkých túr v Čechách. Toto není výlet; je to legendární bonusová stage.`,
    zh: `勇敢的探险家，卡尔什泰因城堡是从布拉格出发可完成的最伟大的单日任务——一座哥特式要塞耸立于布拉格西南三十公里的林木山谷中，由查理四世皇帝于1348年为单一而非凡的目的而建：守护神圣罗马帝国冠冕珠宝、波西米亚王冠珠宝，以及包括荆棘冠碎片和真十字架碎片在内的惊人圣物收藏。解锁封藏在中世纪波西米亚最独特门扉之后的彩蛋：位于大塔楼的圣十字礼拜堂如此神圣，以至于女性被禁止进入城堡长达数百年——不仅仅是礼拜堂，而是整个城堡范围。其墙壁镶嵌了超过2200颗半宝石和黄金，以及由14世纪波西米亚最伟大画家特奥多里克大师绘制的129幅圣像。礼拜堂天花板安装了玻璃以模拟星空。查理四世如此钟爱这个地方，以至于常来此冥想，从塔楼写下私人信件，并在其礼拜堂举办复活节和圣诞节礼拜。这座城堡从未被攻克。从村庄出发的小径是波西米亚最美丽的短途徒步路线之一。这不是一次日间旅行；这是一个传奇的奖励关卡。`,
  },

  "beroun": {
    en: `Brave explorer, Beroun is the first town beyond Prague's gravitational pull — a medieval market town at the confluence of the Berounka and Litavka rivers that has guarded the western approach to Bohemia since the thirteenth century. Founded under King Přemysl Otakar II around 1265, the town preserves two of the finest surviving medieval gate towers in Central Bohemia: the Pražská brána and the Plzeňská brána, standing at opposite ends of the original fortified perimeter like save points from a completed level. Unlock the Easter egg baked into the town's geography: Beroun sits precisely at the point where the Berounka river cuts through the Bohemian Karst limestone plateau, creating a dramatic canyon landscape invisible from the town itself — descend to the riverbanks and the geological drama reveals itself. The karst landscape around Beroun contains over a thousand caves, including the famous Koněprusy Caves with their medieval counterfeit coin-minting operation discovered by archaeologists in the twentieth century. The name of the river, the town, and the entire geological district are the same: Beroun. Everything here converges. This is where the kingdom of Bohemia begins, brave explorer.`,
    cz: `Odvážný průzkumníku, Beroun je první město za gravitačním polem Prahy — středověké tržní město na soutoku Berounky a Litavky, které střeží západní přístup do Čech od třináctého století. Založeno za krále Přemysla Otakara II. kolem roku 1265, město uchovává dvě z nejkrásnějších dochovaných středověkých věžových bran ve středních Čechách: Pražskou bránu a Plzeňskou bránu, stojící na protilehlých koncích původního opevněného obvodu jako save pointy dokončeného levelu. Odemkni easter egg zapečený do geografie města: Beroun leží přesně v místě, kde řeka Berounka proráží vápenecovou plošinu Českého krasu a vytváří dramatický kaňon neviditelný ze samotného města — sestup k břehům řeky a geologické drama se odhalí. Krasová krajina kolem Berouna obsahuje přes tisíc jeskyní, včetně proslulých Koněpruských jeskyní se středověkou dílnou na výrobu padělaných mincí, kterou archeologové odkryli ve dvacátém století. Jméno řeky, města i celého geologického okrsku je totéž: Beroun. Vše se zde sbíhá. Zde začíná království Čech, odvážný průzkumníku.`,
    zh: `勇敢的探险家，贝劳恩是布拉格引力范围之外的第一座城镇——一座中世纪集市小镇，坐落于贝劳恩卡河与利塔夫卡河的交汇处，自13世纪以来一直守护着波西米亚的西部入口。约于1265年在国王普热米斯尔·奥托卡二世治下建立，这座城镇保存着波西米亚中部最精美的两座中世纪城门塔楼：布拉格门和普尔泽尼门，分立于原始城防周界的两端，如同完成关卡的存档点。解锁烘焙在这座城镇地理之中的彩蛋：贝劳恩恰好坐落于贝劳恩卡河切穿波西米亚喀斯特石灰岩台地的位置，形成了一个从城内完全看不到的壮观峡谷景观——走到河岸，地质奇观便会自我揭示。贝劳恩周围的喀斯特地貌包含逾千座洞穴，其中包括著名的科涅普鲁西洞穴——那里的中世纪仿币铸造作坊于20世纪被考古学家发现。这条河、这座城镇和整个地质区域都叫同一个名字：贝劳恩。一切在此汇聚。这里是波西米亚王国的起点，勇敢的探险家。`,
  },

  "viewpoint-maj": {
    en: `Brave explorer, Viewpoint Máj is Prague's best-kept secret among locals who know that the city's most spectacular panoramas are never the famous ones. Perched on the limestone bluffs above Hlubočepy in southwest Prague, this hidden overlook commands an unobstructed view of the Vltava canyon as it curves through the Bohemian Karst — a geological landscape so ancient and dramatic that parts of it appeared in the opening sequence of every Czech fairy-tale film made in the Communist era. Unlock the Easter egg written in stone: the cliffs below this viewpoint are composed of Devonian limestone more than 380 million years old, and Barrandov — the next bluff south — was named after French geologist Joachim Barrande, who spent forty years mapping the fossil beds of this valley in the nineteenth century. The same cliffs where Barrande found trilobites are where Prague later built its film studios, producing hundreds of international co-productions in the canyon's dramatic natural lighting. From this viewpoint, brave explorer, you can see geological deep time, cinematic history, and the serpentine Vltava all at once. Most Praguers have never stood here.`,
    cz: `Odvážný průzkumníku, Vyhlídka Máj je nejlépe střeženým tajemstvím Prahy mezi místními, kteří vědí, že nejspektakulárnější panoramata města nikdy nejsou ta proslulá. Umístěná na vápencových útesech nad Hlubočepy v jihozápadní Praze, tato skrytá vyhlídka nabízí nerušený pohled na kaňon Vltavy, jak se klikatí Českým krasem — geologická krajina tak stará a dramatická, že části z ní se objevily v úvodních sekvencích každého českého pohádkového filmu natočeného v době komunismu. Odemkni easter egg napsaný v kameni: útesy pod touto vyhlídkou jsou složeny z devonského vápence starého více než 380 milionů let a Barrandov — sousední útesy na jihu — byl pojmenován po francouzském geologovi Joachimu Barrandovi, který strávil čtyřicet let mapováním fosiliferních vrstev tohoto údolí v devatenáctém století. Na stejných útesech, kde Barrande nacházel trilobity, Praha později postavila svá filmová studia, produkující stovky mezinárodních koprodukcí v dramatickém přirozeném osvětlení kaňonu. Z této vyhlídky, odvážný průzkumníku, vidíš geologický hluboký čas, filmovou historii a klikatou Vltavu najednou. Většina Pražanů zde nikdy nestála.`,
    zh: `勇敢的探险家，Máj观景台是布拉格本地人之间守护最严密的秘密——这些人知道，这座城市最壮观的全景从来都不是那些出名的地方。它高踞于布拉格西南部的霍布洛切比石灰岩峭壁之上，这个隐秘的观景台拥有伏尔塔瓦河峡谷蜿蜒穿越波西米亚喀斯特地貌的无遮拦视野——一片如此古老而壮观的地质景观，以至于其部分画面出现在共产党时代拍摄的每一部捷克童话电影的片头序列中。解锁刻写在石头里的彩蛋：这处观景台下方的悬崖由超过3.8亿年历史的泥盆纪石灰岩构成，而南面的巴兰多夫——下一处峭壁——以法国地质学家约阿希姆·巴兰德命名，他在19世纪花费了四十年时间绘制这片山谷化石层的地图。同样是在巴兰德发现三叶虫的这些峭壁旁，布拉格后来建起了电影制片厂，在峡谷的戏剧性自然光线中制作了数百部国际合拍影片。从这处观景台，勇敢的探险家，你可以同时看见地质深时、电影历史和蜿蜒的伏尔塔瓦河。大多数布拉格人从未在此驻足。`,
  },

  "zamek-sedlec": {
    en: `Brave explorer, Zámek Sedlec is the most quietly dignified secret in Prague's northernmost district — a manor house of medieval origin standing in the village of Sedlec, which was absorbed into Prague 6 but has never stopped feeling like a separate world. The settlement here is ancient: Sedlec appears in written records from the twelfth century, when it was a minor noble holding on the Vltava bluffs overlooking the river valley. Unlock the Easter egg in its surroundings: the Sedlec area sits directly above the point where the Vltava begins its great northward bend, and the bluffs here were used as navigation landmarks by Vltava boatmen for centuries — before bridges, before roads, Sedlec was a waypoint visible from the water. The château as it stands was rebuilt in the Baroque period and modified again in the nineteenth century, layering centuries of ownership onto a medieval foundation in the way only Central European manor houses can. Unlike Prague's famous palatial residences, this one never became a museum or a hotel — it remains embedded in the fabric of the neighbourhood, which is exactly what makes it worth finding. The explorer who reaches Sedlec has left the tourist circuit entirely. This is a level that rewards the curious, not the crowd.`,
    cz: `Odvážný průzkumníku, Zámek Sedlec je nejtišeji vznešeným tajemstvím nejsevernější čtvrti Prahy — panský dům středověkého původu stojící ve vesnici Sedlec, která byla pohlcena Prahou 6, ale nikdy nepřestala působit jako oddělaný svět. Sídlo zde je starověké: Sedlec se objevuje v písemných pramenech ze dvanáctého století, kdy byl menším šlechtickým statkem na vltavských útesech s výhledem na říční údolí. Odemkni easter egg v jeho okolí: oblast Sedlce leží přímo nad místem, kde Vltava začíná svůj velký severní oblouk, a útesy zde sloužily jako navigační orientační body pro vltavské vorařě po staletí — před mosty, před silnicemi byl Sedlec orientačním bodem viditelným z vody. Zámek v podobě, v jaké stojí, byl přestavěn v barokním období a znovu upraven v devatenáctém století, vrstvíc staletí vlastnictví na středověké základy způsobem, který dokážou pouze středoevropská panská sídla. Na rozdíl od proslulých pražských paláců se tento nikdy nestal muzeem ani hotelem — zůstává zakotven ve struktuře čtvrti, a to je přesně to, co ho stojí za to najít. Průzkumník, který dosáhne Sedlce, opustil turistický okruh zcela. Toto je level, který odměňuje zvídavé, ne dav.`,
    zh: `勇敢的探险家，塞德莱茨庄园是布拉格最北区最静默而高贵的秘密——一座中世纪起源的庄园宅邸，矗立于塞德莱茨村中，这里虽已被划入布拉格6区，但始终未曾停止散发一种独立世界的气息。这片聚落历史悠久：塞德莱茨出现于12世纪的文字记载中，当时是伏尔塔瓦河崖顶一处俯瞰河谷的小型贵族领地。解锁隐藏在其周边的彩蛋：塞德莱茨地区恰好位于伏尔塔瓦河开始向北大弯的位置正上方，这里的崖壁数百年来被伏尔塔瓦河船工用作航行地标——在桥梁建造之前、在道路修筑之前，塞德莱茨是一个从水上便能看见的路标。现存的庄园在巴洛克时期被重建，又在19世纪再度改建，将数百年的所有权以只有中欧庄园宅邸才能做到的方式叠加于中世纪地基之上。与布拉格著名的宏伟宫殿不同，这座庄园从未成为博物馆或酒店——它仍然嵌入街区的肌理之中，而这恰恰是它值得寻访的原因。抵达塞德莱茨的探险家已彻底离开了旅游路线。这是一个奖励好奇者而非人潮的关卡。`,
  },

  "klaster-sv-gabriela": {
    en: `Brave explorer, St. Gabriel's Monastery is the most architecturally surprising building in Smíchov — a full-scale Romanesque Revival convent rising above the streets of Praha 5 like a stone vision from eleventh-century Burgundy, built between 1888 and 1891 for the Benedictine nuns of the Prague congregation. Its architect, Max von Ferstel, designed it in deliberate contrast to the surrounding nineteenth-century residential blocks: the monastery's thick walls, round-arched windows, and solid tower announce a different time entirely. Unlock the Easter egg written into its founding charter: the convent was established by Benedictine nuns who had previously maintained their community in Bavaria, continuing an unbroken female monastic tradition stretching back to the early medieval period. The Rule of St. Benedict — ora et labora, pray and work — has been followed in some form by this community for over a thousand years. The cloister garden hidden behind the public facade is one of the most peaceful enclosed spaces in the entire city. Very few visitors to Smíchov ever look up at this building. This is a level that exists precisely because most explorers keep their eyes on the pavement.`,
    cz: `Odvážný průzkumníku, Klášter sv. Gabriela je architektonicky nejpřekvapivější budovou na Smíchově — kompletní románský konvent vyrůstající nad ulicemi Prahy 5 jako kamenná vize z burgundského jedenáctého století, postavená v letech 1888–1891 pro benediktinky pražské kongregace. Jeho architekt Max von Ferstel ji navrhl v záměrném kontrastu s okolními bloky zástavby devatenáctého století: silné zdi kláštera, oblouková okna a pevná věž oznamují zcela jiný čas. Odemkni easter egg vepsaný do jeho zakládací listiny: konvent byl zřízen benediktinkami, které dříve udržovaly svou komunitu v Bavorsku, navazujíce na nepřerušenou ženskou mnišskou tradici sahající do raného středověku. Řehole sv. Benedikta — ora et labora, modli se a pracuj — je touto komunitou v nějaké formě dodržována více než tisíc let. Rajský dvůr ukrytý za veřejnou fasádou je jedním z nejklidnějších uzavřených prostorů v celém městě. Jen velmi málo návštěvníků Smíchova kdy zvedne oči k této budově. Toto je level, který existuje přesně proto, že většina průzkumníků drží oči na chodníku.`,
    zh: `勇敢的探险家，圣加百列修道院是斯米霍夫建筑上最令人惊喜的建筑——一座完整规模的罗曼式复兴修道院，如同来自11世纪勃艮第的石质幻象，耸立于布拉格5区的街道之上，建于1888至1891年间，专为布拉格本笃会修女会众而建。其建筑师马克斯·冯·弗斯特尔将其设计为与周围19世纪住宅楼群的刻意对比：修道院厚实的墙壁、圆拱窗和坚实的塔楼宣告着一个全然不同的时代。解锁书写在其创立章程中的彩蛋：这座修道院由之前在巴伐利亚维系社区的本笃会修女创立，延续着可追溯至中世纪早期的不间断女性修道传统。圣本笃的规则——祈祷与劳作——已被这个群体以某种形式遵守了逾千年。隐藏在公共立面后方的回廊花园是整座城市中最宁静的封闭空间之一。斯米霍夫极少有访客会抬头看这座建筑。这是一个恰恰因为大多数探险家将目光保持在人行道上而存在的关卡。`,
  },

  "palac-zofin": {
    en: `Brave explorer, Palác Žofín is Prague's most romantic quest destination — a Neo-Classical palace on Slovanský ostrov, the Slavic Island, sitting in the middle of the Vltava River between the Old Town embankment and the New Town like a stage set floating on water. The island and its hall were named after Sophie, the mother of Emperor Franz Joseph I, and throughout the nineteenth century Žofín was the premier venue for the Czech national revival — concerts, balls, political readings, and cultural gatherings that kept Czech identity alive under Habsburg rule. Unlock the Easter egg hiding in the water: the island itself is artificial, built up from a natural sandbank in the Vltava over centuries of accumulated material, and the channel separating it from the New Town embankment is narrow enough to cross in a rowing boat in under thirty seconds. Franz Liszt performed here. Bedřich Smetana conducted here. The very piano on which Czech nationalist music was played in defiance of Viennese cultural dominance stood in these halls. Today the palace hosts weddings, galas, and concerts in restored nineteenth-century interiors. The view from the island's southern tip — Vyšehrad in one direction, Prague Castle in the other — is one of the finest river panoramas in the city. You earned this view, brave explorer.`,
    cz: `Odvážný průzkumníku, Palác Žofín je nejromantičtější quest destinací Prahy — neoklasicistní palác na Slovanském ostrově, ležícím uprostřed Vltavy mezi staroměstským a novoměstským nábřežím jako scéna plovoucí na vodě. Ostrov a jeho sál byly pojmenovány po Žofii, matce císaře Františka Josefa I., a v průběhu devatenáctého století byl Žofín předním místem českého národního obrození — koncerty, plesy, politická čtení a kulturní setkání, která udržovala českou identitu živou pod habsburskou vládou. Odemkni easter egg ukrytý ve vodě: samotný ostrov je umělý, vybudovaný z přirozeného říčního nánosu ve Vltavě po staletí, a kanál oddělující ho od novoměstského nábřeží je natolik úzký, že ho lze přeplout na veslici za méně než třicet sekund. Franz Liszt zde vystupoval. Bedřich Smetana zde dirigoval. Samotný klavír, na němž v těchto sálech bylo hráno česky nacionalistické hudbě na vzdor vídeňské kulturní dominanci. Dnes palác hostí svatby, galavečery a koncerty v restaurovaných interiérech devatenáctého století. Výhled z jižního cípu ostrova — Vyšehrad jedním směrem, Pražský hrad druhým — je jedním z nejkrásnějších říčních panoramat ve městě. Tento výhled sis zasloužil, odvážný průzkumníku.`,
    zh: `勇敢的探险家，若菲因宫是布拉格最浪漫的任务目的地——一座新古典主义宫殿，坐落于斯洛万斯基岛（斯拉夫岛）上，这座小岛漂浮在伏尔塔瓦河中央，夹在老城河堤与新城之间，宛如一座漂浮在水上的舞台布景。这座岛屿和大厅以弗朗茨·约瑟夫一世皇帝的母亲若菲亚命名，在整个19世纪，若菲因宫是捷克民族复兴运动的首要场所——音乐会、舞会、政治朗诵和文化聚会，在哈布斯堡统治下维系着捷克民族认同。解锁隐藏在水中的彩蛋：这座岛屿本身是人工形成的，经过数百年的积累，从伏尔塔瓦河中一个天然沙洲逐渐建起，将其与新城河堤隔开的水道窄到可以在不到三十秒内用划桨小艇穿越。弗朗茨·李斯特曾在此演出，贝德尔日赫·斯美塔那曾在此指挥。就是在这些大厅里，反抗维也纳文化霸权的捷克民族主义音乐在钢琴上响起。如今，宫殿在修复的19世纪内饰中举办婚礼、晚会和音乐会。从岛屿南端眺望——一侧是维谢赫拉德，另一侧是布拉格城堡——是城市中最美丽的河流全景之一。这个景色是你赢得的，勇敢的探险家。`,
  },

  "podolska-vodarna": {
    en: `Brave explorer, Podolí Waterworks is the most beautiful industrial building in Prague — a full Art Nouveau waterworks complex on the Vltava embankment in Podolí, built between 1898 and 1906 when city engineers decided that Prague's new water infrastructure deserved to be as magnificent as its churches. The main pump hall, with its ornate cast-iron columns, ceramic tile floors, and arched windows flooding the machinery with light, looks less like a water treatment facility and more like a cathedral built for the worship of hydraulic engineering. Unlock the extraordinary Easter egg still running beneath your feet: the Podolí waterworks is not a museum relic — it remains one of Prague's operational water treatment plants to this day, pumping purified Vltava water to homes and businesses across the city using infrastructure that has been continuously maintained for over a century. Two distinctive towers flank the main hall like sentinels, each capped with decorative cornices that serve no engineering purpose whatsoever and were added purely because the architects believed a waterworks could also be a landmark. They were right. The complex includes a restored engine room open for tours and a small water museum. This is the level where Prague's obsession with beauty over function achieved its most delicious victory.`,
    cz: `Odvážný průzkumníku, Podolská vodárna je nejkrásnější průmyslovou budovou v Praze — kompletní secesní vodárenský komplex na vltavském nábřeží v Podolí, postavený v letech 1898–1906, kdy inženýři města rozhodli, že nová vodní infrastruktura Prahy si zaslouží být stejně velkolepá jako její kostely. Hlavní čerpací sál se svými zdobnými litinami sloupy, keramickými dlaždicemi a obloukovými okny zaplavujícími strojní zařízení světlem vypadá méně jako čistírna vody a více jako katedrála postavená pro uctívání hydraulického inženýrství. Odemkni mimořádný easter egg stále běžící pod tvýma nohama: Podolská vodárna není muzejní relikvie — dodnes zůstává jednou z provozních úpraven vody v Praze, čerpající přečištěnou vltavskou vodu do domácností a podniků po celém městě pomocí infrastruktury, která je nepřetržitě udržována déle než století. Dvě charakteristické věže lemují hlavní sál jako strážci, každá korunovaná dekorativními římsami, jež nemají žádnou inženýrskou funkci a byly přidány čistě proto, že architekti věřili, že vodárna může být také dominantou. Měli pravdu. Komplex zahrnuje obnovený strojovnu přístupnou pro prohlídky a malé vodní muzeum. Toto je level, kde posedlost Prahy krásou nad funkcí dosáhla svého nejsladšího vítězství.`,
    zh: `勇敢的探险家，波多尔水厂是布拉格最美丽的工业建筑——一座完整的新艺术风格水厂建筑群，坐落于波多尔的伏尔塔瓦河堤岸，建于1898至1906年间，当时城市工程师决定，布拉格的新水利基础设施应当与它的教堂一样宏伟壮观。主泵房拥有华美的铸铁柱、陶瓷砖地板和将光线倾泻到机器上的拱形窗户，看起来与其说是水处理设施，不如说是一座为礼拜水力工程而建的大教堂。解锁仍在你脚下运转的非凡彩蛋：波多尔水厂并非博物馆遗迹——时至今日，它仍是布拉格运营中的水处理厂之一，通过持续维护了逾一个世纪的基础设施，将净化后的伏尔塔瓦河水泵送至全市的住宅和商业场所。两座独特的塔楼如哨兵般护卫着主厅两侧，每座都冠以完全没有工程用途、纯粹因为建筑师相信水厂也可以成为地标而添加的装饰性檐口。他们是对的。建筑群包括一个对公众开放参观的修复发动机房和一个小型水博物馆。这是布拉格对美胜于功能的执念取得最甜蜜胜利的关卡。`,
  },

  "kostel-sv-jana-na-skalce": {
    en: `Brave explorer, the Church of St. John of Nepomuk on the Rock is the most dramatically staged building in Prague — a Baroque twin-tower church by Kilián Ignác Dientzenhofer completed in 1738, set on a natural rock outcrop above Vytoň with a monumental outdoor staircase that approaches it like the final ascent to a sanctuary. The church is dedicated to St. John of Nepomuk, the Czech patron saint who was thrown from Charles Bridge in 1393 on the orders of King Wenceslas IV — according to legend, because he refused to reveal the confessions of the queen. Unlock the Easter egg in its geometry: Dientzenhofer designed the church on a diagonal axis, so that the altar is oriented not to the standard liturgical east but to the rock formation itself — the building bends its theology around the geology beneath it. The twin towers were specifically angled to create a dramatic false-perspective effect when approached from the street below, making the church appear taller than it is. St. John of Nepomuk was the first person to be canonised by the newly reformed Baroque Catholic Church specifically as a Counter-Reformation propaganda saint — his cult spread across Catholic Europe faster than almost any other in history. This church is his monument, his rock, and his drama, all at once.`,
    cz: `Odvážný průzkumníku, kostel sv. Jana Nepomuckého na Skalce je nejdramatičtěji zasazená budova v Praze — barokní kostel s dvěma věžemi od Kiliána Ignáce Dientzenhofera dokončený v roce 1738, umístěný na přirozeném skalním výchozu nad Vytoní s monumentálním venkovním schodištěm, jež k němu přistupuje jako finální výstup k svatyni. Kostel je zasvěcen sv. Janu Nepomuckému, českému patronovi, jenž byl v roce 1393 svržen z Karlova mostu z rozkazu krále Václava IV. — podle legendy proto, že odmítl prozradit zpovědi královny. Odemkni easter egg v jeho geometrii: Dientzenhofer navrhl kostel na diagonální ose, takže oltář je orientován nikoli k liturgickému standardnímu východu, ale k samotné skalní formaci — stavba ohýbá svou teologii kolem geologie pod ní. Dvě věže byly záměrně nakloněny tak, aby při přístupu z ulice dole vytvářely dramatický efekt falešné perspektivy, kvůli níž kostel vypadá vyšší, než je. Sv. Jan Nepomucký byl první osobou kanonizovanou nově reformovanou barokní katolickou církví specificky jako propagandistický světec protireformace — jeho kult se šířil katolickou Evropou rychleji než téměř jakýkoli jiný v historii. Tento kostel je jeho monumentem, jeho skálou a jeho dramatem najednou.`,
    zh: `勇敢的探险家，岩石上的圣内波穆克教堂是布拉格舞台布景最为戏剧化的建筑——一座由基利安·伊格纳茨·迪恩岑霍费尔设计的巴洛克双塔教堂，建成于1738年，建在维托尼上方一处天然岩石突出部上，气势磅礴的室外台阶如同通向圣殿的最后一段攀登。教堂供奉圣内波穆克的扬，这位捷克守护圣人于1393年奉国王瓦茨拉夫四世之命从查理大桥被抛入河中——传说是因为他拒绝透露王后的告解。解锁隐藏在其几何结构中的彩蛋：迪恩岑霍费尔将教堂设计在一条对角线轴上，使得祭坛并不朝向标准的礼仪东方，而是朝向岩石构造本身——建筑将其神学弯曲以顺应其下的地质。双塔被特意倾斜角度，以便从下方街道靠近时产生戏剧性的错误透视效果，使教堂显得比实际更高。圣内波穆克的扬是新改革的巴洛克天主教会专门作为反宗教改革宣传圣人而封圣的第一人——他的崇拜在天主教欧洲的传播速度几乎超过历史上任何其他圣人。这座教堂是他的纪念碑、他的岩石，也是他的戏剧，三者合而为一。`,
  },

  "kostel-nejsvetejsi-trojice": {
    en: `Brave explorer, the Church of the Holy Trinity on Spálená Street is one of the quietest and most rewarding hidden altars in Nové Město — a Baroque church with origins in the seventeenth century, standing on a street whose name means "Burned Street," a direct reference to the fire that destroyed this entire neighbourhood during the Hussite wars of the fifteenth century. The building you see today was rebuilt and reconsecrated after those fires, carrying the memory of an older structure in its foundations. Unlock the Easter egg in its dedication: the Holy Trinity as a theological concept was one of the central battlegrounds of the Hussite reformation — Jan Hus himself preached that the Catholic Church had corrupted the proper understanding of the relationship between Father, Son, and Holy Spirit. A church dedicated to the Trinity on a street named for the fire of the Hussite wars is, intentionally or not, a monument to that entire conflict. The interior contains a notable high altar and side chapels that receive almost no tourist attention, meaning you can often stand in complete silence in a Baroque church two minutes from Wenceslas Square. The city rewards those who walk the streets between the famous addresses, brave explorer. This is one of those streets.`,
    cz: `Odvážný průzkumníku, kostel Nejsvětější Trojice na Spálené ulici je jedním z nejtišších a nejodměňujících skrytých oltářů Nového Města — barokní kostel s počátky v sedmnáctém století, stojící na ulici, jejíž název znamená "Spálená", přímý odkaz na požár, který zničil celou tuto čtvrť za husitských válek patnáctého století. Budova, kterou vidíš dnes, byla po těchto požárech přestavěna a znovu posvěcena, nesoucí v základech paměť starší stavby. Odemkni easter egg v jejím zasvěcení: Nejsvětější Trojice jako teologický koncept bylo jedním z ústředních bojišť husitské reformace — sám Jan Hus kázal, že katolická církev zkorumpovala správné pochopení vztahu mezi Otcem, Synem a Duchem Svatým. Kostel zasvěcený Trojici na ulici pojmenované po ohni husitských válek je, záměrně či nezáměrně, monumentem celého tohoto konfliktu. Interiér obsahuje pozoruhodný hlavní oltář a boční kaple, které nepřitahují téměř žádnou turistickou pozornost, což znamená, že v barokním kostele dvě minuty od Václavského náměstí můžeš stát v naprostém tichu. Město odměňuje ty, kteří kráčejí ulicemi mezi slavnými adresami, odvážný průzkumníku. Toto je jedna z takových ulic.`,
    zh: `勇敢的探险家，斯帕莱纳街上的至圣三位一体教堂是新城区最宁静、最令人回味的隐秘祭坛之一——一座17世纪起源的巴洛克教堂，坐落在一条名字意为"燃烧之街"的街道上，这个名字直接指向15世纪胡斯战争中摧毁整个街区的那场大火。你眼前看到的建筑是在那些大火之后重建和重新祝圣的，在其地基中承载着一座更古老建筑的记忆。解锁隐藏在其献祭意义中的彩蛋：圣三位一体作为神学概念，是胡斯宗教改革的核心战场之一——扬·胡斯本人宣讲说，天主教会已经腐化了对圣父、圣子与圣灵之间关系的正确理解。一座供奉三位一体的教堂，矗立在以胡斯战争之火命名的街道上，无论有意无意，都是整个那场冲突的纪念碑。内部有一座值得注意的高祭坛和几乎不受游客关注的侧礼拜堂，这意味着你常常可以在距瓦茨拉夫广场两分钟路程的一座巴洛克教堂中，独自伫立于完全的寂静之中。城市奖励那些行走在著名地址之间街道上的人，勇敢的探险家。这就是其中一条这样的街道。`,
  },

  "lidice": {
    en: `Brave explorer, Lidice is one of the most solemn coordinates you will ever unlock — a village that no longer exists. On 10 June 1942, in retaliation for the assassination of SS-Obergruppenführer Reinhard Heydrich, Nazi forces killed 173 men and boys, deported 184 women to the Ravensbrück concentration camp, and sent 88 children to be gassed at Chełmno. They then razed every building, exhumed the cemetery, and attempted to erase the village from the map entirely. What they did not anticipate was the global response: towns across the world — in the United States, Mexico, Brazil, and beyond — renamed themselves Lidice in defiance. Today, a rose garden with over 30,000 specimens blooms on the emptied ground, and a haunting sculptural group of 82 children stands where a village once laughed. This is not a ruin. It is a resurrection.`,
    cz: `Odvážný průzkumníku, Lidice jsou jedněmi z nejsmutnějších souřadnic, které kdy odemkneš — vesnice, která již neexistuje. Dne 10. června 1942, jako odplata za atentát na SS-Obergruppenführera Reinharda Heydricha, nacistické síly zabily 173 mužů a chlapců, deportovaly 184 žen do koncentračního tábora Ravensbrück a poslaly 88 dětí do plynových komor v Chełmnu. Poté srovnaly každou budovu se zemí, exhumovaly hřbitov a pokusily se vesnici zcela vymazat z mapy. Co nepředvídaly, byla celosvětová odezva: města po celém světě — ve Spojených státech, Mexiku, Brazílii a jinde — se přejmenovala na Lidice na znamení odporu. Dnes na vyčištěném pozemku kvete zahrada s více než 30 000 růžemi a dojemná sochařská skupina 82 dětí stojí tam, kde se kdysi smála vesnice. Toto není ruina. Je to zmrtvýchvstání.`,
    zh: `勇敢的探险家，利迪策是你将解锁的最庄严的坐标之一——一座已不复存在的村庄。1942年6月10日，为报复对党卫军高级集团领袖莱因哈德·海德里希的刺杀，纳粹军队杀害了173名男性和男孩，将184名妇女驱逐至拉文斯布吕克集中营，并将88名儿童送往赫乌姆诺被毒气杀害。随后他们将每一座建筑夷为平地，掘开墓地，试图将这个村庄彻底从地图上抹去。他们没有预料到的是全球的反应：美国、墨西哥、巴西等地的城镇纷纷将自己改名为利迪策以示抗议。如今，一座拥有超过三万株玫瑰的花园在这片空旷的土地上盛开，82个孩子的雕塑群静静矗立在曾经欢声笑语的村庄旧址上。这不是废墟。这是复活。`,
  },

  "florenc-bus-terminal": {
    en: `Brave explorer, Florenc is not the most glamorous quest zone in Prague — it is, deliberately, the most democratic. This sprawling bus terminal handles thousands of passengers daily on routes to every corner of Central Europe, making it the literal gateway through which most long-distance travellers enter and exit Prague. The terminal sits atop one of Prague's oldest geological features: the Vltava floodplain terrace, where the river once ran before shifting its course over millennia. Unlock the Easter egg built into the terminal's history: during the Communist era, Florenc was the key hub for workers' buses that connected Prague's vast industrial enterprises with the housing estates built to accommodate their employees — a physical manifestation of how the Communist city planned its citizens' movement. Today it is a palimpsest of every era of Czech travel: Communist-era departure boards, post-1989 private bus lines, and now international FlixBus coaches heading to Berlin, Vienna, and Warsaw. The brave explorer who stands still long enough at Florenc will hear a dozen languages in under three minutes.`,
    cz: `Odvážný průzkumníku, Florenc není nejpůvabnější quest zónou v Praze — záměrně je tou nejdemokratičtější. Tento rozlehlý autobusový terminál denně odbavuje tisíce cestujících na linkách do každého kouta střední Evropy, čímž je doslova branou, přes níž většina dálkových cestujících do Prahy přijíždí a odjíždí. Terminál stojí na jednom z nejstarších geologických útvarů Prahy: vltavské náplavové terase, kde řeka dříve tekla, než se v průběhu tisíciletí posunula. Odemkni easter egg zabudovaný do historie terminálu: za komunistické éry byl Florenc klíčovým uzlem dělnických autobusů, které spojovaly pražské rozsáhlé průmyslové podniky se sídlišti postavenými pro jejich zaměstnance — fyzické ztělesnění toho, jak komunistické město plánovalo pohyb svých občanů. Dnes je to palimpsest každé éry české dopravy: komunistické odjezdové tabule, soukromé autobusové linky po roce 1989 a nyní mezinárodní coaches FlixBus mířící do Berlína, Vídně a Varšavy. Odvážný průzkumník, který na Florenci dostatečně dlouho stojí, uslyší tucet jazyků za méně než tři minuty.`,
    zh: `勇敢的探险家，弗洛伦茨并不是布拉格最迷人的任务区——它刻意成为最民主的那个。这个庞大的巴士总站每天在通往中欧每个角落的路线上运送数千名乘客，使其成为大多数长途旅行者进出布拉格的字面意义上的大门。总站坐落在布拉格最古老的地质特征之上：伏尔塔瓦河冲积台地，河流曾经在这里流淌，数千年来逐渐改道。解锁嵌入总站历史中的彩蛋：在共产主义时代，弗洛伦茨是工人班车的关键枢纽，将布拉格庞大的工业企业与为其员工建造的住宅区连接起来——是共产主义城市如何规划市民出行的具体体现。如今它是捷克旅行每个时代的叠写本：共产主义时代的出发时刻表、1989年后的私营巴士线路，以及现在前往柏林、维也纳和华沙的国际FlixBus长途客车。在弗洛伦茨驻足够久的勇敢探险家，将在不到三分钟内听到十几种语言。`,
  },

  "mistodrzitelsky-letohradek": {
    en: `Brave explorer, the Místodržitelský letohrádek — the Viceroy's Summer Palace — is the hidden centrepiece of Stromovka park, Prague's oldest royal game reserve, tucked behind trees near the Vltava in Holešovice. The original Gothic hunting lodge on this site was built for King John of Luxembourg in the 14th century; the current Baroque pavilion was rebuilt for Rudolf II, the Habsburg emperor who turned Prague into the intellectual capital of Renaissance Europe. Rudolf used the surrounding Stromovka as a royal deer park and commissioned the construction of a canal to bring water from the Vltava to feed the ponds — an engineering feat that remains partially visible today. Unlock the Easter egg: in the 19th century, the summer palace was converted into a newspaper reading room for citizens, making it one of the world's earliest examples of a public leisure library. A royal hunting lodge became a place where ordinary Praguers came to read the morning news.`,
    cz: `Odvážný průzkumníku, Místodržitelský letohrádek je skrytým středobodem parku Stromovka — nejstarší královské obory Prahy — schovaný za stromy u Vltavy v Holešovicích. Původní gotická lovecká chata na tomto místě byla postavena pro krále Jana Lucemburského ve 14. století; současný barokní pavilon byl přestavěn pro Rudolfa II., habsburského císaře, který z Prahy učinil intelektuální centrum renesanční Evropy. Rudolf využíval okolní Stromovku jako královskou jelení oboru a nechal vybudovat kanál k přivedení vody z Vltavy pro napájení rybníků — technický výkon, který je dnes částečně stále viditelný. Odemkni easter egg: v 19. století byl letohrádek přestavěn na čítárnu novin pro občany, čímž se stal jedním z nejranějších příkladů veřejné relaxační knihovny na světě. Královská lovecká chata se stala místem, kam obyčejní Pražané přicházeli číst ranní noviny.`,
    zh: `勇敢的探险家，总督夏宫是斯特罗莫夫卡公园的隐秘核心——布拉格最古老的皇家猎场，藏匿在霍列绍维采近伏尔塔瓦河畔的树木之后。这个地点上最初的哥特式狩猎小屋由卢森堡的约翰国王于14世纪建造；现存的巴洛克亭阁是为鲁道夫二世重建的——这位哈布斯堡皇帝将布拉格变成了文艺复兴时期欧洲的思想之都。鲁道夫将周边的斯特罗莫夫卡用作皇家鹿苑，并委托建造了一条运河从伏尔塔瓦河引水灌溉鱼塘——这一工程壮举至今部分仍可见。解锁彩蛋：19世纪，这座夏宫被改建为供市民阅读报纸的阅览室，使其成为世界上最早的公共休闲图书馆之一。一座皇家狩猎小屋变成了普通布拉格人来阅读晨报的地方。`,
  },

  "slunecni-namesti": {
    en: `Brave explorer, Sluneční náměstí — Sunny Square — is the commercial heart of Nové Butovice, a housing district in Prague 13 built during the final decade of Communist-era construction in the 1980s. The square anchors a cluster of panel apartment towers with a shopping centre, tram connections, and the Nové Butovice metro station, all planned simultaneously as a single integrated unit — a rare example of Communist urban design where the transport, retail, and residential functions were conceived together rather than retrofitted. Unlock the Easter egg in its name: Sluneční náměstí was deliberately named "Sunny Square" by Communist urban planners who believed that housing estate residents deserved optimistic place names to counterbalance the concrete monotony of their surroundings — a catalogue of cheerful names was officially approved for new Prague estates during this era. The square itself does receive more direct sunlight than most inner-city locations, positioned on the plateau above the Prokop Valley. Sometimes the optimists were right.`,
    cz: `Odvážný průzkumníku, Sluneční náměstí je obchodním srdcem Nových Butovic, obytné čtvrti v Praze 13 postavené během posledního desetiletí komunistické výstavby v 80. letech. Náměstí zakotvuje skupinu panelových bytových věží s nákupním centrem, tramvajovými spoji a stanicí metra Nové Butovice, vše plánované současně jako jeden integrovaný celek — vzácný příklad komunistického urbanistického designu, kde dopravní, maloobchodní a obytné funkce byly koncipovány společně, nikoli doplňovány dodatečně. Odemkni easter egg v jeho názvu: Sluneční náměstí bylo záměrně pojmenováno komunistickými urbanistickými plánovači, kteří věřili, že obyvatelé sídlišť si zaslouží optimistické názvy míst jako protiváhu betonové monotónnosti svého okolí — katalog veselých názvů byl v tomto období oficiálně schválen pro nová pražská sídliště. Samotné náměstí skutečně dostává více přímého slunečního světla než většina vnitroměstských lokalit, umístěné na plošině nad Prokopským údolím. Někdy měli optimisté pravdu.`,
    zh: `勇敢的探险家，阳光广场是新布托维采的商业核心——布拉格13区的一个住宅区，建于1980年代共产主义时代建设的最后十年。广场以购物中心、有轨电车连接和新布托维采地铁站为支撑，将一组预制板公寓楼锚定其中，所有这些同时规划为一个单一整合体——这是共产主义城市设计的罕见范例，交通、零售和住宅功能被统一构想，而非事后补充。解锁隐藏在其名称中的彩蛋：阳光广场由共产主义城市规划者刻意命名，他们认为住宅区居民应该拥有乐观的地名，以平衡周围混凝土单调的环境——这一时期一份充满愉快名称的目录被正式批准用于布拉格新住宅区。广场本身确实比大多数城市内部地点获得更多直射阳光，坐落在普罗科普山谷上方的高原上。有时候乐观主义者是对的。`,
  },

  "westfield-chodov": {
    en: `Brave explorer, Westfield Chodov is Prague's most complete monument to consumer capitalism — a vast enclosed mall in the Chodov district that has, over the decades since 1997, grown to become one of the largest shopping centres in Central Europe. But beneath the branded facades and food court lighting lies a genuinely interesting piece of urban history: the Chodov district itself was built as one of Prague's largest Communist-era housing estates in the 1970s, designed to house tens of thousands of workers in standardised panel apartment blocks. The mall was then inserted into this carefully planned socialist urban grid like a commercial virus. Unlock the Easter egg in the mall's location: it is built directly above the Chodov metro station, making it one of the rare cases in Europe where you can descend from an underground train and emerge, without ever stepping outside, directly into a branch of H&M. The juxtaposition of Communist infrastructure and Western retail, sharing the same footprint, is the most honest monument to 1989 you will find.`,
    cz: `Odvážný průzkumníku, Westfield Chodov je nejkompletnějším pomníkem spotřebitelského kapitalismu v Praze — rozsáhlý uzavřený obchodní dům v chodovské čtvrti, který v průběhu desetiletí od roku 1997 vyrostl v jedno z největších obchodních center ve střední Evropě. Ale pod branded fasádami a osvětlením food courtu leží opravdu zajímavý kousek urbánní historie: samotná chodovská čtvrť byla vystavěna jako jedno z největších pražských komunistických sídlišť v 70. letech, navržené pro ubytování desítek tisíc pracovníků ve standardizovaných panelových bytových domech. Obchodní centrum bylo poté vloženo do tohoto pečlivě plánovaného socialistického městského rastru jako komerční virus. Odemkni easter egg v umístění nákupního centra: je postaveno přímo nad stanicí metra Chodov, čímž se stává jedním z vzácných případů v Evropě, kde lze sestoupit z podzemního vlaku a vynořit se, aniž byste někdy vyšli ven, přímo do pobočky H&M. Juxtapozice komunistické infrastruktury a západního maloobchodu sdílející stejnou zastavěnou plochu je nejupřímnějším pomníkem roku 1989, jaký najdete.`,
    zh: `勇敢的探险家，西田乔多夫是布拉格消费资本主义最完整的纪念碑——乔多夫区一座巨大的封闭购物中心，自1997年以来数十年间已发展成为中欧最大的购物中心之一。但在品牌外立面和美食广场灯光之下，隐藏着一段真正有趣的城市历史：乔多夫区本身建于1970年代，是布拉格最大的共产主义时代住宅区之一，设计用于将数万名工人安置在标准化的预制板公寓楼中。购物中心随后被插入这个精心规划的社会主义城市网格，如同一个商业病毒。解锁购物中心选址中的彩蛋：它直接建在乔多夫地铁站上方，使其成为欧洲罕见的案例之一——你可以从地铁下车，无需踏出室外，直接走进一家H&M门店。共产主义基础设施与西方零售业共享同一占地面积的并置，是你能找到的对1989年最诚实的纪念。`,
  },

  "zlicin": {
    en: `Brave explorer, Zličín is the westernmost frontier of Prague's metro network — the terminus of Line B, where the city's underground railway surfaces and officially hands you off to the suburban world beyond. For most Praguers, Zličín means one thing: the IKEA. The Swedish furniture giant planted its Central European flagship here in 1996, the first IKEA in the post-Communist Czech Republic, and it transformed a semi-rural Prague suburb into a retail destination drawing customers from across the region. But Zličín has a deeper layer: the area contains preserved fragments of a medieval village, including the Church of Saints Peter and Paul, one of the oldest Romanesque-era church sites in the Prague suburbs, predating the metro by about eight hundred years. Unlock the Easter egg: the metro station is built in a cut-and-cover style that exposes the original terrain — if you look past the park-and-ride lot toward the hills to the west, you are looking at the landscape that existed before Prague expanded to absorb it. The frontier is still visible from the platform.`,
    cz: `Odvážný průzkumníku, Zličín je nejzápadnější hranicí pražské sítě metra — konečnou stanicí linky B, kde se podzemní železniční systém města noří na povrch a oficiálně tě předává příměstskému světu za ním. Pro většinu Pražanů znamená Zličín jednu věc: IKEA. Švédský nábytkářský gigant zde zasadil svoji středoevropskou vlajkovou loď v roce 1996, první IKEA v postkomunistické České republice, a proměnil polovenkovské pražské předměstí v maloobchodní destinaci přitahující zákazníky z celého regionu. Ale Zličín má hlubší vrstvu: oblast obsahuje zachované fragmenty středověké vesnice, včetně kostela svatých Petra a Pavla, jednoho z nejstarších románských sakrálních míst pražského předměstí, staršího než metro o přibližně osm set let. Odemkni easter egg: samotná stanice metra je postavena metodou cut-and-cover, která odhaluje původní terén — pokud se podíváš za záchytné parkoviště směrem k pahorkům na západ, díváš se na krajinu, která existovala, než ji Praha pohltila. Hranice je z nástupiště stále viditelná.`,
    zh: `勇敢的探险家，兹利钦是布拉格地铁网络最西端的边疆——B线的终点站，城市地下铁路系统在此浮出地面，正式将你移交给远处的郊区世界。对大多数布拉格人来说，兹利钦意味着一件事：宜家。这家瑞典家具巨头于1996年在此建立了其中欧旗舰店，是后共产主义时代捷克共和国的第一家宜家，将一个半农村的布拉格郊区转变为吸引来自整个地区顾客的零售目的地。但兹利钦有更深的一层：该地区保存着一座中世纪村庄的残存遗迹，包括圣彼得保罗教堂——布拉格郊区最古老的罗马式教堂遗址之一，比地铁早约八百年。解锁彩蛋：地铁站采用明挖回填工法建造，露出了原始地形——如果你越过公园换乘停车场望向西边的山丘，你所看到的是布拉格扩张将其吞并之前就已存在的景观。从站台上仍然可以看到这条边界。`,
  },

  "vitezne-namesti": {
    en: `Brave explorer, Vítězné náměstí — Victory Square — is Prague's grandest unfinished project, a circular traffic hub that was meant to be the monumental centrepiece of a never-built Dejvice civic palace complex designed in the 1920s. The visionary plan, drawn up by Czech architect Antonín Engel, called for a grand boulevard flanked by government ministries and a towering memorial column at the centre of the roundabout. The column was never built; instead, a modest obelisk was installed. In Communist times, the square was renamed Vítězné náměstí — Victory Square — though exactly what victory it commemorates has shifted with every political regime. Today it serves as one of Prague's busiest tram interchanges, a quiet giant waiting for the monument it was always promised. Unlock its secret: look for the circle of trees in the centre — they mark where the missing centrepiece was supposed to stand.`,
    cz: `Odvážný průzkumníku, Vítězné náměstí je největším nedokončeným projektem Prahy — kruhovým dopravním uzlem, který měl být monumentálním centrem nedostavěného dejvického správního komplexu navrženého ve dvacátých letech 20. století. Vizionářský plán, navržený českým architektem Antonínem Engelem, počítal s velkým bulvárem lemovaným vládními ministerstvy a tyčícím se pomníkovým sloupem uprostřed kruhového objezdu. Sloup nikdy nevznikl; místo toho byl instalován skromný obelisk. V dobách komunismu bylo náměstí přejmenováno na Vítězné náměstí — i když přesně to, jaké vítězství připomíná, se měnilo s každým politickým režimem. Dnes slouží jako jeden z nejrušnějších tramvajových uzlů Prahy — tichý obr, čekající na pomník, který mu byl vždy slibován. Odemkni jeho tajemství: hledej kruh stromů uprostřed — označují místo, kde měl stát chybějící středobod.`,
    zh: `勇敢的探险家，胜利广场是布拉格最宏大的未竟工程——一个圆形交通枢纽，原本设计为1920年代一个从未建成的杰维采市政宫殿综合体的纪念性核心。由捷克建筑师安托宁·恩格尔绘制的雄心壮志规划，构想了一条两侧矗立政府部门建筑的宏伟大道，以及环形交叉路口中央一根高耸的纪念柱。这根柱子从未建成；取而代之的是一座朴素的方尖碑。在共产主义时代，广场更名为胜利广场——尽管它纪念的究竟是哪场胜利，随着每个政治政权的更迭而不断改变。如今，它是布拉格最繁忙的有轨电车换乘站之一——一个沉默的巨人，等待着它始终被承诺却从未到来的纪念碑。解锁它的秘密：寻找中央那一圈树木——它们标记着那个缺失的中心标志物原本应该矗立的地方。`,
  },

  "zbraslavsky-zamek": {
    en: `Brave explorer, Zbraslavský zámek holds a double identity: above ground, a Baroque chateau that replaced a medieval Cistercian monastery; beneath its walls, one of the most dramatic dynastic episodes in Czech heritage. The original Zbraslav Monastery, founded in 1292, held the tombs of the last Přemyslid kings — until the Hussite Wars laid it to waste in 1420. The rebuilt Baroque palace now houses the National Gallery's extraordinary collection of Asian art, making it the unlikely setting where you can walk from a Czech Baroque courtyard into rooms filled with Japanese Noh theatre masks and Tibetan scroll paintings. Unlock its secret: the chateau stands at the confluence of the Berounka and Vltava rivers, and the medieval monks chose this location deliberately — they believed the merging currents held sacred energy. Stand at the riverside terrace and feel two rivers become one.`,
    cz: `Odvážný průzkumníku, Zbraslavský zámek má dvojitou identitu: nad zemí barokní zámek, který nahradil středověký cisterciácký klášter; pod jeho zdmi jeden z nejdramatičtějších dynastických epizod českého dědictví. Původní zbraslavský klášter, založený v roce 1292, uchovával hrobky posledních Přemyslovců — dokud ho husitské války v roce 1420 nezdeptal. Přestavěný barokní palác nyní hostí mimořádnou sbírku asijského umění Národní galerie, čímž se stává nepravděpodobným prostředím, kde lze přejít z českého barokního nádvoří do místností plných japonských masek divadla Noh a tibetských svitků. Odemkni jeho tajemství: zámek stojí na soutoku Berounky a Vltavy a středověcí mniši si toto místo vybrali záměrně — věřili, že spojující proudy uchovávají posvátnou energii. Postav se na říční terasu a pocit, jak se dvě řeky stávají jednou.`,
    zh: `勇敢的探险家，兹布拉斯拉夫宫拥有双重身份：地面之上是一座取代了中世纪西多会修道院的巴洛克风格宫殿；在它的墙壁之下，则是捷克遗产中最戏剧性的王朝事件之一。原兹布拉斯拉夫修道院建于1292年，保存着最后几位普热米斯尔王朝国王的陵墓——直到1420年胡斯战争将其夷为平地。重建的巴洛克宫殿如今收藏着国家美术馆卓越的亚洲艺术藏品，使它成为一个令人意想不到的场所——在这里，你可以从捷克巴洛克式庭院步入摆满日本能乐面具和西藏唐卡画卷的房间。解锁它的秘密：宫殿坐落在贝劳恩卡河与伏尔塔瓦河的交汇处，中世纪的僧侣刻意选择了这个地点——他们相信汇流的水流蕴含着神圣的能量。站在河边露台上，感受两条河流合而为一的时刻。`,
  },

  "praha-bubny-station": {
    en: `Brave explorer, Praha-Bubny is a station that time tried to forget. Between 1941 and 1945, more than 50,000 Prague Jews were deported from this platform — nearly the entire Jewish population of Prague — transported east to ghettos, concentration camps, and extermination centres. The station fell into disuse after the war, its tracks rusting, its halls crumbling. For decades it sat silent, as if the city itself could not decide what to do with a place so weighted by memory. Now it is being transformed into the Station of Memory, a Holocaust memorial complex where the platform, the tracks, and the waiting rooms will be preserved as witness spaces. Unlock its hidden detail: the original departure lists, meticulously maintained by Nazi bureaucracy, survive in full — every name, every date, every destination recorded. The list is the monument.`,
    cz: `Odvážný průzkumníku, Praha-Bubny je nádraží, které se čas pokoušel zapomenout. Mezi lety 1941 a 1945 bylo z tohoto nástupiště deportováno více než 50 000 pražských Židů — téměř celá pražská židovská populace — přepravena na východ do ghett, koncentračních táborů a vyhlazovacích center. Po válce nádraží přestalo sloužit provozu, jeho koleje rzivěly, sály chátraly. Desítky let stálo tiše, jako by si samo město nedokázalo rozhodnout, co dělat s místem tak naloženým vzpomínkami. Nyní je přeměňováno na Nádraží paměti — memoriální komplex holocaustu, kde budou nástupiště, koleje a čekárny zachovány jako svědecké prostory. Odemkni jeho skrytý detail: původní seznamy odjezdů, pečlivě vedené nacistickou byrokracií, se dochovaly v plném rozsahu — každé jméno, každé datum, každý cíl zaznamenány. Seznam je pomníkem.`,
    zh: `勇敢的探险家，布布尼车站是一座时间试图遗忘的车站。1941年至1945年间，超过五万名布拉格犹太人从这个站台被驱逐——几乎是布拉格全部的犹太人口——被运往东方的隔都、集中营和灭绝中心。战后，这座车站陷入废弃，铁轨生锈，大厅颓败。数十年来它静静地矗立，仿佛这座城市自己也无法决定该如何对待一个承载着如此沉重记忆的地方。如今它正在被改造为"记忆之站"——一个大屠杀纪念综合体，站台、铁轨和候车室将被保存为见证空间。解锁它隐藏的细节：由纳粹官僚体系一丝不苟地记录下来的原始驱逐名单，完整地保存至今——每一个名字、每一个日期、每一个目的地都被详细记录。名单就是纪念碑。`,
  },

  "namesti-republiky": {
    en: `Brave explorer, Náměstí Republiky is the threshold between two ages of Prague — the medieval and the modern, pressed together at a single square. On one side rises the Powder Tower, a 15th-century Gothic gate that once marked the edge of the Old Town; beside it stands the Municipal House, an Art Nouveau masterpiece completed in 1912 that contains the Smetana Concert Hall, where Czechoslovakia's independence was declared in 1918. Unlock the Easter egg hidden in plain sight: the Municipal House was built on the exact site of the Royal Court — the former residence of Bohemian kings before they moved to the Castle. The foundation stones of medieval royalty literally lie beneath the Art Nouveau ballrooms. Step through the archway of the Powder Tower and you cross not just a street but six hundred years.`,
    cz: `Odvážný průzkumníku, Náměstí Republiky je práhem mezi dvěma věky Prahy — středověkým a moderním, stlačenými dohromady na jediném náměstí. Na jedné straně se tyčí Prašná brána, gotická brána z 15. století, která kdysi označovala okraj Starého Města; vedle ní stojí Obecní dům, secesní mistrovské dílo dokončené v roce 1912, které obsahuje Smetanovu síň, kde byla v roce 1918 vyhlášena nezávislost Československa. Odemkni easter egg skrytý na očích: Obecní dům byl postaven přesně na místě Královského dvora — dřívějšího sídla českých králů před jejich přesunem na hrad. Základní kameny středověkého království doslova leží pod secesními tanečními sály. Projdi průchodem Prašné brány a přejdeš nejen ulici, ale šest set let.`,
    zh: `勇敢的探险家，共和国广场是布拉格两个时代之间的门槛——中世纪与现代在同一个广场上紧密相邻。一侧矗立着火药塔，这座15世纪的哥特式城门曾标志着旧城的边界；旁边是市政厅，这座完成于1912年的新艺术风格杰作内有斯美塔那音乐厅——1918年，捷克斯洛伐克的独立正是在这里宣告的。解锁隐藏在明处的彩蛋：市政厅建在皇家宫廷的原址之上——那里是波西米亚国王迁往城堡之前的旧居。中世纪王权的基础石字面意义上就埋在新艺术风格舞厅之下。穿过火药塔的拱门，你跨越的不仅是一条街道，而是六百年的历史。`,
  },

  "jizni-pol-prahy": {
    en: `Brave explorer, Jižní pól Prahy — the South Pole of Prague — is exactly what it sounds like: the southernmost geographic point within the city limits of Prague, a pilgrimage site for urban boundary enthusiasts and the kind of person who needs to have stood at the edge of things. Unlike a real pole, it is unmarked, slightly anticlimactic, and surrounded by the ordinary southern suburbs of a Central European city. The point lies somewhere in the farmland and residential fringes where Prague formally ends and the Central Bohemian countryside begins. Unlock the Easter egg in the quest itself: Prague's administrative boundaries are not determined by geography or logic but by a century of annexations, mergers, and political decisions about which villages should become districts and which should remain independent. The "South Pole" is a bureaucratic artifact disguised as a destination. Finding it is a statement that the journey to an arbitrary coordinate can carry its own meaning. The brave explorer who reaches this point has, by definition, explored Prague all the way to its limits.`,
    cz: `Odvážný průzkumníku, Jižní pól Prahy je přesně to, co zní: nejjižnější geografický bod v rámci správních hranic Prahy, poutní místo pro nadšence do urbánních hranic a typ člověka, který potřebuje stát na okraji věcí. Na rozdíl od skutečného pólu je neoznačen, trochu protikulminační a obklopený obyčejnými jižními předměstími středoevropského města. Bod leží někde ve farmářské krajině a obytných okrajích, kde Praha formálně končí a středočeská venkovská krajina začíná. Odemkni easter egg v samotném questu: správní hranice Prahy nejsou určeny geografií ani logikou, ale stoletím annexí, sloučení a politických rozhodnutí o tom, které vesnice se mají stát čtvrtěmi a které mají zůstat samostatné. "Jižní pól" je byrokratický artefakt maskovaný jako cíl. Jeho nalezení je prohlášením, že cesta na libovolnou souřadnici může mít svůj vlastní smysl. Odvážný průzkumník, který tohoto bodu dosáhne, prozkoumal Prahu doslova až na její limity.`,
    zh: `勇敢的探险家，布拉格南极——就是字面意思：布拉格市界内地理上最南端的点，是城市边界爱好者和那种需要站在事物边缘的人的朝圣地。与真正的极点不同，这里没有标记，略显平淡，被中欧城市普通的南部郊区所包围。这个点位于农田和住宅边缘地带的某处，布拉格在此正式结束，波西米亚中部的乡村从此开始。解锁这次任务本身的彩蛋：布拉格的行政边界不是由地理或逻辑决定的，而是由一个世纪的兼并、合并和政治决定——关于哪些村庄应该成为区，哪些应该保持独立——所塑造的。"南极"是一个伪装成目的地的官僚遗存。找到它是一种宣言：前往任意坐标的旅程可以承载自己的意义。抵达这个点的勇敢探险家，从定义上已经将布拉格探索到了它的极限。`,
  },

  "kostel-panny-marie-snezne": {
    en: `Brave explorer, the Church of Our Lady of the Snows is Prague's monument to ambition interrupted — a Gothic church begun by Emperor Charles IV in 1347 that was supposed to be the tallest church in Prague, rival to any cathedral in the Holy Roman Empire, and was never finished. What stands today is only the chancel — the eastern apse of what would have been an enormous nave — yet even this fragment soars to 33 metres in height, making it one of the tallest spaces in Prague's New Town. The Hussite Wars halted construction in the 15th century and the full nave was never built. Unlock the Easter egg: the church's forecourt connects to the Franciscan Garden, and the narrow passage from Wenceslas Square through the garden into the church complex is one of Prague's best hidden transitions — a 30-second walk through a gate that takes you from one of the busiest squares in Central Europe into a quiet Franciscan courtyard where pigeons outnumber tourists three to one. The unfinished church is also, accidentally, perfectly proportioned for what it is. Completion might have ruined it.`,
    cz: `Odvážný průzkumníku, Kostel Panny Marie Sněžné je pražským pomníkem přerušené ctižádosti — gotický kostel, který byl zahájen císařem Karlem IV. v roce 1347, měl být nejvyšším kostelem v Praze, soupeřem každé katedrály ve Svaté říši římské, a nikdy nebyl dokončen. To, co dnes stojí, je pouze presbytář — východní apsida toho, co by bylo obrovskou lodí — přesto i tento fragment sahá do výšky 33 metrů, čímž se stává jedním z nejvyšších prostorů v pražském Novém Městě. Husitské války zastavily stavbu v 15. století a celá loď nebyla nikdy postavena. Odemkni easter egg: předsíň kostela navazuje na Františkánskou zahradu a úzký průchod z Václavského náměstí přes zahradu do komplexu kostela je jedním z nejlépe skrytých přechodů Prahy — třicetisekundová chůze branou, která tě přenese z jednoho z nejrušnějších náměstí ve střední Evropě do tichého františkánského nádvoří, kde holubi převyšují turisty v poměru tři ku jedné. Nedokončený kostel je také, náhodou, dokonale proporcionální pro to, čím je. Dokončení by ho možná zkazilo.`,
    zh: `勇敢的探险家，雪地圣母教堂是布拉格雄心壮志被打断的纪念碑——一座由查理四世皇帝于1347年动工的哥特式教堂，原本应当成为布拉格最高的教堂，可与神圣罗马帝国任何大教堂媲美，却从未完工。今日屹立的只是唱诗班席——原本宏大中殿的东部后殿——然而即便是这个残缺的部分，也高达33米，使其成为布拉格新城最高的空间之一。胡斯战争在15世纪中止了建造工程，完整的中殿从未建成。解锁彩蛋：教堂前院连接着方济各花园，从瓦茨拉夫广场穿过花园进入教堂综合体的狭窄通道，是布拉格隐藏最好的过渡之一——穿过一扇门只需30秒，就能从中欧最繁忙的广场之一，走进一个鸽子比游客多三倍的宁静方济各式庭院。这座未完成的教堂也恰好意外地与其现状完美相称。完工或许会毁了它。`,
  },

  "kostel-sv-jindricha": {
    en: `Brave explorer, the Church of Saint Henry and Saint Kunigunde is one of the least-visited significant Gothic churches in Prague — a 14th-century hall church standing one block from Wenceslas Square that most visitors walk past without ever entering. The church was founded by Emperor Charles IV in 1348 as part of his comprehensive rebuilding of Prague's New Town, which he planned and executed with a speed and vision that has no parallel in medieval European urban history. Beside the church stands the Jindřišská Tower, a free-standing Gothic bell tower from the 15th century that was separated from the church structure and has since been converted into a small museum and café — making it one of the few medieval church towers in Europe where you can have coffee inside the belfry. Unlock the Easter egg: the church is dedicated jointly to Saint Henry (Holy Roman Emperor Henry II) and Saint Kunigunde (his wife), a politically strategic choice by Charles IV — by honouring the imperial couple, he was aligning his New Town foundation with the prestige of the Holy Roman Empire while simultaneously asserting Prague's place at its centre.`,
    cz: `Odvážný průzkumníku, Kostel sv. Jindřicha a sv. Kunhuty je jedním z nejméně navštěvovaných významných gotických kostelů v Praze — halový kostel ze 14. století stojící jeden blok od Václavského náměstí, kolem kterého většina návštěvníků prochází, aniž by kdy vstoupila. Kostel byl založen císařem Karlem IV. v roce 1348 jako součást jeho komplexní přestavby pražského Nového Města, kterou plánoval a prováděl s rychlostí a vizí, jež nemá v středověké evropské urbánní historii paralelu. Vedle kostela stojí Jindřišská věž, samostatná gotická zvonice z 15. století, která byla oddělena od kostela a od té doby přeměněna na malé muzeum a kavárnu — čímž se stala jednou z mála středověkých kostelních věží v Evropě, kde si můžete dát kávu uvnitř zvonice. Odemkni easter egg: kostel je zasvěcen společně sv. Jindřichovi (Svatý říšský císař Jindřich II.) a sv. Kunhutě (jeho manželce), což byl politicky strategický výběr Karla IV. — ctěním císařského páru sladoval svou novoměstskou nadaci s prestiží Svaté říše římské a zároveň prosazoval místo Prahy v jejím centru.`,
    zh: `勇敢的探险家，圣亨德里克与昆胡塔教堂是布拉格参观者最少的重要哥特式教堂之一——一座14世纪的厅堂式教堂，坐落在距瓦茨拉夫广场一个街区的地方，大多数游客从它旁边走过却从未进入。这座教堂由查理四世皇帝于1348年创立，作为他对布拉格新城区综合重建的一部分——他以中世纪欧洲城市历史上无与伦比的速度和远见规划并实施了这一重建。教堂旁边矗立着金德里希斯卡塔，一座15世纪独立的哥特式钟楼，已与教堂建筑分离，此后被改造成一个小型博物馆和咖啡馆——使其成为欧洲少数几个可以在钟楼内喝咖啡的中世纪教堂塔楼之一。解锁彩蛋：这座教堂同时献给圣亨德里克（神圣罗马皇帝亨利二世）和圣昆胡塔（他的妻子），这是查理四世具有政治战略意义的选择——通过向皇帝夫妇致敬，他将自己的新城区基础与神圣罗马帝国的威望相联结，同时确立布拉格在其中心的地位。`,
  },

  "kostel-sv-mikulase-stare-mesto": {
    en: `Brave explorer, the Church of Saint Nicholas on Old Town Square is the younger and less famous of Prague's two churches bearing this name — the other, across the river in Malá Strana, draws thousands of visitors daily. This one, designed by Kilian Ignaz Dientzenhofer and completed in 1735, stands quietly in the corner of Old Town Square, half-hidden behind the other monuments competing for attention. It was a parish church, then a warehouse, then handed to the Russian Orthodox community, then a concert hall, and now serves the Hussite Church — each transition representing a different regime's solution to the problem of what to do with a beautiful building whose original congregation no longer existed. Unlock the Easter egg: after the dissolution of the Benedictine monastery that owned it, the Austrian authorities turned it into a warehouse for storing confiscated property. A church built to glorify the Baroque ideal of heaven became a government storage depot within fifty years of its consecration. The building survived every regime that tried to repurpose it. Most of those regimes did not.`,
    cz: `Odvážný průzkumníku, Kostel sv. Mikuláše na Staroměstském náměstí je mladším a méně slavným ze dvou pražských kostelů nesoucích toto jméno — ten druhý, přes řeku na Malé Straně, přitahuje každodenně tisíce návštěvníků. Tento, navržený Kilianem Ignácem Dientzenhoferem a dokončený v roce 1735, stojí klidně v rohu Staroměstského náměstí, napůl skrytý za ostatními památkami, které soutěží o pozornost. Byl farním kostelem, pak skladem, pak přestoupil ruské pravoslavné komunitě, pak koncertním sálem a nyní slouží Husitské církvi — každý přechod představuje řešení různých režimů problému, co dělat s krásnou budovou, jejíž původní farníci již neexistovali. Odemkni easter egg: po rozpuštění benediktinského kláštera, který jej vlastnil, přeměnily rakouské úřady kostel na sklad konfiskovaného majetku. Kostel postavený k oslavě barokního ideálu nebe se stal vládním skladištěm do padesáti let od svého posvěcení. Budova přežila každý režim, který se ji pokusil přeúčelovat. Většina těch režimů nepřežila.`,
    zh: `勇敢的探险家，老城广场上的圣尼古拉斯教堂是布拉格两座同名教堂中较年轻、较不出名的那座——另一座在河对岸的小城区，每天吸引数千游客。这座由基利安·伊格纳茨·迪恩岑霍费尔设计、完成于1735年的教堂，静静地矗立在老城广场一角，半隐于争夺游客注意力的其他纪念建筑之后。它曾是教区教堂，后成为仓库，再移交给俄国东正教社区，再成为音乐厅，如今服务于胡斯教会——每次转变都代表着不同政权对同一问题的解决方案：如何处置一座美丽建筑，其原始会众已不复存在。解锁彩蛋：本笃会修道院解散后，奥地利当局将其改为没收财产的仓库。一座为彰显巴洛克天堂理想而建的教堂，在祝圣后五十年内便成了政府仓库。这座建筑在每个试图改变其用途的政权下幸存下来。大多数政权自己却没能幸存。`,
  },

  "kacerov": {
    en: `Brave explorer, Kačerov is one of Prague's most important underground crossroads — the point on metro Line C where the city's south-north spine passes through the transition zone between Nusle's valley and the southern plateau. The station sits at a junction where the metro line, built in the 1970s, had to navigate some of the most geologically challenging terrain in Prague: the Nusle Valley's unstable subsoil required tunnelling engineers to solve problems that had no precedent in Czechoslovak infrastructure construction at the time. Unlock the Easter egg: Kačerov gives its name to the surrounding district, which preserves one of Prague's last intact pre-Communist-era villa neighbourhoods — a quiet grid of interwar family houses and gardens that somehow survived the 1970s panel-building wave that consumed most of the surrounding terrain. The neighbourhood where nothing dramatic ever happened is precisely what makes it precious. Most cities demolished their ordinary neighbourhoods; Prague, in places, forgot to.`,
    cz: `Odvážný průzkumníku, Kačerov je jednou z nejdůležitějších podzemních křižovatek Prahy — bod na metrolince C, kde páteř města sever-jih prochází přechodovou zónou mezi nusleským údolím a jižní plošinou. Stanice leží na místě, kde musela linka metra, postavená v 70. letech, zvládnout geologicky nejnáročnější terén v Praze: nestabilní podloží Nuselského údolí vyžadovalo od tunelářských inženýrů řešení problémů, které v československé infrastrukturní výstavbě té doby neměly precedens. Odemkni easter egg: Kačerov dává jméno okolní čtvrti, která uchovává jednu z posledních zachovaných předkomunistických vilových čtvrtí Prahy — tichý rastr meziválečných rodinných domů a zahrad, který nějak přežil vlnu panelové výstavby z 70. let, jež pohltila většinu okolního území. Čtvrť, kde se nikdy nic dramatického nestalo, je přesně tím, co ji činí cennou. Většina měst zbořila své obyčejné čtvrti; Praha na ně v některých místech prostě zapomněla.`,
    zh: `勇敢的探险家，卡切罗夫是布拉格最重要的地下十字路口之一——地铁C线南北主干线穿越努斯莱山谷与南部高原之间过渡带的节点。这座车站建于1970年代，坐落在地铁线路必须穿越布拉格地质条件最具挑战性地形的位置：努斯莱山谷不稳定的地下土层要求隧道工程师解决在当时捷克斯洛伐克基础设施建设中前所未有的难题。解锁彩蛋：卡切罗夫为周边区域命名，该区保存着布拉格最后几处完整的前共产主义时代别墅街区之一——一个安静的两战期间家庭住宅与花园网格，奇迹般地在70年代席卷周边大部分地区的预制板建设浪潮中幸存下来。从未发生过任何戏剧性事件的街区，恰恰正是使它珍贵的原因。大多数城市拆毁了普通街区；布拉格在某些地方，只是忘记了。`,
  },

  "kostel-sv-krize": {
    en: `Brave explorer, Kostel Svatého Kříže — the Rotunda of the Finding of the Holy Cross — is one of the oldest surviving buildings in Prague: a small Romanesque rotunda dating to the 12th century that has outlasted empires, reforms, and demolition campaigns by the sheer stubbornness of its stone. During the great clearance of the Josefov ghetto in the late 19th century, when the city demolished thousands of medieval structures to build Pařížská boulevard, the rotunda was threatened with demolition. It was saved only by a public campaign from Czech historians and architects who argued that destroying a 12th-century rotunda for a 19th-century boulevard was an act of civic vandalism. Unlock the Easter egg: the rotunda is so small — barely 7 metres in diameter — that it was once used as a guardhouse, then as an archive, and at various points in its history as storage. A church that served as a shed is still standing. Everything built to replace the neighbourhood around it is now considered historic.`,
    cz: `Odvážný průzkumníku, Kostel Nalezení Svatého Kříže — rotunda Nalezení Svatého Kříže — je jednou z nejstarších dochovaných budov v Praze: malá románská rotunda pocházející z 12. století, která přežila říše, reformace a demoliční kampaně pouhou tvrdohlavostí svého kamene. Během velké asanace josefovského ghetta na konci 19. století, kdy město zbořilo tisíce středověkých staveb, aby postavilo bulvár Pařížská, byla rotunda ohrožena demolicí. Zachránil ji pouze veřejný tažení českých historiků a architektů, kteří tvrdili, že zboření románské rotundy z 12. století kvůli bulváru z 19. století je aktem občanského vandalismu. Odemkni easter egg: rotunda je tak malá — sotva 7 metrů v průměru — že byla kdysi používána jako strážnice, pak jako archiv a v různých bodech své historie jako skladiště. Kostel, který sloužil jako kůlna, stále stojí. Vše, co bylo postaveno na nahrazení okolního sousedství, je nyní považováno za historické.`,
    zh: `勇敢的探险家，圣十字教堂——发现圣十字圆形教堂——是布拉格现存最古老的建筑之一：一座可追溯至12世纪的小型罗马式圆形教堂，凭借其石砌的顽强，历经帝国更迭、宗教改革和拆除运动而幸存至今。19世纪末，城市为建造巴黎大街而拆除了约瑟夫区聚居区的数千座中世纪建筑，这座圆形教堂也面临被拆除的威胁。只有捷克历史学家和建筑师发起的公众运动才将它拯救下来，他们认为为了一条19世纪大道而拆毁一座12世纪圆形教堂是一种公民破坏行为。解锁彩蛋：这座圆形教堂非常小——直径仅约7米——以至于曾被用作岗亭，后来又作为档案室，在其历史的不同时期还被用作储藏室。一座曾充当棚屋的教堂至今屹立不倒。所有为取代其周围街区而建造的一切，如今都被视为历史遗迹。`,
  },

  "na-prikope": {
    en: `Brave explorer, Na Příkopě — literally "On the Moat" — is Prague's most historically frank street name: it tells you exactly what was here before it was a street. For centuries this was the moat that separated the Old Town from the New Town, filled with water diverted from the Vltava. The moat was filled in during the 18th century and converted into a promenade, which became the city's first fashionable outdoor gathering place — the equivalent of Vienna's Ringstrasse compressed into a single street. Today it is Prague's most visited pedestrian shopping strip, connecting Wenceslas Square to Náměstí Republiky through a corridor of banks, international retail chains, and the occasional palace facade that survived the 20th century. Unlock the Easter egg in the architecture: several of the grandest buildings on Na Příkopě are former aristocratic palaces repurposed as banks during the 19th-century financial boom. The street went from moat to promenade to banking corridor to shopping street without ever being demolished. The layers are still readable if you look above the shop windows.`,
    cz: `Odvážný průzkumníku, Na Příkopě — doslova "Na příkopu" — je nejhistoricky upřímným názvem ulice v Praze: říká ti přesně, co zde bylo, než se z toho stala ulice. Po staletí to byl příkop oddělující Staré Město od Nového Města, naplněný vodou odvedenou z Vltavy. Příkop byl zasypán v 18. století a přeměněn na promenádu, která se stala prvním módním venkovním shromažďovacím místem města — ekvivalentem vídeňského Ringstrasse, ale stlačeným do jediné ulice. Dnes je to nejnavštěvovanější pěší nákupní třída Prahy, spojující Václavské náměstí s Náměstím Republiky přes koridor bank, mezinárodních obchodních řetězců a příležitostné palácové fasády, které přežily 20. století. Odemkni easter egg v architektuře: několik nejvelkolepějších budov Na Příkopě jsou bývalé šlechtické paláce přestavěné na banky během finančního boomu 19. století. Ulice prošla cestu od příkopu přes promenádu přes bankovní koridor na nákupní ulici, aniž by kdy byla zbořena. Vrstvy jsou stále čitelné, pokud se podíváš nad výlohy obchodů.`,
    zh: `勇敢的探险家，"护城河街"——字面意思是"在护城河上"——是布拉格历史上最坦率的街道名称：它明确告诉你，在成为街道之前这里是什么。几个世纪以来，这里是将旧城与新城分隔开来的护城河，注满了从伏尔塔瓦河引来的水。护城河在18世纪被填平并改建为散步道，成为全城第一个时髦的户外聚集场所——相当于维也纳环城大道，但压缩在一条街道中。如今它是布拉格最多游客光顾的步行购物街，通过由银行、国际零售连锁店以及偶尔幸存下来的宫殿外立面组成的走廊，将瓦茨拉夫广场与共和国广场相连。解锁建筑中的彩蛋：护城河街上几座最宏伟的建筑是前贵族宫殿，在19世纪金融繁荣时期被改作银行。这条街从护城河到散步道，从银行走廊到购物街，从未经历过拆除重建。如果你将目光抬过橱窗，这些层次至今仍清晰可读。`,
  },

  "parizska": {
    en: `Brave explorer, Pařížská — Paris Street — is the most expensive and most ideologically loaded thoroughfare in Prague. Built between 1896 and 1906 as part of the radical sanitisation of Josefov, the former Jewish ghetto, it replaced a dense medieval labyrinth of alleys, synagogues, and tenements with a sweeping Art Nouveau boulevard modelled explicitly on Baron Haussmann's Paris. The city demolished approximately 80% of the historic ghetto to build it. Unlock the darkest Easter egg: the street was deliberately designed to erase the ghetto's identity while preserving just enough of its monuments — Pinkas Synagogue, the Old Jewish Cemetery — to serve as tourist attractions. Today Pařížská is lined with Hermès, Chanel, Louis Vuitton, and Cartier boutiques, making it one of the most exclusive retail streets in Central Europe. The luxury shops occupy buildings whose construction required the destruction of one of the oldest Jewish communities in Europe. The boulevard is beautiful. The history beneath it is not.`,
    cz: `Odvážný průzkumníku, Pařížská je nejdražší a ideologicky nejzatíženější třídou v Praze. Postavena v letech 1896 až 1906 jako součást radikální asanace Josefova, bývalého židovského ghetta, nahradila hustý středověký labyrint uliček, synagog a nájemních domů rozsáhlým secesním bulvárem, který byl výslovně modelován na pařížském Haussmannově vzoru. Město zbořilo přibližně 80 % historického ghetta, aby ji postavilo. Odemkni nejtemnější easter egg: ulice byla záměrně navržena tak, aby vymazala identitu ghetta a přitom zachovala dostatek jeho památek — Pinkasovu synagogu, Starý židovský hřbitov — jako turistické atrakce. Dnes je Pařížská lemována butiky Hermès, Chanel, Louis Vuitton a Cartier, čímž se stala jednou z nejexkluzivnějších obchodních ulic ve střední Evropě. Luxusní obchody sídlí v budovách, jejichž stavba vyžadovala zničení jedné z nejstarších židovských komunit v Evropě. Bulvár je krásný. Historie pod ním není.`,
    zh: `勇敢的探险家，巴黎大街是布拉格最昂贵、意识形态上最沉重的街道。这条街建于1896年至1906年间，作为约瑟夫区——前犹太人聚居区——激进城市改造的一部分，用一条明确仿照奥斯曼男爵改造巴黎的新艺术风格大道，取代了由小巷、会堂和租赁公寓构成的密集中世纪迷宫。城市拆除了约80%的历史聚居区来建造它。解锁最黑暗的彩蛋：这条街被刻意设计为抹去聚居区的身份，同时保留足够多的纪念性建筑——平卡斯会堂、老犹太墓地——作为旅游景点。如今巴黎大街两侧排列着爱马仕、香奈儿、路易威登和卡地亚精品店，使其成为中欧最独家的零售街之一。这些豪华店铺占据的建筑，其建造需要摧毁欧洲最古老的犹太社区之一。大道是美丽的。它之下的历史则不然。`,
  },

  "cvut": {
    en: `Brave explorer, ČVUT — the Czech Technical University in Prague — is the oldest and most prestigious technical university in Central Europe, founded in 1707 by imperial decree as the Prague Engineering School, making it one of the first technical universities in the world outside of Paris. Its main campus in Dejvice, built during the First Czechoslovak Republic in the 1920s and 30s, is a deliberate monument to Czech scientific ambition: a planned university quarter of Neo-Classical faculty buildings arranged around a central axis, designed by the same generation of architects who were reshaping Prague's Dejvice district into a modern civic showcase. Unlock the Easter egg: ČVUT alumni include Emil Kolben, who studied under Thomas Edison in the United States and returned to found what became the ČKD industrial conglomerate — one of the most important engineering firms in Central European history. The university that trained the engineers who built Communist Czechoslovakia's industrial infrastructure was itself a product of Habsburg imperial education policy. Every generation rewrote what ČVUT was for; the building stayed the same.`,
    cz: `Odvážný průzkumníku, ČVUT — České vysoké učení technické v Praze — je nejstarší a nejprestižnější technická univerzita ve střední Evropě, založená v roce 1707 císařským dekretem jako Pražská inženýrská škola, čímž se stala jednou z prvních technických univerzit na světě mimo Paříž. Její hlavní kampus v Dejvicích, postavený za první Československé republiky ve 20. a 30. letech, je záměrným pomníkem českých vědeckých ambic: plánovaná univerzitní čtvrť neoklasicistních budov fakult uspořádaných kolem centrální osy, navržená stejnou generací architektů, která přetvářela dejvickou čtvrť Prahy v moderní občanský výkladní skříň. Odemkni easter egg: absolventi ČVUT zahrnují Emila Kolbena, který studoval u Thomase Edisona ve Spojených státech a vrátil se, aby založil to, co se stalo průmyslovým konglomerátem ČKD — jednou z nejdůležitějších strojírenských firem v historii střední Evropy. Univerzita, která vychovala inženýry budující průmyslovou infrastrukturu komunistického Československa, sama byla produktem habsburské imperiální vzdělávací politiky. Každá generace přepsala, k čemu ČVUT sloužilo; budova zůstala stejná.`,
    zh: `勇敢的探险家，ČVUT——布拉格捷克技术大学——是中欧最古老、最负盛名的理工大学，1707年由皇家法令作为布拉格工程学院创立，使其成为巴黎之外世界上最早的理工大学之一。其位于杰维采的主校区建于第一捷克斯洛伐克共和国时期的1920和30年代，是捷克科学雄心的刻意纪念碑：一个规划有序的大学区，新古典主义风格的院系建筑沿中轴线排列，由同一代将布拉格杰维采区改造为现代公民展示窗口的建筑师设计。解锁彩蛋：ČVUT的校友包括埃米尔·科尔本，他曾在美国跟随托马斯·爱迪生学习，回国后创立了后来发展为ČKD工业集团的企业——中欧历史上最重要的工程公司之一。这所培训了建设共产主义捷克斯洛伐克工业基础设施工程师的大学，本身就是哈布斯堡帝国教育政策的产物。每一代人都重新诠释了ČVUT的用途；建筑保持不变。`,
  },

  "kostel-sv-vaclava-vrsovice": {
    en: `Brave explorer, the Church of Saint Wenceslas in Vršovice is one of the most architecturally audacious sacred buildings in Prague — a 1930 Functionalist masterpiece designed by Josef Gočár that abandoned every convention of traditional church architecture and built a house of God using the visual language of modern industry. Its tower is a stark concrete column; its nave is a modernist hall of clean geometric lines and restrained ornamentation. Gočár was one of the founders of Czech Rondo-Cubism and a leading figure in the Czech architectural avant-garde, and this church represents his most radical statement: that spiritual space and modern form were not in conflict. Unlock the Easter egg in the dedication: Saint Wenceslas — the patron saint of Bohemia, killed by his brother Boleslav I in 935 — is the most politically charged saint in Czech history. His image has been claimed by every Czech political movement from medieval nationalism to Communist propaganda to the Velvet Revolution. A church dedicated to him in 1930, at the height of the First Czechoslovak Republic, was an explicit statement of Czech national identity. The building is modern. The argument is a thousand years old.`,
    cz: `Odvážný průzkumníku, kostel svatého Václava ve Vršovicích je jednou z architektonicky nejodvážnějších sakrálních staveb v Praze — funkcionalistické mistrovské dílo z roku 1930 od Josefa Gočára, které opustilo každou konvenci tradiční chrámové architektury a postavilo dům Boží pomocí vizuálního jazyka moderního průmyslu. Jeho věž je strohou betonovou sloupem; jeho loď je modernistickým sálem čistých geometrických linií a zdrženlivé ornamentiky. Gočár byl jedním ze zakladatelů českého rondokubismu a přední postavou české architektonické avantgardy, a tento kostel představuje jeho nejradikálnější výrok: že duchovní prostor a moderní forma nejsou v rozporu. Odemkni easter egg v zasvěcení: Svatý Václav — patron Čech, zabitý svým bratrem Boleslavem I. v roce 935 — je politicky nejnabitějším světcem v české historii. Jeho obraz si přisvojilo každé české politické hnutí od středověkého nacionalismu přes komunistickou propagandu až po Sametovou revoluci. Kostel zasvěcený mu v roce 1930, na vrcholu První československé republiky, byl explicitním vyjádřením české národní identity. Budova je moderní. Argument je tisíc let starý.`,
    zh: `勇敢的探险家，弗尔绍维采的圣瓦茨拉夫教堂是布拉格最具建筑魄力的神圣建筑之一——由约瑟夫·戈恰尔设计的1930年功能主义杰作，彻底抛弃了传统教堂建筑的每一个惯例，用现代工业的视觉语言建造了一座上帝之屋。其塔楼是一根简洁的混凝土柱；其中殿是一个具有干净几何线条和克制装饰的现代主义大厅。戈恰尔是捷克圆拱立体主义的创始人之一，也是捷克建筑先锋的领军人物，这座教堂代表了他最激进的宣言：神圣空间与现代形式并不冲突。解锁献祭意义中的彩蛋：圣瓦茨拉夫——波西米亚的守护圣人，935年被其兄弟波列斯拉夫一世杀害——是捷克历史上政治色彩最浓厚的圣人。他的形象被每一个捷克政治运动所借用，从中世纪民族主义到共产主义宣传，再到天鹅绒革命。1930年，在第一捷克斯洛伐克共和国鼎盛时期，将教堂献给他是对捷克民族认同的明确宣示。建筑是现代的。论点有千年之久。`,
  },

  "karlov-church": {
    en: `Brave explorer, the Church of the Assumption of the Virgin Mary and St. Charles the Great — known simply as Karlov — stands in Nové Město as one of the most geometrically radical sacred buildings in Gothic Europe. Charles IV, who founded it in 1350 on the anniversary of his coronation as Holy Roman Emperor, modelled its eight-sided nave on the octagonal Palatine Chapel at Aachen built by Charlemagne — a deliberate echo of the emperor Charles IV admired most. When the vault over the vast undivided octagonal space was completed without intermediate pillars, contemporary witnesses reported that the craftsmen were rumoured to have made a pact with the devil, so impossible did the engineering seem. Unlock the Easter egg: the church's crypt was converted in the 18th century into a replica of the Bethlehem Grotto, complete with wax figures of the Nativity scene. For two centuries, Praguers who could not make the pilgrimage to the Holy Land came here instead. The crypt remains; the wax figures were destroyed in 1784 by order of Emperor Joseph II during his programme of dissolving monasteries. The building survived the reformers. The figures did not.`,
    cz: `Odvážný průzkumníku, Kostel Nanebevzetí Panny Marie a sv. Karla Velikého — známý jednoduše jako Karlov — stojí v Novém Městě jako jedna z geometricky nejradikálnějších sakrálních staveb v gotické Evropě. Karel IV., který jej v roce 1350 na výročí svého korunování za římskoněmeckého císaře založil, modeloval jeho osmibokou loď po vzoru oktagonální Palatinské kaple v Cáchách postavené Karlem Velikým — záměrná ozvěna císaře, kterého Karel IV. nejvíce obdivoval. Když byla klenba nad obrovským nerozdělitelným oktagonálním prostorem dokončena bez středních sloupů, současní svědci hlásili, že o řemeslnících se šeptalo, že uzavřeli pakt s ďáblem — tak nemožným se zdál tento inženýrský výkon. Odemkni easter egg: krypta kostela byla v 18. století přeměněna na repliku Betlémské jeskyně, kompletní s voskovými figurami vánoční scény. Po dvě staletí sem přicházeli Pražané, kteří nemohli vykonat pouť do Svaté země. Krypta zůstala; voskové figury byly v roce 1784 zničeny rozkazem císaře Josefa II. v rámci jeho programu rušení klášterů. Budova přežila reformátory. Figury ne.`,
    zh: `勇敢的探险家，圣母升天与圣卡罗鲁斯大帝教堂——简称卡洛夫——矗立于新城区，是哥特式欧洲几何上最激进的神圣建筑之一。查理四世于1350年他被加冕为神圣罗马皇帝的周年纪念日创立了它，将其八边形中殿仿照查理曼大帝在亚琛建造的帕拉提纳礼拜堂设计——这是对查理四世最仰慕的那位皇帝的刻意致敬。当巨大的未分割八角形空间上方的穹顶在没有中间支柱的情况下建成时，当代目击者报告称，工匠们被传言与魔鬼做了交易——如此不可能的工程壮举。解锁彩蛋：教堂的地窖在18世纪被改造为伯利恒石窟的复制品，完整地包含了耶稣诞生场景的蜡像。两个世纪以来，无法前往圣地朝圣的布拉格人来到这里代替。地窖保留下来了；蜡像则于1784年被约瑟夫二世皇帝下令在其解散修道院的计划中销毁。建筑熬过了改革者。蜡像没有。`,
  },

  "justicni-palac-smichov": {
    en: `Brave explorer, the Justice Palace on Kinský Square in Smíchov is Prague's grandest Neoclassical courthouse — a massive sandstone building completed in 1908 that served as the administrative and judicial centre of Habsburg authority on the left bank of the Vltava. Its symmetrical façade, monumental staircase, and four-storey atrium were designed to project the authority of imperial law to every citizen who entered. Today it still functions as the Prague 5 District Court, making it one of the few major Habsburg civic buildings still performing its original function anywhere in the city. Unlock the Easter egg in its address: Kinský Square is named for the noble Kinský family, one of the most powerful Bohemian aristocratic houses, whose members included opponents of the Habsburg regime and, later, one of the most enthusiastic collaborators with the Communist state. The square carries the name of contradictions; the courthouse on it was built to resolve them. It never quite managed.`,
    cz: `Odvážný průzkumníku, Justiční palác na náměstí Kinských na Smíchově je největší neoklasicistní soudní budovou Prahy — masivní pískovcová stavba dokončená v roce 1908, která sloužila jako administrativní a soudní centrum habsburské moci na levém břehu Vltavy. Symetrická fasáda, monumentální schodiště a čtyřpatrové atrium byly navrženy tak, aby každému vstupujícímu občanovi představovaly autoritu imperiálního práva. Dnes stále funguje jako Obvodní soud Praha 5, čímž je jednou z mála větších habsburských občanských budov, která kdekoli ve městě stále plní svou původní funkci. Odemkni easter egg v její adrese: náměstí Kinských je pojmenováno po šlechtické rodině Kinských, jednom z nejmocnějších českých aristokratických rodů, jejichž členové zahrnovali jak odpůrce habsburského režimu, tak, později, jednoho z nejnadšenějších spolupracovníků s komunistickým státem. Náměstí nese jméno rozporů; soudní budova na něm stojí byla postavena, aby je řešila. Nikdy se jí to zcela nepodařilo.`,
    zh: `勇敢的探险家，斯米霍夫金斯基广场上的司法宫是布拉格最宏伟的新古典主义法院大楼——一座于1908年竣工的巨大砂岩建筑，曾作为哈布斯堡在伏尔塔瓦河左岸的行政和司法权力中心。其对称的立面、宏伟的楼梯和四层中庭的设计旨在向每一位进入的公民展示帝国法律的权威。如今它仍作为布拉格5区地区法院运转，使其成为城市中为数不多的仍在履行原始功能的主要哈布斯堡公民建筑之一。解锁其地址中的彩蛋：金斯基广场以贵族金斯基家族命名，这是波西米亚最强大的贵族世家之一，其成员既包括哈布斯堡政权的反对者，也包括后来对共产主义国家最热情的合作者之一。这个广场承载着矛盾的名字；建在它上面的法院正是为了解决这些矛盾而建造的。它始终未能完全做到。`,
  },

  "nemocnice-krc": {
    en: `Brave explorer, Krč Hospital — officially Thomayer University Hospital — began its existence in 1928 as Prague's first purpose-built tuberculosis sanatorium, constructed deliberately in the pine forests of the Krč district south of the city, where the air was considered clean enough to support patient recovery. Its founders placed it here following the sanatorium movement's core principle: that architecture and landscape were themselves medical instruments, and that sunlight, forest air, and spacious pavilion wards could heal what drugs could not yet cure. Unlock the Easter egg in its design: the original campus was conceived as a series of separate pavilions dispersed among the trees rather than a single consolidated hospital block — a layout intended to reduce cross-infection and maximise every patient's exposure to fresh air. That pavilion structure survives in the modern campus, which now contains buildings from every decade of the 20th century, creating an unintentional open-air museum of Czech hospital architecture from the interwar Republic through the Communist era to the present. The cure changed; the trees remained.`,
    cz: `Odvážný průzkumníku, Nemocnice Krč — oficiálně Thomayerova fakultní nemocnice — zahájila existenci v roce 1928 jako první pražský specializovaný tuberkulózní sanatorium, záměrně postavený v borových lesích krčské čtvrti jižně od města, kde byl vzduch považován za dostatečně čistý pro zotavení pacientů. Její zakladatelé ji umístili sem v souladu se základním principem sanatorního hnutí: že architektura a krajina jsou samy o sobě léčebnými nástroji a že sluneční světlo, lesní vzduch a prostorné pavilonové sály mohou vyléčit to, co léky ještě nedokázaly. Odemkni easter egg v jejím designu: původní areál byl koncipován jako série oddělených pavilonů rozptýlených mezi stromy spíše než jako jediná konsolidovaná nemocniční budova — rozložení zamýšlené ke snížení křížové infekce a maximalizaci vystavení každého pacienta čerstvému vzduchu. Ta pavilonová struktura přežívá v moderním areálu, který nyní obsahuje budovy z každého desetiletí 20. století, vytvářejíc nezáměrné muzeum pod otevřeným nebem české nemocniční architektury od meziválečné republiky přes komunistickou éru až po současnost. Léčba se změnila; stromy zůstaly.`,
    zh: `勇敢的探险家，克尔奇医院——正式名称为托马耶尔大学医院——1928年作为布拉格首个专用结核病疗养院开始运营，刻意建于城市南部克尔奇区的松林中，那里的空气被认为足够清洁，有助于患者康复。其创始人将它建在这里，遵循了疗养院运动的核心原则：建筑与景观本身就是医疗工具，阳光、森林空气和宽敞的分馆式病房能够治愈药物尚无法治愈的疾病。解锁其设计中的彩蛋：原始园区被设想为分散在树丛中的一系列独立展馆，而非单一的集中式医院大楼——这种布局旨在减少交叉感染，最大限度地让每位患者接触新鲜空气。那种分馆式结构在现代园区中得以保留，园区内现在包含了20世纪每个十年的建筑，无意间创造了一座捷克医院建筑的露天博物馆，从两次大战之间的共和国时代，经历共产主义时代，直至今日。治疗方式改变了；树木依然矗立。`,
  },

  "kristof-kintera-rozhodnuti": {
    en: `Brave explorer, "Of One's Own Accord" (Z vlastního rozhodnutí) is a public artwork by Krištof Kintera (born 1973), one of the most prominent Czech artists of his generation, known internationally for kinetic sculptures, neon text works, and found-object installations that stage quiet confrontations between the everyday and the absurd. Kintera's practice consistently asks a single question in a dozen different forms: who decides, and by what authority, that something is finished, broken, meaningful, or complete? This work continues that inquiry through the materials of the ordinary, transformed into a statement about autonomy and the small freedoms — and refusals — that define a life. Unlock the Easter egg: Kintera represented the Czech Republic at the 2019 Venice Biennale and has created major public commissions across Europe. His work exists in a tradition of Czech conceptual art shaped by artists who had to operate under Communist surveillance, finding ways to smuggle ideas inside objects that appeared to be saying nothing. "Of One's Own Accord" carries that tradition into the present: its title is an assertion that something — anything — was chosen, deliberately, by no one else. In a city whose 20th century was largely decided by others, that is not a small claim.`,
    cz: `Odvážný průzkumníku, "Z vlastního rozhodnutí" je veřejné umělecké dílo od Krištofa Kintery (narozen 1973), jednoho z nejvýznamnějších českých umělců své generace, mezinárodně proslulého kinetickými sochami, neónovými textovými pracemi a instalacemi z nalezených předmětů, které inscenují tiché konfrontace mezi každodenností a absurdnem. Kinterova praxe neustále klade jednu otázku ve dvanácti různých podobách: kdo rozhoduje, a jakým právem, že něco je hotovo, rozbito, smysluplné nebo úplné? Toto dílo pokračuje v tomto zkoumání prostřednictvím materiálů obyčejnosti, přeměněné v prohlášení o autonomii a malých svobodách — a odmítnutích — které definují život. Odemkni easter egg: Kintera zastupoval Českou republiku na Benátském Bienále v roce 2019 a vytvořil velké veřejné zakázky po celé Evropě. Jeho dílo existuje v tradici českého konceptuálního umění formovaného umělci, kteří museli pracovat pod komunistickým dohledem, hledajíc způsoby, jak propašovat myšlenky uvnitř předmětů, které se zdály říkat nic. "Z vlastního rozhodnutí" přináší tuto tradici do přítomnosti: jeho název je ujistěním, že něco — cokoli — bylo zvoleno, záměrně, nikým jiným. V městě, jehož 20. století bylo z velké části rozhodováno ostatními, to není malé tvrzení.`,
    zh: `勇敢的探险家，《由自己决定》（Z vlastního rozhodnutí）是克里什托夫·金特拉（1973年生）的一件公共艺术作品，他是其一代最杰出的捷克艺术家之一，因动力雕塑、霓虹文字作品和实物装置而享誉国际，这些作品在日常与荒诞之间上演着静默的对抗。金特拉的创作始终以十二种不同形式提问一个问题：谁来决定，以何种权威来决定，某件事物是完成的、破损的、有意义的还是完整的？这件作品通过普通物品的材料继续这一探询，将其转化为关于自主性以及定义一种生命的小自由与小拒绝的宣言。解锁彩蛋：金特拉代表捷克共和国参加了2019年威尼斯双年展，并在全欧洲完成了多项重要公共委托创作。他的作品存在于一个由必须在共产主义监视下工作的艺术家所塑造的捷克概念艺术传统中，这些艺术家寻找将思想藏入那些看似什么都没说的物体中的方式。《由自己决定》将这一传统带入当下：其标题是一种断言，表明某件事——任何事——是被刻意选择的，没有任何他人的介入。在一座20世纪的命运大多由他人决定的城市里，这不是一个小小的宣言。`,
  },

  "vyton": {
    en: `Brave explorer, Výtoň is one of the oldest surviving riverside structures in Prague — a late Gothic customs house built around 1501 at the point where the Botič stream once emptied into the Vltava, a location that made it the natural collection point for the river tolls and taxes that funded the medieval city. Every log raft, grain barge, and salt shipment that came down the Vltava passed this point; the officials stationed here recorded, weighed, and levied. The building's name derives from the Czech word for an outflow or confluence — "výtok" — the place where one body of water pours into another. Unlock the Easter egg: the Gothic building you see today was reconstructed in the 1950s as a branch of the Prague City Museum after centuries of alternative uses including a coal store, a flood-damaged shell, and a mid-19th-century charitable soup kitchen. The adjacent stone staircase descending to the water level is one of the last surviving remnants of Prague's old riverfront infrastructure — a piece of the city's working waterfront that has almost entirely disappeared. Step down it and the Vltava is suddenly at ground level, not across a railing.`,
    cz: `Odvážný průzkumníku, Výtoň je jednou z nejstarších dochovaných říčních staveb v Praze — pozdně gotická celnice postavená kolem roku 1501 na místě, kde se kdysi Botiče vlévala do Vltavy, poloha, která z ní přirozeně učinila sběrné místo pro říční mýtné a daně financující středověké město. Každý vor, nákladní loď s obilím a zásilka soli plující po Vltavě procházela tímto místem; úředníci zde umístění zapisovali, vážili a vybírali. Název budovy pochází z českého slova pro odtok nebo soutok — "výtok" — místo, kde se jeden vodní tok vlévá do druhého. Odemkni easter egg: gotická budova, kterou vidíte dnes, byla rekonstruována v 50. letech jako pobočka Muzea hlavního města Prahy po staletích alternativního využití, včetně skladu uhlí, povodněmi poškozeného torza a polední polévkové kuchyně v polovině 19. století. Přilehlé kamenné schodiště klesající k hladině vody je jedním z posledních přeživších pozůstatků staré pražské říční infrastruktury — kus funkčního říčního nábřeží města, které téměř zcela zmizelo. Sejdi po něm dolů a Vltava je najednou na úrovni země, ne za zábradlím.`,
    zh: `勇敢的探险家，维托恩是布拉格最古老的幸存河岸建筑之一——约建于1501年的晚期哥特式海关，建在波蒂奇河曾经汇入伏尔塔瓦河的地方，这个位置使其自然而然地成为征收河运税款（为中世纪城市提供资金）的收集点。每一根木排、每一艘粮食货驳船和每一批盐的运输经过这里时，驻扎在此的官员们进行记录、称重和征税。这座建筑的名字来源于捷克语中表示出流或汇合的词——"výtok"——一个水体流入另一个水体的地方。解锁彩蛋：你今天看到的哥特式建筑在1950年代被重建为布拉格市博物馆的分馆，在此之前经历了数百年的其他用途，包括煤炭仓库、洪水损毁的空壳以及19世纪中期的慈善施粥厨房。旁边那段通往水面的石制台阶是布拉格旧河岸基础设施为数不多的幸存遗迹之一——城市昔日运作性河岸的一块碎片，已几乎完全消失。沿台阶走下，伏尔塔瓦河突然就在地面的高度，而不是隔着栏杆遥望。`,
  },

  "kongresove-centrum-praha": {
    en: `Brave explorer, the Prague Congress Centre — known until 1989 as the Palace of Culture — is the most ambitious single building project of socialist Czechoslovakia, constructed between 1975 and 1981 on the Pankrác plateau to give the Communist state a venue worthy of international prestige. Thirteen halls with a total seating capacity of 9,600, clad in Swedish red granite inside and out, connected by a network of corridors, restaurants, and terraces occupying a footprint larger than many European city blocks. Its chief architect Karel Prager understood the assignment: this was to be the building that demonstrated the Socialist state's mastery of modern architecture, technology, and cultural ambition. Unlock the Easter egg: the Palace of Culture was the site of a historic 1989 rally at which Václav Havel addressed a crowd during the Velvet Revolution, making the building simultaneously the regime's greatest architectural trophy and the stage for that regime's unravelling. After 1989 it was renamed and repurposed, but the building itself did not change — the same granite halls that hosted Communist Party congresses now host international technology conferences, the same terraces once reserved for Party officials are open to any visitor. The building outlasted its original purpose by decades, which is arguably the most Socialist thing about it.`,
    cz: `Odvážný průzkumníku, Kongresové centrum Praha — do roku 1989 známé jako Palác kultury — je nejambicióznějším jednotlivým stavebním projektem socialistického Československa, postaveným v letech 1975 až 1981 na pankrácké plošině, aby komunistický stát získal místo hodné mezinárodní prestiže. Třináct sálů s celkovou kapacitou 9 600 sedadel, obložených švédskou červenou žulou uvnitř i vně, propojených sítí chodeb, restaurací a teras, které zabírají zastavěnou plochu větší než mnohé evropské městské bloky. Jeho hlavní architekt Karel Prager pochopil zadání: toto měla být budova, která demonstruje zvládnutí moderní architektury, technologie a kulturní ambice Socialistickým státem. Odemkni easter egg: Palác kultury byl místem historického shromáždění v roce 1989, na němž Václav Havel oslovil dav během Sametové revoluce, čímž se tato budova stala zároveň největším architektonickým trofejí režimu i scénou jeho rozkladu. Po roce 1989 byla přejmenována a přeúčelována, ale budova samotná se nezměnila — stejné žulové sály, které hostily sjezdy Komunistické strany, nyní hostí mezinárodní technologické konference; terasy, které kdysi nabízely výhledy vyhrazené stranickým funkcionářům, jsou nyní otevřené každému návštěvníkovi. Budova přežila svůj původní účel o desetiletí — což je pravděpodobně to nejsocialističtější, co na ní je.`,
    zh: `勇敢的探险家，布拉格国会中心——1989年前称为文化宫——是社会主义捷克斯洛伐克最雄心勃勃的单一建筑项目，建于1975年至1981年间的潘克拉茨高原，为共产主义国家提供一个配得上国际声誉的场所。十三个大厅总座位数9600个，内外均覆以瑞典红花岗岩，由走廊、餐厅和露台网络连接，建筑占地面积超过许多欧洲城市街区。其首席建筑师卡雷尔·普拉格尔理解了任务：这将是展示社会主义国家掌握现代建筑、技术与文化雄心的建筑。解锁彩蛋：文化宫是1989年历史性集会的举办地，瓦茨拉夫·哈维尔在天鹅绒革命期间在此向人群发表讲话，使这座建筑同时成为政权最伟大的建筑战利品和那个政权瓦解的舞台。1989年后，它被更名和重新定位，但建筑本身没有改变——曾经承办共产党代表大会的同一批花岗岩大厅，如今承办国际技术会议；曾经只向党的官员开放的同一批露台，如今向任何访客开放。这座建筑在其原始用途消亡数十年后依然屹立——这大概是它最具社会主义精神之处。`,
  },

  "taborska-brana": {
    en: `Brave explorer, the Tábor Gate is the older of Vyšehrad's two surviving medieval entrance gates — a 17th-century Baroque structure built over what had been a fortified passage in the cliff walls since at least the 14th century. Its name commemorates the Hussite town of Tábor in southern Bohemia, founded by followers of Jan Hus who established a radical egalitarian commune there in 1420, from whose direction Hussite armies repeatedly attacked the Vyšehrad fortress during the wars that tore medieval Bohemia apart. The gate was rebuilt in its current Baroque form after Vyšehrad was converted into a military fortress in the late 17th century, and it still marks the original historic road leading south from Prague toward Tábor, Písek, and the Bohemian countryside beyond. Unlock the Easter egg: enter through the Tábor Gate on foot and you pass immediately into the Vyšehrad complex along a sunken lane flanked by old stone walls with the feel of a genuine medieval approach — which it is, since the topography has not meaningfully changed in six hundred years. This is the same view, the same walls, the same rising ground, the same sense of entering a place apart, that medieval travellers, Hussite soldiers, Baroque engineers, and 19th-century Romantics all experienced before you. The gate is old. The feeling it produces is older.`,
    cz: `Odvážný průzkumníku, Táborská brána je starší ze dvou dochovaných středověkých vstupních bran Vyšehradu — barokní stavba ze 17. století postavená nad tím, co bylo opevněným průchodem ve skalních stěnách přinejmenším od 14. století. Její název připomíná husitské město Tábor v jižních Čechách, jehož přívrženci Jana Husa tam v roce 1420 zřídili radikální egalitářskou komunitu, z jejíhož směru husitské armády opakovaně útočily na vyšehradskou pevnost během válek, které roztrhly středověké Čechy. Brána byla přestavěna do dnešní barokní podoby po přeměně Vyšehradu ve vojenskou pevnost v pozdním 17. století a stále označuje původní historickou cestu vedoucí z Prahy na jih směrem k Táboru, Písku a za ně do české krajiny. Odemkni easter egg: projdi pěšky Táborskou branou a okamžitě vstoupíš do vyšehradského komplexu zahloubenou uličkou lemovanou starými kamennými zdmi, s charakterem autentického středověkého přístupu — a skutečně jím je, protože topografie se za šest set let smysluplně nezměnila. Toto je stejný pohled, stejné zdi, stejná stoupající půda, stejný pocit vstupu na místo stranou, který před tebou prožili středověcí cestovatelé, husitští vojáci, barokní inženýři i romantici 19. století. Brána je stará. Pocit, který vyvolává, je ještě starší.`,
    zh: `勇敢的探险家，塔博尔门是维谢赫拉德两座幸存中世纪入口城门中历史较久的一座——一座17世纪巴洛克建筑，建于至少从14世纪起就是峭壁上要塞通道的位置之上。其名字纪念波西米亚南部的胡斯派城市塔博尔，扬·胡斯的追随者于1420年在那里建立了激进的平等主义公社，胡斯派军队在撕裂中世纪波西米亚的战争中，多次从那个方向攻打维谢赫拉德要塞。这座城门在17世纪晚期维谢赫拉德被改建为军事要塞后以现有的巴洛克形式重建，它至今仍标志着从布拉格向南通往塔博尔、皮塞克及波西米亚腹地的原始历史道路。解锁彩蛋：徒步穿过塔博尔门，你立即沿着一条两侧夹着旧石墙的下沉小巷进入维谢赫拉德建筑群，那种感觉如同真实的中世纪入口——实际上正是如此，因为地形在六百年间并未发生有意义的改变。这是相同的景象，相同的墙壁，相同的上升地面，相同的进入一处遗世独立之地的感觉——在你之前的中世纪旅行者、胡斯派士兵、巴洛克工程师和19世纪浪漫主义者都曾经历过的。城门古老。它所唤起的感受更为古老。`,
  },

  "lhotka": {
    en: `Brave explorer, Lhotka is one of the quietest and most geographically dramatic neighbourhoods in Prague — a residential district in Prague 12 perched on the edge of the Vltava valley escarpment, where the city's southern plateau drops sharply toward the river below. The name "Lhotka" is one of the most common village names in Bohemia, derived from the medieval Czech word for a settlement granted a temporary tax exemption — a "lhůta," or grace period — as an incentive for settlers to clear and cultivate new land. Dozens of villages across the Czech Republic share this name, each the descendant of a medieval land-grant. Unlock the Easter egg: on Lhotka's southern edge the plateau breaks into a series of ravines and woodland slopes connecting to the Vltava riverbank below — a wild green corridor that most Praguers have never walked, accessible from what appears to be an ordinary housing district. The edge of the city, in this direction, is also the edge of the wild.`,
    cz: `Odvážný průzkumníku, Lhotka je jednou z nejklidnějších a geograficky nejdramatičtějších čtvrtí Prahy — obytná čtvrť v Praze 12 položená na okraji svahu vltavského údolí, kde jižní plošina města prudce klesá směrem k řece níže. Název "Lhotka" je jedním z nejčastějších názvů vesnic v Čechách, odvozený ze středověkého českého slova pro osadu obdařenou dočasným daňovým osvobozením — "lhůtou" — jako pobídka pro osadníky k vyčistění a kultivaci nové půdy. Desítky vesnic po celé České republice sdílí tento název, každá potomkem středověkého pozemkového grantu. Odemkni easter egg: na jižním okraji Lhotky se plošina láme do řady strží a lesních svahů, které se připojují k břehu Vltavy níže — divoký zelený koridor, který většina Pražanů nikdy neprocházela, přístupný z toho, co se zdá být obyčejnou obytnou čtvrtí. Okraj města se v tomto směru kryje s okrajem divočiny.`,
    zh: `勇敢的探险家，利霍特卡是布拉格最宁静、地理上最戏剧性的街区之一——布拉格12区的一个住宅区，坐落在伏尔塔瓦河谷陡坡的边缘，城市南部高原在此急剧跌落至下方的河流。"利霍特卡"这个名字是波西米亚最常见的村庄名之一，源自中世纪捷克语中的一个词，意为被给予临时税务豁免的定居点——"lhůta"，即宽限期——作为激励定居者开垦和耕种新土地的奖励。捷克共和国各地有数十个村庄共享这个名字，每一个都是中世纪土地授权的后裔。解锁彩蛋：在利霍特卡南部边缘，高原断裂成一系列连接至下方伏尔塔瓦河岸的沟壑和林坡——一条野生绿色廊道，大多数布拉格人从未行走过，从看似普通的住宅区即可进入。城市的边缘，在这个方向上，也是荒野的边缘。`,
  },

  "repy": {
    en: `Brave explorer, Řepy is one of Prague's great unsung frontier districts — a western suburb whose identity is split between two worlds that never quite merged. The eastern half was developed in the 1970s and 80s as one of the city's largest panel housing estates, accommodating tens of thousands of residents in the standardised concrete towers that defined Communist-era urban expansion. The western half, however, retains fragments of the original village of Řepy that existed here for centuries before the bulldozers arrived: a Baroque church, old farmstead plots, and street names that remember what once stood there. Unlock the Easter egg: Řepy was technically an independent municipality until 1968, when it was absorbed into Greater Prague — meaning that for most of its history, this "Prague district" was simply a Bohemian village that happened to end up inside city limits. Walk to the old village core and you will find yourself in a country churchyard that is, improbably, a metro ride from Wenceslas Square.`,
    cz: `Odvážný průzkumníku, Řepy jsou jednou z největších nepochválených příhraničních čtvrtí Prahy — západní předměstí, jehož identita je rozdělena mezi dva světy, které se nikdy zcela nespojily. Východní polovina byla rozvinuta v 70. a 80. letech jako jedno z největších pražských panelových sídlišť, ubytovávající desítky tisíc obyvatel ve standardizovaných betonových věžích, které definovaly komunistické urbanistické rozšíření. Západní polovina si však zachovává fragmenty původní vesnice Řepy, která zde existovala staletí před příchodem buldozerů: barokní kostel, staré selské pozemky a názvy ulic, které pamatují, co zde kdysi stálo. Odemkni easter egg: Řepy byly technicky samostatnou obcí až do roku 1968, kdy byly začleněny do Velkého Prahy — což znamená, že po většinu své historie byla tato "pražská čtvrť" prostě českou vesnicí, která se náhodou ocitla uvnitř hranic města. Projdi se ke starému vesničkému jádru a ocitneš se na venkovském hřbitově, který je improbabilně vzdálen jednou jízdou metrem od Václavského náměstí.`,
    zh: `勇敢的探险家，热皮是布拉格最被忽视的边疆区之一——一个西部郊区，其身份被分裂在两个从未完全融合的世界之间。东半部在70年代和80年代被开发为城市最大的预制板住宅区之一，将数万居民安置在定义了共产主义时代城市扩张的标准化混凝土塔楼中。然而西半部保留着热皮原始村庄的碎片——在推土机到来之前，这里存在了数百年：一座巴洛克教堂、老农庄地块，以及还记得这里曾经矗立着什么的街道名称。解锁彩蛋：热皮在技术上是一个独立的市镇，直到1968年才被并入大布拉格——这意味着在其历史的大部分时间里，这个"布拉格区"只是一个碰巧在城市范围内的波西米亚村庄。走到老村庄核心，你会发现自己置身于一个乡村教堂院落，而令人难以置信的是，它距离瓦茨拉夫广场只需一程地铁。`,
  },

  "v-tower": {
    en: `Brave explorer, V Tower is one of the most quietly striking additions to Prague's modern skyline — a sleek glass residential skyscraper rising above the Pankrác plateau, part of the cluster of towers that have transformed this elevated district into Prague's answer to a business and luxury residential quarter. Unlike the older Communist-era administrative towers that once defined Pankrác, V Tower is a product of the post-2000 building boom that followed Czech accession to the EU, representing a new kind of verticality in a city that has historically resisted tall buildings near its historic core. Unlock the Easter egg in its location: Pankrác sits on a natural plateau approximately 60 metres above the Vltava valley, and V Tower's upper floors have unobstructed sightlines across the entire Prague basin — on a clear day you can identify the hills of Bohemia on the horizon, 30 kilometres distant. The view from the top is a reminder that Prague is not flat; it is a city built inside a bowl, and V Tower stands on the rim.`,
    cz: `Odvážný průzkumníku, V Tower je jedním z nejtišeji působivých přírůstků do moderní panoramy Prahy — elegantní skleněný rezidenční mrakodrap tyčící se nad pankráckou plošinou, součást skupiny věží, které proměnily tuto vyvýšenou čtvrť na pražský ekvivalent obchodní a luxusní rezidenční čtvrti. Na rozdíl od starších komunistických administrativních věží, které kdysi definovaly Pankrác, je V Tower produktem stavebního boomu po roce 2000, který následoval po vstupu Česka do EU, představující nový druh vertikality ve městě, které historicky odolávalo vysokým budovám v blízkosti svého historického jádra. Odemkni easter egg v jeho poloze: Pankrác leží na přirozené plošině přibližně 60 metrů nad vltavským údolím, a horní patra V Toweru mají nerušený výhled přes celou pražskou kotlinu — za jasného dne lze na obzoru identifikovat kopce Čech, vzdálené 30 kilometrů. Pohled z vrcholu připomíná, že Praha není plochá; je to město postavené uvnitř misky a V Tower stojí na jejím okraji.`,
    zh: `勇敢的探险家，V塔是布拉格现代天际线中最低调却最引人注目的新增建筑之一——一座矗立于潘克拉茨高原之上的流线型玻璃住宅摩天大楼，是将这个高地区域转变为布拉格商业与豪华住宅区的塔楼群的一部分。与曾经定义潘克拉茨的旧共产主义时代行政塔楼不同，V塔是2000年后捷克加入欧盟后建设热潮的产物，代表着这座历史上一直抵制在历史核心区附近建造高楼的城市中一种新型的垂直性。解锁其位置中的彩蛋：潘克拉茨坐落在一个高于伏尔塔瓦河谷约60米的天然高原上，V塔的上层楼层可以无遮挡地俯瞰整个布拉格盆地——在晴朗的天气里，你可以在地平线上辨认出30公里之外的波西米亚山丘。从顶部望去，令人想起布拉格并不平坦；它是一座建在碗状地形中的城市，而V塔就矗立在碗沿上。`,
  },

  "palackeho-most": {
    zh: `勇敢的探险家，帕拉茨基大桥是布拉格最雄心勃勃的新哥特式跨河工程之一，建于1876至1878年，横跨伏尔塔瓦河，连接新城区与斯米霍夫——或者更准确地说，连接了一侧衣着体面、想去对岸喝廉价啤酒的布拉格人，与另一侧刚刚喝完啤酒、准备回家的布拉格人。大桥以弗兰季谢克·帕拉茨基命名，他是被称为"捷克民族之父"的历史学家与政治家，而与这座桥完全没有任何直接关联，只是他恰好在大桥开工前两年去世，赶上了命名的好时机。桥墩两端装饰着捷克神话人物雕塑，桥面是行人、有轨电车与汽车共享的繁忙通道。解锁彩蛋：站在大桥中央望向上游，你可以在同一个视野里同时看到查理大桥（中世纪）、伊拉塞克大桥（现代）以及更远处的数座桥影——布拉格整个桥梁历史犹如一条时间轴铺展在眼前。布拉格共有十八座桥，而这座是其中在照片里最容易被误认为查理大桥的一座。`,
    en: `Brave explorer, Palacký Bridge is one of Prague's most ambitious Neo-Gothic river crossings, built between 1876 and 1878 to span the Vltava and connect the New Town with Smíchov — or more precisely, to connect people on one side who were respectably dressed and wanted cheaper beer across the river, with people on the other side who had finished their beer and wanted to go home. The bridge is named after František Palacký, the historian and politician known as the "Father of the Czech Nation," who had absolutely no direct connection to this bridge beyond the convenient timing of dying two years before construction began. The bridge ends are decorated with sculptural figures from Czech mythology, and the deck serves as a busy shared corridor for pedestrians, trams, and cars. Unlock the Easter egg: standing at the midpoint and looking upstream, you can see Charles Bridge (medieval), Jiráskův most (modern), and several more bridges fading into the distance — Prague's entire bridging history laid out as a timeline in one glance. Prague has eighteen bridges; this is the one most often mistaken for Charles Bridge in photographs.`,
    cz: `Odvážný průzkumníku, Palackého most je jedním z nejambicióznějších novogotických říčních přechodů Prahy, postavený v letech 1876 až 1878, aby překlenul Vltavu a spojil Nové Město se Smíchovem — nebo přesněji, aby spojil lidi na jedné straně, kteří byli slušně oblečeni a chtěli levnější pivo na druhé straně, s lidmi na druhé straně, kteří dopili pivo a chtěli domů. Most je pojmenován po Františku Palackém, historiku a politikovi zvaném "otec českého národa," který s tímto mostem neměl žádnou přímou spojitost, kromě toho, že pohodlně zemřel dva roky před zahájením stavby. Konce mostu jsou zdobeny sochami postav z české mytologie a vozovka slouží jako rušný sdílený koridor pro chodce, tramvaje a auta. Odemkni easter egg: stojíš-li uprostřed a díváš se po proudu, uvidíš Karlův most (středověký), Jiráskův most (moderní) a několik dalších mostů mizejících v dálce — celá pražská historia mostů rozložená jako časová osa v jediném pohledu. Praha má osmnáct mostů; tento je ten, který je na fotografiích nejčastěji zaměňován s Karlovým mostem.`,
  },

  "palackeho-namesti": {
    zh: `勇敢的探险家，帕拉茨基广场是新城区一处精心构筑的城市空间，广场核心矗立着弗兰季谢克·帕拉茨基纪念碑——这是布拉格最壮观、也最容易让人看得一头雾水的雕塑群之一。纪念碑由雕塑家斯坦尼斯拉夫·苏哈尔达设计，1912年揭幕，呈现帕拉茨基本人被大量象征性人物簇拥的场景：捷克神话中的各路角色、民族复兴运动的精神象征，以及若干姿态各异的寓言裸像，其确切含义在每本艺术史教材里都有不同解读。帕拉茨基（1798—1876）是19世纪最重要的捷克历史学家与政治家，他的多卷本《波西米亚史》实际上为捷克人作为历史民族的自我叙事奠定了基础——在那个时代，告诉一个民族"你们有历史，你们有价值"，是相当激进的政治行为。解锁彩蛋：这座纪念碑在1918年捷克斯洛伐克独立时已经矗立了整整六年，意味着帕拉茨基得以用雕像的形式，亲眼见证了他毕生所追求的事情在某种程度上变为现实。他本人于1876年去世，比独立早了整整四十二年，但雕像版的他等到了那一天。`,
    en: `Brave explorer, Palacký Square is a carefully composed urban space in the New Town, centred on the monument to František Palacký — one of the most spectacular and most interpretively confusing sculptural ensembles in Prague. The monument was designed by sculptor Stanislav Sucharda and unveiled in 1912, depicting Palacký himself surrounded by a considerable crowd of allegorical figures: characters from Czech mythology, spiritual symbols of the National Revival movement, and several naked allegorical figures whose precise meanings are interpreted differently by every art history textbook that covers them. Palacký (1798–1876) was the most important Czech historian and politician of the nineteenth century; his multi-volume History of Bohemia essentially constructed the Czech people's self-narrative as a historical nation — in an era when telling a people "you have history, you have worth" was a genuinely radical political act. Unlock the Easter egg: this monument had already stood for six years by the time Czechoslovakia declared independence in 1918, meaning Palacký got to witness — in sculptural form — the thing he spent his life working toward actually happen. He himself died in 1876, forty-two years before independence, but the statue version of him waited long enough to see it.`,
    cz: `Odvážný průzkumníku, Palackého náměstí je pečlivě komponovaný městský prostor v Novém Městě, jehož středem je pomník Františka Palackého — jeden z nejvelkolepějších a interpretačně nejmatoucích sochařských souborů Prahy. Pomník navrhl sochař Stanislav Sucharda a byl odhalen v roce 1912, zobrazující samotného Palackého obklopeného značným davem alegorických postav: postavami z české mytologie, duchovními symboly národního obrození a několika nahými alegorickými figurami, jejichž přesný význam je v každé učebnici dějin umění interpretován jinak. Palacký (1798–1876) byl nejvýznamnějším českým historikem a politikem devatenáctého století; jeho vícedílné Dějiny národu českého v podstatě vybudovaly sebenarrativum Čechů jako historického národa — v době, kdy říci národu "máte historii, máte hodnotu" byl skutečně radikální politický čin. Odemkni easter egg: tento pomník existoval již šest let, než Československo v roce 1918 vyhlásilo nezávislost, což znamená, že Palacký se mohl — v sochařské podobě — dožít toho, jak se věc, pro kterou celý život pracoval, alespoň v nějaké míře uskutečnila. On sám zemřel v roce 1876, dvaačtyřicet let před nezávislostí, ale jeho socha se dočkala.`,
  },

  "faustuv-dum": {
    zh: `勇敢的探险家，卡洛夫广场旁这栋气宇轩昂的巴洛克宫殿被称为"浮士德之屋"，这个名字是布拉格人民集体赠予历史上若干位古怪房客的绰号，而非声称歌德的浮士德真的在此居住过——尽管你若愿意如此相信，也没有人会阻止你。建筑的黑暗传说始于16世纪：炼金术士爱德华·凯利（约翰·迪伊的合伙人）据传在此研究点金石；此后历任主人中不乏据说与魔鬼签有契约的神秘学家。屋内至今保存着一处天花板破洞，传说是魔鬼带走灵魂时留下的。建筑的正式名称是"姆拉多托夫斯基宫"，由姆拉多塔家族建造，后来改作医院附属楼，如今仍属查理大学医学院产业。解锁彩蛋：布拉格有一张非正式的"炼金术士地图"——浮士德之屋、黄金巷、布拉格城堡内鲁道夫二世的炼金术实验室——共同构成16世纪伪科学在这座城市的空间坐标。当时的布拉格确实是全欧洲炼金术活动最集中的地方之一。真正令人惊讶的是：其中某些人在这个过程中实际发展出了有用的化学知识，只是他们不这样称呼它罢了。`,
    en: `Brave explorer, this imposing Baroque palace on Charles Square is known as Faust House — a nickname collectively bestowed by Prague's population on a series of eccentric historical occupants, rather than a claim that Goethe's Faust literally lived here (though you are welcome to believe that if you prefer). The building's dark reputation began in the sixteenth century: alchemist Edward Kelley, John Dee's associate, reportedly conducted his research on the philosopher's stone here; subsequent owners included various mystics rumoured to have signed agreements with the devil. There is a hole in the building's ceiling, allegedly torn open by the devil while collecting a soul. The building's formal name is Mladota Palace, built by the Mladota family, later converted into a hospital annex and still owned by Charles University's medical faculty today. Unlock the Easter egg: Prague has an informal "alchemist map" — Faust House, Golden Lane, and Emperor Rudolf II's alchemical laboratory inside Prague Castle — forming the spatial coordinates of sixteenth-century pseudoscience across the city. Prague was genuinely one of Europe's largest concentrations of alchemical activity at the time. The real surprise: some of those practitioners actually developed useful chemical knowledge along the way; they just didn't call it that.`,
    cz: `Odvážný průzkumníku, tento impozantní barokní palác u Karlova náměstí je znám jako Faustův dům — přezdívka kolektivně udělená pražským obyvatelstvem sérii výstředních historických nájemníků, spíše než tvrzení, že Goethův Faust zde skutečně bydlel (ačkoli tomu můžeš věřit, pokud dáváš přednost). Temná pověst budovy začala v šestnáctém století: alchymista Edward Kelley, spolupracovník Johna Dee, zde prý prováděl svůj výzkum kamene mudrců; následující majitelé zahrnovali různé mystiky, o nichž se tradovalo, že podepsali smlouvy s ďáblem. V budově je díra v stropě, údajně roztržená ďáblem při odnášení duše. Formální název budovy je Mladotovský palác, postavený rodinou Mladotů, který se později proměnil v nemocniční přístavek a dodnes je ve vlastnictví lékařské fakulty Karlovy univerzity. Odemkni easter egg: Praha má neformální "alchymistickou mapu" — Faustův dům, Zlatá ulička a alchymistická laboratoř císaře Rudolfa II. uvnitř Pražského hradu — tvořící prostorové souřadnice pseudovědy šestnáctého století ve městě. Praha byla tehdy skutečně jednou z největších koncentrací alchymistické činnosti v Evropě. Skutečné překvapení: někteří z těchto praktiků přitom skutečně rozvinuli užitečné chemické znalosti — jen je tak nenazývali.`,
  },

  "stvanice-ostrov": {
    zh: `勇敢的探险家，斯特万尼采岛是伏尔塔瓦河中的一片小洲，名字来自捷克语"追猎"（štvanice），因为这里曾是布拉格贵族举行鹿猎与熊斗的场地——中欧中世纪娱乐活动的完整套餐。此后这里发生了转变：捷克冰球在此诞生。布拉格第一座室内冰场于1931年在岛上建成，捷克斯洛伐克冰球的黄金时代由此开启，捷克斯洛伐克也在随后数十年间跻身全球最具竞争力的冰球强国之列。如今，斯特万尼采岛最为人知的是中欧历史最悠久的网球俱乐部之一（可追溯至1893年）以及夏季休闲区。一座小岛，先后承载了中世纪猎杀、20世纪冰球传奇与21世纪网球赛事——这是一个你五分钟就能横穿的地方所拥有的相当惊人的历史密度。解锁彩蛋：斯特万尼采冰球场于1933年承办了首届捷克斯洛伐克冰球锦标赛，并在20世纪中叶长期作为捷克斯洛伐克国家队的主场。该场馆于1990年代被拆除，但捷克冰球的灵魂至今仍萦绕在这片夹于两股河流之间的土地上。`,
    en: `Brave explorer, Štvanice Island is a small island in the Vltava whose name comes from the Czech word for "the hunt" (štvanice), because it was once the site of Prague's noble deer hunts and bear-baiting arenas — the full programme of medieval Central European entertainment. It later became something else entirely: the birthplace of Czech ice hockey. Prague's first indoor ice rink was built on this island in 1931, and Czechoslovak hockey's golden era began here, with Czechoslovakia going on to become one of the world's most competitive ice hockey nations over the following decades. Today Štvanice is best known for one of Central Europe's oldest tennis clubs, dating to 1893, and a popular summer leisure area. One island has successively hosted medieval hunts, twentieth-century hockey legend, and twenty-first-century tennis — a remarkable density of history for a piece of land you can walk across in five minutes. Unlock the Easter egg: the Štvanice ice stadium hosted the first Czechoslovak ice hockey championship in 1933 and served as the main home rink for Czechoslovak national team matches through the mid-twentieth century. The venue was demolished in the 1990s, but Czech hockey's soul still lingers on this patch of ground between two currents of the Vltava.`,
    cz: `Odvážný průzkumníku, Štvanice je malý ostrov ve Vltavě, jehož jméno pochází z českého slova pro "hon" (štvanice), protože zde kdysi bývaly pražské šlechtické hony a medvědí zápasy — plný program středoevropské středověké zábavy. Později se zde odehrávalo něco zcela jiného: zrodil se zde český hokej. První krytý ledový stadion v Praze byl postaven na tomto ostrově v roce 1931 a zlatá éra československého hokeje začala zde, přičemž Československo se v následujících desetiletích stalo jednou z nejkonkurenceschopnějších hokejových zemí světa. Dnes je Štvanice nejznámější jako jeden z nejstarších tenisových klubů ve střední Evropě, datující se k roku 1893, a jako oblíbená letní rekreační oblast. Jeden ostrov postupně hostil středověké hony, hokejové legendy dvacátého století a tenisová utkání dvacátého prvního — působivá hustota dějin pro kus země, přes který se přejde za pět minut. Odemkni easter egg: ledový stadion Štvanice hostil první Mistrovství Československa v ledním hokeji v roce 1933 a sloužil jako hlavní domácí led pro utkání československé reprezentace v polovině dvacátého století. Stadion byl zbořen v 90. letech, ale duše českého hokeje stále přebývá na tomto kousku půdy mezi dvěma proudy Vltavy.`,
  },

  "muzeum-mhd": {
    zh: `勇敢的探险家，布拉格公共交通博物馆坐落在斯特雷绍维采的一座历史性电车车库里，是布拉格最低调却最真诚可爱的博物馆之一——一个专门收藏布拉格有轨电车、无轨电车和公共汽车历史的地方，以及那些用整整一个世纪的时间负责把布拉格人从A点运到B点的各种笨重美丽机器。馆内收藏超过40辆历史车辆，从19世纪末的马拉有轨电车，到各种令人叹为观止的20世纪早期和中期电车车型，其中不少至今仍可运转。布拉格的有轨电车系统始于1875年马车牵引，1891年改为电力驱动——比大多数人所设想的要早得多。解锁彩蛋：每逢特定节假日，这座博物馆会让真正的历史电车驶上城市现役线路，供乘客购票乘坐。这意味着你有机会登上一辆1930年代的车辆，穿越布拉格市中心——这是这座城市最廉价、最有时光穿越感的旅游体验之一，而且行驶在真实的、仍在使用的电车轨道上。历史并不总是锁在展示柜里；有时候它会把你从国家大道直接送到老城广场。`,
    en: `Brave explorer, the Prague Public Transport Museum occupies a historic tram depot in Střešovice and is one of Prague's most understated and genuinely charming museums — a place dedicated to the history of Prague's trams, trolleybuses, and buses, and to the collection of heavy beautiful machines that spent a hundred years getting Praguers from point A to point B. The museum holds over 40 historical vehicles, from late-nineteenth-century horse-drawn trams to spectacular early-and-mid-twentieth-century electric tram models, many of which still run. Prague's tram network began in 1875 with horse-drawn cars and converted to electric traction in 1891 — considerably earlier than most people assume. Unlock the Easter egg: on certain public holidays, this museum puts actual historical trams back onto the city's active lines for paying passengers to ride. This means you can board a 1930s vehicle and ride it through central Prague — one of the cheapest and most genuinely time-travel-flavoured tourist experiences in the city, running on real, still-operational tram tracks. History is not always behind glass; sometimes it will take you from Národní třída directly to Old Town Square.`,
    cz: `Odvážný průzkumníku, Muzeum MHD sídlí v historické tramvajové vozovně ve Střešovicích a je jedním z nejskromnějších, ale nejupřímnějších okouzlujících muzeí Prahy — místo věnované dějinám pražských tramvají, trolejbusů a autobusů a sbírce těžkých krásných strojů, které sto let zajišťovaly přepravu Pražanů z bodu A do bodu B. Muzeum uchovává přes 40 historických vozidel, od koněspřežných tramvají z konce devatenáctého století po úchvatné modely elektrických tramvají z počátku a poloviny dvacátého století, z nichž mnohé jsou stále funkční. Pražská tramvajová síť začala v roce 1875 s koňskými vozy a přešla na elektrický pohon v roce 1891 — podstatně dříve, než většina lidí předpokládá. Odemkni easter egg: v určité svátky toto muzeum nasazuje skutečné historické tramvaje zpět na aktivní linky města pro platící cestující. To znamená, že můžeš nastoupit do vozidla z 30. let a projet se jím centrem Prahy — jeden z nejlevnějších a nejautentičtěji časoprostorově přenosných turistických zážitků ve městě, jedoucí po skutečných, stále provozních tramvajových kolejích. Dějiny nejsou vždy za sklem; někdy tě odvezou z Národní třídy přímo na Staroměstské náměstí.`,
  },

  "zahrada-na-valech": {
    zh: `勇敢的探险家，城垛花园（Zahrada Na Valech）是布拉格城堡建筑群中最华美、也最容易被游客错过的部分——一座建在城堡南坡城墙之上的阶梯式花园，从上方可以俯瞰整个布拉格市区，从下方的城市街道却完全看不见它的存在。花园历史可追溯至中世纪，18世纪初被改建为巴洛克风格，融合了几何花坛、喷泉、凉亭与观景平台，每一处均精心计算了视线与光影关系。20世纪初，建筑师约热·普勒茨尼克对其进行了大规模翻新，为花园注入了他标志性的克制现代主义元素，使巴洛克传统与现代主义之间形成了布拉格最出人意料的对话之一。解锁彩蛋：绝大多数布拉格城堡游客在院落里转了一圈便扬长而去，完全没有意识到就在城墙南侧，一片安静美丽、几乎不需要排队的花园正在等待他们，而且从这里俯瞰伏尔塔瓦河与老城的视角，是布拉格最好的全景之一，而且完全免费。这就是保持好奇心所能得到的回报。`,
    en: `Brave explorer, the Garden on the Ramparts is one of the most magnificent and most consistently overlooked parts of Prague Castle — a terraced garden built onto the castle's south-facing rampart walls, with views over the entire city of Prague, completely invisible from the streets below. The garden's origins date to the medieval period; it was redesigned in Baroque style in the early eighteenth century with geometric flowerbeds, fountains, pavilions, and viewing terraces, each carefully positioned for sightlines and light. In the early twentieth century, architect Jože Plečnik undertook a major renovation, adding his signature spare modernist elements and creating one of Prague's most unexpected dialogues between Baroque tradition and modernism. Unlock the Easter egg: the overwhelming majority of Prague Castle visitors circuit the inner courtyards and leave, entirely unaware that just south of the walls, a quiet, beautiful, nearly queue-free garden is waiting for them, with one of Prague's finest panoramas over the Vltava and the Old Town — and it is completely free. This is the reward for staying curious.`,
    cz: `Odvážný průzkumníku, Zahrada Na valech je jednou z nejvelkolepějších a nejsystematičtěji přehlížených částí Pražského hradu — terasovitá zahrada postavená na jižně orientovaných hradebních zdech hradu, s výhledem na celou Prahu, zcela neviditelná z ulic dole. Počátky zahrady sahají do středověkého období; v raném osmnáctém století byla přepracována v barokním stylu s geometrickými záhony, fontánami, pavilony a vyhlídkovými terasami, každá pečlivě rozmístěna pro výhledy a světlo. V raném dvacátém století provedl architekt Jože Plečnik rozsáhlou renovaci, přidal své typické střídmé modernistické prvky a vytvořil jeden z nejnečekanějších dialogů Prahy mezi barokní tradicí a modernismem. Odemkni easter egg: drtivá většina návštěvníků Pražského hradu obchází vnitřní nádvoří a odchází, aniž by si uvědomila, že právě jižně od hradeb je tichá, krásná, téměř bezfrontová zahrada, která na ně čeká, s jedním z nejkrásnějších panoramat Prahy nad Vltavou a Starým Městem — a je zcela zdarma. Toto je odměna za zachování zvídavosti.`,
  },

  "radio-free-europe": {
    zh: `勇敢的探险家，你站在这栋建筑面前，它曾经是冷战最响亮的大喇叭之一——自由欧洲电台的布拉格总部，一家由美国国会资助、官方身份是"非政府广播机构"、实际操作是每天用匈牙利语、罗马尼亚语、波兰语和捷克语向铁幕后面的人民大喊"嘿，你们政府在撒谎！"的电台。自由欧洲电台1995年从慕尼黑搬来布拉格，理由是"离受众更近"——这话倒是真的，因为当时大部分受众已经从压迫者的统治下解放了，可以随便听任何他们想听的广播，完全不需要这个电台再来告诉他们什么了。但电台依然继续存在，一如既往地令某些政府头疼。共产主义阵营的情报机构曾多次试图炸掉慕尼黑旧总部；布加勒斯特站曾被炸弹袭击；克格勃和斯塔西对这个电台的仇恨程度本身就是衡量其效力的最好指标。解锁彩蛋：布拉格成为媒体庇护所，部分原因是捷克共和国的新闻自由法律在欧洲首屈一指。如果你想通过广播向威权政府传递令其不舒服的真相，布拉格是一个合理的出发地——这个城市在这件事上已经有相当丰富的历史经验了。`,
    en: `Brave explorer, you stand before a building that was once one of the Cold War's loudest megaphones — the Prague headquarters of Radio Free Europe, an organisation funded by the US Congress, officially a "non-governmental broadcaster," and practically a station that spent decades shouting "hey, your government is lying to you!" at the populations behind the Iron Curtain in Hungarian, Romanian, Polish, and Czech. RFE moved from Munich to Prague in 1995 on the grounds of being "closer to its audience" — which was technically true, since by then most of that audience had already been liberated and could listen to whatever they liked without needing to be told. But the station continued anyway, and certain governments continue to find it headache-inducing. The Communist bloc's intelligence services had repeatedly tried to bomb the Munich headquarters; the Bucharest bureau was actually hit; the KGB and Stasi's intensity of hatred is itself a reliable measure of how effective the station was. Unlock the Easter egg: Prague became a media sanctuary partly because Czech press freedom laws rank among the strictest in Europe. If you want to broadcast inconvenient truths into authoritarian states, Prague is a reasonable place to start — the city has accumulated considerable historical experience in exactly this business.`,
    cz: `Odvážný průzkumníku, stojíš před budovou, která byla jedním z nejhlasitějších megafonů studené války — pražským sídlem Rádia Svobodná Evropa, organizace financované Kongresem USA, oficiálně "nevládního vysílatele" a prakticky stanice, která desítky let křičela "hej, vaše vláda vám lže!" na obyvatele za železnou oponou v maďarštině, rumunštině, polštině a češtině. RSE se přestěhovalo z Mnichova do Prahy v roce 1995 s odůvodněním, že je "blíže svému publiku" — což bylo technicky pravda, protože v té době bylo většina tohoto publika osvobozena a mohla poslouchat cokoliv, aniž by to vůbec potřebovala. Ale stanice stejně pokračovala, a jisté vlády ji stále považují za problém. Zpravodajské služby komunistického bloku se opakovaně pokoušely vyhodit mnichovské sídlo do vzduchu; bukarestská kancelář byla skutečně zasažena; intenzita nenávisti KGB a Stasi je sama o sobě spolehlivou mírou účinnosti stanice. Odemkni easter egg: Praha se stala mediálním útočištěm částečně proto, že české zákony o svobodě tisku patří k nejpřísnějším v Evropě. Pokud chcete vysílat nepohodlné pravdy do autoritářských států, Praha je rozumné místo pro začátek — toto město v této oblasti nashromáždilo značné historické zkušenosti.`,
  },

  "ruzovy-sad-petrin": {
    zh: `勇敢的探险家，欢迎来到布拉格最浪漫、最让蜜蜂感到满足的地方——佩任山玫瑰花园，一片种植着数百个玫瑰品种的华美园地，每年五六月间开花时，整座山坡的香气浓烈到据说站在查理大桥上就能闻到，不过这可能只是爱情小说写多了的人说的。这座花园建于1932年，是布拉格市赠给市民的礼物——一个让人坐在长椅上发呆、假装自己活在某部捷克浪漫电影里的完美场所。佩任山本来就已经是布拉格的后花园，有观景台、镜宫和天文台，而玫瑰园是这座山奉献给人类嗅觉的终极礼物。解锁彩蛋：这是布拉格最上镜的约会地点之一，但因为它藏在山坡上不那么显眼的位置，老城广场的游客团里大概有90%的人从未找到过它。你找到了。这说明你比那90%更有冒险精神，或者更愿意在地图上乱戳。两种能力都值得肯定。`,
    en: `Brave explorer, welcome to Prague's most romantic and bee-endorsed destination — the Petřín Rose Garden, a magnificent park planted with hundreds of rose varieties that, when they bloom in May and June, perfume the entire hillside so intensely that people on Charles Bridge can allegedly detect them, though this claim may originate primarily from writers of Czech romantic fiction. The garden was established in 1932 as a gift from the city to its citizens — a perfect place to sit on a bench, stare into the middle distance, and pretend you are inside a Czech romantic film. Petřín Hill already had the observation tower, the mirror maze, and the observatory, but the Rose Garden is the hill's gift to the human nose. Unlock the Easter egg: this is one of Prague's most photogenic spots for a date, but because it sits on a hillside rather than a central square, roughly 90% of Old Town tour groups never find it. You found it. This means you are either more adventurous than that 90%, or more willing to randomly tap a map. Both abilities deserve acknowledgement.`,
    cz: `Odvážný průzkumníku, vítej v nejromantičtějším a včelami nejvíce uznávaném místě Prahy — Petřínském růžovém sadu, nádherném parku osázeném stovkami odrůd růží, které když rozkvétají v květnu a červnu, voní po celém svahu tak intenzivně, že lidé na Karlově mostě je prý cítí, ačkoliv tento nárok může pocházet především od autorů české romantické prózy. Zahrada byla zřízena v roce 1932 jako dar města svým občanům — dokonalé místo k sezení na lavičce, zírání do neurčita a představám, že jsi uvnitř českého romantického filmu. Petřín již měl rozhlednu, zrcadlové bludiště a hvězdárnu, ale Růžový sad je dárek tohoto kopce pro lidský čich. Odemkni easter egg: toto je jedno z nejfotogeničtějších míst Prahy pro rande, ale protože leží na svahu spíše než na centrálním náměstí, přibližně 90 % skupin z prohlídek Starého Města ho nikdy nenajde. Ty jsi ho našel. To znamená, že jsi buď dobrodružnější než oněch 90 %, nebo ochotnější náhodně klepat na mapu. Obě schopnosti si zaslouží uznání.`,
  },

  "kostel-sv-vaclava-smichov": {
    zh: `勇敢的探险家，这座低调而坚守阵地的教堂是斯米霍夫区的圣瓦茨拉夫教堂——几个世纪以来一直在布拉格这个工人阶级街区里默默屹立，亲眼目睹了斯米霍夫从渔村、到啤酒产区（著名的斯米霍夫啤酒厂曾在此运营）、再到今日科技公司和精品咖啡馆云集的都市的全程蜕变。圣瓦茨拉夫是波西米亚的守护圣人，布拉格至少有六七座以他命名的教堂——这并不令人惊讶，因为在捷克给孩子取名"Václav"就像在英语世界取名"John"一样普遍，而波西米亚人对圣人的热情也同样毫不节制。这座教堂不是那种人声鼎沸的旅游景点，它只是一个真实的、正在使用的礼拜场所，安静地存在于一个正在飞速变化的城区里。解锁彩蛋："斯米霍夫"这个名字的来源至今众说纷纭，没有定论。但可以确定的是：这里曾经是布拉格最重要的工业区之一，如今变成了共享办公空间和燕麦拿铁的领地。这座教堂是见证这一切变化的沉默观察者，而且它还会继续看下去。`,
    en: `Brave explorer, this quietly persistent church is the Church of St. Wenceslas in Smíchov — a place of worship that has held its ground in this working-class district for centuries, watching Smíchov transform from fishing village to major brewing centre (the famous Smíchov Brewery once operated here) to its current incarnation as a neighbourhood of tech companies and artisan coffee shops. Saint Wenceslas is Bohemia's patron saint, and Prague has at least six or seven churches named after him — unsurprising, since naming a Czech child "Václav" is roughly as common as naming an English child "John," and Bohemians have historically been equally generous in dedicating churches to their favourite patron. This is not a thundering tourist landmark; it is a quiet, still-functioning place of worship sitting in a rapidly changing neighbourhood. Unlock the Easter egg: the origin of the name "Smíchov" is genuinely disputed and unresolved. What is not disputed: this was once one of Prague's most important industrial zones and is now full of oat-milk lattes and co-working spaces. The church has watched all of this without comment, and will continue to do so.`,
    cz: `Odvážný průzkumníku, tento tiše vytrvale stojící kostel je Kostel svatého Václava na Smíchově — místo uctívání, které si drží svou pozici v této dělnické čtvrti po staletí a sleduje, jak se Smíchov proměňuje z rybářské vesnice na hlavní pivovarské centrum (slavný smíchovský pivovar zde kdysi působil) až po jeho současnou podobu čtvrti technologických firem a řemeslných kaváren. Svatý Václav je patron Čech a Praha má nejméně šest nebo sedm kostelů pojmenovaných po něm — není to překvapivé, protože pojmenovat české dítě "Václav" je přibližně tak běžné jako pojmenovat anglické dítě "John" a Češi byli historicky stejně štědří v zasvěcování kostelů svým oblíbeným patronům. Toto není bujará turistická atrakce; je to tiché, stále fungující místo uctívání v rychle se měnící čtvrti. Odemkni easter egg: původ názvu "Smíchov" je skutečně sporný a nevyřešený. Co sporné není: toto bylo kdysi jedno z nejdůležitějších průmyslových center Prahy a nyní je plné ovesných latte a co-workingových prostor. Kostel sledoval všechno bez komentáře a bude tak pokračovat.`,
  },

  "strahov-monastery-church": {
    zh: `勇敢的探险家，斯特拉霍夫修道院的圣母升天教堂是布拉格最著名的旅游景点里最被人忽视的建筑——因为几乎所有来斯特拉霍夫的人都是奔着图书馆去的，奔着神学厅和哲学厅那两间让Instagram彻底失去自我的书房去的，结果把这座建于12世纪、后来用巴洛克重新包装过的真正修道院教堂完全晾在一边。普雷蒙特雷会修士（白衣修士）从1143年起就在这里生活祈祷，中间虽然被约瑟夫二世的宗教改革强制关闭过，又被共产党政府折腾了几十年，但这座修道院就是不肯消失，简直是历史上最顽强的机构之一。现任修士依然在这里主持弥撒，而图书馆里那些书大多已经七八百年没有被人认真翻阅，主要职能是充当摄影背景。解锁彩蛋：斯特拉霍夫图书馆的书不能借阅，不能触摸，主要功能是被拍照——这与当初誓死将其一字一句手抄下来的中世纪修士们的初衷，存在某种微妙的落差。但教堂本身是完全功能正常的。去参加弥撒，做一个真正的探险家，而不是图书馆背景板的配角。`,
    en: `Brave explorer, the Church of the Assumption at Strahov Monastery is the most overlooked building in one of Prague's most visited complexes — because almost everyone who comes to Strahov is headed for the Library, for the Theological Hall and Philosophical Hall that make Instagram lose its mind, and in the process completely ignores this genuine twelfth-century monastic church, later repackaged in Baroque. The Premonstratensian monks (white canons) have been living and praying here since 1143, surviving Joseph II's religious reforms which briefly shut them down, surviving decades of Communist harassment, and simply refusing to disappear — making this one of history's more tenacious institutions. The current monks still hold Mass in the church, while most of the Library's books have not been seriously read in seven or eight hundred years and now function primarily as photographic backdrop. Unlock the Easter egg: Strahov's Library is also Prague's most-visited yet least-usable library — the books cannot be borrowed, cannot be touched, and serve mainly as scenic backdrop. This represents a certain divergence from the intentions of the medieval monks who hand-copied them to preserve human knowledge. The church, by contrast, is fully operational. Go to Mass. Be an explorer, not a backdrop extra.`,
    cz: `Odvážný průzkumníku, Kostel Nanebevzetí Panny Marie ve Strahovském klášteře je nejpřehlíženější budovou v jednom z nejnavštěvovanějších komplexů Prahy — protože téměř každý, kdo přijde na Strahov, míří do Knihovny, do Teologického a Filozofického sálu, které přivádějí Instagram k šílenství, a přitom zcela přehlíží tento skutečný dvanáctistolletý klášterní kostel, který byl později zabalen do baroka. Premonstráti (bílí kanovníci) zde žijí a modlí se od roku 1143, přežili Josefínské reformy, které je na čas zavřely, přežili desetiletí komunistického obtěžování a prostě odmítli zmizet — čímž se tato instituce řadí mezi nejhouževnatější v dějinách. Současní řeholníci stále slouží mše v kostele, zatímco většina knih Knihovny nebyla vážně čtena sedm nebo osm set let a slouží nyní primárně jako fotografická kulisa. Odemkni easter egg: Strahovská knihovna je zároveň nejnavštěvovanější a nejméně použitelnou knihovnou Prahy — knihy si nelze půjčit, nelze se jich dotknout a slouží hlavně jako malebná kulisa. To představuje určitou odchylku od záměrů středověkých mnichů, kteří je opisovali rukou, aby zachovali lidské vědění. Kostel je naproti tomu plně funkční. Jdi na mši. Buď průzkumníkem, ne statistou kulisy.`,
  },

  "pamatnik-jana-husa": {
    zh: `勇敢的探险家，老城广场上这座庄严的雕像纪念的是扬·胡斯——波西米亚历史上最重要的人物之一，他在1415年被烧死在康斯坦茨的火刑柱上，罪名是"异端"，翻译成现代语言就是：他有一个在当时极为危险的想法——教会应该向穷人负责，腐败不是美德，圣经应该用普通人能读懂的语言写成，而不是被教士阶级当作拉丁语权力工具来垄断。这座纪念碑由雕塑家拉迪斯拉夫·沙洛恩设计，1915年落成，正好是胡斯殉道五百周年。中央是站立的胡斯本人，周围是胡斯战争中的武士和被迫流亡的波西米亚新教徒，底座刻着他最著名的那句话："真理必胜"（Pravda vítězí）——这句话后来成了捷克斯洛伐克的国家格言，现在仍然印在总统府的旗帜上。解锁彩蛋：扬·胡斯的思想提前了约一百年——他倡导的宗教改革与马丁·路德后来发动的新教改革几乎一模一样，而路德本人也承认胡斯是自己的精神前辈。区别在于：胡斯先被烧死了，路德后来成功了。历史有时候只是时间差的问题，而时间差有时候要用人命来衡量。`,
    en: `Brave explorer, this solemn monument in Old Town Square commemorates Jan Hus — one of the most important figures in Bohemian history, burned at the stake in Constance in 1415 on a charge of heresy, which in modern translation means he held the extremely dangerous belief that the Church should be accountable to the poor, that corruption was not a virtue, and that the Bible should be written in languages ordinary people could actually read rather than kept as a Latin power tool for the clergy. The monument was designed by sculptor Ladislav Šaloun and unveiled in 1915, exactly five hundred years after Hus's execution. The central figure is Hus himself, standing tall, surrounded by Hussite warriors and Bohemian Protestant exiles, with his most famous line carved into the base: "Truth Prevails" (Pravda vítězí) — which later became the national motto of Czechoslovakia and still flies on the presidential banner today. Unlock the Easter egg: Jan Hus's ideas arrived approximately one hundred years early — his proposed reforms are nearly identical to what Martin Luther successfully launched a century later, and Luther himself acknowledged Hus as a forerunner. The difference: Hus was burned first; Luther succeeded. History is sometimes just a question of timing, and sometimes timing is measured in human lives.`,
    cz: `Odvážný průzkumníku, tento slavnostní pomník na Staroměstském náměstí připomíná Jana Husa — jednu z nejvýznamnějších postav české historie, upálenou na hranici v Kostnici v roce 1415 za kacířství, což v moderním překladu znamená: zastával extrémně nebezpečnou myšlenku, že církev by měla být odpovědná chudým, korupce není ctností a Bible by měla být psána v jazycích, které obyčejní lidé skutečně mohli číst, spíše než aby zůstala latinským mocenským nástrojem duchovenstva. Pomník navrhl sochař Ladislav Šaloun a byl odhalen v roce 1915, přesně pět set let po Husově popravě. Ústřední figura je sám Hus, stojící vzpřímeně, obklopený husitskými bojovníky a českými protestantskými exulanty, s jeho nejslavnější větou vytesanou do základu: "Pravda vítězí" — která se později stala státním mottem Československa a dodnes vlaje na prezidentském praporu. Odemkni easter egg: myšlenky Jana Husa přišly přibližně sto let příliš brzy — jeho navrhované reformy jsou téměř totožné s tím, co Martin Luther o století později úspěšně spustil, a Luther sám Husa uznal jako svého předchůdce. Rozdíl: Hus byl upálen jako první; Luther uspěl. Historie je někdy jen otázkou načasování, a načasování je někdy měřeno lidskými životy.`,
  },

  "mariansky-sloup": {
    zh: `勇敢的探险家，老城广场上这根巴洛克石柱拥有布拉格所有纪念碑中最戏剧性的履历——原版于1650年竖立，纪念布拉格在三十年战争中奇迹般地幸免于瑞典军队的彻底蹂躏，同时也是哈布斯堡天主教统治的物质象征；然后在1918年捷克斯洛伐克建国后第三天，被一群民族主义者用绳子拉倒了，理由是它代表着哈布斯堡的压迫和强制天主教化政策。这一拉倒举动在捷克社会引发了长达一百年的争议，各方争论始终没有结果，直到2020年，复制品终于被重新竖立回原位——于是一批新的人群开始愤怒。柱子顶端是圣母玛利亚像，踩着新月，四角有天使护卫。解锁彩蛋：同一根柱子：1650年竖立，是天主教帝国的胜利纪念碑；1918年倒下，是民族独立的仪式性行动；2020年重立，立刻引发了新一轮关于历史、身份认同和国家记忆的文化战争。一根石柱，承载了捷克整个现代史上最核心的身份认同争议。布拉格的石头记得的，比这座城市的人类想记得的要多得多。`,
    en: `Brave explorer, this Baroque column in Old Town Square has the most dramatic biography of any monument in Prague — the original was erected in 1650 to celebrate Prague's miraculous survival of Swedish attack during the Thirty Years' War and to serve as a material symbol of Habsburg Catholic rule; then, three days after Czechoslovakia declared independence in 1918, it was pulled down with ropes by a group of nationalists on the grounds that it represented Habsburg oppression and forced Catholicism. This act of monument demolition triggered a hundred years of argument in Czech society that never fully resolved, until 2020, when a replica was re-erected in the original location — at which point a new group of people became furious. The top of the column carries a figure of the Virgin Mary standing on a crescent moon, attended by four angels. Unlock the Easter egg: the same column: erected 1650 as an imperial Catholic victory monument; toppled 1918 as a ritual act of national independence; re-erected 2020, immediately sparking a new cultural war over history, identity, and national memory. One stone column has absorbed the central identity argument of all modern Czech history. Prague's stones remember more than its people are always willing to.`,
    cz: `Odvážný průzkumníku, tento barokní sloup na Staroměstském náměstí má nejdramatičtější životopis ze všech pražských pomníků — originál byl vztyčen v roce 1650 k oslavě zázračného přežití Prahy při švédském útoku během třicetileté války a sloužil jako hmotný symbol habsburské katolické nadvlády; poté, tři dny po vyhlášení nezávislosti Československa v roce 1918, ho strhla skupina nacionalistů s odůvodněním, že reprezentuje habsburský útlak a nucené katolictví. Tento akt stržení pomníku vyvolal v české společnosti sto let diskusí, které se nikdy plně nevyřešily, dokud v roce 2020 nebyla replika znovu vztyčena na původním místě — načež nová skupina lidí začala zuřit. Na vrcholu sloupu je socha Panny Marie stojící na půlměsíci, obklopená čtyřmi anděly. Odemkni easter egg: stejný sloup: vztyčen 1650 jako imperiální katolický vítězný pomník; stržen 1918 jako rituální akt národní nezávislosti; znovu vztyčen 2020, okamžitě vyvolal novou kulturní válku o dějinách, identitě a národní paměti. Jeden kamenný sloup pohltil ústřední debatu o identitě z celých moderních českých dějin. Pražské kameny si pamatují více, než jsou jeho obyvatelé vždy ochotni přiznat.`,
  },

  "nejuzsi-prazska-ulicka": {
    zh: `勇敢的探险家，你刚刚找到了布拉格最窄的街道——窄到为了防止迎面而来的两个行人互相卡死，这里安装了一个完全可以正常运作的交通信号灯，只允许单向通行。这条小巷藏在小城区查理大桥附近，宽度约50厘米（某些测量结果说是70厘米，取决于你测哪个位置，也取决于测量者的身材），如果两人同时从两端走来，其中一个必须退回去，没有讨论的余地。这是布拉格给城市规划问题提供的一个独特解决方案：与其把墙拆掉拓宽道路，不如装一个红绿灯。从某种意义上说，这比大规模拆迁重建文明得多。解锁彩蛋：这个信号灯的存在意味着：历史上某一天，某个城市管理人员认真地坐下来开了一个会，会议议题是"一条宽50厘米的小巷是否需要交通管理基础设施"，而会议结论是"是的，需要"。这个决策过程本身，就是布拉格某种务实荒诞主义精神的完美注脚。另外：如果你在这里等红灯，你正在等的很可能是人类历史上最窄的合法路口。`,
    en: `Brave explorer, you have just found Prague's narrowest street — a lane so tight that, to prevent two approaching pedestrians from becoming physically wedged against each other, it was equipped with a fully functional traffic light permitting passage in only one direction at a time. The alley is tucked into Malá Strana near Charles Bridge, with a width of approximately 50 centimetres (some measurements say 70cm, depending on which point you measure and the dimensions of the measurer), meaning that if two people approach from opposite ends simultaneously, one must retreat — no negotiation possible. This is Prague's unique answer to an urban planning problem: rather than demolishing the walls to widen the street, install a traffic signal. In its own way, this is considerably more civilised than large-scale demolition. Unlock the Easter egg: the existence of this traffic light means that at some point in history, a city official sat in a meeting, seriously considered whether a 50-centimetre alley merited traffic management infrastructure, and concluded that yes, it did. This decision-making process is a perfect footnote to Prague's brand of practical absurdism. Also: if you are waiting at this red light, you are almost certainly waiting at the narrowest legal intersection in human history.`,
    cz: `Odvážný průzkumníku, právě jsi našel nejužší ulici Prahy — uličku tak těsnou, že aby se zabránilo fyzickému uvíznutí dvou chodců jdoucích naproti sobě, byla vybavena plně funkčním semaforem, který umožňuje průchod pouze jedním směrem najednou. Ulička je ukrytá na Malé Straně poblíž Karlova mostu, s šířkou přibližně 50 centimetrů (některá měření říkají 70 cm, záleží na tom, kde měříte a jakých rozměrů je měřič), což znamená, že pokud přicházejí dva lidé současně z opačných konců, jeden musí couvat — bez možnosti vyjednávání. To je jedinečná pražská odpověď na problém urbanistického plánování: místo zbourání zdí pro rozšíření ulice nainstalovat semafor. Svým způsobem je to podstatně civilizovanější než rozsáhlé demolice. Odemkni easter egg: existence tohoto semaforu znamená, že v určitém okamžiku v historii úředník sedl na schůzi, vážně zvažoval, zda 50centimetrová ulička si zaslouží dopravní infrastrukturu, a dospěl k závěru, že ano. Tento rozhodovací proces je dokonalou poznámkou pod čarou k pražskému druhu praktického absurdismu. Také: pokud čekáš na červenou, s velkou pravděpodobností čekáš na nejužší legální křižovatku v lidských dějinách.`,
  },

  "malostranska-mostecka-vez": {
    zh: `勇敢的探险家，查理大桥小城一端有两座塔，而不是一座——这不是建筑师的失误或者什么出于审美原因的重复，而是历史的层叠：矮的那座（罗马式风格）是查理大桥前身、12世纪的朱迪思桥遗留下来的桥塔，高的那座（哥特式风格）是14世纪查理大桥建成后新添的。两座塔一高一矮、一老一新，并排站了几百年，中间有一道门洞，是每一个从查理大桥步行进入小城区的人必须穿越的关口。这意味着这个门洞在八百年间目睹了几乎无法计量的人类流动：波西米亚国王、奥斯曼大使、哈布斯堡皇帝、胡斯派士兵、巴洛克艺术家、共产党官员，以及现在每天好几千名举着手机的游客。解锁彩蛋：站在塔下仰望，你可以在同一个视野里同时看到罗马式和哥特式两种建筑风格贴合在一起——大约七百年的建筑史压缩在一个街角。布拉格最高效的历史教育课，往往只需要你抬起头那一秒钟。`,
    en: `Brave explorer, on the Malá Strana end of Charles Bridge there are two towers rather than one — not an architect's error or an aesthetic indulgence, but layered history: the shorter tower (Romanesque) is a survivor from the twelfth-century Judith Bridge, Charles Bridge's predecessor; the taller tower (Gothic) was added after Charles Bridge was completed in the fourteenth century. The two towers — one short and old, one tall and slightly newer — have stood side by side for several centuries with a gateway between them, through which every person walking from Charles Bridge into Malá Strana must pass. This means the gateway has witnessed an almost incalculable flow of humanity over eight hundred years: Bohemian kings, Ottoman ambassadors, Habsburg emperors, Hussite soldiers, Baroque artists, Communist officials, and now several thousand people per day holding up their phones. Unlock the Easter egg: stand beneath the towers and look up — you can see Romanesque and Gothic architectural styles pressed together in a single field of view, approximately seven hundred years of building history compressed into one street corner. Prague's most efficient history lesson often takes just the second you look up.`,
    cz: `Odvážný průzkumníku, na malostranské straně Karlova mostu jsou dvě věže spíše než jedna — ne chyba architekta ani estetická rozmařilost, ale vrstvená historie: nižší věž (románský styl) je pozůstatkem dvanáctistolletého Juditina mostu, předchůdce Karlova mostu; vyšší věž (gotický styl) byla přidána po dokončení Karlova mostu ve čtrnáctém století. Obě věže — jedna nízká a stará, jedna vysoká a o něco novější — stojí vedle sebe po několik staletí s branou mezi nimi, přes kterou musí procházet každý, kdo jde z Karlova mostu na Malou Stranu. To znamená, že tato brána za osm set let sledovala téměř nepočitatelný proud lidstva: české krále, osmanské vyslance, habsburské císaře, husitské vojáky, barokní umělce, komunistické funkcionáře a nyní několik tisíc lidí denně s telefonem v ruce. Odemkni easter egg: stůj pod věžemi a podívej se nahoru — uvidíš románský a gotický architektonický styl přitisknuté k sobě v jediném zorném poli, přibližně sedm set let stavební historie stlačené do jednoho rohu ulice. Nejefektivnější historická lekce Prahy trvá často jen tu vteřinu, kdy zvednete pohled.`,
  },

  "basilika-sv-petra-pavla": {
    en: `Brave explorer, the Basilica of Saints Peter and Paul is Vyšehrad's crown — the twin-spired Neo-Gothic cathedral that has dominated the rocky promontory above the Vltava since 1903 and stands as one of the most recognisable silhouettes in the entire city. A place of worship has occupied this site since the eleventh century, when King Vratislaus II founded a Romanesque basilica here in the 1070s; the church was rebuilt multiple times over the medieval and Baroque periods before architects Josef Mocker and František Mikš gave it its present dramatic form between 1885 and 1903. The interior is extraordinary: the nave is lined with Art Nouveau mosaics and frescoes by František Urban and Karel Jakub Mašek, their rich blues and golds creating an atmosphere unlike any other Prague church. The twin towers rise 58 metres above the Vyšehrad plateau. Unlock the Easter egg: the church shelters the tombs of the Přemyslid kings, but the real secret lies in the crypt beneath the nave — fragments of the original eleventh-century Romanesque structure survive in the foundations, making this one of the few places in Prague where you can physically stand on the ground level of the early medieval city. The patron saints Peter and Paul share their feast day on June 29 — and in years when Czech pilgrims mark it at Vyšehrad, the basilica fills with candlelight and plainchant in a ritual that dates back unbroken to the Přemyslid dynasty.`,
    cz: `Odvážný průzkumníku, Bazilika svatého Petra a Pavla je korunou Vyšehradu — dvojvěžová novogotická katedrála, která dominuje skalnatému ostrohu nad Vltavou od roku 1903 a tvoří jeden z nejrozpoznatelnějších siluet celého města. Místo uctívání zde existuje od jedenáctého století, kdy král Vratislav II. v 70. letech 11. století na tomto místě založil románskou baziliku; kostel byl v průběhu středověkého a barokního období několikrát přestavěn, než mu architekti Josef Mocker a František Mikš dali jeho současnou dramatickou podobu v letech 1885 až 1903. Interiér je mimořádný: loď je lemována secesními mozaikami a freskami Františka Urbana a Karla Jakuba Maška, jejichž bohaté modré a zlaté barvy vytváří atmosféru nepodobnou žádnému jinému pražskému kostelu. Dvojice věží se tyčí 58 metrů nad vyšehradskou plošinou. Odemkni easter egg: kostel ukrývá hrobky přemyslovských králů, ale skutečné tajemství leží v kryptě pod lodí — fragmenty původní románské stavby z jedenáctého století přežívají v základech, čímž je toto jedno z mála míst v Praze, kde lze fyzicky stát na úrovni terénu raně středověkého města. Patroni Petr a Pavel sdílí svátek 29. června — a v letech, kdy čeští poutníci slaví na Vyšehradě, bazilika se naplňuje svíčkami a zpěvem gregoriánského chorálu v rituálu, který sahá nepřerušeně až k přemyslovské dynastii.`,
    zh: `勇敢的探险家，圣彼得和保罗大教堂是维谢赫拉德的王冠——自1903年以来主宰着伏尔塔瓦河上方岩石峭壁的双塔新哥特式大教堂，是整座城市最标志性的轮廓之一。自11世纪以来，这里就是礼拜场所：国王弗拉蒂斯拉夫二世于1070年代在此建造了一座罗马式圣殿；这座教堂在中世纪和巴洛克时期经历了多次重建，最终由建筑师约瑟夫·莫克尔和弗兰季谢克·米克什在1885年至1903年间赋予其现在这戏剧性的面貌。内部令人叹为观止：中殿两侧装饰着弗兰季谢克·乌尔班和卡雷尔·雅库布·马谢克创作的新艺术运动马赛克和壁画，其丰富的蓝色和金色创造出与布拉格任何其他教堂都截然不同的氛围。双塔在维谢赫拉德高原上方耸立58米之高。解锁彩蛋：教堂庇护着普热米斯利德王朝国王的陵墓，但真正的秘密藏在中殿下方的地下室里——11世纪原始罗马式建筑的遗迹在地基中留存了下来，使这里成为布拉格少数几个你可以实实在在站在早期中世纪城市地面高度的地方之一。主保圣人彼得和保罗在6月29日共享节日——在捷克朝圣者于维谢赫拉德举行庆典的年份，大教堂中烛光闪烁，素歌回荡，这一仪式可以无间断地追溯到普热米斯利德王朝。`,
  },

  "storch-house": {
    en: `Brave explorer, Storch House is the most theatrically decorated building on Old Town Square — a Neo-Gothic revival facade covered in spectacular sgrafitto paintings that transform an otherwise ordinary building into an illustrated page from Czech mythology. The house at No. 16 was rebuilt in 1896 for bookseller Jan Štorch by architect Bedřich Ohmann and completed by Osvald Polívka; the dominant image is Mikoláš Aleš's monumental sgrafitto of Saint Wenceslas on horseback, painted directly into the plaster in the traditional Italian technique, with the patron saint of Bohemia riding in full armour across the upper storey while eagle heraldry and Hussite motifs fill the panels below. The building's full historical name — Dům U Kamenné Panny Marie, "House at the Stone Virgin Mary" — refers to a Gothic stone relief of the Madonna embedded in the building's wall centuries before the current structure was built, continuing a medieval tradition of naming Prague houses after sculptural landmarks on their facades. Unlock the Easter egg: stand directly in front of the building and look carefully at the sgrafitto detail — the figures in Aleš's Saint Wenceslas panel are not generic medieval warriors but include portraits of real Czech historical figures that Aleš embedded as visual jokes for viewers who knew their faces. The building sits on a plot whose documented history extends to at least the thirteenth century. Most visitors photograph it but few read it; treat the facade as a page and the Easter egg is the story it tells.`,
    cz: `Odvážný průzkumníku, Štorchův dům je nejdivadelnější ozdobenou budovou na Staroměstském náměstí — novogotická renesanční fasáda pokrytá velkolepými sgrafittovými malbami, které přeměňují jinak obyčejnou budovu v ilustrovanou stránku z české mytologie. Dům č. 16 byl přestavěn v roce 1896 pro knihkupce Jana Štorcha architektem Bedřichem Ohmannem a dokončen Osvaldem Polívkou; dominantním obrazem je monumentální sgrafitto Mikoláše Alše zobrazující svatého Václava na koni, malované přímo do omítky v tradiční italské technice, kde patron Čech jede v plné zbroji přes horní podlaží, zatímco orlí heraldika a husitské motivy zaplňují panely níže. Celé historické jméno budovy — Dům U Kamenné Panny Marie — odkazuje na gotický kamenný reliéf Madony zasazený do zdi budovy staletí před tím, než byla postavena současná stavba, a pokračuje tak ve středověké tradici pojmenovávání pražských domů podle sochařských pamětihodností na jejich fasádách. Odemkni easter egg: stůj přímo před budovou a pozorně se dívej na sgrafittové detaily — postavy na Alšově panelu sv. Václava nejsou generičtí středověcí bojovníci, ale zahrnují portréty skutečných českých historických osobností, které Aleš vložil jako vizuální vtipy pro diváky, kteří znali jejich tváře. Budova stojí na pozemku, jehož doložená historie sahá přinejmenším do třináctého století. Většina návštěvníků ji fotografuje, ale málokdo ji čte; zacházej s fasádou jako se stránkou a easter egg je příběh, který vypráví.`,
    zh: `勇敢的探险家，斯托尔赫之屋是老城广场上装饰最具戏剧性的建筑——一座新哥特式复兴风格的门面覆盖着壮观的刮墙画，将一栋普通的建筑变成了捷克神话的图解页面。这栋位于16号的建筑于1896年由建筑师贝德日赫·奥曼为书商扬·斯托尔赫重建，并由奥斯瓦尔德·波利夫卡完成；其主要图像是米科拉什·阿勒什创作的圣瓦茨拉夫骑马的宏大刮墙画，直接用传统意大利技法刮入灰泥，波西米亚的守护圣人身披全套盔甲在上层楼层驰骋，而老鹰纹章和胡斯派图案则填满了下方的嵌板。这座建筑的完整历史名称——"石头圣母之家"——指的是一个哥特式石雕圣母像，它在现有建筑建造之前数百年就被嵌入建筑墙壁中，延续了布拉格住宅以正面雕塑地标命名的中世纪传统。解锁彩蛋：站在建筑正前方，仔细观察刮墙画细节——阿勒什的圣瓦茨拉夫嵌板中的人物并非普通的中世纪武士，而是包含了真实捷克历史人物的肖像，阿勒什将它们作为视觉玩笑藏在其中，供认识这些面孔的观众发现。这栋建筑所在的地块有文献记载的历史至少可以追溯到13世纪。大多数游客拍照留念，但很少有人真正"阅读"它；把这个门面当作一页书来对待，彩蛋就是它所讲述的故事。`,
  },

  "stare-purkrabstvi": {
    en: `Brave explorer, Staré Purkrabství — the Old Burgrave's House — is one of Vyšehrad's most overlooked architectural surprises: a handsome Baroque building that once served as the official residence of the purkrabí, the imperial governor of the Vyšehrad fortress and its attached estates. The title of Vyšehrad burgrave was one of the most prestigious administrative posts in the Kingdom of Bohemia; the holder managed not just the physical fortress but all the lands, revenues, and legal affairs of the Vyšehrad chapter — a significant mediaeval institution independent of Prague Castle. The current building dates from the late seventeenth century, when Vyšehrad was converted from a royal and ecclesiastical site into a full Habsburg military fortress; the burgrave's house was rebuilt in the Baroque style to serve the new administration. After the fortress was decommissioned in the mid-nineteenth century, the building passed to the Vyšehrad chapter and has served various administrative and cultural functions since. Unlock the Easter egg: the name "Staré Purkrabství" — Old Burgrave's House — implies a newer one exists elsewhere on the rock, and indeed it does: Nové Purkrabství, slightly lower on the hill, served the later phase of administration after the Baroque rebuild. Walking between the two buildings you pass through essentially the entire administrative history of Vyšehrad condensed into two facades. Few visitors look twice at either.`,
    cz: `Odvážný průzkumníku, Staré Purkrabství je jedním z nejvíce přehlížených architektonických překvapení Vyšehradu: reprezentativní barokní budova, která kdysi sloužila jako oficiální sídlo purkrabího, císařského správce vyšehradské pevnosti a jejích přidružených statků. Titul vyšehradského purkrabího byl jedním z nejprestižnějších správních postů v Království českém; jeho držitel spravoval nejen fyzickou pevnost, ale veškeré pozemky, příjmy a právní záležitosti vyšehradské kapituly — významné středověké instituce nezávislé na Pražském hradě. Současná budova pochází z konce sedmnáctého století, kdy byl Vyšehrad přeměněn z královského a církevního místa na plnohodnotnou habsburskou vojenskou pevnost; purkrabský dům byl přestavěn v barokním stylu pro potřeby nové správy. Po deaktivaci pevnosti v polovině devatenáctého století přešla budova na vyšehradskou kapitulu a od té doby slouží různým správním a kulturním účelům. Odemkni easter egg: název "Staré Purkrabství" implikuje, že "Nové" existuje někde jinde na skále, a skutečně existuje: Nové Purkrabství, o něco níže na kopci, sloužilo pozdější fázi správy po barokní přestavbě. Procházením mezi oběma budovami procházíš v podstatě celou správní historií Vyšehradu kondenzovanou do dvou fasád. Málokdo se podívá podruhé na kteroukoli z nich.`,
    zh: `勇敢的探险家，斯塔雷·普尔克拉布斯特维——旧城守府——是维谢赫拉德最被忽视的建筑惊喜之一：一座曾作为普尔克拉比官邸的精美巴洛克建筑，普尔克拉比是维谢赫拉德要塞及其附属庄园的帝国总督。维谢赫拉德城守的头衔是波西米亚王国最负盛名的行政职位之一；持有者不仅管理着实体要塞，还管理着维谢赫拉德圣堂章会所有的土地、收入和法律事务——这是一个独立于布拉格城堡的重要中世纪机构。现有建筑可追溯到17世纪晚期，当时维谢赫拉德从王室和宗教场所转变为哈布斯堡军事要塞；城守之屋以巴洛克风格重建，以服务新的行政管理。在要塞于19世纪中叶退役后，该建筑移交给维谢赫拉德圣堂章会，此后一直服务于各种行政和文化功能。解锁彩蛋："斯塔雷·普尔克拉布斯特维"——旧城守府——这个名字暗示着在山岩的其他地方还有一座"新"的城守府，确实如此：诺维·普尔克拉布斯特维（新城守府），位于山坡稍低处，在巴洛克重建后的后期行政阶段服务。在两栋建筑之间穿行，你实际上穿越了浓缩在两个门面中的维谢赫拉德完整行政历史。几乎没有游客会对任何一栋多看一眼。`,
  },

  "kostel-sv-pankrace": {
    en: `Brave explorer, the Church of St. Pancras in Nusle is one of Prague's oldest continuously active places of worship — a small, severe Romanesque-Gothic church whose origins stretch back to the twelfth century and whose very existence explains the name of the entire district around it. Pankrác — the plateau, the neighbourhood, the notorious communist-era prison, and now one of Prague's main business districts — is named after this unremarkable-looking stone church, which is in turn named after Saint Pancras, a Roman martyr executed around 304 CE at the age of fourteen for refusing to renounce his Christian faith. The church's Romanesque core was built in the mid-twelfth century, when Nusle was an independent village on the approach road to Vyšehrad; Gothic modifications were added in the fourteenth century. It survived the Hussite wars, the Baroque period, the Habsburg suppressions, and the Communist era with most of its medieval fabric intact. Unlock the Easter egg: the church sits in a small enclosure at what was once the geographic centre of the original village of Nusle, which is now completely absorbed into Prague 4 but was an independent municipality until 1922. The deeper Easter egg is topographic: this medieval church stands at almost exactly the same elevation as the Nusle Valley floor below — while the famous Nusle Bridge, built in 1973, soars 43 metres above the valley. The bridge and the church are separated by a kilometre and by 43 vertical metres, but they mark the same human territory; one is the oldest thing here, one is the newest, and between them is the whole story of what Prague did to Nusle.`,
    cz: `Odvážný průzkumníku, Kostel svatého Pankráce v Nuslích je jedním z nejstarších nepřetržitě aktivních míst uctívání v Praze — malý, přísný románsko-gotický kostel, jehož počátky sahají do dvanáctého století a jehož samotná existence vysvětluje název celé čtvrti kolem něj. Pankrác — plošina, čtvrť, nechvalně proslulá komunistická věznice a nyní jedno z hlavních obchodních čtvrtí Prahy — je pojmenována po tomto nenápadně vypadajícím kamenném kostele, který je zase pojmenován po svatém Pankrácovi, římském mučedníkovi popraveném kolem roku 304 n. l. ve věku čtrnácti let za odmítnutí vzdát se křesťanské víry. Románské jádro kostela bylo postaveno v polovině dvanáctého století, kdy Nusle byly samostatnou vesnicí na přístupové cestě k Vyšehradu; gotické úpravy byly přidány ve čtrnáctém století. Přežil husitské války, barokní období, habsburské potlačení i komunistickou éru s většinou středověkého materiálu nedotčenou. Odemkni easter egg: kostel stojí v malém uzavřeném prostoru, který byl kdysi geografickým centrem původní vesnice Nusle, nyní zcela pohlcené Prahou 4, ale do roku 1922 samostatnou obcí. Hlubší easter egg je topografický: tento středověký kostel stojí téměř přesně ve stejné nadmořské výšce jako dno Nuselského údolí níže — zatímco slavný Nuselský most, postavený v roce 1973, se tyčí 43 metrů nad údolím. Most a kostel jsou od sebe vzdáleny jeden kilometr a 43 metrů svisle, ale označují stejné lidské území; jeden je tady nejstarší věcí, druhý nejnovější, a mezi nimi je celý příběh toho, co Praha udělala s Nuslemi.`,
    zh: `勇敢的探险家，努斯莱的圣潘克拉斯教堂是布拉格最古老的持续活跃礼拜场所之一——一座小巧严肃的罗马式-哥特式教堂，其起源可追溯至12世纪，而其存在本身就解释了周边整个地区名称的由来。潘克拉茨——那片高原、那个街区、共产主义时代臭名昭著的监狱，以及现在布拉格的主要商业区之一——都以这座看起来平淡无奇的石头小教堂命名，而这座教堂又以圣潘克拉斯命名，他是一位大约在公元304年因拒绝放弃基督教信仰而在14岁时被处决的罗马殉教者。教堂的罗马式核心建于12世纪中期，当时努斯莱还是通往维谢赫拉德的道路上一个独立的村庄；哥特式改建在14世纪完成。它历经胡斯战争、巴洛克时期、哈布斯堡镇压和共产主义时代，大部分中世纪结构保持完整。解锁彩蛋：教堂坐落在一个小围场内，这里曾是努斯莱原始村庄的地理中心，如今已完全被布拉格4区所吸收，但直到1922年仍是独立市镇。更深层的彩蛋是地形上的：这座中世纪教堂所处的海拔高度几乎与下方努斯莱谷底完全相同——而建于1973年的著名努斯莱大桥则在谷地上方43米处凌空飞架。大桥和教堂相距一公里，垂直高度差43米，但它们标志着同一片人类领地；一个是这里最古老的事物，一个是最新的，而在它们之间，是布拉格对努斯莱所做的一切的完整故事。`,
  },

  "televizni-stredisko-kavci-hory": {
    en: `Brave explorer, the Kavčí Hory Television Centre is the heartbeat of Czech public broadcasting — a monumental Brutalist complex on the southern plateau of Prague 4 that has been transmitting Czech reality, Czech myth, and Czech argument to the entire country since it opened in 1975. "Kavčí hory" translates as "Jackdaw Hills" — named for the corvid birds that historically nested on this wooded ridge before it was levelled and built upon — and the complex is a textbook specimen of late Socialist Brutalism: raw concrete, cantilevered masses, and horizontal window strips, built to house multiple production studios, post-production suites, broadcasting equipment, and thousands of staff under one fortress-like roof. This is where Czechoslovak Television made its broadcasts during the Communist period, and where, in November 1989, the station's journalists and technicians publicly defied the regime during the Velvet Revolution, broadcasting live coverage of the protests at a moment when state media was trying to suppress the story. Unlock the Easter egg: the complex sits on the highest point of the Kavčí hory ridge, and from the uppermost levels there are sweeping views across south Prague toward Vyšehrad and the Vltava bend — a geography that television has been framing and transmitting for half a century. The building is not open to general visitors, but its exterior is genuinely worth studying: it is a complete example of late-Socialist institutional architecture at full scale, built to last a hundred years and already halfway there.`,
    cz: `Odvážný průzkumníku, Televizní středisko Kavčí hory je srdcem českého veřejného vysílání — monumentální brutalistický komplex na jižní plošině Prahy 4, který od svého otevření v roce 1975 vysílá do celé země českou realitu, český mýtus a českou debatu. "Kavčí hory" se překládá jako "kavčí kopce" — pojmenované po kavkách, které historicky hnízdily na tomto zalesněném hřbetu, než byl srovnán a zastavěn — a komplex je učebnicovým vzorkem pozdního socialistického brutalismu: surový beton, konzolové hmoty a horizontální pásy oken, postavené pro ubytování několika produkčních studií, post-produkčních místností, vysílacího zařízení a tisíců zaměstnanců pod jednou pevnostní střechou. Zde Československá televize vysílala během komunistického období a zde, v listopadu 1989, novináři a technici stanice veřejně vzdorovali režimu během Sametové revoluce, vysílajíce živé záběry protestů v okamžiku, kdy se státní média snažila příběh potlačit. Odemkni easter egg: komplex stojí na nejvyšším bodě hřbetu Kavčích hor a z nejvyšších pater se rozkládají rozsáhlé výhledy přes jižní Prahu směrem k Vyšehradu a ohbí Vltavy — geografie, kterou televize zarámovává a vysílá půl století. Budova není otevřena pro běžné návštěvníky, ale její exteriér stojí za skutečné studium: je to kompletní příklad pozdně socialistické institucionální architektury v plném měřítku, postavená na sto let a již na půli cesty.`,
    zh: `勇敢的探险家，卡夫奇山电视中心是捷克公共广播的心脏——布拉格4区南部高原上一座宏大的野兽派建筑综合体，自1975年开放以来，一直在向全国广播捷克的现实、捷克的神话和捷克的争论。"卡夫奇山"翻译为"寒鸦之丘"——以历史上在这片丘陵林地筑巢的寒鸦命名，在它被夷平建设之前——这座综合体是晚期社会主义野兽派风格的教科书式标本：粗犷混凝土、悬臂体量和水平窗带，建造用于在一个堡垒般的屋顶下容纳多个制作工作室、后期制作套间、广播设备和数千名员工。这里是捷克斯洛伐克电视台在共产主义时期进行广播的地方，也是1989年11月，在丝绒革命期间，该台记者和技术人员公开反抗政权、在国家媒体试图压制故事的时刻播出抗议现场直播的地方。解锁彩蛋：这座综合体位于卡夫奇山山脊的最高点，从建筑的最高楼层可以俯瞰布拉格南部向维谢赫拉德和伏尔塔瓦河弯延伸的壮阔景色——电视已经框取并播出了这片地理景观半个世纪。这座建筑不向普通游客开放，但其外观确实值得仔细观察：它是晚期社会主义机构建筑的完整范本，以全尺度建造，设计使用寿命一百年，如今已到了一半。`,
  },

  "budova-centrotex": {
    en: `Brave explorer, the Centrotex Building is one of Wenceslas Square's most historically layered facades — a seven-storey Socialist Realist structure at No. 36 built in 1957 for Centrotex, the Czechoslovak state foreign-trade enterprise for textiles, which used it as its headquarters during the Communist period. The building's architecture is a textbook specimen of 1950s Czechoslovak Socialist Realism: the massive rusticated stone base, the rhythmic vertical articulation of the upper storeys, the decorative relief panels incorporating socialist iconography, and the slightly ceremonial quality that the regime's architects imposed on state institutions to signal power and permanence. After 1989, Centrotex was dissolved along with dozens of other state foreign-trade monopolies as Czechoslovakia re-entered the market economy, and the building was repurposed for commercial use — a transformation typical of socialist-era buildings along Wenceslas Square. Unlock the Easter egg: Wenceslas Square, despite its status as the most famous address in the Czech Republic, is not technically a square — it is a boulevard, 750 metres long and 60 metres wide, oriented north-south on the gentle slope up from the Old Town moat to the National Museum. The Centrotex Building sits near the lower northern end, which is the oldest-settled end; the pattern of ownership and architecture along the Square is a compressed history of modern Czech political economy, from Habsburg commercial liberalism to First Republic modernism to Communist Socialist Realism to post-1989 commercial redevelopment, all readable in the facades within a ten-minute walk.`,
    cz: `Odvážný průzkumníku, Budova Centrotexu je jednou z historicky nejvrstvovitějších fasád Václavského náměstí — sedmipodlažní sociálně realistická stavba na č. 36, postavená v roce 1957 pro Centrotex, československý státní zahraničně-obchodní podnik pro textil, který ji v komunistickém období využíval jako sídlo. Architektura budovy je učebnicovým vzorkem československého socialistického realismu 50. let: masivní rustiková kamenná základna, rytmická vertikální artikulace horních podlaží, dekorativní reliéfní panely zahrnující socialistickou ikonografii a mírně slavnostní kvalita, kterou architekti režimu vnucovali státním institucím, aby signalizovaly moc a trvalost. Po roce 1989 byl Centrotex rozpuštěn spolu s desítkami dalších státních zahranično-obchodních monopolů, když Československo znovu vstoupilo do tržní ekonomiky, a budova byla repurposována pro komerční využití — proměna typická pro budovy z éry socialismu podél Václavského náměstí. Odemkni easter egg: Václavské náměstí, přes svůj status nejslavnější adresy v České republice, není technicky náměstím — je to bulvár, 750 metrů dlouhý a 60 metrů široký, orientovaný sever-jih na mírném svahu od starého městského příkopu k Národnímu muzeu. Budova Centrotexu stojí poblíž dolního severního konce, který je nejstarší osídlenou částí; vzorec vlastnictví a architektury podél náměstí je kondenzovanou historií moderní české politické ekonomie, od habsburského obchodního liberalismu přes prvorepublikový modernismus až ke komunistickému socialistickému realismu a post-1989 komerčnímu rozvoji, vše čitelné z fasád v deseti minutách chůze.`,
    zh: `勇敢的探险家，中心纺织大楼是瓦茨拉夫广场历史层次最为丰富的门面之一——位于36号的一栋七层社会主义现实主义建筑，建于1957年，为捷克斯洛伐克国家纺织品外贸企业中心纺织公司（Centrotex）所建，该公司在共产主义时期将其用作总部。这栋建筑的建筑风格是1950年代捷克斯洛伐克社会主义现实主义的教科书式范本：厚重的粗石石材基座、上层楼层有节律的垂直分节、融入社会主义图像学的装饰性浮雕嵌板，以及政权建筑师强加给国家机构以示权力与永久性的那种略带仪式感的气质。1989年后，随着捷克斯洛伐克重返市场经济，中心纺织公司与数十家其他国家外贸垄断企业一同被解散，这栋建筑被改作商业用途——这是瓦茨拉夫广场沿线社会主义时代建筑典型的转变轨迹。解锁彩蛋：瓦茨拉夫广场尽管拥有捷克共和国最著名地址的地位，但从技术上讲它并不是一个广场——它是一条林荫大道，长750米，宽60米，从老城护城河沿缓坡向南朝国家博物馆延伸。中心纺织大楼坐落于其较低的北部端，也是历史上最早定居的一端；广场沿线的所有权和建筑格局是现代捷克政治经济的浓缩历史，从哈布斯堡商业自由主义到第一共和国现代主义，再到共产主义社会主义现实主义和1989年后的商业再开发，所有这些都可以在十分钟步行范围内的门面上读出来。`,
  },

  "celetna": {
    en: `Brave explorer, you walk one of Prague's oldest streets — a medieval market route so ancient the Baroque facades are merely the latest coat of paint over Romanesque foundations from the 11th century.\n\nCeletná was the beginning of the Royal Route, where coronation processions entered the city. Today it routes tourists to amber shops with similar efficiency.\n\nEaster egg: At No. 34, a Cubist lamppost stands as one of the rarest street fixtures in the world. It has been waiting for someone to notice it for over a hundred years.`,
    cz: `Odvážný průzkumníku, kráčíš jednou z nejstarších pražských ulic — středověkou tržní cestou tak starou, že barokní fasády jsou jen nejnovějším nátěrem přes románské základy z 11. století.\n\nCeletná byla počátkem Královské cesty, kudy vcházely korunovační průvody. Dnes turisty k jantarovým obchodům navádí s podobnou účinností.\n\nEaster egg: Na č. 34 stojí kubistický sloup pouličního osvětlení — jeden z nejraritněji vzácných exemplářů na světě. Čeká, až si ho někdo všimne, přes sto let.`,
    zh: `勇敢的探险家，你走在布拉格最古老的街道之一——一条11世纪的中世纪市场通道，巴洛克外立面不过是最新一层粉刷，其下是千年的罗马式地基。\n\n采列特纳街是皇家大道的起点，加冕游行从这里进入城市。如今它以同等效率引导游客前往各家琥珀纪念品店。\n\n彩蛋：34号有一盏立体主义路灯，是世界上最罕见的街头设施之一。它已经等待有人注意它超过一百年了。`,
  },

  "strahov-library": {
    en: `Brave explorer, the Strahov Library contains two Baroque halls so magnificent they make you feel guilty for not reading more — the Theological Hall (1679) and Philosophical Hall (1794) form the finest monastic library interior in Central Europe.\n\nThe Philosophical Hall ceiling fresco was completed by Franz Maulbertsch in just six months in 1794. The monks were apparently unconcerned about impossible deadlines.\n\nEaster egg: In the corridor between the halls, a cabinet of curiosities holds a dried whale specimen and a narwhal tusk once sold as a genuine unicorn horn. The monks had broader interests than the reading material suggests.`,
    cz: `Odvážný průzkumníku, Strahovská knihovna ukrývá dva barokní sály tak velkolepé, že při jejich pohledu člověka přepadnou výčitky svědomí, že málo čte — Teologický sál (1679) a Filozofický sál (1794) tvoří nejkrásnější klášterní knižní interiér ve střední Evropě.\n\nStropní fresku Filozofického sálu dokončil Franz Maulbertsch za pouhých šest měsíců roku 1794. Mniši se zřejmě nemožnými termíny netrápili.\n\nEaster egg: V chodbě mezi sály skrývá kabinet kuriozit vyschlý velrybí exemplář a narwhalí kel, kdysi prodávaný jako pravý jednorožčí roh. Záběr mnichů byl širší, než by čtenářský charakter knihovny napovídal.`,
    zh: `勇敢的探险家，斯特拉霍夫图书馆拥有两个巴洛克大厅，美得让人觉得自己这辈子读书太少——神学厅（1679年）和哲学厅（1794年）构成中欧最精美的修道院图书馆内饰。\n\n哲学厅穹顶壁画由弗朗茨·毛尔伯奇在1794年的六个月内完成。修道士们显然对不可能完成的截止日期毫不在意。\n\n彩蛋：两厅之间的走廊藏有珍奇柜，里面有干制鲸鱼标本和曾被作为真正独角兽角销售的独角鲸牙。修道士们的兴趣爱好比书架上的读物要丰富得多。`,
  },

  "kostel-sv-jakuba-stare-mesto": {
    en: `Brave explorer, the Church of St. James the Greater has a mummified human arm hanging near the entrance — and the story behind it is exactly as medieval as you expect.\n\nFounded in 1232, rebuilt Baroque after the great fire of 1689. The arm has been there since 1400: a thief grabbed the statue of the Virgin Mary, she grabbed back, and the monks severed his arm rather than release him. Six hundred years and counting.\n\nThe organ is one of the finest in Prague. The arm is more famous.`,
    cz: `Odvážný průzkumníku, Kostel svatého Jakuba Většího má u vchodu mumifikovanou lidskou paži — a příběh za ní je přesně tak středověký, jak čekáš.\n\nZaložen roku 1232, po požáru roku 1689 přestavěn barokně. Paže tu visí od roku 1400: zloděj sáhl po soše Panny Marie, ona sáhla zpět a mniši zvolili amputaci před propuštěním. Šest set let a počítá se dál.\n\nVarhany patří k nejlepším v Praze. Paže je slavnější.`,
    zh: `勇敢的探险家，圣雅各伯大教堂入口附近挂着一只木乃伊化的人类手臂——其背后的故事和你想象的一样充满中世纪气息。\n\n教堂始建于1232年，1689年大火后重建为巴洛克风格。这条手臂自1400年起就挂在那里：一名小偷试图抓走圣母玛利亚雕像，圣母抓了回去，修道士们选择砍掉他的手臂而非放手。六百年了，还在计时。\n\n教堂的管风琴是布拉格最精美的之一。但手臂更出名。`,
  },

  "nova-radnice-marianske-namesti": {
    en: `Brave explorer, Prague's New Town Hall stands in Old Town — Prague's civic naming conventions have always been aspirational rather than literal.\n\nBuilt 1910–1912 by Osvald Polívka in Art Nouveau style on Mariánské náměstí. Two statues guard the corners: Rabbi Loew — the creator of the Golem — and the Iron Man, a ghost condemned to confess to 100 strangers every year or face eternal damnation. Extraordinarily demanding social obligations.\n\nThe city library lives inside. The Golem does not.`,
    cz: `Odvážný průzkumníku, Nová radnice stojí na Starém Městě — pražské pojmenovávání institucí bylo vždy spíše přání než skutečnost.\n\nPostavena 1910–1912 Osvaldem Polívkou v secesním stylu na Mariánském náměstí. Rohové sochy: rabín Löw — stvořitel Golema — a Železný muž, duch odsouzený každoročně zpovídat 100 cizinců, jinak propadne věčnému zatracení. Mimořádně náročné společenské závazky.\n\nUvnitř je Městská knihovna. Golem ne.`,
    zh: `勇敢的探险家，布拉格的新市政厅坐落在旧城区——布拉格的行政命名体系向来以愿望代替现实。\n\n1910-1912年由奥斯瓦尔德·波利夫卡以新艺术风格建造于玛利安广场。两尊雕像守护角落：拉比洛维——魔像的创造者——还有铁人，一个每年必须向100名陌生人忏悔否则下地狱的鬼魂，社交义务极为繁重。\n\n市立图书馆在里面。魔像不在。`,
  },

  "maiselova-synagoga": {
    en: `Brave explorer, the Maisel Synagogue was built in 1590 by Mordecai Maisel, a man so wealthy that Emperor Rudolf II attended the opening ceremony in person. When Maisel died heirless in 1601, Rudolf II confiscated his entire fortune within the week.\n\nThe original Renaissance synagogue burned in 1689 — the same catastrophic fire that hit St. James. Rebuilt Neo-Gothic in the 19th century, it now houses part of the Jewish Museum's permanent collection.\n\nMaisel bankrolled the Habsburg war machine for decades. He got a synagogue. They got the rest.`,
    cz: `Odvážný průzkumníku, Maiselova synagoga byla postavena roku 1590 Mordecajem Maiselem, mužem natolik bohatým, že na otevření přišel sám císař Rudolf II. Když Maisel roku 1601 zemřel bez dědiců, císař do týdne zkonfiskoval celé jeho jmění.\n\nPůvodní renesanční synagoga vyhořela roku 1689 — stejný katastrofický požár jako u sv. Jakuba. Ve 19. století přestavěna novogoticky, dnes je součástí stálé sbírky Židovského muzea.\n\nMaisel financoval habsburský válečný stroj po desetiletí. Dostal synagogu. Habsburkové dostali zbytek.`,
    zh: `勇敢的探险家，迈塞尔犹太会堂由莫尔代凯·迈塞尔于1590年建造——此人富可敌国，连神圣罗马皇帝鲁道夫二世都亲临开幕式。1601年迈塞尔无嗣而终，皇帝在一周之内没收了他的全部财产。\n\n原建筑在1689年大火中焚毁（与圣雅各伯教堂同一场火），19世纪重建为新哥特式，现为犹太博物馆永久馆藏展馆之一。\n\n迈塞尔数十年来赞助哈布斯堡的战争机器。他得到了一座会堂。皇帝得到了其余的一切。`,
  },

  "kostel-sv-jilji": {
    en: `Brave explorer, the Church of St. Giles has been run by Dominicans since 1626 — the same order that historically ran the Inquisition. This detail is not prominently advertised.\n\nThe Gothic church dates to 1371. Its interior was Baroquified in the 18th century with ceiling frescoes by Václav Vavřinec Reiner (1736). Reiner apparently felt no professional discomfort decorating a former Inquisition order's flagship church.\n\nRegular concerts are held here. The acoustics are excellent. The history is complicated.`,
    cz: `Odvážný průzkumníku, Kostel sv. Jiljí je od roku 1626 spravovaný dominikány — stejným řádem, který historicky vedl inkvizici. Tento detail není výrazně propagován.\n\nGotický kostel pochází z roku 1371. Interior byl v 18. století barokizován se stropními freskami Václava Vavřince Reinera (1736). Reiner zřejmě nepociťoval profesní nepohodlí při výzdobě vlajkového kostela nástupců inkvizice.\n\nKonají se tu pravidelné koncerty. Akustika výborná. Historie komplikovaná.`,
    zh: `勇敢的探险家，圣吉利斯教堂自1626年起由多明我会管理——正是历史上曾主持宗教裁判所的那个修会。这一细节并不在显眼位置标注。\n\n哥特式教堂建于1371年，18世纪改建为巴洛克风格，天顶壁画由瓦茨拉夫·雷纳于1736年绘制，是布拉格最精美的教堂内饰之一。雷纳显然对为宗教裁判所继承者的旗舰教堂绘制壁画毫无职业顾虑。\n\n这里定期举办音乐会，音效绝佳，历史复杂。`,
  },

  "kostel-sv-hastala": {
    en: `Brave explorer, the Church of St. Castulus is named after a Roman soldier martyred in 286 AD by being thrown into a pit. Prague marked this by installing a relief showing exactly how it happened, in graphic detail.\n\nOne of Old Town's quietest Gothic churches, founded in the 13th century. The name 'Haštál' is 700 years of Czech pronunciation attempting to render 'Castulus' — the telephone game played across centuries.\n\nFew tourists find this church. You found it. That distinction counts for something.`,
    cz: `Odvážný průzkumníku, Kostel svatého Haštala je pojmenován po římském vojáku, který byl roku 286 n. l. vhozen do jámy. Praha to připomíná reliéfem zobrazujícím přesně jak k tomu došlo, se vší grafičností.\n\nJeden z nejklidnějších gotických kostelů Starého Města, ze 13. století. Jméno 'Haštál' je sedmisetletý pokus české výslovnosti o zvládnutí slova 'Castulus' — telefonní hra hraná přes staletí.\n\nMálo turistů tento kostel najde. Ty jsi ho našel. Takové rozlišení má svou cenu.`,
    zh: `勇敢的探险家，圣哈什塔尔教堂以圣卡斯图卢斯命名——他是公元286年被扔入坑中殉道的罗马士兵。布拉格为此安装了一块精确展现事发经过的浮雕，细节详尽。\n\n旧城最安静的哥特式教堂之一，建于13世纪。"哈什塔尔"是七百年来捷克语对"Castulus"发音的不断尝试——一场跨越数百年的传话游戏。\n\n很少有游客能找到这座教堂。你找到了。这种差异值得认可。`,
  },

  "kostel-sv-frantiska-z-assisi": {
    en: `Brave explorer, the Church of St. Francis of Assisi was built 1679–1688 by the Knights of the Cross with the Red Star — the only Crusader military order ever founded in Bohemia, and one of the few that never disbanded. Their headquarters remains literally next door.\n\nThe dome fresco by Václav Vavřinec Reiner depicts the Last Judgment, with particularly detailed attention to those heading in the wrong direction.\n\nThe church stands at Křižovnické náměstí with a direct view of Charles Bridge's Old Town Tower. Finest approach to the bridge in the city.`,
    cz: `Odvážný průzkumníku, Kostel sv. Františka z Assisi byl postaven 1679–1688 Křižovníky s červenou hvězdou — jediným křižáckým vojenským řádem kdy vzniklým v Čechách a jedním z mála, který se nikdy nerozpustil. Jejich sídlo je doslova vedle.\n\nFreska kupole od Václava Vavřince Reinera zobrazuje Poslední soud s obzvláště detailní pozorností věnovanou těm, kdo míří špatným směrem.\n\nKostel stojí na Křižovnickém náměstí s přímým výhledem na Staroměstskou mosteckou věž Karlova mostu. Nejkrásnější přístup k mostu ve městě.`,
    zh: `勇敢的探险家，圣方济各教堂由红星骑士团于1679-1688年建造——波西米亚唯一成立的十字军骑士团，也是极少数从未解散的骑士团之一。他们的总部至今仍在隔壁。\n\n穹顶壁画由瓦茨拉夫·雷纳绘制，描绘最后的审判，对走错方向者的刻画尤为详尽。\n\n教堂矗立于十字骑士广场，正对查理大桥旧城桥塔，是全城欣赏查理大桥入口的最佳位置。`,
  },

  "kostel-sv-salvatora": {
    en: `Brave explorer, the Church of the Holy Saviour was built by Jesuits from 1578 — positioned specifically to face the Protestant-leaning Clementinum across the road. Baroque architectural passive aggression, executed at ecclesiastical scale.\n\nOne of Prague's first Baroque buildings, completed in stages until 1714. The facade statues represent saints celebrated for defeating heretics. The Counter-Reformation messaging could not be more direct.\n\nIt stands shoulder-to-shoulder with St. Francis of Assisi at Křižovnické náměstí — two religious orders on one corner, with entirely different views on the Reformation.`,
    cz: `Odvážný průzkumníku, Kostel nejsvětějšího Salvátora stavěli jezuité od roku 1578 — umístěný záměrně tak, aby mohl hledět na protestantsky nakloněné Klementinum přes ulici. Barokní architektonická pasivní agrese prováděná v církevním měřítku.\n\nJedna z prvních barokních staveb Prahy, dokončovaná etapami do roku 1714. Sochy na fasádě představují světce oslavované za vítězství nad kacíři. Protireformační poselství nemůže být přímočařejší.\n\nStojí bok po boku s kostelem sv. Františka na Křižovnickém náměstí — dva náboženské řády na jednom rohu s zcela odlišnými názory na reformaci.`,
    zh: `勇敢的探险家，至圣救主教堂由耶稣会士从1578年开始建造——位置经过刻意选择，专门用于对面凝视倾向新教的克莱门特学院。巴洛克建筑被动攻击，以宗教机构的规模执行。\n\n布拉格最早的巴洛克建筑之一，分阶段建造至1714年。正面雕像代表以击败异端著称的圣人们——反宗教改革的信息传递不能再直白了。\n\n它与圣方济各教堂肩并肩矗立于十字骑士广场——两个宗教修会共处一角，对宗教改革的看法截然不同。`,
  },

  "kostel-sv-klimenta": {
    en: `Brave explorer, the Church of St. Clement on Klimentská street has changed religious ownership more times than most Prague real estate. Founded in the 13th century, it has served Catholics, Hussites, and Catholics again, each era leaving marks on the interior.\n\nThe Baroque interior dates to the 17th–18th century overhaul, conducted at a time when Baroquifying things was the default response to most problems in Prague.\n\nPatron saint Clement was the fourth Pope, reportedly martyred by being thrown into the sea tied to an anchor. Prague churches have a recurring theme with imaginative martyrdom.`,
    cz: `Odvážný průzkumníku, Kostel sv. Klimenta na Klimentské ulici střídal náboženskou příslušnost častěji než většina pražských nemovitostí. Původně postaven ve 13. století, sloužil střídavě katolíkům, husitům a znovu katolíkům, přičemž každá éra zanechala stopy v interiéru.\n\nBarokní interiér pochází z přestavby 17.–18. století, prováděné v době, kdy barokizace byla výchozí odpovědí na většinu problémů v Praze.\n\nPatron sv. Klement byl čtvrtým papežem, podle tradice umučen uvázáním k kotvě a vhozením do moře. Pražské kostely mají opakující se téma s nápaditým mučednictvím.`,
    zh: `勇敢的探险家，克利门茨卡街的圣克莱门特教堂更换宗教归属的频率堪比布拉格大多数房产。13世纪初建，先后服务天主教徒、胡斯派，再回到天主教徒，每个时代都在内饰上留下了印记。\n\n现有巴洛克内饰源自17-18世纪的大整修——那个年代，巴洛克化几乎是布拉格应对大多数问题的默认方案。\n\n守护圣人克莱门特是第四任教皇，据传被绑在铁锚上投入大海而殉道。布拉格的教堂对富有想象力的殉道方式情有独钟。`,
  },

  "kostel-sv-petra-na-porici": {
    en: `Brave explorer, the Church of St. Peter at Poříčí is one of Prague's oldest surviving churches, founded in the 12th century in what was then a riverside settlement called Poříčí — meaning 'riverbank area'. The Vltava has since relocated its priorities.\n\nRomanesque foundations survive beneath Gothic and Baroque modifications added over the centuries. The church has outlasted Hussite wars, Habsburg consolidation, and the construction of a metro line below its feet.\n\nNa Poříčí is now a busy commercial thoroughfare. The church stands among the storefronts, quietly outlasting all of them.`,
    cz: `Odvážný průzkumníku, Kostel sv. Petra na Poříčí je jedním z nejstarších dochovaných pražských kostelů, z 12. století, v tehdejším říčním osídlení zvaném Poříčí. Vltava od té doby přesunula své priority jinam.\n\nRománské základy přežily gotické i barokní úpravy přidávané po staletí. Kostel přečkal husitské války, habsburskou konsolidaci i výstavbu linky metra pod svými základy.\n\nNa Poříčí je dnes rušným obchodním bulvárem. Kostel stojí mezi obchody a tiše je všechny přežívá.`,
    zh: `勇敢的探险家，波日奇圣彼得教堂是布拉格现存最古老的教堂之一，12世纪初建于当时名为波日奇的河岸聚落——意为"河岸地带"。伏尔塔瓦河此后将重心转移他处。\n\n罗马式地基在数百年来叠加的哥特式与巴洛克式改建下依然存留。教堂历经胡斯战争、哈布斯堡整合和脚下地铁线的修建，始终屹立。\n\n波日奇街如今是繁忙的商业干道。教堂伫立于商铺之间，静静地比所有人都活得更长。`,
  },

  "nova-obradni-sin": {
    en: `Brave explorer, the New Ceremonial Hall was built in 1906 by the Prague Jewish Burial Society — the Chevra Kadisha — the brotherhood responsible for preparing the dead for burial according to Jewish law. It is the last building the departed passed through before entering the Old Jewish Cemetery next door.\n\nThe Neo-Romanesque building now houses a permanent exhibition on Jewish customs of death, mourning, and burial in Bohemia and Moravia. Every ritual has a name, a reason, and a history longer than most cities.\n\nEaster egg: The Chevra Kadisha was one of Prague's most prestigious organisations. Membership was a mark of communal honour, not a grim duty. The Jewish community had long understood something that modern society still works hard to avoid thinking about.`,
    cz: `Odvážný průzkumníku, Nová obřadní síň byla postavena roku 1906 pražským pohřebním bratrstvem — Chevra Kadiša — společenstvím zodpovědným za přípravu zemřelých k pohřbu podle židovského zákona. Je to poslední budova, kudy procházeli zesnulí před vstupem na Starý židovský hřbitov vedle.\n\nNeorománská budova nyní hostí stálou výstavu o židovských zvycích při úmrtí, truchlení a pohřbívání v Čechách a na Moravě. Každý rituál má jméno, důvod a historii delší, než má většina měst.\n\nEaster egg: Chevra Kadiša bylo jedno z nejprestižnějších pražských sdružení. Členství bylo znamením komunitní cti, ne pochmurnou povinností. Židovská komunita už dávno pochopila něco, co se moderní společnost stále snaží nevnímat.`,
    zh: `勇敢的探险家，新礼仪厅由布拉格犹太葬礼协会——圣社——于1906年建造。这个兄弟会负责按照犹太律法为逝者做最后的准备。这是亡者在进入隔壁旧犹太公墓之前经过的最后一座建筑。\n\n这座新罗马式建筑现收藏波西米亚和摩拉维亚犹太死亡、哀悼与安葬习俗的永久展览。每一个仪式都有名字、缘由，以及比大多数城市历史更为悠久的传统。\n\n彩蛋：圣社曾是布拉格最负盛名的组织之一。加入其中是社区荣誉的标志，而非沉重的义务。犹太社区早已理解了某些现代社会至今仍竭力回避思考的事情。`,
  },

  "vysoka-synagoga": {
    en: `Brave explorer, the High Synagogue earned its name honestly — the prayer hall is on the upper floor. Built in 1568 under Emperor Maximilian II, it was designed as a companion to the adjacent Jewish Town Hall, sharing a roofline so it would not appear too prominent from street level. Modesty as architecture.\n\nThe synagogue now houses a remarkable exhibition of historical Jewish textiles and Torah ornaments collected from across Bohemia. These objects survived the Holocaust because the Nazis documented everything they looted with meticulous precision.\n\nEaster egg: The Nazi inventories of confiscated Jewish property were so thorough and detailed that their own records became the primary source for postwar Holocaust restitution claims. The perpetrators inadvertently preserved the evidence against themselves.`,
    cz: `Odvážný průzkumníku, Vysoká synagoga si svůj název zasloužila poctivě — modlitební sál je v patře. Postavena roku 1568 za vlády císaře Maxmiliána II., byla navržena jako přístavba sousední Židovské radnice, sdílející s ní střešní linii, aby z úrovně ulice nevypadala příliš okázale. Pokora jako architektura.\n\nSynagoga nyní hostí pozoruhodnou výstavu historických židovských textilií a ozdob Tóry, shromážděných z celých Čech. Tyto předměty holocaust přežily proto, že nacisté vše, co uloupili, zaznamenávali s pedantskou přesností.\n\nEaster egg: Nacistické soupisy konfiskovaného židovského majetku byly tak důkladné a podrobné, že jejich vlastní záznamy se staly primárním pramenem pro poválečné restituce za holocaust. Pachatelé tím neúmyslně zachovali důkazy proti sobě.`,
    zh: `勇敢的探险家，高犹太会堂以最诚实的方式赢得了它的名字——祈祷大厅在楼上。建于1568年，神圣罗马皇帝马克西米利安二世在位期间，它被设计为与隔壁犹太市政厅共用屋顶线，以免从街道层面看起来过于显眼。谦逊，作为一种建筑语言。\n\n会堂现收藏有一批来自波西米亚各地的历史犹太纺织品和托拉装饰品展览。这些物品在大屠杀中得以幸存，是因为纳粹对他们掠夺的一切都做了一丝不苟的记录。\n\n彩蛋：纳粹对没收犹太财产的记录如此详尽，以至于他们自己的档案成为战后大屠杀赔偿申请的主要史料来源。施害者无意间为对抗自身的指控保留了证据。`,
  },

  "jerusalem-synagogue": {
    en: `Brave explorer, the Jerusalem Synagogue is Prague's largest — and most flamboyant — synagogue: a spectacle of Moorish arches, Art Nouveau stained glass, and polychrome tilework that causes more tourists to mistake it for a mosque than any other building in the city. This is not accidental.\n\nBuilt 1905–1906 to replace three synagogues demolished during the city's compulsory 'sanitation' of the Jewish ghetto, it was funded as a declaration of permanence after displacement. The Moorish Revival style references the golden age of Jewish life in Moorish Spain — chosen with some bitterness.\n\nEaster egg: The synagogue is nicknamed the 'Jubilee Synagogue' because it was consecrated in 1906 during Emperor Franz Joseph I's regnal jubilee. The emperor was considered unusually tolerant of Jews by Habsburg standards — the bar was historically low, but he clears it.`,
    cz: `Odvážný průzkumníku, Jeruzalémská synagoga je největší — a nejokázalejší — pražskou synagogou: podívaná maurských oblouků, secesních vitráží a polychromního obkládání, která způsobuje, že ji více turistů zaměňuje za mešitu než jakoukoli jinou budovu ve městě. To není náhoda.\n\nPostavena 1905–1906 jako náhrada za tři synagogy zbořené při povinné 'asanaci' pražského židovského ghetta, byla financována jako prohlášení trvalosti po vysídlení. Maurský revival odkazuje na zlatý věk židovského života v maurském Španělsku — zvolený s jistou hořkostí.\n\nEaster egg: Synagoga má přezdívku 'Jubilejní', protože byla vysvěcena roku 1906 při jubilejní slavnosti vlády císaře Františka Josefa I. Císař byl v habsburském standardu považován za neobvykle tolerantního vůči Židům — laťka byla historicky nízko, ale on přes ni přeskočil.`,
    zh: `勇敢的探险家，耶路撒冷犹太会堂是布拉格最大——也是最张扬——的会堂：摩尔式拱门、新艺术风格彩色玻璃窗和多彩瓷砖装饰交织的视觉奇观，让它成为全城被游客误认为清真寺次数最多的建筑。这并非偶然。\n\n1905-1906年建造，用以替代在城市强制"卫生整治"犹太区过程中被拆除的三座会堂，以社区资金建造，是经历迁徙后宣示永久存在的声明。摩尔复兴风格指涉犹太人在摩尔式西班牙的黄金时代——带着几分苦涩的选择。\n\n彩蛋：这座会堂有"禧年会堂"的别名，因为它于1906年皇帝弗兰茨·约瑟夫一世在位禧年期间落成献堂。这位皇帝以哈布斯堡标准被认为对犹太人异乎寻常地宽容——历史上的门槛本就不高，但他跨过去了。`,
  },

  "zidovska-radnice": {
    en: `Brave explorer, the Jewish Town Hall has two clocks on its tower. The upper clock runs clockwise, with Roman numerals. The lower clock runs counter-clockwise, with Hebrew letters instead of numerals — because Hebrew is written right to left, so the hands move accordingly. It is the only building in Prague where time literally runs backwards.\n\nOriginally built in 1577, funded by Mordecai Maisel (the same man who built the Maisel Synagogue), the current Baroque building dates from 1763. It remains the administrative seat of the Prague Jewish community to this day — one of the only Jewish communal institutions in Central Europe with continuous, unbroken operation across five centuries.\n\nEaster egg: During WWII, the Nazis forced the Jewish community to establish a Judenrat — a Jewish council — in this building to administer deportation logistics. The institution survived the war intact. Most of the people who worked in it did not.`,
    cz: `Odvážný průzkumníku, Židovská radnice má na věži dvoje hodiny. Horní hodiny jdou po směru hodinových ručiček, s římskými číslicemi. Dolní hodiny jdou proti směru hodinových ručiček, s hebrejskými písmeny místo číslic — protože hebrejština se píše zprava doleva, takže ručičky se pohybují podle toho. Je to jediná budova v Praze, kde čas doslova běží pozpátku.\n\nPůvodně postaven roku 1577, financován Mordecajem Maiselem (stejným mužem, který postavil Maiselovu synagogu), dnešní barokní budova pochází z roku 1763. Dodnes je administrativním sídlem pražské židovské obce — jedna z mála židovských komunitních institucí ve střední Evropě s nepřerušenou pětisetletou kontinuitou.\n\nEaster egg: Během druhé světové války nacisté přinutili židovskou komunitu zřídit v této budově Judenrat — židovskou radu — k řízení logistiky deportací. Instituce válku přežila neporušena. Většina lidí, kteří v ní pracovali, nikoli.`,
    zh: `勇敢的探险家，犹太市政厅塔楼上有两面时钟。上面那面顺时针运转，配有罗马数字。下面那面逆时针运转，用希伯来字母代替数字——因为希伯来语从右往左书写，指针也随之移动。这是布拉格唯一一座时间真正倒流的建筑。\n\n最初建于1577年，由莫尔代凯·迈塞尔出资（就是建造迈塞尔会堂的同一个人），现存巴洛克建筑建于1763年。时至今日，它仍是布拉格犹太社区的行政总部——中欧极少数延续五百年、从未中断运作的犹太社区机构之一。\n\n彩蛋：二战期间，纳粹强迫犹太社区在这栋建筑内设立犹太理事会，负责管理驱逐流程。这个机构完好无损地熬过了战争。在其中工作的大多数人没有。`,
  },

  "kostel-sv-havla": {
    en: `Brave explorer, the Church of St. Gall is named after St. Gallus — an Irish monk who wandered through Europe in the 7th century, founded a hermitage in what is now Switzerland (St. Gallen), and was later adopted as 'Havel' by the Czechs. The name stuck to the church, the square, and the market.\n\nThe Havelský trh — Havel's Market — has operated in front of this church since the 13th century, making it one of the oldest continuously running markets in Prague. It now sells flowers, fruit, and tourist trinkets, in what might be described as a gradient of decreasing authenticity.\n\nEaster egg: Czech tourists occasionally mistake this for a Václav Havel memorial site. It is not. St. Gallus died in 640. The confusion is understandable. The timeline is not.`,
    cz: `Odvážný průzkumníku, Kostel sv. Havla je pojmenován po sv. Havlovi — irském mnichovi, který v 7. století putoval Evropou, založil poustevnu v dnešním Švýcarsku (St. Gallen) a byl Čechy přijat jako Havel. Jméno se přichytilo ke kostelu, náměstí i trhu.\n\nHavelský trh před tímto kostelem funguje od 13. století, čímž patří k nejstarším nepřetržitě fungujícím trhům v Praze. Dnes se na něm prodávají květiny, ovoce a turistické suvenýry — v tom, co by se dalo popsat jako gradient klesající autentičnosti.\n\nEaster egg: Čeští turisté si toto místo občas pletou s památníkem Václava Havla. Není. Sv. Gallus zemřel roku 640. Záměna je pochopitelná. Časová osa není.`,
    zh: `勇敢的探险家，圣加卢斯教堂以圣加卢斯命名——他是7世纪在欧洲各地流浪的爱尔兰修道士，在今天的瑞士建立了一处隐修地（即圣加仑），后来被捷克人称为"哈维尔"。这个名字就此附在了教堂、广场和市场上。\n\n教堂前的哈维尔市场自13世纪起持续运营，是布拉格延续时间最长的市场之一。如今这里出售鲜花、水果和旅游纪念品，可以说是一个真实性依次递减的渐变带。\n\n彩蛋：捷克游客偶尔会误以为这里是瓦茨拉夫·哈维尔纪念地。并不是。圣加卢斯去世于640年。混淆情有可原。时间线上并不成立。`,
  },

  "muzeum-fantastickych-iluzi": {
    en: `Brave explorer, the Museum of Fantastic Illusions offers three floors of optical illusions, trick art, holography, and mirror labyrinths — the kind of attraction where photos are mandatory, orientation is optional, and your own brain becomes the unreliable narrator.\n\nThe museum sits less than 200 metres from Wenceslas Square, which means you can spend the morning watching the real city and the afternoon watching the unreal city, with only a short walk in between.\n\nEaster egg: Prague is the city where Kafka wrote stories about men turned into insects and bureaucracies that defeat all reason. A museum about things that aren't what they seem fits the local tradition perfectly.`,
    cz: `Odvážný průzkumníku, Muzeum fantastických iluzí nabízí tři patra optických klamů, trikového umění, holografie a labyrintů zrcadel — druh atrakce, kde jsou fotografie povinné, orientace volitelná a váš vlastní mozek se stává nespolehlivým vypravěčem.\n\nMuzeum stojí méně než 200 metrů od Václavského náměstí, což znamená, že ráno můžete trávit sledováním skutečného města a odpoledne sledováním neskutečného — s krátkou procházkou uprostřed.\n\nEaster egg: Praha je město, kde Kafka psal příběhy o mužích proměněných v hmyz a o byrokraciích, jež porážejí veškerý rozum. Muzeum o věcech, které nejsou tím, čím se zdají, dokonale odpovídá místní tradici.`,
    zh: `勇敢的探险家，奇幻错觉博物馆提供三层视觉错觉、立体艺术、全息摄影和镜子迷宫——在这里，拍照是必须的，方向感是可选的，而你自己的大脑成了最不可信赖的叙述者。\n\n博物馆距瓦茨拉夫广场不足200米，这意味着你可以上午花时间观察真实的城市，下午花时间观察不真实的城市，中间只需步行片刻。\n\n彩蛋：布拉格是一座卡夫卡写下人变虫子、官僚机构战胜一切理性的故事的城市。一座专门展示事物并非表象的博物馆与本地传统完美契合。`,
  },

  "kostel-sv-martina-ve-zdi": {
    en: `Brave explorer, the Church of St. Martin in the Wall earned its name honestly: when it was built in the 12th century, it was literally incorporated into Prague's Old Town fortification wall. The wall is long gone. The church remains.\n\nOn October 3, 1414, in this church, Jakoubek ze Stříbra administered communion in both kinds — bread and wine — to laypeople for the first time in Bohemia. This utraquist practice became the central demand of the Hussite movement and a principal cause of the Hussite Wars. Jan Hus was already in Constance awaiting trial when it happened. He was executed the following year.\n\nEaster egg: The chalice — symbol of receiving both kinds — became the defining emblem of Czech religious and national identity for the next two centuries and still appears on Prague's coat of arms today. A single church service changed the trajectory of Central European history.`,
    cz: `Odvážný průzkumníku, Kostel sv. Martina ve zdi si zasloužil svůj název poctivě: když byl ve 12. století postaven, byl doslova zabudován do hradeb Starého Města. Hradby jsou dávno pryč. Kostel zůstává.\n\n3. října 1414 v tomto kostele podal Jakoubek ze Stříbra poprvé v Čechách přijímání pod obojí způsobou — chléb i víno — laikům. Tato utrakvistická praxe se stala ústředním požadavkem husitského hnutí a jednou z hlavních příčin husitských válek. Jan Hus byl tehdy již v Kostnici, kde čekal na soud. Byl popraven následujícího roku.\n\nEaster egg: Kalich — symbol přijímání pod obojí způsobou — se stal určujícím symbolem českého náboženského a národního identity na příštích dvě staletí a dodnes se objevuje na znaku Prahy. Jedna bohoslužba změnila trajektorii středoevropských dějin.`,
    zh: `勇敢的探险家，墙中圣马丁教堂名副其实：12世纪建造时，它确实被嵌入了布拉格旧城的城墙防御工事中。城墙早已消失。教堂依然矗立。\n\n1414年10月3日，在这座教堂里，雅克贝克·泽斯特里伯拉首次在波西米亚向平信徒施行两种形式的圣餐——面饼与圣酒。这就是圣杯派的做法，它成为胡斯运动的核心诉求，也是胡斯战争的主要起因之一。扬·胡斯当时已身在康斯坦茨等待受审，翌年被处决。\n\n彩蛋：圣杯——领受两种形式圣餐的象征——在此后两个世纪里成为捷克宗教与民族认同的标志性符号，至今仍出现在布拉格的市徽上。一场弥撒改变了中欧历史的走向。`,
  },

  "kostel-sv-bartolomeje": {
    en: `Brave explorer, the Church of St. Bartholomew in Bartolomějská street is Gothic, peaceful, and easy to overlook — which is appropriate, because the building next to it is not.\n\nThe adjoining Baroque convent became the headquarters of the Communist secret police (Státní bezpečnost — StB) in 1948. The cells were used as interrogation rooms. Former inmates described hearing hymns from the church through the walls during their detention. The convent was returned to the Franciscan sisters in 1990. The church never left.\n\nEaster egg: During Pope John Paul II's visit to Prague in 1997, he prayed in the former StB prison chapel in this building — a gesture that required no commentary. He was the pope widely credited with helping bring down Communist regimes across Eastern Europe. The address was not coincidental.`,
    cz: `Odvážný průzkumníku, Kostel sv. Bartoloměje v Bartolomějské ulici je gotický, klidný a snadno přehlédnutelný — což je vhodné, protože budova vedle není.\n\nPřilehlý barokní klášter se roku 1948 stal sídlem komunistické Státní bezpečnosti (StB). Cely sloužily jako výslechové místnosti. Bývalí vězni popisovali, jak slyšeli skrze zdi kostelní zpěv. Klášter byl v roce 1990 vrácen františkánským sestrám. Kostel nikdy neopustily.\n\nEaster egg: Při návštěvě Jana Pavla II. v Praze roku 1997 se papež modlil v bývalé vězeňské kapli StB v této budově — gesto, které nepotřebovalo žádný komentář. Byl to papež, jemuž byl připisován zásadní podíl na pádu komunistických režimů ve východní Evropě. Adresa nebyla náhodná.`,
    zh: `勇敢的探险家，巴托洛梅斯卡街上的圣巴托洛梅奥教堂是哥特式的，宁静的，容易被忽视的——这恰如其分，因为隔壁的建筑并非如此。\n\n毗邻的巴洛克修道院于1948年成为共产党国家安全局（StB）的总部。修道院的牢房被用作审讯室。前被拘留者描述说，在被拘期间能透过墙壁听到教堂传来的圣歌。修道院于1990年归还给方济各会修女。教堂从未离开。\n\n彩蛋：1997年教皇若望保禄二世访问布拉格时，他在这栋楼内昔日的国安局监狱小礼拜堂中祈祷——一个无需任何注释的举动。这位教皇被广泛认为在推翻东欧共产主义政权中发挥了重要作用。选择这个地址并非偶然。`,
  },

  "rotunda-sv-krize": {
    en: `Brave explorer, the Rotunda of the Finding of the Holy Cross is one of Prague's three surviving Romanesque rotundas — round churches built in the 11th–12th century that predate Gothic architecture by several hundred years. It sits in a narrow lane off Konviktská street and is easy to walk past without noticing.\n\nThe name comes from the legend of Helena, mother of Emperor Constantine, who reportedly found the True Cross in Jerusalem in 326 AD. Prague has maintained this rotunda commemorating the discovery since the 12th century, which is a long time to sustain enthusiasm for a relic-finding story.\n\nEaster egg: The building is so small it is largely indistinguishable from a garden outbuilding at first glance. The thousand-year age reveal requires reading the plaque. Prague hides its oldest buildings in plain sight.`,
    cz: `Odvážný průzkumníku, Rotunda Nalezení sv. Kříže je jednou ze tří dochovaných románských rotund Prahy — kulatých kostelíků z 11.–12. století, předcházejících gotiku o několik set let. Stojí v úzké uličce u Konviktské ulice a je snadné jít kolem a nevšimnout si jí.\n\nJméno pochází z legendy o Heleně, matce císaře Konstantina, která prý nalezla Pravý kříž v Jeruzalémě roku 326 n. l. Praha tuto rotundu připomínající nalezení udržuje od 12. století, což je dlouhá doba zachovávat nadšení pro příběh o nalezení ostatku.\n\nEaster egg: Budova je tak malá, že na první pohled ji lze těžko odlišit od zahradního domku. Tisíciletý věk odhalíte až přečtením desky. Praha schovává své nejstarší stavby na odlehlých místech přede zraky všech.`,
    zh: `勇敢的探险家，寻获圣十字圆形教堂是布拉格现存的三座罗马式圆形教堂之一——建于11至12世纪的圆形教堂，比哥特式建筑早了几百年。它位于康维克茨卡街旁的一条窄巷中，很容易路过而浑然不觉。\n\n名字来源于君士坦丁皇帝之母海伦娜的传说，据说她于公元326年在耶路撒冷发现了真十字架。布拉格自12世纪起就保有这座纪念此发现的圆形教堂，为纪念一则遗物发现故事而保持了如此漫长的热忱。\n\n彩蛋：这座建筑太小，乍一看与花园小屋几乎无法区分。千年的年龄只有读了铭牌才能得知。布拉格将它最古老的建筑藏在众目睽睽之下。`,
  },

  "zamek-panenske-brezany": {
    en: `Brave explorer, Panenské Břežany Upper Castle is a Baroque manor north of Prague that became the official residence of Reinhard Heydrich — Reich Protector of Bohemia and Moravia, architect of the Holocaust, referred to in wartime documents as 'the most dangerous man in the Third Reich'. He moved in with his family in 1941.\n\nOn May 27, 1942, British-trained Czech and Slovak paratroopers (Operation Anthropoid) attacked his open-top car on his daily commute from this castle. He died of his wounds on June 4. Hitler's response included the complete destruction of the village of Lidice, which had no connection to the assassination. The paratroopers were killed in the Cathedral of Saints Cyril and Methodius.\n\nEaster egg: After the war, the castle became a scientific research institute. The dark history is not prominently documented on site. What happened here is the reason Lidice was destroyed — and why the Cathedral of Saints Cyril and Methodius has bullet holes in its crypt.`,
    cz: `Odvážný průzkumníku, Horní zámek Panenské Břežany je barokní sídlo severně od Prahy, které se stalo oficiálním sídlem Reinharda Heydricha — říšského protektora Čech a Moravy, architekta holocaustu, v válečných dokumentech označovaného jako 'nejnebezpečnější muž Třetí říše'. Nastěhoval se sem s rodinou roku 1941.\n\n27. května 1942 britsky vycvičení čeští a slovenští výsadkáři (operace Anthropoid) zaútočili na jeho otevřený automobil při každodenní cestě z tohoto zámku. Zemřel na svá zranění 4. června. Hitlerova reakce zahrnovala úplné zničení obce Lidice, jež s atentátem neměla žádnou spojitost. Výsadkáři byli zabiti v kryptě katedrály sv. Cyrila a Metoděje.\n\nEaster egg: Po válce se zámek stal vědeckým výzkumným ústavem. Temná historie není na místě výrazně dokumentována. Co se tu stalo, je důvod, proč byly Lidice zničeny — a proč jsou v kryptě katedrály sv. Cyrila a Metoděje kulometné stopy.`,
    zh: `勇敢的探险家，帕内内斯凯布热扎尼上城堡是布拉格北部一座巴洛克庄园，成为莱因哈德·海德里希的官方驻地——波西米亚和摩拉维亚的帝国保护长官，大屠杀的设计者，战时文件中被称为"第三帝国最危险的人"。他于1941年携家入住。\n\n1942年5月27日，英国训练的捷克和斯洛伐克伞兵（人类行动）在他每天从这座城堡上班途中袭击了他的敞篷汽车。他于6月4日因伤去世。希特勒的回应包括彻底摧毁利迪策村——一个与暗杀毫无关联的村庄。伞兵们被杀死在圣西里尔与美多迪主教座堂的地下室。\n\n彩蛋：战后，城堡成为一个科研机构。这段黑暗历史在现场没有被显著记录。这里发生的事情是利迪策被摧毁的原因——也是圣西里尔与美多迪主教座堂地下室墙上留有弹痕的原因。`,
  },

  "zamek-brandys-nad-labem": {
    en: `Brave explorer, Brandýs nad Labem Castle is a Renaissance chateau above the Labe (Elbe) river, rebuilt for the Habsburgs in the early 16th century on the site of an older Gothic fortress and used as a royal summer residence for generations.\n\nEmperor Rudolf II spent considerable time here between his astronomical obsessions in Prague. His court attracted alchemists, astrologers, and scientists in approximately that order of credibility. The castle was more relaxed than the Prague court and apparently more comfortable than the stars.\n\nEaster egg: Jan Ámos Komenský — Comenius, the 17th-century educator who invented the modern illustrated textbook and influenced educational systems across three continents — spent time in this region during the Thirty Years' War before being exiled after White Mountain. His educational reforms outlasted the empire that expelled him.`,
    cz: `Odvážný průzkumníku, Zámek Brandýs nad Labem je renesanční zámek nad řekou Labem, přestavěný pro Habsburky na počátku 16. století na místě starší gotické tvrze a po generace sloužící jako letní rezidence panovníků.\n\nCísař Rudolf II. trávil zde značný čas mezi svými astronomickými posedlostmi v Praze. Jeho dvůr přitahoval alchymisty, astrology a vědce přibližně v tomto pořadí důvěryhodnosti. Zámek byl uvolněnější než pražský dvůr a zřejmě pohodlnější než hvězdy.\n\nEaster egg: Jan Ámos Komenský — pedagog 17. století, který vynalezl moderní ilustrovanou učebnici a ovlivnil vzdělávací systémy na třech kontinentech — strávil čas v tomto regionu za třicetileté války, než byl po Bílé hoře vyhnán. Jeho vzdělávací reformy přežily říši, která ho vypověděla.`,
    zh: `勇敢的探险家，拉贝河畔布兰迪斯城堡是一座俯瞰拉贝（易北）河的文艺复兴风格城堡，16世纪初为哈布斯堡家族在更早的哥特式堡垒遗址上改建，历代作为皇家夏宫使用。\n\n皇帝鲁道夫二世在布拉格的天文学痴迷之余，在此度过了大量时间。他的宫廷以吸引炼金术士、占星家和科学家著称——大致按此可信度排序。城堡比布拉格宫廷更轻松，显然也比繁星更为舒适。\n\n彩蛋：扬·阿莫斯·科梅尼乌斯——17世纪教育家，发明了现代插图教科书并影响了三大洲的教育体系——三十年战争期间在这一地区度过了一段时间，随后在白山之战后被流放。他的教育改革比驱逐他的帝国存活得更久。`,
  },

  "ricany": {
    en: `Brave explorer, Říčany is a medieval market town southeast of Prague that has spent the last three decades being absorbed into Prague's suburban sprawl, one commuter at a time. The old town centre — with its Gothic church and remnants of fortification — predates the suburbs by about six centuries.\n\nThe town had one of Bohemia's earliest Jewish communities outside Prague, established in the medieval period. The Jewish quarter and cemetery survive. The town's history is considerably longer and more layered than its current role as a commuter hub would suggest.\n\nEaster egg: The original Říčany Castle — a 14th-century fortress — was demolished by its own owners in the 16th century for building materials. The stones were repurposed into other buildings. The castle's absence is more thoroughly documented than most buildings' presence.`,
    cz: `Odvážný průzkumníku, Říčany jsou středověké trhové město jihovýchodně od Prahy, které posledních třicet let pohltila pražská příměstská zástavba, jednoho pendlera za druhým. Staré centrum s gotickým kostelem a zbytky opevnění předchází předměstí o přibližně šest století.\n\nMěsto mělo jednu z nejstarších židovských obcí v Čechách mimo Prahu, ustavenou ve středověku. Židovská čtvrť a hřbitov přežily. Historie města je podstatně delší a vrstvnatější, než jeho současná role příměstského uzlu napovídá.\n\nEaster egg: Původní říčanský hrad — tvrz ze 14. století — byl v 16. století zbořen svými vlastníky pro stavební materiál. Kameny skončily v jiných budovách. Absence hradu je historicky dokumentována lépe než přítomnost většiny budov.`,
    zh: `勇敢的探险家，日查尼是布拉格东南方的一座中世纪集市小镇，在过去三十年里被布拉格郊区扩张逐步吞并，一个通勤者接着一个通勤者。旧城中心有哥特式教堂和防御工事遗迹，比郊区早了大约六个世纪。\n\n这座城镇拥有波西米亚最早的布拉格以外犹太社区之一，建立于中世纪。犹太区和墓地得以保存。这座城镇的历史比其目前作为通勤枢纽的角色所揭示的要悠久和丰富得多。\n\n彩蛋：原日查尼城堡——14世纪的要塞——在16世纪被其主人拆除以获取建筑材料。石头被用于其他建筑。城堡的缺席比大多数建筑的存在记录得更为详细。`,
  },

  "chvalsky-zamek": {
    en: `Brave explorer, Chvaly Chateau is a Baroque manor in the Horní Počernice district of northeastern Prague, built in the early 18th century on the site of an older Renaissance residence. It is the kind of place that appears on local heritage maps and surprises visitors who did not know it existed.\n\nThe chateau grounds include a small English-style park and a series of outbuildings that have served various uses across the centuries. The property is managed by Prague's municipal authority and used for cultural events, having previously served as a school, an agricultural cooperative, and several other purposes that Baroque architecture was not originally designed for.\n\nEaster egg: The chateau's most architecturally notable feature is its unusual courtyard layout rather than a compact block — considered provincial at the time of construction. Three hundred years later, it reads as distinctive.`,
    cz: `Odvážný průzkumníku, Chvalský zámek je barokní sídlo v části Horní Počernice v severovýchodní Praze, postavené na počátku 18. století na místě staršího renesančního sídla. Je to druh místa, který se objevuje na místních mapách kulturního dědictví a překvapí návštěvníky, kteří netušili, že existuje.\n\nZámecký areál zahrnuje malý anglický park a řadu hospodářských budov, jež v průběhu staletí sloužily k různým účelům. Objekt spravuje pražský magistrát a využívá pro kulturní akce, předtím sloužil jako škola, zemědělské družstvo a k dalším účelům, pro které barokní architektura původně nebyla navržena.\n\nEaster egg: Architektonicky nejpozoruhodnějším prvkem zámku je jeho neobvyklé uspořádání kolem dvora namísto kompaktního bloku — v době výstavby považované za provinciální. O tři sta let později to působí jako svébytné.`,
    zh: `勇敢的探险家，赫瓦利城堡是布拉格东北部霍日尼波切尔尼采地区的一座巴洛克庄园，18世纪初建于更早的文艺复兴式建筑遗址上。这是那种出现在地方遗址地图上、让不知其存在的游客感到惊喜的地方。\n\n城堡庭院包括一个小型英式花园和一系列附属建筑，数百年来用途各异。该建筑由布拉格市政当局管理，用于举办文化活动，此前曾作为学校、农业合作社以及其他几种巴洛克建筑当初并未设计用途的场所。\n\n彩蛋：城堡最具建筑趣味的特色是其不寻常的围绕庭院而非紧凑方块的布局——建造时被认为是乡土风格。三百年后，这却成了与众不同的标志。`,
  },

  "rozhledna-doubravka": {
    en: `Brave explorer, the DOUBRAVKA XIV lookout tower is a 21-metre wooden observation tower in the Horní Měcholupy area of eastern Prague, opened in 2016 as part of Prague's network of hilltop viewpoints.\n\nThe name combines 'doubrava' — Czech for an oak grove — with the Roman numeral XIV, because this was the fourteenth lookout tower built in Prague as part of a coordinated city-wide programme. Prague has been systematically installing observation towers the way other cities install bus shelters: methodically, across the entire city, with signage.\n\nEaster egg: From the top, you can see the D1 motorway, Horní Měcholupy housing estates, and on clear days portions of the Bohemian Central Highlands. What it lacks in drama it compensates in comprehensiveness. The fourteenth tower exists because somebody was keeping count.`,
    cz: `Odvážný průzkumníku, Rozhledna DOUBRAVKA XIV je 21metrová dřevěná vyhlídková věž v části Horní Měcholupy ve východní Praze, otevřená roku 2016 jako součást sítě pražských vyhlídkových bodů na kopcích.\n\nJméno kombinuje 'doubrava' — český výraz pro dubový háj — s římskou číslicí XIV, protože tato věž byla čtrnáctou vyhlídkovou věží postavenou v Praze jako součást koordinovaného celoměstského programu. Praha systematicky instaluje vyhlídkové věže, jako jiná města instalují autobusové zastávky: metodicky, po celém městě, se značením.\n\nEaster egg: Z vrcholu je vidět dálnice D1, sídliště Horní Měcholupy a za jasného počasí části Českého středohoří. Co jí chybí na dramatičnosti, vynahrazuje se komplexností. Čtrnáctá věž existuje proto, že někdo počítal.`,
    zh: `勇敢的探险家，多布拉夫卡十四号瞭望塔是布拉格东部霍日尼梅霍卢皮地区一座21米高的木制观景塔，2016年作为布拉格山顶观景点网络的一部分建成开放。\n\n名字结合了"doubrava"——捷克语中的"橡树林"——和罗马数字XIV，因为这是布拉格作为协调的全市计划建造的第十四座瞭望塔。布拉格系统性地安装观景塔，就像其他城市安装公交站亭一样：有条不紊，遍布全市，配有指示牌。\n\n彩蛋：从顶部可以看到D1高速公路、霍日尼梅霍卢皮住宅区，晴天还能看到波西米亚中央高地的部分景色。在戏剧性方面的缺乏被全面性所弥补。第十四座塔的存在，是因为有人在计数。`,
  },

  "michelska-vodarenska-vez": {
    en: `Brave explorer, the Michle Water Tower was built between 1906 and 1910 in Neo-Romanesque style — architecturally ambitious for a church, remarkable for a municipal water pressure equalisation tank. Prague consistently built its infrastructure as if it might be judged on appearances.\n\nThe tower formed part of the expanding water supply network for Prague's southern neighbourhoods as the city grew rapidly in the early 20th century. City engineers had strong opinions about what functional hydraulic infrastructure should look like from the street, and they acted on those opinions.\n\nEaster egg: The tower stands in a residential area of Michle that otherwise makes no particular claims to architectural distinction. It has outlasted its original purpose and is now a listed cultural monument. Prague has protected water towers that most cities would have quietly demolished.`,
    cz: `Odvážný průzkumníku, Michelská vodárenská věž byla postavena v letech 1906–1910 v neorománském stylu — architektonicky ambiciózním pro kostel, pozoruhodném pro obecní vyrovnávací vodní nádrž. Praha důsledně budovala svou infrastrukturu, jako by mohla být souzena podle vzhledu.\n\nVěž tvořila součást rozrůstající se sítě zásobování vodou pro jižní části Prahy, jež v počátku 20. století rychle rostla. Městští inženýři měli silné názory na to, jak má funkční hydraulická infrastruktura vypadat z ulice, a podle toho jednali.\n\nEaster egg: Věž stojí v obytné části Michle, která jinak nemá zvláštní architektonické nároky. Přežila svůj původní účel a je nyní zapsána jako chráněná kulturní památka. Praha chrání vodárenské věže, které by většina měst tiše zbourala.`,
    zh: `勇敢的探险家，米赫莱水塔于1906年至1910年间以新罗马风格建造——这种风格用在教堂上已属雄心勃勃，用在市政水压平衡水箱上则令人称奇。布拉格始终如一地把它的基础设施建造得好像要接受外观评判一样。\n\n这座水塔是20世纪初布拉格快速扩张期间南部街区扩展供水网络的一部分。城市工程师对功能性水利基础设施应如何在街道上呈现有着强烈的看法，并付诸实践。\n\n彩蛋：这座水塔矗立于米赫莱的住宅区，周边并无特别值得称道的建筑特色。它已超越了建造时的原始用途，现在被列为受保护的文化遗址。布拉格将其他大多数城市早已悄然拆除的水塔列为文物加以保护。`,
  },

  "fortuna-arena": {
    en: `Brave explorer, Fortuna Arena is the home of SK Slavia Prague — one of the two great Prague football clubs, the other being Sparta Prague, their eternal crosstown rivals. Slavia was founded in 1892 by Czech university students and academics, which explains both the academic emblem on the badge and the outsized intensity of the supporters.\n\nThe current stadium, opened in 2008, seats around 21,000. 'Fortuna' is the naming rights sponsor — Fortuna Entertainment, a Czech betting company. The irony of a club whose founding identity is rooted in intellectual seriousness having a stadium named after a gambling firm is either profound or coincidental, depending on your perspective.\n\nEaster egg: The Slavia–Sparta derby is one of Central Europe's most intense. The clubs are two kilometres apart. Slavia fans traditionally identify with Czech academic culture; Sparta fans with working-class Prague. The distinction is largely symbolic now. The intensity is not.`,
    cz: `Odvážný průzkumníku, Fortuna Arena je domovský stadion SK Slavia Praha — jednoho ze dvou velkých pražských fotbalových klubů, druhým je Sparta Praha, jejich věční rivalové z druhé strany města. Slavia byla founded roku 1892 českými vysokoškolskými studenty a akademiky, což vysvětluje jak akademický emblém na dresu, tak přemrštěnou intenzitu fanoušků.\n\nNynější stadion, otevřený roku 2008, pojme kolem 21 000 diváků. 'Fortuna' je sponzor jmenných práv — Fortuna Entertainment, česká sázková společnost. Ironie toho, že klub, jehož zakládající identita je zakořeněna v intelektuální serióznosti, má stadion pojmenovaný po sázkové firmě, je buď hluboká, nebo náhodná — podle vašeho pohledu.\n\nEaster egg: Derby Slavia–Sparta je jedním z nejintenzivnějších ve střední Evropě. Kluby jsou od sebe dva kilometry. Fanoušci Slavie se tradičně identifikují s českou akademickou kulturou; fanoušci Sparty s dělnickou Prahou. Toto rozlišení je dnes převážně symbolické. Intenzita není.`,
    zh: `勇敢的探险家，幸运竞技场是SK斯拉维亚布拉格的主场——布拉格两支伟大足球俱乐部之一，另一支是他们的跨城永久宿敌斯巴达布拉格。斯拉维亚于1892年由捷克大学生和学术人员创立，这既解释了球衣上的学术徽章，也解释了球迷超乎寻常的热情强度。\n\n现役球场于2008年开放，容纳约21000人。"幸运"是命名权赞助商——幸运娱乐，一家捷克博彩公司。一家创立身份根植于知识分子严肃性的俱乐部，其球场以博彩公司命名，这种讽刺要么意味深长，要么纯属巧合——取决于你的视角。\n\n彩蛋：斯拉维亚与斯巴达的同城德比是中欧最激烈的对抗之一。两家俱乐部相距两公里。斯拉维亚球迷传统上认同捷克学术文化；斯巴达球迷则认同工人阶级布拉格。这一区别如今大多是象征性的。激烈程度则不然。`,
  },

  "muzeum-studene-valky": {
    en: `Brave explorer, the Cold War Museum is located in a real Cold War-era nuclear bunker beneath central Prague — built in the 1950s as an emergency command shelter for city officials who, the planners optimistically hoped, would survive long enough to make decisions that mattered.\n\nThe exhibits cover Soviet-era espionage, nuclear strategy, Warsaw Pact military equipment, and the daily reality of living under a security apparatus that monitored everything from workplace attendance to private correspondence. Prague was not merely adjacent to the Cold War; it was one of its principal theatres.\n\nEaster egg: The StB (secret police) maintained files on an estimated one-third of the population. Some files have since been opened; many have not. The museum tells the official history. The archives hold the personal ones. There is a difference.`,
    cz: `Odvážný průzkumníku, Muzeum studené války sídlí ve skutečném jaderném krytu z dob studené války pod centrem Prahy — postaveném v 50. letech jako nouzový velitelský úkryt pro městské úředníky, kteří by, jak optimisticky doufali plánovači, přežili dostatečně dlouho na to, aby přijímali rozhodnutí, která měla váhu.\n\nExpozice pokrývají sovětskou špionáž, jadernou strategii, vojenské vybavení Varšavské smlouvy a každodenní realitu života pod bezpečnostním aparátem, který monitoroval vše od docházky v práci po soukromou korespondenci. Praha nebyla jen v sousedství studené války; byla jedním z jejích hlavních dějišť.\n\nEaster egg: StB (Státní bezpečnost) vedla složky odhadem na třetinu obyvatelstva. Některé složky byly od té doby otevřeny; mnohé nikoli. Muzeum vypráví oficiální historii. Archivy uchovávají osobní. Je v tom rozdíl.`,
    zh: `勇敢的探险家，冷战博物馆坐落在布拉格市中心地下一处真实的冷战时期核避难所中——建于20世纪50年代，作为城市官员的紧急指挥掩体，规划者乐观地希望他们能存活足够长的时间来作出有意义的决定。\n\n展览涵盖苏联间谍活动、核战略、华沙条约组织军事装备，以及在监视一切——从出勤记录到私人信件——的安全机构下生活的日常现实。布拉格不仅仅毗邻冷战；它是冷战的主要舞台之一。\n\n彩蛋：国家安全局（StB）据估计对三分之一的人口建立了档案。部分档案此后已经公开；许多尚未公开。博物馆讲述的是官方历史。档案馆保存的是个人的。两者之间有区别。`,
  },

  "depo-hostivar": {
    en: `Brave explorer, Depo Hostivař is a former tram depot in the Hostivař district, built in 1962 to service Prague's expanding tram network, and repurposed in the 2010s as a cultural and events venue — the standard urban trajectory for large industrial buildings that outlast their function but are too substantial to demolish.\n\nThe space now hosts concerts, food markets, club nights, and theatre performances. It is one of the more successful industrial conversion projects in Prague, which is notable because Prague has several such projects and they vary considerably in outcome.\n\nEaster egg: The trams that were once maintained here still run on the street outside. Depo Hostivař is also a metro terminus — line A ends here, at the outer edge of a district most Praguers would struggle to describe with confidence. The end of the line has become a destination.`,
    cz: `Odvážný průzkumníku, Depo Hostivař je bývalé tramvajové depo v části Hostivař, postavené roku 1962 pro obsluhu rozrůstající se pražské tramvajové sítě a přebudované v 2010. letech na kulturní a eventové místo — standardní městská trajektorie pro velké průmyslové budovy, které přežijí svůj účel, ale jsou příliš podstatné na zbourání.\n\nProstor nyní hostí koncerty, food markety, klubové noci a divadelní představení. Patří k úspěšnějším přestavbám průmyslových objektů v Praze, což je pozoruhodné, protože Praha má takových projektů několik a výsledky se výrazně liší.\n\nEaster egg: Tramvaje, které se tu kdysi opravovaly, jezdí stále na ulici venku. Depo Hostivař je také stanicí metra — linka A zde končí, na vnějším okraji čtvrti, kterou by většina Pražanů popsala jen s námahou. Konec linky se stal cílovou destinací.`,
    zh: `勇敢的探险家，霍斯提瓦日车辆段是霍斯提瓦日地区一座昔日的电车车辆段，1962年为服务布拉格扩张中的电车网络而建，2010年代改建为文化和活动场地——这是大型工业建筑超越原始功能却又太过宏大以至无法拆除时的标准城市轨迹。\n\n这个空间现在举办音乐会、美食市集、俱乐部之夜和戏剧演出。这是布拉格较为成功的工业改造项目之一，值得一提，因为布拉格有若干此类项目，结果参差不齐。\n\n彩蛋：曾在此维修的电车至今仍在外面的街道上运行。霍斯提瓦日车辆段同时也是地铁终点站——A线在此结束，位于一个大多数布拉格人难以自信描述的街区外缘。线路的终点成了一个目的地。`,
  },

  "vse-praha": {
    en: `Brave explorer, the Prague University of Economics and Business — universally known as VŠE — was founded in 1953 by the Communist government as a training institution for socialist economic planners. The curriculum covered central planning, Marxist economic theory, and state enterprise management. This turned out to be useful preparation for approximately forty years.\n\nAfter November 1989, VŠE pivoted to market economics with notable speed. Within a decade, its graduates were working in private banking, investment management, and the consulting firms simultaneously advising on the privatisation of the state enterprises their predecessors had been trained to manage. The transition required minimal institutional self-reflection.\n\nEaster egg: The campus architecture is pure socialist modernism — functional, monumental, and built from materials that have weathered into a patina architects now call 'honest'. It is the same campus. The economics taught inside has changed almost entirely.`,
    cz: `Odvážný průzkumníku, Vysoká škola ekonomická v Praze — všeobecně známá jako VŠE — byla roku 1953 founded komunistickou vládou jako vzdělávací instituce pro socialistické ekonomické plánovače. Curriculum pokrývalo centrální plánování, marxistickou ekonomickou teorii a řízení státních podniků. To se ukázalo být užitečnou přípravou na přibližně čtyřicet let.\n\nPo listopadu 1989 se VŠE přeorientovala na tržní ekonomiku s pozoruhodnou rychlostí. Během desetiletí vychovávala absolventy pracující v soukromém bankovnictví, investičním managementu a poradenských firmách, které zároveň radily v privatizaci státních podniků, jejichž řízení byli předchůdci absolventů vyškoleni. Přechod vyžadoval minimální institucionální sebereflexe.\n\nEaster egg: Kampusová architektura je čistý socialistický modernismus — funkcionální, monumentální a ze materiálů, které zvětraly do patiny, kterou architekti nyní popisují jako 'upřímnou'. Je to stejný kampus. Ekonomika vyučovaná uvnitř se změnila téměř úplně.`,
    zh: `勇敢的探险家，布拉格经济大学——普遍简称VŠE——由共产党政府于1953年创建，作为培训社会主义经济规划师的教育机构。课程涵盖中央计划、马克思主义经济理论和国有企业管理。这被证明是大约四十年的有用培训。\n\n1989年11月后，VŠE以显著的速度转向市场经济。十年之内，它培养出了在私人银行、投资管理以及咨询公司工作的毕业生，而这些咨询公司同时在为国有企业私有化提供建议——这些国有企业正是其前辈被训练来管理的。这一转型几乎不需要任何机构层面的自我反思。\n\n彩蛋：校园建筑是纯粹的社会主义现代主义——功能性、纪念性，建造材料经风化形成了一种建筑师现在称之为"诚实"的铜绿感。是同一个校园。内部教授的经济学几乎已完全改变。`,
  },

  "klanovsky-les": {
    en: `Brave explorer, Klánovice Forest is an 800-hectare woodland reserve on Prague's eastern edge — one of the few large natural areas that survived the city's 20th-century expansion intact. The forest has been documented continuously since the medieval period. Some of the oaks are estimated at over 300 years old.\n\nThe forest sits between the commuter villages of Klánovice and Újezd nad Lesy, accessible by rail from the city centre in under 30 minutes. It contains marked hiking and cycling trails, a small lake, and an absence of the construction that has absorbed most of the surrounding landscape over the past fifty years.\n\nEaster egg: During WWII, the forest was used by Czech resistance groups for clandestine meetings. The trees are older than those events. The silence of a forest that has absorbed three centuries of European history is a different kind of silence than an empty room.`,
    cz: `Odvážný průzkumníku, Klánovický les je 800hektarový lesní rezervát na východním okraji Prahy — jedna z mála rozsáhlých přírodních lokalit, které přežily rozvoj města ve 20. století nedotčeně. Les je nepřetržitě dokumentován od středověku. Některé duby jsou odhadovány na více než 300 let.\n\nLes leží mezi příměstskými vesnicemi Klánovice a Újezd nad Lesy, dostupný vlakem z centra za méně než 30 minut. Obsahuje značené turistické a cyklistické stezky, malé jezero a absenci zástavby, jíž za posledních padesát let podlehla většina okolní krajiny.\n\nEaster egg: Za druhé světové války byl les využíván českými odbojovými skupinami pro konspirativní schůzky. Stromy jsou starší než ty události. Ticho lesa, který vstřebal tři staletí evropských dějin, je jiné ticho než prázdné místnosti.`,
    zh: `勇敢的探险家，克拉诺维采森林是布拉格东部边缘一片800公顷的林地保护区——少数在20世纪城市扩张中完整保留下来的大型自然区域之一。该森林自中世纪以来有持续的文献记录，据估计部分橡树树龄超过300年。\n\n森林位于通勤村庄克拉诺维采和于耶兹德纳德莱西之间，从市中心乘火车不到30分钟即可到达。内有标记的徒步和自行车路线、一个小湖，以及过去五十年间淹没了大多数周边景观的建设活动所留下的那份缺席。\n\n彩蛋：二战期间，捷克抵抗组织曾利用这片森林举行秘密会议。树木比那些事件更古老。一片吸纳了三个世纪欧洲历史的森林的寂静，是一种与空房间不同的寂静。`,
  },

  "kostel-sv-salvatora-salvatorska": {
    en: `Brave explorer, the Church of the Holy Saviour on Salvátorská street was built by German Lutherans around 1614 — making it one of Prague's few purpose-built Protestant churches. This turns out to have been poor timing.\n\nThe Battle of White Mountain in 1620 ended Bohemian Protestantism for the next three centuries. The church was seized, recatholicised, and passed through Catholic institutions before eventually returning to Protestant use in the 19th century. The congregation took a very long route home.\n\nEaster egg: The street is named after the church. The church is named after the Saviour. In a city where churches are named after saints and streets are named after churches, this creates a chain of attribution that historians find elegant and tourists find confusing.`,
    cz: `Odvážný průzkumníku, Kostel svatého Salvátora na Salvátorské ulici stavěli němečtí luteráni kolem roku 1614 — čímž patří k hrstce pražských kostelů přímo postavených pro protestanty. To se ukázalo jako špatné načasování.\n\nBitva na Bílé hoře roku 1620 ukončila české protestantství na příštích tři sta let. Kostel byl zabrán, rekatolizován a přecházel z ruky do ruky, než se v 19. století vrátil k protestantskému využití. Kongregace se domů dostala pěkně oklikou.\n\nEaster egg: Ulice je pojmenovaná po kostelu. Kostel je pojmenovaný po Spasiteli. Ve městě, kde jsou kostely pojmenovány po světcích a ulice po kostelech, vzniká řetězec atribucí, který historici nacházejí elegantním a turisté matoucím.`,
    zh: `勇敢的探险家，萨尔瓦托斯卡街上的圣救世主教堂由德意志路德宗教徒于约1614年建造——使其成为布拉格少数专为新教徒所建的教堂之一。时机选得不太好。\n\n1620年的白山战役终结了波西米亚的新教存在，此后长达三百年。教堂随即被没收、重新天主教化，在天主教各机构间辗转，直至19世纪才回归新教使用。会众走了一条相当漫长的归途。\n\n彩蛋：这条街以教堂命名，教堂以救主命名。在一座教堂以圣人命名、街道以教堂命名的城市里，这条归属链让历史学家觉得优雅，让游客觉得费解。`,
  },

  "katedra-sv-klimenta": {
    en: `Brave explorer, the Cathedral of St. Clement is a Baroque church hidden inside the Clementinum — the Jesuit mega-complex occupying nearly an entire Old Town block. The Jesuits assembled this real estate over the 17th century through purchase, donation, and the kind of institutional confidence that comes with managing the Counter-Reformation.\n\nThe church now serves as the Greek Catholic Cathedral of Prague — a rite that follows Eastern liturgical traditions while maintaining communion with Rome, a theological position that manages to be complicated by the standards of both camps it navigates between.\n\nEaster egg: The Clementinum complex also contains a Baroque library hall regularly ranked among Europe's most beautiful rooms, an astronomical tower with a meridian observatory, and the National Library. The Jesuits arrived to educate. They stayed to collect everything else.`,
    cz: `Odvážný průzkumníku, Katedrála sv. Klimenta je barokní kostel ukrytý uvnitř Klementina — jezuitského megakomplexu zabírajícího skoro celý starý měšťanský blok. Jezuité tuto nemovitost shromažďovali přes 17. století koupí, darováním a druhem institucionální sebedůvěry, který přichází s řízením protireformace.\n\nKostel dnes slouží jako řeckokatolická katedrála Praha — ritus sledující východní liturgické tradice při zachování společenství s Římem, teologická pozice, která je složitá podle standardů obou táborů, mezi nimiž naviguje.\n\nEaster egg: Klementinský komplex rovněž obsahuje barokní knihovní sál, pravidelně řazený mezi nejkrásnější místnosti v Evropě, astronomickou věž s meridionální observatoří a Národní knihovnu. Jezuité přišli vzdělávat. Zůstali, aby sbírali vše ostatní.`,
    zh: `勇敢的探险家，圣克莱门特主教座堂是隐藏在克莱门特学院内的一座巴洛克教堂——这座耶稣会巨型建筑群占据了旧城区将近整整一个街区。耶稣会士在17世纪通过购买、捐赠，以及主导反宗教改革运动所带来的那种机构自信，逐步积累起这片房产。\n\n教堂如今作为布拉格希腊天主教主教座堂——遵循东方礼仪传统、同时与罗马保持共融的礼仪，一个以其所处两个阵营的神学标准来衡量都称得上复杂的位置。\n\n彩蛋：克莱门特学院还包含一个巴洛克图书馆大厅（屡屡被列为欧洲最美厅室之一）、一座带子午线天文台的天文塔，以及国家图书馆。耶稣会士来布拉格是为了教育。留下来是为了收集其他一切。`,
  },

  "zamek-konopiste": {
    en: `Brave explorer, Konopiště Castle is most famous as the home of Archduke Franz Ferdinand d'Este — the man whose assassination in Sarajevo on June 28, 1914 triggered the First World War. The castle interiors still bear evidence of his primary hobby: he reportedly killed over 300,000 animals across his lifetime, the tally recorded in meticulous hunting journals. The walls confirm this.\n\nFranz Ferdinand was also obsessed with depictions of St. George — the dragon-slaying saint — and accumulated over 3,500 representations of him. He had the largest St. George collection in the world. He did not survive to hear whether anyone found this noteworthy.\n\nEaster egg: His assassination was partly accidental. The first attempt that morning had already failed. His motorcade then took a wrong turn, stalled while correcting course, and stopped directly in front of Gavrilo Princip — who had given up for the day and was eating at a nearby deli. Princip shot Ferdinand from less than two metres away. Twenty million deaths, a wrong turn, and a sandwich.`,
    cz: `Odvážný průzkumníku, Zámek Konopiště je nejznámější jako domov arcivévody Františka Ferdinanda d'Este — muže, jehož atentát v Sarajevu 28. června 1914 spustil první světovou válku. Zámecké interiéry stále nesou doklad jeho hlavního koníčku: za život prý zastřelil přes 300 000 zvířat, přičemž počet je zaznamenán v pečlivých loveckých deníkách. Stěny to potvrzují.\n\nFrantišek Ferdinand byl také posedlý zobrazeními sv. Jiří — světce zabíjejícího draka — a nahromadil přes 3 500 jeho vyobrazení. Měl největší sbírku sv. Jiří na světě. Nedožil se, aby zjistil, zda to někdo považuje za pozoruhodné.\n\nEaster egg: Jeho atentát byl zčásti náhodný. První pokus ráno již selhal. Arcivévodův kortej pak odbočil špatně, zastavil při opravě kurzu a zastavil přímo před Gavrilo Principem — který se na den vzdal a jedl v nedaleké lahůdkářství. Princip střelil Ferdinanda z méně než dvou metrů. Dvacet milionů mrtvých, špatná odbočka a svačina.`,
    zh: `勇敢的探险家，科诺皮什捷城堡最广为人知的，是它作为弗朗茨·斐迪南大公故居的身份——此人于1914年6月28日在萨拉热窝遇刺，直接引发了第一次世界大战。城堡内饰至今仍是他主要爱好的明证：据记载，他一生共猎杀逾30万头动物，战绩详细记录于他一丝不苟的猎记日志中。墙上的战利品证实了这一切。\n\n弗朗茨·斐迪南还对屠龙圣人圣乔治的形象痴迷不已，积累了超过3500件各种媒介的圣乔治作品，是世界上最大的圣乔治藏品。他没能活到听说有没有人认为这值得关注。\n\n彩蛋：他的遇刺部分属于意外。当天早些时候的第一次行刺尝试已经失败。然而他的车队随后转错了弯，在纠正路线时停了下来，正好停在了加弗里洛·普林西普面前——此人已经放弃了这一天，正在附近的一家小店里吃东西。普林西普在不到两米的距离外开枪射杀了斐迪南。两千万人的死亡，一次错误的转弯，和一顿午饭。`,
  },

  "pamatnik-tg-masaryka": {
    en: `Brave explorer, Tomáš Garrigue Masaryk became the first President of Czechoslovakia in 1918 at the age of 68, after spending World War I in exile, lobbying Allied governments, writing political philosophy, and watching the Austro-Hungarian Empire disintegrate on schedule. He returned home as a founding father. The Habsburg authorities had issued a warrant for his arrest.\n\nThe 'Garrigue' is not Czech. In 1878, Masaryk married Charlotte Garrigue, an American from Brooklyn, and incorporated her maiden surname into his own as a statement of marital equality. He was 28 and considered this obvious. Society considered it alarming. He did not adjust his opinion.\n\nEaster egg: His son Jan Masaryk was found dead beneath the bathroom window of the Czech Foreign Ministry on March 10, 1948, two weeks after the Communist coup. The official verdict in 1948 was suicide. Every subsequent investigation has arrived at a more complicated answer. The window remains a subject of study.`,
    cz: `Odvážný průzkumníku, Tomáš Garrigue Masaryk se stal prvním prezidentem Československa roku 1918 ve věku 68 let, poté co strávil první světovou válku v exilu, lobbováním u spojeneckých vlád, psaním politické filozofie a sledováním, jak se Rakousko-Uhersko rozkládá podle plánu. Vrátil se domů jako zakladatel státu. Habsburské úřady na něj vydaly zatykač.\n\n'Garrigue' není česky. Roku 1878 si Masaryk vzal Charlottu Garriguovou, Američanku z Brooklynu, a přidal její rodné příjmení ke svému jako prohlášení o manželské rovnosti. Bylo mu 28 a považoval to za samozřejmé. Společnost to považovala za znepokojivé. Svůj názor neupravil.\n\nEaster egg: Jeho syn Jan Masaryk byl nalezen mrtvý pod oknem koupelny Černínského paláce 10. března 1948, dva týdny po komunistickém puči. Úřední verdikt z roku 1948 zněl: sebevražda. Každé následné vyšetřování dospělo ke složitější odpovědi. Okno zůstává předmětem studia.`,
    zh: `勇敢的探险家，托马斯·加里格·马萨里克于1918年以68岁高龄成为捷克斯洛伐克第一任总统。此前他在第一次世界大战期间流亡海外，游说协约国各国政府，撰写政治哲学著作，并目睹奥匈帝国如期瓦解。他以国父之姿归国。哈布斯堡当局曾对他发出逮捕令。\n\n"加里格"不是捷克语。1878年，马萨里克迎娶了来自布鲁克林的美国女子夏洛特·加里格，并将她的娘家姓并入自己的姓名，以此宣示婚姻平等。他当时28岁，认为这不言而喻。社会认为这令人不安。他没有改变立场。\n\n彩蛋：他的儿子扬·马萨里克于1948年3月10日——共产党政变两周后——被发现陈尸于捷克外交部浴室窗户下方。1948年的官方裁定是自杀。此后每一次调查都得出了更为复杂的结论。那扇窗户至今仍是研究对象。`,
  },

  "srdce-pro-vaclava-havla": {
    en: `Brave explorer, the Heart for Václav Havel is a permanent installation on the square now bearing his name — Náměstí Václava Havla, renamed in 2012 from the blander 'Theatre Square', six months after Havel's death. The city spent decades jailing him. It eventually put his name on a square. Progress is non-linear.\n\nVáclav Havel was a playwright who spent twenty years being harassed, surveilled, briefly imprisoned, and denied work by a government that found his plays politically inconvenient. He then spent thirteen years as president. This is not the usual career trajectory for Central European dramatists.\n\nEaster egg: The Theatre on the Balustrade nearby — Divadlo Na zábradlí — is where Havel worked as a stagehand, then resident playwright, in the 1960s before the authorities made this professionally impossible. He wrote The Garden Party there, which the Communists found insufficiently enthusiastic about the Party. They were correct about this.`,
    cz: `Odvážný průzkumníku, Srdce pro Václava Havla je stálá instalace na náměstí, které nyní nese jeho jméno — Náměstí Václava Havla, přejmenované roku 2012 z nudnějšího 'Divadelního náměstí' šest měsíců po Havlově smrti. Město ho desítky let věznilo. Nakonec mu pojmenovalo náměstí. Pokrok není lineární.\n\nVáclav Havel byl dramatik, který strávil dvacet let pronásledováním, sledováním, krátkým vězněním a odepřením práce od vlády, jíž jeho hry přišly politicky nepohodlné. Poté strávil třináct let jako prezident. To není obvyklá kariérní dráha pro středoevropské dramatiky.\n\nEaster egg: Nedalejší Divadlo Na zábradlí je místem, kde Havel v 60. letech pracoval jako jevištní technik, poté jako domovský dramaturg, než mu úřady tuto profesi znemožnily. Napsal zde Zahradní slavnost, která se komunistům zdála nedostatečně nadšená pro stranu. V tom měli pravdu.`,
    zh: `勇敢的探险家，哈维尔之心是矗立于以他命名的广场上的永久装置——瓦茨拉夫·哈维尔广场，于哈维尔逝世六个月后的2012年，从较为平淡的"剧院广场"更名至此。这座城市曾多次将他投入监狱，最终却在广场上刻下他的名字。进步从不走直线。\n\n瓦茨拉夫·哈维尔是一位剧作家，他花了二十年被当局骚扰、监视、短暂监禁和剥夺工作权利——只因为一个认为他的戏剧政治上不合时宜的政府。之后他担任了十三年总统。这不是中欧剧作家通常的职业轨迹。\n\n彩蛋：附近的"栏杆上的剧院"——Divadlo Na zábradlí——是哈维尔1960年代担任舞台工作人员、后成为驻院剧作家的地方，直到当局让这份职业变得不可能。他在那里创作了《园游会》，共产党人认为这部作品对党的热忱远远不够。在这一点上，他们是对的。`,
  },

  "pamatnik-palacha-zajice": {
    en: `Brave explorer, on January 16, 1969 — five months after Soviet tanks ended the Prague Spring — a 20-year-old philosophy student named Jan Palach set himself on fire on Wenceslas Square to protest the 'normalisation' programme systematically reversing eight months of reform. He died three days later. Within weeks, 18-year-old Jan Zajíc repeated the act at the same spot.\n\nThe Communist government tried to suppress both deaths. Palach's grave became a pilgrimage site, so authorities removed the body to a remote cemetery. They falsely claimed he had been misled, that he regretted the act, that his wishes had been misrepresented. None of the official responses worked.\n\nEaster egg: The small cross set into the pavement marks the exact location. In 1989, twenty years after Palach's death, this spot became a focal point of the protests that ended Communist rule. The regime that spent two decades trying to erase this memory was itself erased first.`,
    cz: `Odvážný průzkumníku, 16. ledna 1969 — pět měsíců poté, co sovětské tanky ukončily Pražské jaro — se dvacetiletý student filozofie Jan Palach zapálil na Václavském náměstí na protest proti programu 'normalizace', systematicky rušícímu osm měsíců reforem. Zemřel o tři dny později. V dalších týdnech 18letý Jan Zajíc zopakoval totéž na stejném místě.\n\nKomunistická vláda se pokoušela obě smrti potlačit. Palachův hrob se stal místem poutí, takže úřady tělo přemístily na vzdálený hřbitov. Lživě tvrdily, že byl zmaten, že toho litoval, že jeho přání bylo překrouceno. Žádná z těchto oficiálních reakcí nezabírala.\n\nEaster egg: Malý kříž zapuštěný do chodníku označuje přesné místo. Roku 1989, dvacet let po Palachově smrti, se toto místo stalo ústředním bodem protestů, které ukončily komunistickou vládu. Režim, který dvě desetiletí usiloval o vymazání této paměti, byl sám vymazán jako první.`,
    zh: `勇敢的探险家，1969年1月16日——苏联坦克终结布拉格之春后五个月——一名20岁的哲学系学生扬·帕拉赫在瓦茨拉夫广场自焚，以抗议系统性撤销八个月改革成果的"正常化"运动。三天后他去世。数周内，18岁的扬·扎伊茨在同一地点重演了这一幕。\n\n共产党政府试图压制这两起死亡事件。帕拉赫的墓地成为朝圣之所，当局便将遗体迁往偏远的墓地。他们谎称他受到了误导，声称他感到后悔，声称他的心愿遭到了歪曲。这些官方回应没有一条起了作用。\n\n彩蛋：嵌入人行道的小十字架标记了确切地点。1989年，帕拉赫去世二十年后，这个地点成为终结共产主义统治的抗议运动的焦点之一。那个耗费二十年试图抹去这段记忆的政权，自己率先被抹去了。`,
  },

  "pomnik-sv-vaclava": {
    en: `Brave explorer, Wenceslas I, Duke of Bohemia, was murdered by his younger brother Boleslav in 935. Boleslav then ruled Bohemia for thirty years and was considered a reasonably effective duke. The brother he had killed was meanwhile canonised, became Bohemia's eternal patron saint, and had an enormous square, a famous carol, and a crown named after him. History distributes its outcomes unevenly.\n\nThe equestrian statue by sculptor Josef Václav Myslbek was unveiled in 1912 after twenty-five years of work, debate, and complaints about the design. Four patron saints — Ludmila, Prokop, Anežka, and Vojtěch — stand at the base. They have been there for over a century and appear accustomed to it.\n\nEaster egg: 'Meet me under the horse' — pod koněm — is how Praguers arrange to meet at this statue. Specifically beneath the hindquarters, where the crowd thins and the landmark is unambiguous. It functions as the city's least glamorous but most reliable navigation anchor.`,
    cz: `Odvážný průzkumníku, Václav I., přemyslovský kníže, byl zavražděn svým mladším bratrem Boleslavem roku 935. Boleslav pak vládl Čechám třicet let a byl považován za přiměřeně schopného knížete. Mezitím byl bratr, kterého zabil, kanonizován, stal se věčným patronem Čech a nechal po sobě pojmenovat obrovské náměstí, slavnou koledu a korunu. Historie rozděluje výsledky nerovnoměrně.\n\nJezdecká socha od sochaře Josefa Václava Myslbeka byla odhalena roku 1912 po pětadvaceti letech práce, debat a stížností na design. U podnože stojí čtyři patroni: Ludmila, Prokop, Anežka a Vojtěch. Stojí tam přes sto let a vypadají zvyklí.\n\nEaster egg: 'Sejdeme se pod koněm' — pod koněm — je způsob, jakým Pražané domlouvají schůzky u sochy. Konkrétně pod zadními nohami, kde se dav ztenčuje a orientační bod je jednoznačný. Funguje jako nejméně okázalý, ale nejspolehlivější navigační uzel města.`,
    zh: `勇敢的探险家，波西米亚公爵瓦茨拉夫一世于935年被他的弟弟博列斯拉夫所杀。博列斯拉夫随后统治波西米亚三十年，被认为是一位还算有效率的公爵。而他所杀的那位兄长，与此同时被封圣，成为波西米亚永恒的守护圣人，一座巨大的广场、一首著名颂歌和一顶王冠都以他命名。历史对成果的分配向来不均。\n\n雕塑家约瑟夫·瓦茨拉夫·米斯尔贝克的骑马雕像于1912年揭幕，此前历经二十五年的制作、争论和对设计的抗议。底座上有四位守护圣人：卢德米拉、普罗科普、阿涅日卡和沃伊切赫。他们已经在那里站了一百多年，看起来已经习以为常。\n\n彩蛋："在马下见"——pod koněm——是布拉格人约在雕像旁见面的说法。具体来说，是在马的后半身下方，那里人群稀少，地标清晰无误。它是这座城市最不华丽却最可靠的导航锚点。`,
  },

  "kostel-sv-vojtecha": {
    en: `Brave explorer, the Church of St. Adalbert is named after Vojtěch — Bishop of Prague, missionary, and martyr who in 997 brought his evangelical project to the Prussians, who received it poorly and killed him with a spear. He was canonised two years later. The Prussians were canonised by nobody.\n\nThe church stands in New Town, Charles IV's ambitious 1348 expansion of Prague. Charles seeded his new district with parish churches to serve every neighbourhood — an approach to urban planning that prioritised walking distance to salvation at a time when this was considered the more urgent metric.\n\nEaster egg: Vojtěch's relics were taken to Gniezno in Poland after his death and never returned. Prague's patron saint's bones are not in Prague. The Poles negotiated this arrangement more effectively than anyone in Bohemia has managed to contest it since.`,
    cz: `Odvážný průzkumníku, Kostel sv. Vojtěcha je pojmenován po Vojtěchovi — pražském biskupu, misionáři a mučedníku, který roku 997 přinesl svůj evangelizační projekt Prusům, kteří ho přijali špatně a zabili ho kopím. O dva roky později byl kanonizován. Prusové nebyli kanonizováni nikým.\n\nKostel stojí v Novém Městě, Karlově ambiciózním rozšíření Prahy z roku 1348. Karel zasázel do nové čtvrti farní kostely pro každou část města — přístup k urbanismu, který prioritizoval dostupnost spásy pěšky v době, kdy se to považovalo za naléhavější metriku.\n\nEaster egg: Vojtěchovy ostatky byly po jeho smrti odvezeny do Hnězdna v Polsku a nikdy nevráceny. Ostatky pražského patrona nejsou v Praze. Poláci toto urovnání vyjednali účinněji, než se to od té doby komukoliv v Čechách podařilo zpochybnit.`,
    zh: `勇敢的探险家，圣沃伊切赫教堂以沃伊切赫命名——布拉格主教、传教士兼殉道者，997年将他的传教使命带到了普鲁士人中间，后者对此反应冷淡，用长矛将他杀死。两年后他被封圣。没有人将普鲁士人封圣。\n\n教堂坐落于新城区，即查理四世1348年对布拉格的雄心勃勃的扩建规划。查理在新城区遍植教区教堂，确保每个街区都有覆盖——一种城市规划方式，在那个时代将步行可及救赎的距离视为最紧迫的衡量指标。\n\n彩蛋：沃伊切赫的遗骨在他死后被带到了波兰的格涅兹诺，从未归还。布拉格守护圣人的遗骨不在布拉格。波兰人在谈判中达成了这一安排，而波西米亚此后从未能有效地提出争议。`,
  },

  "kostel-sv-stepana": {
    en: `Brave explorer, the Church of St. Stephen was founded in 1351 by Charles IV as one of the main parish churches for his expanded New Town. St. Stephen was the first Christian martyr — stoned to death in Jerusalem around 34 AD — giving the church a reputation associated with firsts, if catastrophic ones.\n\nThe Gothic structure was built over the 14th and 15th centuries. Among its interior artworks is a panel painting attributed to the Master of the Třeboň Altarpiece — anonymous, 14th century, responsible for some of the most technically accomplished panel paintings in Bohemia. The anonymous craftsmen left the best things.\n\nEaster egg: A few hundred metres away stands the Church of St. Henry and St. Kunigunde — meaning this stretch of New Town contains two full medieval churches within easy walking distance of each other. Charles IV built parish infrastructure the way other rulers built city walls: as a matter of settled policy, without gaps.`,
    cz: `Odvážný průzkumníku, Kostel sv. Štěpána byl roku 1351 založen Karlem IV. jako jeden z hlavních farních kostelů pro jeho rozšířené Nové Město. Sv. Štěpán byl prvním křesťanským mučedníkem — ukamenován v Jeruzalémě kolem roku 34 n. l. — čímž dává kostelu pověst spojenou s prvenstvy, byť katastrofálními.\n\nGotická stavba vznikala ve 14. a 15. století. Mezi interiérovými díly je deskový obraz připisovaný Mistru třeboňského oltáře — anonymnímu malíři 14. století, zodpovědnému za některé z technicky nejdokonalejších deskových maleb v Čechách. Anonymní řemeslníci zanechali ty nejlepší věci.\n\nEaster egg: Několik set metrů odtud stojí Kostel sv. Jindřicha a sv. Kunhuty — to znamená, že tento úsek Nového Města má dva plnohodnotné středověké kostely v snadné docházkové vzdálenosti od sebe. Karel IV. budoval farní infrastrukturu tak, jak jiní vládci stavěli městské hradby: jako záležitost pevné politiky, bez mezer.`,
    zh: `勇敢的探险家，圣斯蒂芬教堂由查理四世于1351年创建，是他扩建后的新城区主要教区教堂之一。圣斯蒂芬是第一位基督教殉道者——约公元34年在耶路撒冷被乱石砸死——赋予这座教堂一种与"第一"相关的声誉，尽管是令人痛心的第一。\n\n哥特式建筑在14至15世纪间逐步建成。室内艺术品中有一幅归于特热博恩祭坛画大师名下的木板画——无名氏，14世纪，是波西米亚技艺最精湛的木板画作品之一。无名工匠留下了最好的东西。\n\n彩蛋：几百米外是圣亨里克与圣昆胡塔教堂——这意味着新城区的这一段在步行可及的距离内就有两座完整的中世纪教堂。查理四世建造教区基础设施的方式，就像其他统治者建造城墙一样：作为既定政策的一部分，没有缺口。`,
  },

  "vystaviste-praha": {
    en: `Brave explorer, Prague Exhibition Centre is the most exuberant monument to nineteenth-century optimism in the entire city — a sprawling complex of exhibition halls, gardens, and pavilions in Holešovice, built in 1891 for the General Land Centennial Exhibition celebrating a hundred years since the first great Czech industrial fair of 1791. At its heart stands the Industrial Palace, a magnificent steel-and-glass structure 238 metres long whose architects drew on the Crystal Palace in London and the Galerie des Machines in Paris, then did both one better by adding Czech decorative motifs in every wrought-iron curve. Unlock the greatest Easter egg in the grounds: Křižík's Fountain, operating since 1891, was the first electrically illuminated musical fountain in the world — inventor František Křižík designed the system himself, using the then-revolutionary technology of electric light to choreograph water jets to music. It has been performing every summer for over 130 years. The exhibition also marked the first time Edison's electric light system was publicly demonstrated in Central Europe. The grounds were later used by the Communist government for the Spartakiad mass gymnastic festivals, adding another layer of history to a place already soaked in it. This is the level where Czech industry, art, and electricity converged.`,
    cz: `Odvážný průzkumníku, Výstaviště Praha je nejpůsobivějším pomníkem optimismu devatenáctého století v celém městě — rozlehlý komplex výstavních hal, zahrad a pavilonů v Holešovicích, postavený v roce 1891 pro Všeobecnou zemskou jubilejní výstavu slavící sto let od první velké české průmyslové výstavy z roku 1791. V jeho srdci stojí Průmyslový palác, velkolepá ocelová a skleněná stavba 238 metrů dlouhá, jejíž architekti se inspirovali londýnským Crystal Palace a pařížskou Galerie des Machines, pak obě překonali přidáním českých dekorativních motivů do každé kované obloučky. Odemkni největší easter egg v areálu: Křižíkova fontána, fungující od roku 1891, byla první elektricky osvětlenou hudební fontánou na světě — vynálezce František Křižík navrhl systém sám, použijíc tehdy revoluční technologii elektrického světla k choreografii vodních trysek na hudbu. Hraje každé léto déle než 130 let. Výstava také znamenala první veřejnou demonstraci Edisonova systému elektrického osvětlení ve střední Evropě. Areál byl later využíván komunistickou vládou pro Spartakiádu, masová cvičení, přidávajíce další vrstvu dějin na místo, které jimi je již nasyceno. Toto je level, kde se setkaly český průmysl, umění a elektřina.`,
    zh: `勇敢的探险家，布拉格展览中心是整座城市19世纪乐观主义最令人叹为观止的纪念碑——一个位于霍列绍维采的宏大建筑群，包含展览厅、花园和展馆，建于1891年，为纪念1791年第一届捷克工业博览会一百周年而举办的"普通土地百年展览会"而建。其核心是工业宫，一座长238米的宏伟钢铁与玻璃建筑，建筑师们从伦敦的水晶宫和巴黎的机器大厅汲取灵感，然后在每一条铸铁曲线中加入捷克装饰图案，双双超越了原型。解锁场地中最伟大的彩蛋：克日日克喷泉自1891年起运行，是世界上第一座电力照明音乐喷泉——发明家弗兰季谢克·克日日克亲自设计了这套系统，运用当时革命性的电光技术，将水柱的舞动编排为音乐伴奏。它已经在每个夏天连续演出逾130年。这次展览也是爱迪生电力照明系统在中欧首次公开展示的场合。这片场地后来被共产党政府用于斯巴达克运动会大型体操节，为这个已经浸透历史的地方再添一层。这是捷克工业、艺术与电力汇聚的关卡。`,
  },
};

async function seedDescriptionsStatic() {
  await connectDB();
  const slugs = Object.keys(descriptions);
  console.log(`Saving descriptions for ${slugs.length} locations...\n`);
  let done = 0, failed = 0;
  for (const slug of slugs) {
    process.stdout.write(`Saving "${slug}"... `);
    try {
      const result = await Location.findOneAndUpdate(
        { slug },
        { $set: { description: descriptions[slug] } },
        { new: true }
      );
      if (!result) { failed++; console.log('FAILED — not found'); }
      else { done++; console.log(`done (${done}/${slugs.length})`); }
    } catch (err) { failed++; console.log(`FAILED — ${err.message}`); }
  }
  console.log(`\nFinished. ${done} saved, ${failed} failed.`);
  process.exit(failed > 0 ? 1 : 0);
}

seedDescriptionsStatic().catch(err => { console.error(err); process.exit(1); });
